import { useLocation, Link } from 'react-router-dom';
import {
  LayoutDashboard,
  ArrowLeftRight,
  Wallet,
  TrendingUp,
  MessageCircle,
  Briefcase,
  BarChart3,
  Settings,
  Bell,
  LogOut,
  ChevronLeft,
  Calendar,
  UserCircle,
  CloudUpload,
  X,
  MoreHorizontal,
  Store,
  ShieldCheck,
  Globe,
  type LucideIcon,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useAuth } from '@/features/auth/auth-context';
import { useT } from '@/lib/i18n';
import { useState } from 'react';
import { useIsAdmin } from '@/features/admin/hooks/useAdminProfiles';

interface NavItem {
  labelKey: string;
  fallback: string;
  icon: LucideIcon;
  path: string;
}

export const tradingNav: NavItem[] = [
  { labelKey: 'dashboard', fallback: 'Dashboard', icon: LayoutDashboard, path: '/dashboard' },
  { labelKey: 'orders', fallback: 'Orders', icon: TrendingUp, path: '/trading/orders' },
  { labelKey: 'stock', fallback: 'Stock', icon: Wallet, path: '/trading/stock' },
  { labelKey: 'crm', fallback: 'CRM', icon: UserCircle, path: '/crm' },
  { labelKey: 'chat', fallback: 'Chat', icon: MessageCircle, path: '/chat' },
  { labelKey: 'calendar', fallback: 'Calendar', icon: Calendar, path: '/trading/calendar' },
  { labelKey: 'p2pTracker', fallback: 'P2P Market', icon: Globe, path: '/trading/p2p' },
];

export const networkNav: NavItem[] = [
  { labelKey: 'theMerchants', fallback: 'The Merchants', icon: Store, path: '/merchants' },
  { labelKey: 'vault', fallback: 'Vault', icon: CloudUpload, path: '/trading/vault' },
  { labelKey: 'settings', fallback: 'Settings', icon: Settings, path: '/settings' },
];

type AppSidebarProps = {
  isMobile?: boolean;
  mobileOpen?: boolean;
  onMobileClose?: () => void;
};

export function MobileBottomNav({ onMoreClick }: { onMoreClick: () => void }) {
  const location = useLocation();
  const t = useT();
  const primaryNav = [
    tradingNav[0], // Dashboard
    tradingNav[1], // Orders
    tradingNav[2], // Stock
    networkNav[0], // Merchants
    tradingNav[4], // Chat
  ].filter(Boolean) as NavItem[];

  return (
    <nav className="mobile-bottom-nav">
      {primaryNav.map((item) => {
        const [itemPath, itemQuery] = item.path.split('?');
        const active = itemQuery
          ? location.pathname === itemPath && location.search.includes(itemQuery)
          : location.pathname === item.path || location.pathname.startsWith(item.path + '/');
        return (
          <Link
            key={item.path}
            to={item.path}
            className={cn('mobile-bottom-nav__item', active && 'is-active')}
          >
            <span className="mobile-bottom-nav__icon-wrap">
              <item.icon className="mobile-bottom-nav__icon" />
            </span>
            <span className="mobile-bottom-nav__label">{t(item.labelKey as any) || item.fallback}</span>
          </Link>
        );
      })}
      <button onClick={onMoreClick} className="mobile-bottom-nav__item">
        <span className="mobile-bottom-nav__icon-wrap">
          <MoreHorizontal className="mobile-bottom-nav__icon" />
        </span>
        <span className="mobile-bottom-nav__label">More</span>
      </button>
    </nav>
  );
}
function AdminNavSection({ collapsed, isActive, isMobile, onMobileClose }: { collapsed: boolean; isActive: (p: string) => boolean; isMobile: boolean; onMobileClose?: () => void }) {
  const { data: isAdmin } = useIsAdmin();
  const t = useT();
  if (!isAdmin) return null;
  return (
    <div className="mb-2">
      {!collapsed && (
        <div className="px-3 py-2 text-[11px] font-bold uppercase tracking-wider text-sidebar-foreground/50">
          {t('admin') || 'Admin'}
        </div>
      )}
      <ul className="space-y-0.5 px-2">
        <li>
          <Link
            to="/admin"
            onClick={isMobile ? onMobileClose : undefined}
            className={cn(
              'flex items-center gap-3 rounded-lg px-3 py-2 text-[13px] transition-colors',
              'text-sidebar-foreground/80 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground',
              isActive('/admin') && 'bg-sidebar-accent text-sidebar-primary font-medium'
            )}
          >
            <ShieldCheck className="h-3.5 w-3.5 shrink-0" />
            {!collapsed && <span>{t('admin') || 'Admin Center'}</span>}
          </Link>
        </li>
      </ul>
    </div>
  );
}

export function AppSidebar({ isMobile = false, mobileOpen = false, onMobileClose }: AppSidebarProps) {
  const location = useLocation();
  const [collapsed, setCollapsed] = useState(false);
  const { merchantProfile, logout } = useAuth();
  const t = useT();

  const isActive = (path: string) =>
    location.pathname === path || location.pathname.startsWith(path + '/');

  const NavSection = ({ title, items }: { title: string; items: NavItem[] }) => (
    <div className="mb-2">
      {!collapsed && (
        <div className="px-3 py-2 text-[11px] font-bold uppercase tracking-wider text-sidebar-foreground/50">
          {title}
        </div>
      )}
      <ul className="space-y-0.5 px-2">
        {items.map((item) => (
          <li key={item.path}>
            <Link
              to={item.path}
              onClick={isMobile ? onMobileClose : undefined}
              className={cn(
                'flex items-center gap-3 rounded-lg px-3 py-2 text-[13px] transition-colors',
                'text-sidebar-foreground/80 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground',
                isActive(item.path) && 'bg-sidebar-accent text-sidebar-primary font-medium'
              )}
            >
              <item.icon className="h-3.5 w-3.5 shrink-0" />
              {!collapsed && <span className="truncate">{t(item.labelKey as any) || item.fallback}</span>}
            </Link>
          </li>
        ))}
      </ul>
    </div>
  );

  const sidebarContent = (
    <aside
      className={cn(
        'flex flex-col bg-sidebar border-sidebar-border h-full transition-all duration-200',
        'ltr:border-r rtl:border-l',
        collapsed ? 'w-[52px]' : 'w-fit min-w-[120px] max-w-[200px]'
      )}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-3 py-4 border-b border-sidebar-border">
        {!collapsed && (
          <span className="font-display text-[13px] font-bold text-sidebar-foreground tracking-tight">
            P2P Tracker
          </span>
        )}
        {!isMobile && (
          <button
            onClick={() => setCollapsed(!collapsed)}
            className="p-1 rounded hover:bg-sidebar-accent text-sidebar-foreground/60"
          >
            <ChevronLeft className={cn('h-3.5 w-3.5 transition-transform', collapsed && 'ltr:rotate-180 rtl:rotate-0', !collapsed && 'rtl:rotate-180')} />
          </button>
        )}
        {isMobile && (
          <button onClick={onMobileClose} className="p-1 rounded hover:bg-sidebar-accent text-sidebar-foreground/60">
            <X className="h-3.5 w-3.5" />
          </button>
        )}
      </div>

      {/* Merchant info */}
      {!collapsed && merchantProfile && (
        <div className="px-3 py-3 border-b border-sidebar-border">
          <div className="text-[13px] font-medium text-sidebar-foreground truncate">
            {merchantProfile.display_name}
          </div>
          <div className="text-[11px] text-sidebar-foreground/50 truncate">
            @{merchantProfile.nickname}
          </div>
        </div>
      )}

      {/* Navigation */}
      <div className="flex-1 overflow-y-auto py-2">
        <NavSection title={t('trading')} items={tradingNav} />
        <NavSection title={t('network')} items={networkNav} />
        <AdminNavSection collapsed={collapsed} isActive={isActive} isMobile={isMobile} onMobileClose={onMobileClose} />
      </div>

      {/* Footer */}
      <div className="border-t border-sidebar-border p-2 space-y-0.5">
        <Link
          to="/notifications"
          onClick={isMobile ? onMobileClose : undefined}
          className={cn(
            'flex items-center gap-3 rounded-lg px-3 py-2 text-[13px] transition-colors',
            'text-sidebar-foreground/80 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground',
            isActive('/notifications') && 'bg-sidebar-accent text-sidebar-primary font-medium'
          )}
        >
          <Bell className="h-3.5 w-3.5 shrink-0" />
          {!collapsed && <span>{t('notifications')}</span>}
        </Link>
        <button
          onClick={logout}
          className="flex w-full items-center gap-3 rounded-lg px-3 py-2 text-[13px] text-sidebar-foreground/80 hover:bg-sidebar-accent hover:text-destructive transition-colors"
        >
          <LogOut className="h-3.5 w-3.5 shrink-0" />
          {!collapsed && <span>{t('signOut')}</span>}
        </button>
      </div>
    </aside>
  );

  if (!isMobile) {
    return sidebarContent;
  }

  // Mobile overlay
  return (
    <>
      {mobileOpen && (
        <div className="fixed inset-0 z-40 bg-black/50" onClick={onMobileClose} />
      )}
      <div
        className={cn(
          'fixed top-0 z-50 h-full transition-transform duration-200',
          'ltr:left-0 rtl:right-0',
          mobileOpen ? 'translate-x-0' : 'ltr:-translate-x-full rtl:translate-x-full'
        )}
      >
        {sidebarContent}
      </div>
    </>
  );
}

import { useLocation } from 'react-router-dom';
import { useMemo, useState } from 'react';
import { Menu, Bell, Users, TrendingUp, User } from 'lucide-react';
import ActivityCenter from '@/components/notifications/ActivityCenter';
import { useTheme } from '@/lib/theme-context';
import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { cn } from '@/lib/utils';
import { UserProfileModal } from '@/features/profile/UserProfileModal';

function titleFromPath(pathname: string, t: ReturnType<typeof useT>): { title: string; subtitle: string } {
  if (pathname === '/dashboard') return { title: t('dashboard'), subtitle: t('dashboardSub') };
  if (pathname === '/trading/orders') return { title: t('orders'), subtitle: t('tradesSub') };
  if (pathname === '/trading/stock') return { title: t('stock'), subtitle: t('stockSub') };
  if (pathname === '/trading/calendar') return { title: t('calendar'), subtitle: t('calendarSub') };
  if (pathname === '/trading/p2p') return { title: t('p2pTracker'), subtitle: 'Live market rates' };
  if (pathname === '/crm') return { title: t('crm'), subtitle: t('crmSub') };
  if (pathname === '/merchants') return { title: t('theMerchants'), subtitle: 'Relationships, deals & invitations' };
  if (pathname === '/deals') return { title: t('deals'), subtitle: 'Deal management' };
  if (pathname === '/analytics') return { title: t('analytics'), subtitle: 'Performance insights' };
  if (pathname === '/vault') return { title: t('vault'), subtitle: 'Document storage' };
  if (pathname === '/settings') return { title: t('settings'), subtitle: t('layoutThemesData') };
  if (pathname === '/notifications') return { title: t('notifications'), subtitle: 'Activity feed' };
  return { title: 'P2P Tracker', subtitle: 'P2P Trading Platform' };
}

const RANGES = [
  { id: 'today', label: '1D' },
  { id: '7d', label: '7D' },
  { id: 'this_month', label: '30D' },
  { id: 'all', label: 'ALL' },
] as const;

type TopBarProps = {
  isMobile?: boolean;
  onMenuClick?: () => void;
};

export function TopBar({ isMobile = false, onMenuClick }: TopBarProps) {
  const location = useLocation();
  const { settings, update } = useTheme();
  const { merchantProfile, logout } = useAuth();
  const t = useT();
  const meta = useMemo(() => titleFromPath(location.pathname, t), [location.pathname, t]);
  const [profileOpen, setProfileOpen] = useState(false);

  return (
    <header
      className="sticky top-0 z-20 flex items-center gap-1 md:gap-2 border-b border-border bg-background/95 backdrop-blur-sm px-2 md:px-3 py-1.5"
      style={isMobile ? {
        paddingTop: 'calc(env(safe-area-inset-top, 0px) + 6px)',
        paddingLeft: 'max(8px, env(safe-area-inset-left, 0px))',
        paddingRight: 'max(8px, env(safe-area-inset-right, 0px))',
      } : undefined}
    >
      {isMobile && onMenuClick && (
        <button onClick={onMenuClick} className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground">
          <Menu className="h-4 w-4" />
        </button>
      )}

      {/* ── Period Toggle ── */}
      <div className="flex items-center gap-0.5 bg-muted rounded-md p-0.5">
        {RANGES.map(r => (
          <button
            key={r.id}
            onClick={() => update({ range: r.id as any })}
            className={cn(
              'px-1.5 py-1 rounded text-[10px] font-semibold transition-all md:px-2.5 md:text-[11px]',
              settings.range === r.id
                ? 'bg-primary text-primary-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            )}
          >
            {r.label}
          </button>
        ))}
      </div>

      {/* ── Currency Toggle ── */}
      <div className="flex items-center gap-0.5 bg-muted rounded-md p-0.5">
        {(['QAR', 'USDT'] as const).map(c => (
          <button
            key={c}
            onClick={() => update({ currency: c })}
            className={cn(
              'px-1.5 py-1 rounded text-[10px] font-semibold transition-all md:px-2.5 md:text-[11px]',
              settings.currency === c
                ? 'bg-primary text-primary-foreground shadow-sm'
                : 'text-muted-foreground hover:text-foreground'
            )}
          >
            {c}
          </button>
        ))}
      </div>

      {/* ── Language Toggle ── */}
      <div className="flex items-center gap-0.5 bg-muted rounded-md p-0.5">
        <button
          onClick={() => update({ language: 'ar' })}
          className={cn(
            'px-1.5 py-1 rounded text-[10px] font-semibold transition-all md:px-2.5 md:text-[11px]',
            settings.language === 'ar'
              ? 'bg-primary text-primary-foreground shadow-sm'
              : 'text-muted-foreground hover:text-foreground'
          )}
        >
          <span className="md:hidden">AR</span>
          <span className="hidden md:inline">{t('arabic')}</span>
        </button>
        <button
          onClick={() => update({ language: 'en' })}
          className={cn(
            'px-1.5 py-1 rounded text-[10px] font-semibold transition-all md:px-2.5 md:text-[11px]',
            settings.language === 'en'
              ? 'bg-primary text-primary-foreground shadow-sm'
              : 'text-muted-foreground hover:text-foreground'
          )}
        >
          <span className="md:hidden">EN</span>
          <span className="hidden md:inline">{t('english')}</span>
        </button>
      </div>

      {/* ── Activity ── */}
      <ActivityCenter />

      {/* ── Spacer ── */}
      <div className="flex-1" />

      {/* ── Sync indicator ── */}
      <div className="hidden md:flex items-center gap-1">
        <TrendingUp className="h-3.5 w-3.5 text-muted-foreground" />
        <span className="text-[11px] text-emerald-500 font-medium">{t('synced')}</span>
      </div>

      {/* ── User info ── */}
      {merchantProfile && (
        <button
          onClick={() => setProfileOpen(true)}
          className="hidden md:flex flex-col items-end cursor-pointer hover:opacity-80 transition-opacity"
        >
          <span className="text-[11px] font-semibold text-foreground leading-tight">{merchantProfile.display_name}</span>
          <span className="text-[9px] text-muted-foreground leading-tight">{t('clientId')}: {merchantProfile.merchant_code ?? merchantProfile.merchant_id.slice(0, 5)}</span>
        </button>
      )}

      {/* ── Sign out ── */}
      <button
        onClick={logout}
        className="hidden md:block px-2.5 py-1 rounded-md bg-muted hover:bg-muted/80 text-[11px] font-semibold text-muted-foreground transition-all"
      >
        {t('signOut')}
      </button>

      <UserProfileModal open={profileOpen} onClose={() => setProfileOpen(false)} />
    </header>
  );
}

/**
 * ActivityCenter — top-nav notification dropdown
 *
 * Features:
 *  • Real-time badge via Supabase channel (live green dot)
 *  • Category filter tabs with per-category unread counts
 *  • Smart grouping (dedup + 30-min collapse)
 *  • Per-notification icon based on kind
 *  • Inline action buttons:
 *      - approval   → Approve / Reject deal or settlement
 *      - invite     → Accept / Decline invite
 *      - agreement  → Approve / Reject profit-share agreement
 *      - profile    → Approve / Reject admin user (with reason prompt)
 *  • Empty state per category
 *  • Click-row navigates with deep-link + marks read
 *  • RTL-aware layout
 */

import { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Bell, CheckCheck, Check, X, MessageSquare, ShoppingBag,
  Users, Shield, Settings2, FileText, RefreshCw, ChevronRight,
  Wifi, WifiOff,
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Textarea } from '@/components/ui/textarea';
import { cn } from '@/lib/utils';
import { useT } from '@/lib/i18n';
import {
  useMarkAllRead, useMarkCategoryRead,
  useMarkNotificationRead, useMarkNotificationsRead,
  useNotifications,
} from '@/hooks/useNotifications';
import { smartGroupNotifications, type SmartNotification } from '@/lib/notification-grouping';
import { handleNotificationClick } from '@/lib/notification-router';
import { normalizeNotificationCategory, type NotificationCategoryGroup } from '@/types/notifications';
import { useUpdateAgreementStatus } from '@/hooks/useProfitShareAgreements';
import {
  useInlineDealApprove, useInlineDealReject,
  useInlineInviteAccept, useInlineInviteReject,
  useInlineProfileApprove, useInlineProfileReject,
  useInlineSettlementApprove, useInlineSettlementReject,
  resolveNotificationActionKind,
} from '@/hooks/useNotificationActions';
import { toast } from 'sonner';

// ─── Category config ────────────────────────────────────────────────────────

interface CatConfig {
  id: NotificationCategoryGroup;
  labelKey: string;
  Icon: React.ElementType;
  color: string;
}

const CAT_CONFIG: CatConfig[] = [
  { id: 'all',      labelKey: 'notifCatAll',      Icon: Bell,         color: 'text-muted-foreground' },
  { id: 'approval', labelKey: 'notifCatApproval',  Icon: Shield,       color: 'text-amber-500'        },
  { id: 'deal',     labelKey: 'notifCatDeal',      Icon: FileText,     color: 'text-blue-500'         },
  { id: 'order',    labelKey: 'notifCatOrder',     Icon: ShoppingBag,  color: 'text-emerald-500'      },
  { id: 'invite',   labelKey: 'notifCatInvite',    Icon: Users,        color: 'text-violet-500'       },
  { id: 'message',  labelKey: 'notifCatMessage',   Icon: MessageSquare,color: 'text-sky-500'          },
  { id: 'system',   labelKey: 'notifCatSystem',    Icon: Settings2,    color: 'text-muted-foreground' },
];

function iconForCategory(cat: string): React.ElementType {
  switch (normalizeNotificationCategory(cat)) {
    case 'approval':  return Shield;
    case 'deal':      return FileText;
    case 'order':     return ShoppingBag;
    case 'invite':    return Users;
    case 'message':   return MessageSquare;
    default:          return Bell;
  }
}

function colorForCategory(cat: string): string {
  switch (normalizeNotificationCategory(cat)) {
    case 'approval':  return 'text-amber-500';
    case 'deal':      return 'text-blue-500';
    case 'order':     return 'text-emerald-500';
    case 'invite':    return 'text-violet-500';
    case 'message':   return 'text-sky-500';
    default:          return 'text-muted-foreground';
  }
}

// ─── Inline action area ─────────────────────────────────────────────────────

interface ActionAreaProps {
  n: SmartNotification;
  onDone: (ids: string[]) => void;
  t: ReturnType<typeof useT>;
}

function InlineActionArea({ n, onDone, t }: ActionAreaProps) {
  const kind = resolveNotificationActionKind(n.category, n.target.entityType);

  // Agreement action (handled here too)
  const isAgreement = n.category === 'agreement';
  const updateAgreement = useUpdateAgreementStatus();

  // Deal
  const dealApprove  = useInlineDealApprove();
  const dealReject   = useInlineDealReject();

  // Invite
  const inviteAccept = useInlineInviteAccept();
  const inviteReject = useInlineInviteReject();

  // Profile (admin)
  const profileApprove = useInlineProfileApprove();
  const profileReject  = useInlineProfileReject();
  const [showRejectReason, setShowRejectReason] = useState(false);
  const [rejectReason, setRejectReason]         = useState('');

  // Settlement
  const settlApprove = useInlineSettlementApprove();
  const settlReject  = useInlineSettlementReject();

  const entityId = n.target.entityId ?? null;

  if (!entityId && !isAgreement) return null;

  // ── Busy state ────────────────────────────────────────────────────────────
  const busy =
    dealApprove.isPending || dealReject.isPending ||
    inviteAccept.isPending || inviteReject.isPending ||
    profileApprove.isPending || profileReject.isPending ||
    settlApprove.isPending || settlReject.isPending ||
    updateAgreement.isPending;

  const ids = n.groupIds?.length ? n.groupIds : [n.id];

  // ── Agreement ─────────────────────────────────────────────────────────────
  if (isAgreement) {
    const agreementId = (n.target as any).targetEntityId ?? entityId;
    if (!agreementId) return null;
    return (
      <div className="flex gap-1.5 mt-2" onClick={(e) => e.stopPropagation()}>
        <Button size="sm" variant="default" className="h-6 text-[10px] px-2.5 gap-1" disabled={busy}
          onClick={async () => {
            try {
              await updateAgreement.mutateAsync({ agreementId, status: 'approved' });
              onDone(ids);
              toast.success(t('agreementApprovedSuccess'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <Check className="h-3 w-3" />{t('approve')}
        </Button>
        <Button size="sm" variant="destructive" className="h-6 text-[10px] px-2.5 gap-1" disabled={busy}
          onClick={async () => {
            try {
              await updateAgreement.mutateAsync({ agreementId, status: 'rejected' });
              onDone(ids);
              toast.success(t('agreementRejectedSuccess'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <X className="h-3 w-3" />{t('reject')}
        </Button>
      </div>
    );
  }

  // ── Deal approval ─────────────────────────────────────────────────────────
  if (kind === 'deal_approval') {
    return (
      <div className="flex gap-1.5 mt-2" onClick={(e) => e.stopPropagation()}>
        <Button size="sm" variant="default" className="h-6 text-[10px] px-2.5 gap-1 bg-emerald-600 hover:bg-emerald-700" disabled={busy}
          onClick={async () => {
            try {
              await dealApprove.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('tradeApproved'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <Check className="h-3 w-3" />{t('approve')}
        </Button>
        <Button size="sm" variant="destructive" className="h-6 text-[10px] px-2.5 gap-1" disabled={busy}
          onClick={async () => {
            try {
              await dealReject.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('tradeRejected'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <X className="h-3 w-3" />{t('reject')}
        </Button>
        <span className="ml-auto text-[9px] text-amber-500 font-semibold self-center">{t('actionNeeded')}</span>
      </div>
    );
  }

  // ── Invite ────────────────────────────────────────────────────────────────
  if (kind === 'invite_incoming') {
    return (
      <div className="flex gap-1.5 mt-2" onClick={(e) => e.stopPropagation()}>
        <Button size="sm" variant="default" className="h-6 text-[10px] px-2.5 gap-1 bg-violet-600 hover:bg-violet-700" disabled={busy}
          onClick={async () => {
            try {
              await inviteAccept.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('inviteAccepted'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <Check className="h-3 w-3" />{t('accept')}
        </Button>
        <Button size="sm" variant="outline" className="h-6 text-[10px] px-2.5 gap-1 border-destructive text-destructive hover:bg-destructive/10" disabled={busy}
          onClick={async () => {
            try {
              await inviteReject.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('inviteRejected'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <X className="h-3 w-3" />{t('decline')}
        </Button>
      </div>
    );
  }

  // ── Profile approval (admin) ──────────────────────────────────────────────
  if (kind === 'profile_approval') {
    if (showRejectReason) {
      return (
        <div className="mt-2 flex flex-col gap-1.5" onClick={(e) => e.stopPropagation()}>
          <Textarea
            placeholder={t('rejectReasonPlaceholder')}
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            className="text-xs min-h-[56px] resize-none"
          />
          <div className="flex gap-1.5">
            <Button size="sm" variant="destructive" className="h-6 text-[10px] px-2.5" disabled={busy || !rejectReason.trim()}
              onClick={async () => {
                try {
                  await profileReject.mutateAsync({ profileUserId: entityId!, reason: rejectReason.trim() });
                  onDone(ids);
                  toast.success(t('rejected'));
                } catch (e: any) { toast.error(e.message); }
              }}>
              {t('confirmReject')}
            </Button>
            <Button size="sm" variant="ghost" className="h-6 text-[10px]" onClick={() => { setShowRejectReason(false); setRejectReason(''); }}>
              {t('cancel')}
            </Button>
          </div>
        </div>
      );
    }
    return (
      <div className="flex gap-1.5 mt-2" onClick={(e) => e.stopPropagation()}>
        <Button size="sm" variant="default" className="h-6 text-[10px] px-2.5 gap-1 bg-emerald-600 hover:bg-emerald-700" disabled={busy}
          onClick={async () => {
            try {
              await profileApprove.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('tradeApproved'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <Check className="h-3 w-3" />{t('approve')}
        </Button>
        <Button size="sm" variant="outline" className="h-6 text-[10px] px-2.5 gap-1 border-destructive text-destructive hover:bg-destructive/10" disabled={busy}
          onClick={() => setShowRejectReason(true)}>
          <X className="h-3 w-3" />{t('reject')}
        </Button>
      </div>
    );
  }

  // ── Settlement ────────────────────────────────────────────────────────────
  if (kind === 'settlement_approval') {
    return (
      <div className="flex gap-1.5 mt-2" onClick={(e) => e.stopPropagation()}>
        <Button size="sm" variant="default" className="h-6 text-[10px] px-2.5 gap-1 bg-emerald-600 hover:bg-emerald-700" disabled={busy}
          onClick={async () => {
            try {
              await settlApprove.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('settlementApproved'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <Check className="h-3 w-3" />{t('approve')}
        </Button>
        <Button size="sm" variant="destructive" className="h-6 text-[10px] px-2.5 gap-1" disabled={busy}
          onClick={async () => {
            try {
              await settlReject.mutateAsync(entityId!);
              onDone(ids);
              toast.success(t('rejectedNoMutation'));
            } catch (e: any) { toast.error(e.message); }
          }}>
          <X className="h-3 w-3" />{t('reject')}
        </Button>
        <span className="ml-auto text-[9px] text-amber-500 font-semibold self-center">{t('actionNeeded')}</span>
      </div>
    );
  }

  return null;
}

// ─── Notification row ────────────────────────────────────────────────────────

interface RowProps {
  n: SmartNotification;
  onNavigate: (n: SmartNotification) => void;
  onActionDone: (ids: string[]) => void;
  t: ReturnType<typeof useT>;
}

function NotificationRow({ n, onNavigate, onActionDone, t }: RowProps) {
  const Icon  = iconForCategory(n.category);
  const color = colorForCategory(n.category);
  const isUnread = !n.read_at;

  const kind = resolveNotificationActionKind(n.category, n.target.entityType);
  const isAgreement = n.category === 'agreement';
  const hasAction = (isUnread && (kind !== null || isAgreement));

  return (
    <div
      role="button"
      tabIndex={0}
      onClick={() => onNavigate(n)}
      onKeyDown={(e) => e.key === 'Enter' && onNavigate(n)}
      className={cn(
        'group w-full text-left px-3 py-2.5 border-b last:border-b-0 cursor-pointer',
        'hover:bg-muted/50 transition-colors',
        isUnread && 'bg-primary/[0.04]',
      )}
    >
      <div className="flex items-start gap-2.5">
        {/* Category icon */}
        <div className={cn('mt-0.5 shrink-0 rounded-full p-1.5',
          isUnread ? 'bg-primary/10' : 'bg-muted')}>
          <Icon className={cn('h-3.5 w-3.5', isUnread ? color : 'text-muted-foreground')} />
        </div>

        <div className="flex-1 min-w-0">
          {/* Title row */}
          <div className="flex items-baseline gap-1 justify-between">
            <span className={cn('text-xs font-semibold truncate', isUnread ? 'text-foreground' : 'text-muted-foreground')}>
              {n.title}
              {n.groupCount && n.groupCount > 1 && (
                <span className="ml-1 text-[10px] font-normal text-muted-foreground">×{n.groupCount}</span>
              )}
            </span>
            <span className="text-[10px] text-muted-foreground whitespace-nowrap shrink-0">
              {formatDistanceToNow(new Date(n.created_at), { addSuffix: true })}
            </span>
          </div>

          {/* Body */}
          {n.body && (
            <p className="text-[11px] text-muted-foreground mt-0.5 line-clamp-2">{n.body}</p>
          )}

          {/* Inline action buttons */}
          {hasAction && (
            <InlineActionArea n={n} onDone={onActionDone} t={t} />
          )}

          {/* Navigate hint for non-action items */}
          {!hasAction && (
            <div className="flex items-center gap-1 mt-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <ChevronRight className="h-3 w-3 text-muted-foreground" />
              <span className="text-[10px] text-muted-foreground">{t('viewDetails')}</span>
            </div>
          )}
        </div>

        {/* Unread dot */}
        {isUnread && (
          <div className="mt-1.5 h-1.5 w-1.5 rounded-full bg-primary shrink-0" />
        )}
      </div>
    </div>
  );
}

// ─── Empty state ─────────────────────────────────────────────────────────────

function EmptyState({ category, t }: { category: NotificationCategoryGroup; t: ReturnType<typeof useT> }) {
  const messages: Record<NotificationCategoryGroup, string> = {
    all:      t('noNotifications'),
    approval: t('noApprovals'),
    deal:     t('noNotifications'),
    order:    t('noNotifications'),
    invite:   t('acceptInviteToStart'),
    message:  t('noNotifications'),
    system:   t('noNotifications'),
