export function AdminNotificationSender() {
  const { toast } = useToast();
  const { data: users } = useAdminUsers();
  const [mode, setMode] = useState<'individual' | 'broadcast'>('individual');
  const [targetUserId, setTargetUserId] = useState('');
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [category, setCategory] = useState('system');
  const [sending, setSending] = useState(false);
  const [userSearch, setUserSearch] = useState('');

  const filteredUsers = (users ?? []).filter(u => {
    if (!userSearch.trim()) return true;
    const q = userSearch.toLowerCase();
    return u.email.toLowerCase().includes(q) || u.display_name?.toLowerCase().includes(q) || u.user_id.includes(q);
  });

  const selectedUser = users?.find(u => u.user_id === targetUserId);

  const handleSend = async () => {
    if (!title.trim()) return;
    setSending(true);
    try {
      if (mode === 'broadcast') {
        const { data, error } = await supabase.rpc('admin_broadcast_notification' as any, {
          _title: title.trim(),
          _body: body.trim() || null,
          _category: category,
        });
        if (error) throw error;
        toast({ title: 'Broadcast sent', description: `Notification sent to ${data} users.` });
      } else {
        if (!targetUserId) {
          toast({ title: 'Select a user', variant: 'destructive' });
          setSending(false);
          return;
        }
        const { error } = await supabase.from('notifications').insert({
          user_id: targetUserId,
          title: title.trim(),
          body: body.trim() || null,
          category,
        });
        if (error) throw error;

        // Audit log
        await supabase.from('admin_audit_logs').insert({
          admin_user_id: (await supabase.auth.getUser()).data.user!.id,
          action: 'send_notification',
          target_type: 'notification',
          target_id: targetUserId,
          details: { title: title.trim(), body: body.trim(), category, target_user_id: targetUserId },
        });

        toast({ title: 'Notification sent', description: `Sent to ${selectedUser?.email ?? targetUserId.slice(0, 8)}` });
      }
      setTitle('');
      setBody('');
    } catch (err: any) {
      toast({ title: 'Error', description: err.message, variant: 'destructive' });
    } finally {
      setSending(false);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        <h2 className="text-lg font-semibold text-foreground">Send Notifications</h2>
      </div>

      <div className="flex gap-2">
        <Button
          variant={mode === 'individual' ? 'default' : 'outline'}
          size="sm"
          className="text-xs gap-1"
          onClick={() => setMode('individual')}
        >
          <User className="h-3 w-3" /> Individual
        </Button>
        <Button
          variant={mode === 'broadcast' ? 'default' : 'outline'}
          size="sm"
          className="text-xs gap-1"
          onClick={() => setMode('broadcast')}
        >
          <Users className="h-3 w-3" /> Broadcast All
        </Button>
      </div>

      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-sm flex items-center gap-2">
            {mode === 'broadcast' ? (
              <><Megaphone className="h-4 w-4 text-warning" /> Broadcast to All Approved Users</>
            ) : (
              <><Send className="h-4 w-4 text-primary" /> Send to Individual User</>
            )}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {mode === 'individual' && (
            <div className="space-y-2">
              <Label className="text-xs">Recipient</Label>
              {selectedUser ? (
                <div className="flex items-center gap-2">
                  <Badge variant="secondary" className="text-xs">
                    {selectedUser.display_name ?? selectedUser.email}
                  </Badge>
                  <Button variant="ghost" size="sm" className="h-6 text-[10px]" onClick={() => setTargetUserId('')}>
                    Change
                  </Button>
                </div>
              ) : (
                <div className="space-y-1">
                  <Input
                    placeholder="Search users…"
                    value={userSearch}
                    onChange={e => setUserSearch(e.target.value)}
                    className="h-8 text-sm"
                  />
                  {userSearch.trim() && (
                    <div className="border rounded-md max-h-32 overflow-y-auto">
                      {filteredUsers.slice(0, 10).map(u => (
                        <button
                          key={u.user_id}
                          className="w-full text-left px-3 py-1.5 text-xs hover:bg-muted/50 flex justify-between"
                          onClick={() => { setTargetUserId(u.user_id); setUserSearch(''); }}
                        >
                          <span className="font-medium">{u.display_name ?? u.email}</span>
                          <span className="text-muted-foreground">{u.email}</span>
                        </button>
                      ))}
                      {filteredUsers.length === 0 && (
                        <p className="text-xs text-muted-foreground p-2 text-center">No users found</p>
                      )}
                    </div>
                  )}
                </div>
              )}
            </div>
          )}

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <div>
              <Label className="text-xs">Category</Label>
              <Select value={category} onValueChange={setCategory}>
                <SelectTrigger className="h-8 text-sm">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {CATEGORIES.map(c => (
                    <SelectItem key={c.value} value={c.value} className="text-xs">
                      {c.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs">Title *</Label>
              <Input value={title} onChange={e => setTitle(e.target.value)} className="h-8 text-sm" placeholder="Notification title" />
            </div>
          </div>

          <div>
            <Label className="text-xs">Body (optional)</Label>
            <Textarea value={body} onChange={e => setBody(e.target.value)} className="text-sm min-h-[60px]" placeholder="Additional details…" />
          </div>

          <div className="flex items-center justify-between pt-1">
            {mode === 'broadcast' && (
              <p className="text-[10px] text-warning">⚠ This will notify all approved users</p>
            )}
            <Button
              size="sm"
              className="ml-auto gap-1"
              onClick={handleSend}
              disabled={sending || !title.trim() || (mode === 'individual' && !targetUserId)}
            >
              {sending ? <Loader2 className="h-3 w-3 animate-spin" /> : mode === 'broadcast' ? <Megaphone className="h-3 w-3" /> : <Send className="h-3 w-3" />}
              {mode === 'broadcast' ? 'Broadcast' : 'Send'}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTheme } from '@/lib/theme-context';
import { useT } from '@/lib/i18n';
import { computeFIFO, fmtDate, fmtP, fmtQ, fmtU, inRange, rangeLabel, type TrackerState } from '@/lib/tracker-helpers';
import { buildDealRowModel, parseDealMeta } from '@/features/orders/utils/dealRowModel';
import { getWorkspaceDealPerspective, isDealVisibleInWorkspace } from '@/features/orders/utils/workspaceDealScope';
import '@/styles/tracker.css';

interface Props {
  userId: string;
  merchantId?: string | null;
  trackerState: TrackerState | null;
}

export function AdminOrdersMirror({ userId, merchantId, trackerState }: Props) {
  const { settings } = useTheme();
  const t = useT();
  const [activeTab, setActiveTab] = useState<'my' | 'incoming' | 'outgoing'>('my');
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));

  const state = trackerState;
  const derived = useMemo(() => state ? computeFIFO(state.batches, state.trades) : null, [state]);

  const { data } = useQuery({
    queryKey: ['admin-orders-mirror', userId, merchantId],
    enabled: !!merchantId,
    queryFn: async () => {
      const relsRes = await supabase
        .from('merchant_relationships')
        .select('*')
        .eq('status', 'active')
        .or(`merchant_a_id.eq.${merchantId},merchant_b_id.eq.${merchantId}`);
      const relIds = (relsRes.data || []).map(r => r.id);
      const [dealsRes, profilesRes] = await Promise.all([
        relIds.length > 0
          ? supabase.from('merchant_deals').select('*').in('relationship_id', relIds).order('created_at', { ascending: false })
          : Promise.resolve({ data: [], error: null } as any),
        supabase.from('merchant_profiles').select('merchant_id, user_id, display_name, nickname, merchant_code'),
      ]);

      if (relsRes.error) throw relsRes.error;
      if (dealsRes.error) throw dealsRes.error;
      if (profilesRes.error) throw profilesRes.error;

      const profileMap = new Map((profilesRes.data || []).map(p => [p.merchant_id, p]));
      const enrichedRels = (relsRes.data || []).map(r => {
        const cpId = r.merchant_a_id === merchantId ? r.merchant_b_id : r.merchant_a_id;
        const cp = profileMap.get(cpId);
        const aProfile = profileMap.get(r.merchant_a_id);
        const bProfile = profileMap.get(r.merchant_b_id);
        return {
          ...r,
          counterparty: { display_name: cp?.display_name || cpId, nickname: cp?.nickname || '' },
          counterparty_name: cp?.display_name || cpId,
          merchant_a_user_id: aProfile?.user_id || null,
          merchant_b_user_id: bProfile?.user_id || null,
        } as any;
      });

      const workspaceRelIds = new Set((relsRes.data || []).map(r => r.id));
      const workspaceDeals = (dealsRes.data || []).filter(d => isDealVisibleInWorkspace({
        deal: d,
        workspaceMerchantId: merchantId!,
        workspaceRelationshipIds: workspaceRelIds,
      }));

      const enrichedDeals = workspaceDeals.map(d => {
        const rel = enrichedRels.find((r: any) => r.id === d.relationship_id);
        return { ...d, counterparty_name: rel?.counterparty_name || '—' } as any;
      });

      return { relationships: enrichedRels, allMerchantDeals: enrichedDeals };
    },
  });

  const relationships = data?.relationships ?? [];
  const allMerchantDeals = data?.allMerchantDeals ?? [];
  const allTrades = useMemo(() => state ? [...state.trades].sort((a, b) => b.ts - a.ts) : [], [state]);

  const cancelledDealIds = useMemo(() => new Set(
    allMerchantDeals.filter((d: any) => d.status === 'cancelled' || (d.status as string) === 'voided').map((d: any) => d.id)
  ), [allMerchantDeals]);
  const cancelledLocalTradeIds = useMemo(() => new Set(
    allMerchantDeals
      .filter((d: any) => d.status === 'cancelled' || (d.status as string) === 'voided')
      .map((d: any) => parseDealMeta(d.notes).local_trade)
      .filter(Boolean)
  ), [allMerchantDeals]);

  const visibleTrades = useMemo(() => allTrades.filter((tr) => {
    const range = state?.range || settings.range;
    if (!inRange(tr.ts, range)) return false;
    if (tr.voided || tr.approvalStatus === 'cancelled') return false;
    if (tr.linkedDealId && cancelledDealIds.has(tr.linkedDealId)) return false;
    if (cancelledLocalTradeIds.has(tr.id)) return false;
    if ((tr.approvalStatus === 'pending_approval' || tr.approvalStatus === 'approved' || tr.approvalStatus === 'rejected') && !tr.linkedDealId) {
      const matchedServerDeal = allMerchantDeals.some((d: any) => parseDealMeta(d.notes).local_trade === tr.id && d.created_by === userId && d.status !== 'cancelled' && (d.status as string) !== 'voided');
      if (!matchedServerDeal) return false;
    }
    return true;
  }), [allTrades, state?.range, settings.range, cancelledDealIds, cancelledLocalTradeIds, allMerchantDeals, userId]);

  const availableMonths = useMemo(() => {
    const months = new Set<string>();
    const curMonthKey = new Date().toISOString().slice(0, 7);
    months.add(curMonthKey);
    visibleTrades.forEach(tr => {
      const d = new Date(tr.ts);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      months.add(key);
    });
    allMerchantDeals.forEach((d: any) => {
      const date = new Date(d.created_at);
      const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      months.add(key);
    });
    return Array.from(months).sort().reverse();
  }, [visibleTrades, allMerchantDeals]);

  const subFilteredTrades = useMemo(() => {
    if (selectedMonth === 'all') return visibleTrades;
    return visibleTrades.filter(tr => {
      const d = new Date(tr.ts);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      return key === selectedMonth;
    });
  }, [visibleTrades, selectedMonth]);

  const relationshipById = useMemo(() => new Map(
    relationships.map((r: any) => [r.id, { merchant_a_id: r.merchant_a_id, merchant_b_id: r.merchant_b_id }]),
  ), [relationships]);
  const merchantUserByMerchantId = useMemo(() => {
    const m = new Map<string, string>();
    for (const rel of relationships as any[]) {
      if (rel.merchant_a_id && rel.merchant_a_user_id) m.set(rel.merchant_a_id, rel.merchant_a_user_id);
      if (rel.merchant_b_id && rel.merchant_b_user_id) m.set(rel.merchant_b_id, rel.merchant_b_user_id);
    }
    return m;
  }, [relationships]);

  const workspaceScopedDeals = useMemo(() => allMerchantDeals.filter((d: any) => d.status !== 'cancelled' && (d.status as string) !== 'voided'), [allMerchantDeals]);
  const partnerMerchantDeals = useMemo(
    () => workspaceScopedDeals.filter((d: any) => getWorkspaceDealPerspective({
      deal: d,
      workspaceMerchantId: merchantId || '',
      relationshipById,
      merchantUserByMerchantId,
    }) === 'incoming'),
    [workspaceScopedDeals, merchantId, relationshipById, merchantUserByMerchantId],
  );
  const creatorMerchantDeals = useMemo(
    () => workspaceScopedDeals.filter((d: any) => getWorkspaceDealPerspective({
      deal: d,
      workspaceMerchantId: merchantId || '',
      relationshipById,
      merchantUserByMerchantId,
    }) === 'outgoing'),
    [workspaceScopedDeals, merchantId, relationshipById, merchantUserByMerchantId],
  );

  const subFilteredInDeals = useMemo(() => {
    if (selectedMonth === 'all') return partnerMerchantDeals;
    return partnerMerchantDeals.filter((d: any) => {
      const date = new Date(d.created_at);
      const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      return key === selectedMonth;
    });
  }, [partnerMerchantDeals, selectedMonth]);

  const subFilteredOutDeals = useMemo(() => {
    if (selectedMonth === 'all') return creatorMerchantDeals;
    return creatorMerchantDeals.filter((d: any) => {
      const date = new Date(d.created_at);
      const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
      return key === selectedMonth;
    });
  }, [creatorMerchantDeals, selectedMonth]);

  const resolveDealAvgBuy = (deal: any, normalizedMeta?: Record<string, string>): number => {
    const meta = normalizedMeta ?? parseDealMeta(deal.notes);
    const metaAvg = Number(meta.avg_buy) || 0;
    if (metaAvg > 0) return metaAvg;
    const localTradeId = meta.local_trade;
    if (localTradeId && derived) {
      const c = derived.tradeCalc.get(localTradeId);
      if (c?.ok) return c.avgBuyQAR;
      const localTrade = state.trades.find(t => t.id === localTradeId);
      if (localTrade?.manualBuyPrice && localTrade.manualBuyPrice > 0) return localTrade.manualBuyPrice;
    }
    return 0;
  };

  const myKpi = useMemo(() => {
    let qty = 0, vol = 0, net = 0;
    for (const tr of subFilteredTrades.filter(tr => !tr.voided)) {
      const c = derived?.tradeCalc.get(tr.id);
      qty += tr.amountUSDT;
      vol += tr.amountUSDT * tr.sellPriceQAR;
      if (c?.ok) net += c.netQAR;
    }
    return { count: subFilteredTrades.length, qty, vol, net };
  }, [subFilteredTrades, derived]);

  const outKpi = useMemo(() => {
    let vol = 0, net = 0;
    for (const deal of subFilteredOutDeals) {
      const row = buildDealRowModel({ deal, perspective: 'outgoing', locale: t.isRTL ? 'ar' : 'en', resolveAvgBuy: resolveDealAvgBuy });
      vol += row.volume;
      net += row.myNet ?? 0;
    }
    return { count: subFilteredOutDeals.length, vol, net };
  }, [subFilteredOutDeals, t.isRTL]);
  const inKpi = useMemo(() => {
    let vol = 0, net = 0;
    for (const deal of subFilteredInDeals) {
      const row = buildDealRowModel({ deal, perspective: 'incoming', locale: t.isRTL ? 'ar' : 'en', resolveAvgBuy: resolveDealAvgBuy });
      vol += row.volume;
      net += row.myNet ?? 0;
    }
    return { count: subFilteredInDeals.length, vol, net };
  }, [subFilteredInDeals, t.isRTL]);

  const renderKpiBar = (kpi: { count: number; qty?: number; vol: number; net: number }) => (
    <div style={{ display: 'flex', gap: 16, padding: '8px 12px', background: 'color-mix(in srgb, var(--brand) 5%, transparent)', borderRadius: 6, marginBottom: 10, flexWrap: 'wrap' }}>
      <div><div style={{ fontSize: 8, color: 'var(--muted)', fontWeight: 700, letterSpacing: '.5px' }}>{t('count').toUpperCase()}</div><div className="mono" style={{ fontSize: 13, fontWeight: 700 }}>{kpi.count}</div></div>
      {kpi.qty != null && <div><div style={{ fontSize: 8, color: 'var(--muted)', fontWeight: 700, letterSpacing: '.5px' }}>USDT {t('qty').toUpperCase()}</div><div className="mono" style={{ fontSize: 13, fontWeight: 700 }}>{fmtU(kpi.qty)}</div></div>}
      <div><div style={{ fontSize: 8, color: 'var(--muted)', fontWeight: 700, letterSpacing: '.5px' }}>{t('volume').toUpperCase()}</div><div className="mono" style={{ fontSize: 13, fontWeight: 700 }}>{fmtQ(kpi.vol)}</div></div>
      <div><div style={{ fontSize: 8, color: 'var(--muted)', fontWeight: 700, letterSpacing: '.5px' }}>{t('net').toUpperCase()} P&L</div><div className="mono" style={{ fontSize: 13, fontWeight: 700, color: kpi.net >= 0 ? 'var(--good)' : 'var(--bad)' }}>{kpi.net >= 0 ? '+' : ''}{fmtQ(kpi.net)}</div></div>
    </div>
  );

  if (!state || !derived) {
    return <div className="tracker-root" style={{ padding: 12 }}><div className="empty"><div className="empty-t">No orders data.</div></div></div>;
  }

  const rLabel = rangeLabel(state.range || settings.range);

  const renderMonthSelector = () => (
    <div className="orders-tab-bar" style={{ marginBottom: 8, background: 'transparent', border: 'none', padding: 0, gap: 8, boxShadow: 'none' }}>
      <button onClick={() => setSelectedMonth('all')} className={`orders-tab-btn ${selectedMonth === 'all' ? 'active' : ''}`} style={{ fontSize: 10, padding: '5px 12px', borderRadius: 8 }}>
        {t('allMonths')}
      </button>
      {availableMonths.map(m => {
        const [y, mm] = m.split('-');
        const label = new Date(parseInt(y), parseInt(mm) - 1).toLocaleString(t.lang === 'ar' ? 'ar-EG' : 'en-US', { month: 'short', year: '2-digit' });
        return (
          <button key={m} onClick={() => setSelectedMonth(m)} className={`orders-tab-btn ${selectedMonth === m ? 'active' : ''}`} style={{ fontSize: 10, padding: '5px 12px', borderRadius: 8 }}>
            {label}
          </button>
        );
      })}
    </div>
  );

  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'} style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: '100%' }}>
      <div style={{ display: 'flex', gap: 0, borderBottom: '1px solid var(--line)', marginBottom: 2 }}>
        {(['my', 'incoming', 'outgoing'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            style={{
              padding: '9px 18px', fontSize: 11, fontWeight: activeTab === tab ? 700 : 500,
              color: activeTab === tab ? 'var(--brand)' : 'var(--muted)',
              borderBottom: activeTab === tab ? '2px solid var(--brand)' : '2px solid transparent',
              background: 'transparent', border: 'none', borderBottomStyle: 'solid', cursor: 'pointer', transition: 'all 0.15s', letterSpacing: '.2px',
            }}
          >
            {tab === 'my' ? `👤 ${t('myOrders')}` : tab === 'incoming' ? `📥 ${t('incomingOrders')}` : `📤 ${t('outgoingOrders')}`}
          </button>
        ))}
      </div>

      {renderMonthSelector()}

      {activeTab === 'my' && (
        <>
          {renderKpiBar({ count: myKpi.count, qty: myKpi.qty, vol: myKpi.vol, net: myKpi.net })}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8, gap: 8 }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 800 }}>{t('trades')}</div>
              <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('fifoCostBasisMargin')}</div>
            </div>
            <span className="pill">{rLabel}</span>
          </div>
          {subFilteredTrades.length === 0 ? <div className="empty"><div className="empty-t">{t('noTradesYet')}</div></div> : (
            <div className="tableWrap ledgerWrap"><table><thead><tr>
              <th>{t('date')}</th><th>{t('type')}</th><th>{t('buyer')}</th><th className="r">{t('qty')}</th><th className="r">{t('avgBuy')}</th><th className="r">{t('sell')}</th><th className="r">{t('volume')}</th><th className="r">{t('net')}</th><th>{t('margin')}</th>
            </tr></thead><tbody>
              {subFilteredTrades.map((tr) => {
                const c = derived.tradeCalc.get(tr.id);
                const ok = !!c?.ok;
                const rev = tr.amountUSDT * tr.sellPriceQAR;
                const net = ok ? c!.netQAR : NaN;
                const margin = ok && rev > 0 ? c!.netQAR / rev : NaN;
                const pct = Number.isFinite(margin) ? Math.min(1, Math.abs(margin) / 0.05) : 0;
                const cn = state.customers.find(x => x.id === tr.customerId)?.name || '';
                const isMerchantLinked = !!(tr.agreementFamily || tr.linkedDealId || tr.linkedRelId);
                return (
                  <tr key={tr.id} style={isMerchantLinked ? { background: 'color-mix(in srgb, var(--brand) 4%, transparent)' } : undefined}>
                    <td><span className="mono" style={{ whiteSpace: 'nowrap' }}>{fmtDate(tr.ts)}</span></td>
                    <td style={{ textAlign: 'center', fontSize: 16 }}>{isMerchantLinked ? '🤝' : '👤'}</td>
                    <td>{cn ? <span className="tradeBuyerChip" title={cn} style={{ maxWidth: 130 }}>{cn}</span> : <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span>}</td>
                    <td className="mono r">{fmtU(tr.amountUSDT)}</td>
                    <td className="mono r">{ok ? fmtP(c!.avgBuyQAR) : '—'}</td>
                    <td className="mono r">{fmtP(tr.sellPriceQAR)}</td>
                    <td className="mono r">{fmtQ(rev)}</td>
                    <td className="mono r" style={{ color: Number.isFinite(net) ? (net >= 0 ? 'var(--good)' : 'var(--bad)') : 'var(--muted)', fontWeight: 700 }}>{Number.isFinite(net) ? (net >= 0 ? '+' : '') + fmtQ(net) : '—'}</td>
                    <td><div className={`prog ${Number.isFinite(margin) && margin < 0 ? 'neg' : ''}`} style={{ maxWidth: 90 }}><span style={{ width: `${(pct * 100).toFixed(0)}%` }} /></div><div className="muted" style={{ fontSize: 9, marginTop: 2 }}>{Number.isFinite(margin) ? `${(margin * 100).toFixed(2)}% ${t('marginLabel')}` : '—'}</div></td>
                  </tr>
                );
              })}
            </tbody></table></div>
          )}
        </>
      )}

      {activeTab === 'incoming' && (
        <>
          {renderKpiBar({ count: inKpi.count, vol: inKpi.vol, net: inKpi.net })}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8, gap: 8 }}>
            <div><div style={{ fontSize: 13, fontWeight: 800 }}>📥 {t('incomingOrders')}</div><div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('partnerTradesAwaitingApproval')}</div></div>
            <span className="pill">{subFilteredInDeals.length} {t('trades')}</span>
          </div>
          {subFilteredInDeals.length === 0 ? <div className="empty"><div className="empty-t">{t('noIncomingTrades')}</div></div> : (
            <div className="tableWrap ledgerWrap"><table><thead><tr>
              <th>{t('date')}</th><th>{t('merchant')}</th><th>{t('buyer')}</th><th className="r">{t('qty')}</th><th className="r">{t('avgBuy')}</th><th className="r">{t('sell')}</th><th className="r">{t('volume')}</th><th className="r">{t('net')}</th><th>{t('margin')}</th><th>{t('actions')}</th>
            </tr></thead><tbody>
              {subFilteredInDeals.map((deal: any) => {
                const rel = relationships.find((r: any) => r.id === deal.relationship_id) as any;
                const row = buildDealRowModel({ deal, perspective: 'incoming', locale: t.isRTL ? 'ar' : 'en', resolveAvgBuy: resolveDealAvgBuy });
                const marginPct = row.margin != null ? Math.min(1, Math.abs(row.margin) / 0.05) : 0;
                return <tr key={deal.id}>
                  <td>
                    <span className="mono" style={{ whiteSpace: 'nowrap' }}>{row.dateLabel}</span>
                    <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginTop: 3 }}>
                      <span className={`pill ${deal.status === 'approved' ? 'good' : deal.status === 'pending' ? 'warn' : ''}`} style={{ fontSize: 8 }}>{deal.status}</span>
                      <span className="pill" style={{ fontSize: 8 }}>{row.familyIcon} {row.familyLabel}</span>
                      {row.splitLabel && <span className="pill" style={{ fontSize: 8 }}>{row.splitLabel}</span>}
                    </div>
                  </td>
                  <td>{rel?.counterparty?.display_name ? <span className="tradeBuyerChip" style={{ maxWidth: 130 }}>{rel.counterparty.display_name}</span> : <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span>}</td>
                  <td>{row.buyer ? <span className="tradeBuyerChip" style={{ maxWidth: 130 }}>{row.buyer}</span> : <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span>}</td>
                  <td className="mono r">{fmtU(row.quantity)}</td>
                  <td className="mono r">{row.hasAvgBuy ? fmtP(row.avgBuy) : '—'}</td>
                  <td className="mono r">{row.sellPrice > 0 ? fmtP(row.sellPrice) : '—'}</td>
                  <td className="mono r">{fmtQ(row.volume)}</td>
                  <td className="mono r">
                    {!row.hasAvgBuy ? (
                      <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span>
                    ) : row.myPct != null && row.fullNet != null && row.myNet != null && row.fullNet !== row.myNet ? (
                      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 1 }}>
                        <span style={{ color: 'var(--muted)', fontSize: 9, textDecoration: 'line-through' }}>{row.fullNet >= 0 ? '+' : ''}{fmtQ(row.fullNet)}</span>
                        <span style={{ color: row.myNet >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 700 }}>{row.myNet >= 0 ? '+' : ''}{fmtQ(row.myNet)} <span style={{ fontSize: 8, opacity: 0.7 }}>my cut</span></span>
                      </div>
                    ) : (
                      <span style={{ color: (row.myNet ?? 0) >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 700 }}>{row.myNet != null && row.myNet !== 0 ? `${row.myNet >= 0 ? '+' : ''}${fmtQ(row.myNet)}` : '—'}</span>
                    )}
                  </td>
                  <td><div className={`prog ${row.margin != null && row.margin < 0 ? 'neg' : ''}`} style={{ maxWidth: 90 }}><span style={{ width: `${(marginPct * 100).toFixed(0)}%` }} /></div><div className="muted" style={{ fontSize: 9, marginTop: 2 }}>{row.margin != null && row.margin !== 0 ? `${(row.margin * 100).toFixed(2)}% ${t('marginLabel')}` : '—'}</div></td>
                  <td><span className="pill">{deal.status}</span></td>
                </tr>;
              })}
            </tbody></table></div>
          )}
        </>
      )}

      {activeTab === 'outgoing' && (
        <>
          {renderKpiBar({ count: outKpi.count, vol: outKpi.vol, net: outKpi.net })}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8, gap: 8 }}>
            <div><div style={{ fontSize: 13, fontWeight: 800 }}>📤 {t('outgoingOrders')}</div><div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('yourMerchantLinkedTrades')}</div></div>
            <span className="pill">{subFilteredOutDeals.length} {t('trades')}</span>
          </div>
          {subFilteredOutDeals.length === 0 ? <div className="empty"><div className="empty-t">{t('noOutgoingTrades')}</div></div> : (
            <div className="tableWrap ledgerWrap"><table><thead><tr>
              <th>{t('date')}</th><th>{t('merchant')}</th><th>{t('buyer')}</th><th className="r">{t('qty')}</th><th className="r">{t('avgBuy')}</th><th className="r">{t('sell')}</th><th className="r">{t('volume')}</th><th className="r">{t('net')}</th><th>{t('margin')}</th><th>{t('actions')}</th>
            </tr></thead><tbody>
              {subFilteredOutDeals.map((deal: any) => {
                const rel = relationships.find((r: any) => r.id === deal.relationship_id) as any;
                const row = buildDealRowModel({ deal, perspective: 'outgoing', locale: t.isRTL ? 'ar' : 'en', resolveAvgBuy: resolveDealAvgBuy });
                const marginPct = row.margin != null ? Math.min(1, Math.abs(row.margin) / 0.05) : 0;
                return <tr key={deal.id}><td><span className="mono">{row.dateLabel}</span><div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginTop: 3 }}><span className={`pill ${deal.status === 'approved' ? 'good' : deal.status === 'pending' ? 'warn' : ''}`} style={{ fontSize: 8 }}>{deal.status}</span><span className="pill" style={{ fontSize: 8 }}>{row.familyIcon} {row.familyLabel}</span>{row.splitLabel && <span className="pill" style={{ fontSize: 8 }}>{row.splitLabel}</span>}</div></td><td>{rel?.counterparty?.display_name ? <span className="tradeBuyerChip" style={{ maxWidth: 130 }}>{rel.counterparty.display_name}</span> : <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span>}</td><td>{row.buyer ? <span className="tradeBuyerChip" style={{ maxWidth: 130 }}>{row.buyer}</span> : <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span>}</td><td className="mono r">{fmtU(row.quantity)}</td><td className="mono r">{row.hasAvgBuy ? fmtP(row.avgBuy) : '—'}</td><td className="mono r">{row.sellPrice > 0 ? fmtP(row.sellPrice) : '—'}</td><td className="mono r">{fmtQ(row.volume)}</td><td className="mono r">{!row.hasAvgBuy ? <span style={{ color: 'var(--muted)', fontSize: 9 }}>—</span> : row.myPct != null && row.fullNet != null && row.myNet != null && row.fullNet !== row.myNet ? <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 1 }}><span style={{ color: 'var(--muted)', fontSize: 9, textDecoration: 'line-through' }}>{row.fullNet >= 0 ? '+' : ''}{fmtQ(row.fullNet)}</span><span style={{ color: row.myNet >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 700 }}>{row.myNet >= 0 ? '+' : ''}{fmtQ(row.myNet)} <span style={{ fontSize: 8, opacity: 0.7 }}>my cut</span></span></div> : <span style={{ color: (row.myNet ?? 0) >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 700 }}>{row.myNet != null && row.myNet !== 0 ? `${row.myNet >= 0 ? '+' : ''}${fmtQ(row.myNet)}` : '—'}</span>}</td><td><div className={`prog ${row.margin != null && row.margin < 0 ? 'neg' : ''}`} style={{ maxWidth: 90 }}><span style={{ width: `${(marginPct * 100).toFixed(0)}%` }} /></div><div className="muted" style={{ fontSize: 9, marginTop: 2 }}>{row.margin != null && row.margin !== 0 ? `${(row.margin * 100).toFixed(2)}% ${t('marginLabel')}` : '—'}</div></td><td><span className="pill">{deal.status}</span></td></tr>;
              })}
            </tbody></table></div>
          )}
        </>
      )}
    </div>
  );
}

import { useState, useCallback } from 'react';
import { format } from 'date-fns';
import { ArrowLeft, Edit, Ban, Loader2, Download } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Skeleton } from '@/components/ui/skeleton';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { AdminOrdersMirror } from './AdminOrdersMirror';
import { AdminStockMirror } from './AdminStockMirror';
import DashboardPage from '@/pages/DashboardPage';
import MerchantsPage from '@/pages/MerchantsPage';
import { fmtTotal } from '@/lib/tracker-helpers';
import {
  useAdminUserDeals,
  useAdminUserSettlements,
  useAdminUserProfits,
  useAdminUserTracker,
  useAdminUserProfile,
  useAdminCorrectDeal,
  useAdminVoidDeal,
  useAdminCorrectTracker,
  useAdminVoidTrackerEntity,
} from '../hooks/useAdminWorkspace';

interface Props {
  userId: string;
  onBack: () => void;
}

export function AdminUserWorkspace({ userId, onBack }: Props) {
  const { toast } = useToast();
  const { data: profile, isLoading: profileLoading } = useAdminUserProfile(userId);
  const { data: deals, isLoading: dealsLoading } = useAdminUserDeals(userId);
  const { data: settlements } = useAdminUserSettlements(userId);
  const { data: profits } = useAdminUserProfits(userId);
  const { data: tracker } = useAdminUserTracker(userId);
  const correctDeal = useAdminCorrectDeal();
  const voidDeal = useAdminVoidDeal();
  const correctTracker = useAdminCorrectTracker();
  const voidTrackerEntity = useAdminVoidTrackerEntity();

  const [editDeal, setEditDeal] = useState<any | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editAmount, setEditAmount] = useState('');
  const [editReason, setEditReason] = useState('');
  const [voidTarget, setVoidTarget] = useState<any | null>(null);
  const [voidReason, setVoidReason] = useState('');

  // Tracker edit state
  const [editEntity, setEditEntity] = useState<{ type: 'batch' | 'trade'; data: any } | null>(null);
  const [editEntityQty, setEditEntityQty] = useState('');
  const [editEntityPrice, setEditEntityPrice] = useState('');
  const [editEntityReason, setEditEntityReason] = useState('');
  const [voidEntity, setVoidEntity] = useState<{ type: 'batch' | 'trade'; data: any } | null>(null);
  const [voidEntityReason, setVoidEntityReason] = useState('');

  const trackerState = tracker?.state as any;
  const batches = Array.isArray(trackerState?.batches) ? trackerState.batches : [];
  const trades = Array.isArray(trackerState?.trades) ? trackerState.trades : [];

  const exportCSV = useCallback((filename: string, headers: string[], rows: string[][]) => {
    const csv = [headers.join(','), ...rows.map(r => r.map(c => `"${String(c ?? '').replace(/"/g, '""')}"`).join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = filename; a.click();
    URL.revokeObjectURL(url);
    toast({ title: 'Exported', description: `${filename} downloaded.` });
  }, [toast]);

  const exportDeals = () => {
    if (!deals?.length) return;
    exportCSV(`deals_${userId.slice(0,8)}.csv`,
      ['ID','Title','Amount','Currency','Type','Status','Created','Notes'],
      deals.map((d: any) => [d.id, d.title, d.amount, d.currency, d.deal_type, d.status, d.created_at, d.notes ?? ''])
    );
  };

  const exportSettlements = () => {
    if (!settlements?.length) return;
    exportCSV(`settlements_${userId.slice(0,8)}.csv`,
      ['ID','Deal ID','Amount','Currency','Date','Notes'],
      settlements.map((s: any) => [s.id, s.deal_id, s.amount, s.currency, s.created_at, s.notes ?? ''])
    );
  };

  const exportTrades = () => {
    if (!trades.length) return;
    exportCSV(`trades_${userId.slice(0,8)}.csv`,
      ['ID','Amount USDT','Sell Price QAR','Customer','Date','Voided'],
      trades.map((t: any) => [t.id, t.amountUSDT ?? t.qty ?? '', t.sellPriceQAR ?? t.price ?? '', t.customer ?? '', t.ts ? new Date(t.ts).toISOString() : '', t.voided ? 'yes' : 'no'])
    );
  };

  const exportBatches = () => {
    if (!batches.length) return;
    exportCSV(`batches_${userId.slice(0,8)}.csv`,
      ['ID','Qty','Price','Supplier','Date','Voided'],
      batches.map((b: any) => [b.id, b.qty, b.price, b.supplier ?? '', b.ts ? new Date(b.ts).toISOString() : '', b.voided ? 'yes' : 'no'])
    );
  };

  const exportAll = () => {
    exportDeals();
    exportSettlements();
    exportTrades();
    exportBatches();
  };

  const openEdit = (deal: any) => {
    setEditDeal(deal);
    setEditTitle(deal.title);
    setEditAmount(String(deal.amount));
    setEditReason('');
  };

  const handleCorrect = async () => {
    if (!editDeal || !editReason.trim()) return;
    try {
      await correctDeal.mutateAsync({
        dealId: editDeal.id,
        updates: { title: editTitle, amount: Number(editAmount) },
        reason: editReason.trim(),
      });
      toast({ title: 'Deal corrected', description: 'Audit log recorded.' });
      setEditDeal(null);
    } catch {
      toast({ title: 'Error', description: 'Failed to correct deal.', variant: 'destructive' });
    }
  };

  const handleVoid = async () => {
    if (!voidTarget || !voidReason.trim()) return;
    try {
      await voidDeal.mutateAsync({ dealId: voidTarget.id, reason: voidReason.trim() });
      toast({ title: 'Deal voided', description: 'Audit log recorded.' });
      setVoidTarget(null);
    } catch {
      toast({ title: 'Error', description: 'Failed to void deal.', variant: 'destructive' });
    }
  };

  const handleCorrectEntity = async () => {
    if (!editEntity || !editEntityReason.trim()) return;
    try {
      const updates: Record<string, unknown> = {};
      if (editEntity.type === 'batch') {
        if (editEntityQty) updates.qty = Number(editEntityQty);
        if (editEntityPrice) updates.price = Number(editEntityPrice);
      } else {
        if (editEntityQty) updates.amountUSDT = Number(editEntityQty);
        if (editEntityPrice) updates.sellPriceQAR = Number(editEntityPrice);
      }
      await correctTracker.mutateAsync({
        targetUserId: userId, entityType: editEntity.type, entityId: editEntity.data.id,
        updates, reason: editEntityReason.trim(),
      });
      toast({ title: `${editEntity.type} corrected`, description: 'Audit log recorded.' });
      setEditEntity(null);
    } catch {
      toast({ title: 'Error', description: 'Failed to correct record.', variant: 'destructive' });
    }
  };

  const handleVoidEntity = async () => {
    if (!voidEntity || !voidEntityReason.trim()) return;
    try {
      await voidTrackerEntity.mutateAsync({
        targetUserId: userId, entityType: voidEntity.type, entityId: voidEntity.data.id,
        reason: voidEntityReason.trim(),
      });
      toast({ title: `${voidEntity.type} voided`, description: 'Audit log recorded.' });
      setVoidEntity(null);
    } catch {
      toast({ title: 'Error', description: 'Failed to void record.', variant: 'destructive' });
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-3 flex-wrap">
        <Button variant="ghost" size="sm" onClick={onBack}><ArrowLeft className="h-4 w-4 mr-1" /> Back</Button>
        <h2 className="text-lg font-semibold text-foreground flex-1">
          User Workspace — {profile?.display_name || userId.slice(0, 8)}
        </h2>
        <Button variant="outline" size="sm" className="text-xs gap-1" onClick={exportAll}>
          <Download className="h-3 w-3" /> Export All CSV
        </Button>
      </div>

      {/* Profile card */}
      {profileLoading ? <Skeleton className="h-24" /> : profile ? (
        <Card>
          <CardContent className="grid grid-cols-2 md:grid-cols-4 gap-4 p-4 text-xs">
            <div><span className="text-muted-foreground">Display Name</span><p className="font-medium">{profile.display_name}</p></div>
            <div><span className="text-muted-foreground">Merchant ID</span><p className="font-mono">{profile.merchant_id}</p></div>
            <div><span className="text-muted-foreground">Region</span><p>{profile.region ?? '—'}</p></div>
            <div><span className="text-muted-foreground">Status</span><p><Badge variant="outline" className="text-[10px]">{profile.status}</Badge></p></div>
          </CardContent>
        </Card>
      ) : (
        <p className="text-sm text-muted-foreground">No merchant profile found.</p>
      )}

      <Tabs defaultValue="dashboard" className="w-full">
        <TabsList className="w-full justify-start flex-wrap h-auto gap-1">
          <TabsTrigger value="dashboard" className="text-xs">Dashboard</TabsTrigger>
          <TabsTrigger value="merchants" className="text-xs">Merchants</TabsTrigger>
          <TabsTrigger value="orders" className="text-xs">Orders</TabsTrigger>
          <TabsTrigger value="stock" className="text-xs">Stock</TabsTrigger>
          <TabsTrigger value="deals" className="text-xs">Deals ({deals?.length ?? 0})</TabsTrigger>
          <TabsTrigger value="settlements" className="text-xs">Settlements ({settlements?.length ?? 0})</TabsTrigger>
          <TabsTrigger value="profits" className="text-xs">Profits ({profits?.length ?? 0})</TabsTrigger>
          <TabsTrigger value="tracker" className="text-xs">Tracker ({batches.length}B / {trades.length}T)</TabsTrigger>
        </TabsList>

        <TabsContent value="dashboard" className="mt-3">
          <DashboardPage
            adminUserId={userId}
            adminMerchantId={profile?.merchant_id ?? undefined}
            adminTrackerState={trackerState ?? undefined}
            isAdminView
          />
        </TabsContent>

        <TabsContent value="merchants" className="mt-3">
          <MerchantsPage
            adminUserId={userId}
            adminMerchantId={profile?.merchant_id ?? undefined}
            isAdminView
          />
        </TabsContent>

        <TabsContent value="orders" className="mt-3">
          <AdminOrdersMirror userId={userId} merchantId={profile?.merchant_id ?? null} trackerState={trackerState ?? null} />
        </TabsContent>

        <TabsContent value="stock" className="mt-3">
          <AdminStockMirror trackerState={trackerState ?? null} />
        </TabsContent>

        <TabsContent value="deals" className="mt-3">
          <div className="flex justify-end mb-2">
            <Button variant="ghost" size="sm" className="text-xs gap-1" onClick={exportDeals} disabled={!deals?.length}>
              <Download className="h-3 w-3" /> CSV
            </Button>
          </div>
          {dealsLoading ? <Skeleton className="h-32" /> : !deals?.length ? (
            <p className="text-sm text-muted-foreground text-center py-6">No deals.</p>
          ) : (
            <div className="border rounded-lg overflow-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="text-xs">Title</TableHead>
                    <TableHead className="text-xs">Amount</TableHead>
                    <TableHead className="text-xs">Type</TableHead>
                    <TableHead className="text-xs">Status</TableHead>
                    <TableHead className="text-xs">Created</TableHead>
                    <TableHead className="text-xs text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {deals.map((d: any) => (
                    <TableRow key={d.id}>
                      <TableCell className="text-xs font-medium">{d.title}</TableCell>
                      <TableCell className="text-xs">{fmtTotal(Number(d.amount))} {d.currency}</TableCell>
                      <TableCell><Badge variant="secondary" className="text-[10px]">{d.deal_type}</Badge></TableCell>
                      <TableCell><Badge variant={d.status === 'voided' ? 'destructive' : 'outline'} className="text-[10px]">{d.status}</Badge></TableCell>
                      <TableCell className="text-xs text-muted-foreground">{format(new Date(d.created_at), 'MMM d, yyyy')}</TableCell>
                      <TableCell className="text-right space-x-1">
                        <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2" onClick={() => openEdit(d)}>
                          <Edit className="h-3 w-3 mr-1" /> Edit
                        </Button>
                        {d.status !== 'voided' && d.status !== 'cancelled' && (
                          <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2 text-destructive" onClick={() => { setVoidTarget(d); setVoidReason(''); }}>
                            <Ban className="h-3 w-3 mr-1" /> Void
                          </Button>
                        )}
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </TabsContent>

        <TabsContent value="settlements" className="mt-3">
          <div className="flex justify-end mb-2">
            <Button variant="ghost" size="sm" className="text-xs gap-1" onClick={exportSettlements} disabled={!settlements?.length}>
              <Download className="h-3 w-3" /> CSV
            </Button>
          </div>
          {!settlements?.length ? (
            <p className="text-sm text-muted-foreground text-center py-6">No settlements.</p>
          ) : (
            <div className="border rounded-lg overflow-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="text-xs">Deal ID</TableHead>
                    <TableHead className="text-xs">Amount</TableHead>
                    <TableHead className="text-xs">Currency</TableHead>
                    <TableHead className="text-xs">Date</TableHead>
                    <TableHead className="text-xs">Notes</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {settlements.map((s: any) => (
                    <TableRow key={s.id}>
                      <TableCell className="text-xs font-mono">{s.deal_id.slice(0, 8)}</TableCell>
                      <TableCell className="text-xs">{fmtTotal(Number(s.amount))}</TableCell>
                      <TableCell className="text-xs">{s.currency}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">{format(new Date(s.created_at), 'MMM d, yyyy')}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">{s.notes ?? '—'}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </TabsContent>

        <TabsContent value="profits" className="mt-3">
          {!profits?.length ? (
            <p className="text-sm text-muted-foreground text-center py-6">No profit records.</p>
          ) : (
            <div className="border rounded-lg overflow-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="text-xs">Deal ID</TableHead>
                    <TableHead className="text-xs">Amount</TableHead>
                    <TableHead className="text-xs">Currency</TableHead>
                    <TableHead className="text-xs">Date</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {profits.map((p: any) => (
                    <TableRow key={p.id}>
                      <TableCell className="text-xs font-mono">{p.deal_id.slice(0, 8)}</TableCell>
                      <TableCell className="text-xs">{Number(p.amount).toLocaleString()}</TableCell>
                      <TableCell className="text-xs">{p.currency}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">{format(new Date(p.created_at), 'MMM d, yyyy')}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </TabsContent>

        <TabsContent value="tracker" className="mt-3">
          {!tracker ? (
            <p className="text-sm text-muted-foreground text-center py-6">No tracker data.</p>
          ) : (
            <div className="space-y-4">
              <div className="flex justify-end gap-2">
                <Button variant="ghost" size="sm" className="text-xs gap-1" onClick={exportBatches} disabled={!batches.length}>
                  <Download className="h-3 w-3" /> Batches CSV
                </Button>
                <Button variant="ghost" size="sm" className="text-xs gap-1" onClick={exportTrades} disabled={!trades.length}>
                  <Download className="h-3 w-3" /> Trades CSV
                </Button>
              </div>
              <Card>
                <CardHeader className="pb-2"><CardTitle className="text-sm">Batches ({batches.length})</CardTitle></CardHeader>
                <CardContent className="p-0">
                  {batches.length === 0 ? <p className="text-xs text-muted-foreground p-4">No batches.</p> : (
                    <div className="border-t overflow-auto">
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead className="text-xs">ID</TableHead>
                            <TableHead className="text-xs">Qty</TableHead>
                            <TableHead className="text-xs">Price</TableHead>
                            <TableHead className="text-xs">Date</TableHead>
                            <TableHead className="text-xs">Status</TableHead>
                            <TableHead className="text-xs text-right">Actions</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {batches.slice(0, 50).map((b: any) => (
                            <TableRow key={b.id} className={b.voided ? 'opacity-40' : ''}>
                              <TableCell className="text-xs font-mono">{String(b.id).slice(0, 8)}</TableCell>
                              <TableCell className="text-xs">{b.qty}</TableCell>
                              <TableCell className="text-xs">{b.price}</TableCell>
                              <TableCell className="text-xs text-muted-foreground">
                                {b.ts ? format(new Date(b.ts), 'MMM d, yyyy') : '—'}
                              </TableCell>
                              <TableCell className="text-xs">
                                {b.voided ? <Badge variant="destructive" className="text-[10px]">voided</Badge> : <Badge variant="outline" className="text-[10px]">active</Badge>}
                              </TableCell>
                              <TableCell className="text-right space-x-1">
                                <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2" onClick={() => {
                                  setEditEntity({ type: 'batch', data: b });
                                  setEditEntityQty(String(b.qty ?? ''));
                                  setEditEntityPrice(String(b.price ?? ''));
                                  setEditEntityReason('');
                                }}>
                                  <Edit className="h-3 w-3 mr-1" /> Edit
                                </Button>
                                {!b.voided && (
                                  <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2 text-destructive" onClick={() => {
                                    setVoidEntity({ type: 'batch', data: b });
                                    setVoidEntityReason('');
                                  }}>
                                    <Ban className="h-3 w-3 mr-1" /> Void
                                  </Button>
                                )}
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    </div>
                  )}
                </CardContent>
              </Card>
              <Card>
                <CardHeader className="pb-2"><CardTitle className="text-sm">Trades ({trades.length})</CardTitle></CardHeader>
                <CardContent className="p-0">
                  {trades.length === 0 ? <p className="text-xs text-muted-foreground p-4">No trades.</p> : (
                    <div className="border-t overflow-auto">
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead className="text-xs">ID</TableHead>
                            <TableHead className="text-xs">Qty</TableHead>
                            <TableHead className="text-xs">Sell Price</TableHead>
                            <TableHead className="text-xs">Customer</TableHead>
                            <TableHead className="text-xs">Date</TableHead>
                            <TableHead className="text-xs">Status</TableHead>
                            <TableHead className="text-xs text-right">Actions</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {trades.slice(0, 50).map((t: any) => (
                            <TableRow key={t.id} className={t.voided ? 'opacity-40' : ''}>
                              <TableCell className="text-xs font-mono">{String(t.id).slice(0, 8)}</TableCell>
                              <TableCell className="text-xs">{t.amountUSDT ?? t.qty}</TableCell>
                              <TableCell className="text-xs">{t.sellPriceQAR ?? t.price}</TableCell>
                              <TableCell className="text-xs">{t.customer ?? '—'}</TableCell>
                              <TableCell className="text-xs text-muted-foreground">
                                {t.ts ? format(new Date(t.ts), 'MMM d, yyyy') : '—'}
                              </TableCell>
                              <TableCell className="text-xs">
                                {t.voided ? <Badge variant="destructive" className="text-[10px]">voided</Badge> : <Badge variant="outline" className="text-[10px]">active</Badge>}
                              </TableCell>
                              <TableCell className="text-right space-x-1">
                                <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2" onClick={() => {
                                  setEditEntity({ type: 'trade', data: t });
                                  setEditEntityQty(String(t.amountUSDT ?? t.qty ?? ''));
                                  setEditEntityPrice(String(t.sellPriceQAR ?? t.price ?? ''));
                                  setEditEntityReason('');
                                }}>
                                  <Edit className="h-3 w-3 mr-1" /> Edit
                                </Button>
                                {!t.voided && (
                                  <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2 text-destructive" onClick={() => {
                                    setVoidEntity({ type: 'trade', data: t });
                                    setVoidEntityReason('');
                                  }}>
                                    <Ban className="h-3 w-3 mr-1" /> Void
                                  </Button>
                                )}
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    </div>
                  )}
                </CardContent>
              </Card>
              <p className="text-[10px] text-muted-foreground">
                Last synced: {tracker.updated_at ? format(new Date(tracker.updated_at), 'MMM d, yyyy HH:mm') : '—'}
              </p>
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* Edit Deal Dialog */}
      <Dialog open={!!editDeal} onOpenChange={(open) => !open && setEditDeal(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="text-sm">Correct Deal</DialogTitle>
            <DialogDescription className="text-xs">Changes are audited and permanent.</DialogDescription>
          </DialogHeader>
          <div className="space-y-3">
            <div><Label className="text-xs">Title</Label><Input value={editTitle} onChange={e => setEditTitle(e.target.value)} className="h-8 text-sm" /></div>
            <div><Label className="text-xs">Amount</Label><Input type="number" value={editAmount} onChange={e => setEditAmount(e.target.value)} className="h-8 text-sm" /></div>
            <div><Label className="text-xs">Reason (required)</Label><Textarea value={editReason} onChange={e => setEditReason(e.target.value)} placeholder="Why is this correction needed?" className="text-sm min-h-[60px]" /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" size="sm" onClick={() => setEditDeal(null)}>Cancel</Button>
            <Button size="sm" onClick={handleCorrect} disabled={!editReason.trim() || correctDeal.isPending}>
              {correctDeal.isPending ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : null}
              Save Correction
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Void Deal Dialog */}
      <Dialog open={!!voidTarget} onOpenChange={(open) => !open && setVoidTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="text-sm">Void Deal</DialogTitle>
            <DialogDescription className="text-xs">This will mark the deal as voided. This action is audited.</DialogDescription>
          </DialogHeader>
          <div>
            <Label className="text-xs">Reason (required)</Label>
            <Textarea value={voidReason} onChange={e => setVoidReason(e.target.value)} placeholder="Why is this deal being voided?" className="text-sm min-h-[60px]" />
          </div>
          <DialogFooter>
            <Button variant="outline" size="sm" onClick={() => setVoidTarget(null)}>Cancel</Button>
            <Button variant="destructive" size="sm" onClick={handleVoid} disabled={!voidReason.trim() || voidDeal.isPending}>
              {voidDeal.isPending ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : null}
              Confirm Void
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Tracker Entity Dialog */}
      <Dialog open={!!editEntity} onOpenChange={(open) => !open && setEditEntity(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="text-sm">Correct {editEntity?.type === 'batch' ? 'Batch' : 'Trade'}</DialogTitle>
            <DialogDescription className="text-xs">Changes are audited and permanent.</DialogDescription>
          </DialogHeader>
          <div className="space-y-3">
            <div>
              <Label className="text-xs">{editEntity?.type === 'batch' ? 'Quantity' : 'Amount (USDT)'}</Label>
              <Input type="number" value={editEntityQty} onChange={e => setEditEntityQty(e.target.value)} className="h-8 text-sm" />
            </div>
            <div>
              <Label className="text-xs">{editEntity?.type === 'batch' ? 'Buy Price' : 'Sell Price (QAR)'}</Label>
              <Input type="number" value={editEntityPrice} onChange={e => setEditEntityPrice(e.target.value)} className="h-8 text-sm" />
            </div>
            <div>
              <Label className="text-xs">Reason (required)</Label>
              <Textarea value={editEntityReason} onChange={e => setEditEntityReason(e.target.value)} placeholder="Why is this correction needed?" className="text-sm min-h-[60px]" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" size="sm" onClick={() => setEditEntity(null)}>Cancel</Button>
            <Button size="sm" onClick={handleCorrectEntity} disabled={!editEntityReason.trim() || correctTracker.isPending}>
              {correctTracker.isPending ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : null}
              Save Correction
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Void Tracker Entity Dialog */}
      <Dialog open={!!voidEntity} onOpenChange={(open) => !open && setVoidEntity(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="text-sm">Void {voidEntity?.type === 'batch' ? 'Batch' : 'Trade'}</DialogTitle>
            <DialogDescription className="text-xs">This will mark the record as voided. This action is audited.</DialogDescription>
          </DialogHeader>
          <div>
            <Label className="text-xs">Reason (required)</Label>
            <Textarea value={voidEntityReason} onChange={e => setVoidEntityReason(e.target.value)} placeholder="Why is this record being voided?" className="text-sm min-h-[60px]" />
          </div>
          <DialogFooter>
            <Button variant="outline" size="sm" onClick={() => setVoidEntity(null)}>Cancel</Button>
            <Button variant="destructive" size="sm" onClick={handleVoidEntity} disabled={!voidEntityReason.trim() || voidTrackerEntity.isPending}>
              {voidTrackerEntity.isPending ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : null}
              Confirm Void
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export interface AuditLogRow {
  id: string;
  admin_user_id: string;
  action: string;
  target_type: string;
  target_id: string | null;
  details: Record<string, unknown> | null;
  created_at: string;
}

export function useAdminAuditLogs(search: string = '') {
  return useQuery({
    queryKey: ['admin-audit', search],
    queryFn: async (): Promise<AuditLogRow[]> => {
      let query = supabase
        .from('admin_audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(200);

      const { data, error } = await query;
      if (error) throw error;

      let rows = (data ?? []) as AuditLogRow[];
      if (search.trim()) {
        const q = search.toLowerCase();
        rows = rows.filter(r =>
          r.action.toLowerCase().includes(q) ||
          r.target_type.toLowerCase().includes(q) ||
          r.admin_user_id.toLowerCase().includes(q) ||
          r.target_id?.toLowerCase().includes(q)
        );
      }
      return rows;
    },
    refetchInterval: 15_000,
  });
}

