import { supabase } from '@/integrations/supabase/client';
import { DeterministicResult, fail, ok, ChatRoom } from '@/features/chat/lib/types';
import { QueryClient } from '@tanstack/react-query';

export async function getRooms(): Promise<DeterministicResult<ChatRoom[]>> {
  try {
    // We query the new room summary view which handles unread counts and last messages
    const { data, error } = await supabase
      .from('chat_room_summary_v' as any)
      .select('*')
      .order('last_message_at', { ascending: false });
    
    if (error) throw error;
    
    return ok((data ?? []).map(normalizeRoom));
  } catch (error) {
    return fail([], error);
  }
}

function normalizeRoom(r: any): ChatRoom {
  return {
    room_id: r.id,
    kind: r.type === 'standard' ? 'direct' : 'group',
    lane: (r.lane as any) || 'Personal',
    title: r.name || 'Secure Channel',
    relationship_id: r.relationship_id || null,
    member_role: r.member_role || 'member',
    unread_count: Number(r.unread_count || 0),
    last_message_id: r.last_message_id || null,
    last_message_body: r.last_message_content || '',
    last_message_at: r.last_message_at || null,
    updated_at: r.updated_at || new Date().toISOString(),
    security_policies: r.security_policies,
    retention_policy: r.retention_policy,
    type: r.type,
  };
}

export async function createRoom(input: {
  name: string;
  type: string;
  lane: string;
  members: string[];
}): Promise<DeterministicResult<string | null>> {
  try {
    const { data, error } = await (supabase.rpc as any)('fn_chat_create_room', {
      _name: input.name,
      _type: input.type,
      _lane: input.lane,
      _member_merchant_ids: input.members
    });
    if (error) throw error;
    return ok(data as string);
  } catch (error) {
    return fail(null, error);
  }
}

/**
 * Manually updates the unread count for a room in the React Query cache.
 */
export function setRoomUnreadCountInCache(qc: QueryClient, roomId: string, count: number) {
  qc.setQueryData(['chat', 'rooms'], (old: ChatRoom[] | undefined) => {
    if (!old) return old;
    return old.map(r => r.room_id === roomId ? { ...r, unread_count: count } : r);
  });
}

import { supabase } from '@/integrations/supabase/client';
import { DeterministicResult, fail, ok } from '@/features/chat/lib/types';

async function currentUserId(): Promise<string> {
  const { data } = await supabase.auth.getUser();
  const userId = data.user?.id;
  if (!userId) throw new Error('Not authenticated');
  return userId;
}

export async function createBusinessObjectFromMessage(input: {
  roomId: string;
  messageId: string;
  objectType: 'order' | 'payment' | 'agreement' | 'dispute' | 'task' | 'deal_offer' | 'snapshot';
  payload: Record<string, unknown>;
  title: string;
}): Promise<DeterministicResult<{ objectId: string | null }>> {
  try {
    const userId = await currentUserId();
    const { data: obj, error: objError } = await supabase
      .from('os_business_objects' as any)
      .insert({
        room_id: input.roomId,
        object_type: input.objectType,
        source_message_id: input.messageId,
        created_by: userId,
        payload: input.payload,
        status: 'pending',
      })
      .select('id')
      .single();
    if (objError) throw objError;

    // Track in original tracker links for backward compatibility
    await createActionItemFromMessage({
      roomId: input.roomId,
      messageId: input.messageId,
      kind: input.objectType === 'task' ? 'task' : 'reminder',
      title: input.title,
      payload: input.payload,
    });

    return ok({ objectId: (obj as any).id as string });
  } catch (error) {
    return fail({ objectId: null }, error);
  }
}

export async function createOrderDraftFromMessage(input: {
  roomId: string;
  messageId: string;
  relationshipId?: string | null;
  title: string;
  amount?: number;
  currency?: string;
}): Promise<DeterministicResult<{ dealId: string | null }>> {
  try {
    const userId = await currentUserId();
    if (!input.relationshipId) throw new Error('Room is not linked to a relationship');

    const { data: deal, error: dealError } = await supabase
      .from('merchant_deals' as any)
      .insert({
        relationship_id: input.relationshipId,
        title: input.title,
        amount: input.amount ?? 0,
        currency: input.currency ?? 'USDT',
        deal_type: 'general',
        status: 'pending',
        created_by: userId,
        notes: `source:chat|message_id:${input.messageId}`,
      })
      .select('id')
      .single();
    if (dealError) throw dealError;

    const { error: linkError } = await supabase.from('chat_tracker_links' as any).insert({
      room_id: input.roomId,
      message_id: input.messageId,
      link_type: 'order',
      linked_id: (deal as any).id,
      linked_path: '/trading/orders',
      merchant_relationship_id: input.relationshipId,
      created_by: userId,
      metadata: { prefill: { title: input.title, amount: input.amount ?? 0, currency: input.currency ?? 'USDT' } },
    });
    if (linkError) throw linkError;

    return ok({ dealId: (deal as any).id as string });
  } catch (error) {
    return fail({ dealId: null }, error);
  }
}

export async function createActionItemFromMessage(input: {
  roomId: string;
  messageId: string;
  kind: 'task' | 'reminder' | 'cash' | 'stock';
  title: string;
  payload?: Record<string, unknown>;
}): Promise<DeterministicResult<{ itemId: string | null }>> {
  try {
    const userId = await currentUserId();
    const { data: item, error: itemError } = await supabase
      .from('chat_action_items' as any)
      .insert({
        kind: input.kind,
        title: input.title,
        payload: input.payload ?? {},
        created_by: userId,
      })
      .select('id')
      .single();
    if (itemError) throw itemError;

    const { error: linkError } = await supabase.from('chat_tracker_links' as any).insert({
      room_id: input.roomId,
      message_id: input.messageId,
      link_type: input.kind,
      linked_id: (item as any).id,
      linked_path: '/chat',
      created_by: userId,
      metadata: input.payload ?? {},
    });
    if (linkError) throw linkError;

    return ok({ itemId: (item as any).id as string });
  } catch (error) {
    return fail({ itemId: null }, error);
  }
}

export async function getTrackerLinksForRoom(roomId: string): Promise<DeterministicResult<any[]>> {
  try {
    const { data, error } = await supabase
      .from('chat_tracker_links' as any)
      .select('*')
      .eq('room_id', roomId)
      .order('created_at', { ascending: false });
    if (error) throw error;
    return ok((data ?? []) as any[]);
  } catch (error) {
    return fail([], error);
  }
}

/* ═══════════════════════════════════════════════════════════════
   ContextPanel — Right panel with merchant profile card,
   real data (orders/agreements/settlements), and quick actions
   ═══════════════════════════════════════════════════════════════ */

import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { supabase } from '@/integrations/supabase/client';
import { Package, FileText, Receipt, Loader2, ExternalLink, Plus, Target } from 'lucide-react';
import { getPalette } from '../lib/message-codec';

interface Relationship {
  id: string;
  counterparty_name: string;
  counterparty_nickname: string;
  counterparty_code?: string;
  merchant_a_id: string;
  merchant_b_id: string;
}

interface Props {
  relationship: Relationship | null;
  onOpenRelationship?: (relationshipId: string) => void;
}

const STATUS_COLORS: Record<string, string> = {
  pending: 'text-amber-400',
  active: 'text-emerald-400',
  approved: 'text-emerald-400',
  completed: 'text-primary',
  settled: 'text-primary',
  due: 'text-destructive',
  overdue: 'text-destructive',
  rejected: 'text-destructive',
  expired: 'text-muted-foreground',
  cancelled: 'text-muted-foreground',
  disputed: 'text-amber-400',
};

function StatusBadge({ status }: { status: string }) {
  return (
    <span className={`font-semibold capitalize text-[10px] ${STATUS_COLORS[status] || 'text-muted-foreground'}`}>
      {status}
    </span>
  );
}

export function ContextPanel({ relationship, onOpenRelationship }: Props) {
  const navigate = useNavigate();
  const relId = relationship?.id;

  const { data: orders = [], isLoading: ordersLoading } = useQuery({
    queryKey: ['context-orders', relId],
    queryFn: async () => {
      const { data } = await supabase
        .from('merchant_deals')
        .select('id, title, amount, currency, status, deal_type, created_at')
        .eq('relationship_id', relId!)
        .in('status', ['pending', 'active'])
        .order('created_at', { ascending: false })
        .limit(5);
      return data || [];
    },
    enabled: !!relId,
    staleTime: 15_000,
  });

  const { data: agreements = [], isLoading: agreementsLoading } = useQuery({
    queryKey: ['context-agreements', relId],
    queryFn: async () => {
      const { data } = await supabase
        .from('profit_share_agreements')
        .select('id, merchant_ratio, partner_ratio, settlement_cadence, status, effective_from, expires_at')
        .eq('relationship_id', relId!)
        .order('created_at', { ascending: false })
        .limit(5);
      return data || [];
    },
    enabled: !!relId,
    staleTime: 15_000,
  });

  const { data: settlements = [], isLoading: settlementsLoading } = useQuery({
    queryKey: ['context-settlements', relId],
    queryFn: async () => {
      const { data } = await supabase
        .from('settlement_periods')
        .select('id, period_key, status, net_profit, settled_amount, cadence, resolution')
        .eq('relationship_id', relId!)
        .in('status', ['pending', 'due', 'overdue', 'disputed'])
        .order('created_at', { ascending: false })
        .limit(5);
      return data || [];
    },
    enabled: !!relId,
    staleTime: 15_000,
  });

  if (!relationship) {
    return (
      <div className="w-[260px] flex-shrink-0 border-l border-border hidden lg:flex items-center justify-center text-muted-foreground text-xs p-5 bg-card">
        Select a conversation to see details
      </div>
    );
  }

  const isLoading = ordersLoading || agreementsLoading || settlementsLoading;
  const palette = getPalette(relationship.counterparty_name);
  const activeDeals = agreements.filter((a: any) => a.status === 'approved' || a.status === 'active');

  const handleOrderClick = (orderId: string) => navigate(`/orders?deal=${orderId}`);
  const handleAgreementClick = () => {
    if (onOpenRelationship && relId) onOpenRelationship(relId);
    else navigate(`/merchants?rel=${relId}&tab=deals`);
  };
  const handleSettlementClick = () => navigate(`/merchants?rel=${relId}&tab=settlements`);

  return (
    <div className="w-[260px] flex-shrink-0 border-l border-border overflow-y-auto bg-card h-full hidden lg:block">
      {/* ── Merchant Profile Card ── */}
      <div className="p-4 flex flex-col items-center border-b border-border">
        <div
          className="w-14 h-14 rounded-full flex items-center justify-center text-xl font-extrabold mb-2"
          style={{ background: palette.bg, color: palette.text }}
        >
          {relationship.counterparty_name.charAt(0).toUpperCase()}
        </div>
        <div className="text-sm font-bold text-foreground text-center">
          {relationship.counterparty_nickname || relationship.counterparty_name}
        </div>
        {relationship.counterparty_code && (
          <div className="text-[10px] text-muted-foreground mt-0.5">
            Code: {relationship.counterparty_code}
          </div>
        )}
        <div className="text-[10px] text-emerald-400 font-semibold mt-1">Active</div>
      </div>

      <div className="p-3 space-y-3">

        {/* ── Active Orders ── */}
        <Section icon={Package} title="Active Orders" count={orders.length} loading={isLoading}>
          {orders.length === 0 ? (
            <Empty>No active orders with this merchant</Empty>
          ) : (
            orders.map((o: any) => (
              <button
                key={o.id}
                onClick={() => handleOrderClick(o.id)}
                className="rounded border border-border bg-background p-2.5 space-y-1 w-full text-left hover:border-primary/40 hover:bg-accent/30 transition-colors cursor-pointer group"
              >
                <div className="flex items-center justify-between">
                  <span className="text-[11px] font-bold text-foreground truncate flex-1 group-hover:text-primary transition-colors">{o.title}</span>
                  <ExternalLink size={10} className="text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity ml-1 flex-shrink-0" />
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-[11px] text-muted-foreground">{Number(o.amount).toLocaleString()} {o.currency}</span>
                  <StatusBadge status={o.status} />
                </div>
              </button>
            ))
          )}
        </Section>

        {/* ── Deals & Agreements ── */}
        <Section icon={FileText} title="Deals & Agreements" count={agreements.length} loading={isLoading}>
          {agreements.length === 0 ? (
            <Empty>No active deals</Empty>
          ) : (
            agreements.map((a: any) => (
              <button
                key={a.id}
                onClick={handleAgreementClick}
                className="rounded border border-border bg-background p-2.5 space-y-1 w-full text-left hover:border-primary/40 hover:bg-accent/30 transition-colors cursor-pointer group"
              >
                <div className="flex items-center justify-between">
                  <span className="text-[11px] font-bold text-foreground group-hover:text-primary transition-colors">
                    {a.merchant_ratio}/{a.partner_ratio} split
                  </span>
                  <StatusBadge status={a.status} />
                </div>
                <div className="text-[10px] text-muted-foreground capitalize">{a.settlement_cadence} settlement</div>
              </button>
            ))
          )}
        </Section>

        {/* ── Settlement State ── */}
        <Section icon={Receipt} title="Settlement State" count={settlements.length} loading={isLoading}>
          {settlements.length === 0 ? (
            <Empty>No pending settlements</Empty>
          ) : (
            settlements.map((s: any) => (
              <button
                key={s.id}
                onClick={handleSettlementClick}
                className="rounded border border-border bg-background p-2.5 space-y-1 w-full text-left hover:border-primary/40 hover:bg-accent/30 transition-colors cursor-pointer group"
              >
                <div className="flex items-center justify-between">
                  <span className="text-[11px] font-bold text-foreground group-hover:text-primary transition-colors">{s.period_key}</span>
                  <StatusBadge status={s.status} />
                </div>
                <div className="flex items-center justify-between text-[10px] text-muted-foreground">
                  <span>Net: {Number(s.net_profit).toLocaleString()}</span>
                  {s.resolution && <span className="capitalize text-primary font-semibold">{s.resolution}</span>}
                </div>
              </button>
            ))
          )}
        </Section>

        {/* ── Quick Actions ── */}
        <div>
          <div className="text-[11px] font-bold uppercase tracking-wider text-muted-foreground mb-2">
            Quick Actions
          </div>
          <div className="space-y-1">
            <QuickAction
              label="New Order from Chat"
              onClick={() => navigate(`/orders?new=true&rel=${relId}`)}
            />
            <QuickAction
              label="Request Agreement"
              onClick={() => navigate(`/merchants?rel=${relId}&tab=deals`)}
            />
            <QuickAction
              label="Initiate Settlement"
              onClick={() => navigate(`/merchants?rel=${relId}&tab=settlements`)}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── Helpers ── */

function Section({ icon: Icon, title, count, loading, children }: {
  icon: any; title: string; count: number; loading: boolean; children: React.ReactNode;
}) {
  return (
    <div>
      <div className="flex items-center justify-between mb-1.5">
        <div className="flex items-center gap-1.5">
          <Icon size={12} className="text-muted-foreground" />
          <span className="text-[11px] font-bold uppercase tracking-wider text-muted-foreground">{title}</span>
          {loading && <Loader2 size={10} className="animate-spin text-muted-foreground" />}
        </div>
        <span className="text-[11px] font-bold text-foreground">{count}</span>
      </div>
      <div className="space-y-1.5">{children}</div>
    </div>
  );
}

function Empty({ children }: { children: React.ReactNode }) {
  return <div className="text-[10px] text-muted-foreground py-1">{children}</div>;
}

function QuickAction({ label, onClick }: { label: string; onClick: () => void }) {
  return (
    <button
      onClick={onClick}
      className="flex items-center gap-2 w-full text-left px-2 py-1.5 rounded text-[11px] font-semibold text-primary hover:bg-primary/10 transition-colors cursor-pointer bg-transparent border-none"
    >
      <Plus size={12} className="flex-shrink-0" />
      {label}
    </button>
  );
}

import { useState, useRef, useCallback } from 'react';
import { cn } from '@/lib/utils';
import { Send, Mic, Smile, Zap, Command, X, StopCircle, Package } from 'lucide-react';

interface Props {
  onSend: (payload: { content: string; type: string; bodyJson?: any }) => void;
  onTyping: () => void;
  sending: boolean;
  compact?: boolean;
  /** BUG 9 FIX: real P&L summary string from tracker state, used by /pnl command */
  pnlSummary?: string;
}

const COMMANDS = [
  { key: '/order', label: 'Create Order', icon: Zap, desc: 'Quickly draft a new trade' },
  { key: '/stock', label: 'Check Stock', icon: Package, desc: 'View current inventory levels' },
  { key: '/pnl', label: 'Share P&L', icon: Command, desc: 'Post current session performance' },
];

export function MessageComposer({ onSend, onTyping, sending, compact, pnlSummary }: Props) {
  const [content, setContent] = useState('');
  const [showCommands, setShowCommands] = useState(false);

  const handleCommand = (cmd: string) => {
    if (cmd === '/order') {
      onSend({ content: '||SYS_ACTION||create_order||/SYS_ACTION||', type: 'text' });
    } else if (cmd === '/stock') {
      onSend({ content: '||SYS_ACTION||check_stock||/SYS_ACTION||', type: 'text' });
    } else if (cmd === '/pnl') {
      // BUG 9 FIX: use real tracker P&L passed from ChatWorkspacePage
      const summary = pnlSummary ?? 'P&L unavailable — open the Dashboard to sync data';
      onSend({ content: `||AI_SUMMARY|| ${summary}`, type: 'text' });
    }
    setContent('');
    setShowCommands(false);
  };

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!content.trim() || sending) return;
    if (content.startsWith('/')) {
      const match = COMMANDS.find(c => content.startsWith(c.key));
      if (match) { handleCommand(match.key); return; }
    }
    onSend({ content: content.trim(), type: 'text' });
    setContent('');
  };

  return (
    <div className={cn("bg-background p-3 border-t border-border relative")}>
      {showCommands && (
        <div className="absolute bottom-full left-4 mb-2 w-64 bg-popover border border-border rounded-2xl shadow-2xl overflow-hidden animate-in slide-in-from-bottom-2">
          <div className="p-2 bg-muted/50 text-[10px] font-black uppercase tracking-widest text-muted-foreground">Available Protocols</div>
          {COMMANDS.map(cmd => (
            <button 
              key={cmd.key}
              onClick={() => handleCommand(cmd.key)}
              className="w-full flex items-center gap-3 p-3 hover:bg-accent text-left transition-colors"
            >
              <cmd.icon size={16} className="text-primary" />
              <div>
                <div className="text-xs font-bold">{cmd.key}</div>
                <div className="text-[10px] text-muted-foreground">{cmd.desc}</div>
              </div>
            </button>
          ))}
        </div>
      )}

      <form onSubmit={handleSubmit} className="flex items-end gap-2">
        <div className="flex-1 relative flex items-center bg-muted rounded-2xl px-4 min-h-[44px]">
          <input
            value={content}
            onChange={(e) => {
              setContent(e.target.value);
              setShowCommands(e.target.value === '/');
              onTyping();
            }}
            placeholder="Type a message or / for protocols..."
            className="flex-1 bg-transparent border-none focus:outline-none text-sm py-3"
          />
        </div>
        <button
          type="submit"
          disabled={!content.trim() || sending}
          className="w-11 h-11 rounded-xl bg-primary text-primary-foreground flex items-center justify-center shadow-lg shadow-primary/20 hover:scale-105 transition-all"
        >
          <Send size={18} />
        </button>
      </form>
    </div>
  );
}

/**
 * MessageItem
 *
 * BUG 3 FIX: Exposes onReact / onDeleteForMe via a hover action bar.
 *            Previously all callbacks in ChatWorkspacePage were () => {} stubs.
 *
 * BUG 4 FIX: Read receipt uses read_at (set by receiver via fn_chat_mark_read)
 *            instead of the never-populated status === 'read' string.
 *            The real-time UPDATE subscription (Bug 1 fix) propagates read_at live.
 */

import { cn } from '@/lib/utils';
import { format } from 'date-fns';
import {
  Check, CheckCheck, Shield, Eye, Lock, Zap, LayoutGrid,
  PlusCircle, Search, RefreshCcw, Trash2, SmilePlus,
} from 'lucide-react';
import { parseMsg } from '../lib/message-codec';
import { useMemo, useState, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useNavigate } from 'react-router-dom';

const QUICK_EMOJIS = ['👍', '❤️', '😂', '😮', '🙏', '🔥'];

interface MessageProps {
  message: {
    id: string;
    content: string;
    sender_id: string;
    created_at: string;
    type?: string;
    metadata?: any;
    status?: string;
    expires_at?: string;
    read_at?: string | null;        // BUG 4: counterparty read timestamp
  };
  currentUserId: string;
  // BUG 3: optional action callbacks
  onReact?: (messageId: string, emoji: string) => void;
  onDeleteForMe?: (messageId: string) => void;
  reactions?: Record<string, string[]>; // emoji → userIds
}

// BUG 4 FIX: derive status from read_at, not from a status field that is never 'read'
function ReadStatusIcon({ status, readAt }: { status?: string; readAt?: string | null }) {
  if (status === 'sending') return <RefreshCcw size={10} className="opacity-40 animate-spin" />;
  if (status === 'failed')  return <span className="text-destructive text-[9px] font-bold">!</span>;
  if (readAt)               return <CheckCheck size={12} className="text-primary" />;
  return <Check size={12} className="opacity-40" />;
}

export function MessageItem({ message, currentUserId, onReact, onDeleteForMe, reactions = {} }: MessageProps) {
  const isMe     = message.sender_id === currentUserId;
  const isSystem = message.type === 'system';
  const parsed   = useMemo(() => parseMsg(message.content), [message.content]);
  const navigate = useNavigate();

  const [showOneTime,  setShowOneTime]  = useState(false);
  const [showEmojiBar, setShowEmojiBar] = useState(false);
  const hideTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const isOneTime = !!message.expires_at && !message.metadata?.timer;
  const isViewed  = parsed.isViewed || (message.metadata?.viewed === true);

  const handleReveal = async () => {
    if (isMe || isViewed) return;
    setShowOneTime(true);
    try {
      const viewedContent = `${message.content}||VIEWED||${new Date().toISOString()}||/VIEWED||`;
      await supabase.from('os_messages').update({ content: viewedContent }).eq('id', message.id);
    } catch {
      // non-critical — local reveal already shown
    }
  };

  const onEnter = () => { if (hideTimer.current) clearTimeout(hideTimer.current); setShowEmojiBar(true); };
  const onLeave = () => { hideTimer.current = setTimeout(() => setShowEmojiBar(false), 250); };

  // ── System message ────────────────────────────────────────────────────────
  if (isSystem) {
    return (
      <div className="flex justify-center my-4">
        <span className="bg-muted/50 text-muted-foreground text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-[0.2em] border border-border/50">
          {parsed.text || message.content}
        </span>
      </div>
    );
  }

  if (parsed.isAiSummary) {
    return (
      <div className="mx-6 my-4 p-4 rounded-2xl bg-violet-50/50 border border-violet-100 shadow-sm">
        <div className="flex items-center gap-2 mb-2 text-violet-600">
          <Zap size={14} className="fill-current" />
          <span className="text-[10px] font-black uppercase tracking-widest">AI Protocol Summary</span>
        </div>
        <p className="text-[13px] text-slate-700 leading-relaxed italic">{parsed.text}</p>
      </div>
    );
  }

  if (parsed.isAppOutput) {
    return (
      <div className="mx-6 my-4 p-4 rounded-2xl bg-slate-900 text-white border border-slate-800 shadow-xl">
        <div className="flex items-center gap-2 mb-3 text-slate-400">
          <LayoutGrid size={14} />
          <span className="text-[10px] font-black uppercase tracking-widest">{parsed.appName || 'MiniApp'} Output</span>
        </div>
        <div className="font-mono text-[12px] bg-black/40 p-3 rounded-lg border border-white/5">{parsed.text}</div>
      </div>
    );
  }

  if (parsed.isAction) {
    const action = parsed.actionType;
    return (
      <div className={cn('flex w-full mb-4 px-4', isMe ? 'justify-end' : 'justify-start')}>
        <div className={cn('flex flex-col max-w-[85%] md:max-w-[70%]', isMe ? 'items-end' : 'items-start')}>
          <div className="bg-card border border-border rounded-[22px] p-4 shadow-sm flex flex-col gap-3">
            <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-muted-foreground">
              <Zap size={12} className="text-primary" />
              Protocol Action Required
            </div>
            {action === 'create_order' && (
              <button onClick={() => navigate('/trading/orders?new=true')}
                className="flex items-center gap-3 w-full px-4 py-3 bg-primary text-primary-foreground rounded-xl shadow-lg shadow-primary/10 hover:scale-[1.02] transition-all active:scale-95">
                <PlusCircle size={16} />
                <span className="text-[11px] font-black uppercase tracking-widest">Create New Order</span>
              </button>
            )}
            {action === 'check_stock' && (
              <button onClick={() => navigate('/trading/stock')}
                className="flex items-center gap-3 w-full px-4 py-3 bg-accent text-accent-foreground rounded-xl shadow-sm hover:scale-[1.02] transition-all active:scale-95">
                <Search size={16} />
                <span className="text-[11px] font-black uppercase tracking-widest">Check Inventory</span>
              </button>
            )}
          </div>
        </div>
      </div>
    );
  }

  // ── Standard bubble ────────────────────────────────────────────────────────

  const reactionEntries = Object.entries(reactions).filter(([, users]) => users.length > 0);

  return (
    <div
      className={cn('flex w-full mb-1 px-4 group/msg', isMe ? 'justify-end' : 'justify-start')}
      onMouseEnter={onEnter}
      onMouseLeave={onLeave}
    >
      <div className={cn('flex flex-col max-w-[85%] md:max-w-[70%]', isMe ? 'items-end' : 'items-start')}>

        {/* Timestamp */}
        <div className="flex items-center gap-2 mb-1 px-1 opacity-0 group-hover/msg:opacity-100 transition-opacity">
          <span className="text-[8px] font-black text-muted-foreground uppercase tracking-tighter">
            {format(new Date(message.created_at), 'HH:mm')}
          </span>
        </div>

        <div className="relative flex items-end gap-2">

          {/* BUG 3 FIX: hover action bar */}
          {showEmojiBar && (onReact || onDeleteForMe) && (
            <div
              className={cn(
                'absolute bottom-full mb-1 flex items-center gap-0.5 bg-popover border border-border rounded-full px-2 py-1 shadow-lg z-10 animate-in fade-in-0 zoom-in-95 duration-100',
                isMe ? 'right-0' : 'left-0',
              )}
              onMouseEnter={onEnter}
              onMouseLeave={onLeave}
            >
              {onReact && QUICK_EMOJIS.map((emoji) => (
                <button key={emoji} onClick={() => { onReact(message.id, emoji); setShowEmojiBar(false); }}
                  className="text-base hover:scale-125 transition-transform px-0.5 leading-none" title={emoji}>
                  {emoji}
                </button>
              ))}
              {onReact && onDeleteForMe && <span className="w-px h-4 bg-border mx-1" />}
              {onDeleteForMe && (
                <button onClick={() => { onDeleteForMe(message.id); setShowEmojiBar(false); }}
                  className="p-1 hover:bg-destructive/10 rounded-full transition-colors" title="Delete for me">
                  <Trash2 size={12} className="text-muted-foreground hover:text-destructive" />
                </button>
              )}
            </div>
          )}

          {/* Bubble */}
          <div className={cn(
            'px-4 py-3 rounded-[22px] text-[13px] leading-relaxed shadow-sm border relative overflow-hidden transition-all',
            isMe
              ? 'bg-primary text-primary-foreground rounded-br-none border-primary/50'
              : 'bg-card text-card-foreground rounded-bl-none border-border',
          )}>
            {isOneTime && isViewed && !isMe ? (
              <div className="flex items-center gap-2 py-1 opacity-50 italic text-[11px]">
                <Lock size={12} /> Message viewed and locked
              </div>
            ) : isOneTime && !showOneTime && !isMe && !isViewed ? (
              <button onClick={handleReveal}
                className="flex items-center gap-2 py-1 px-2 rounded-lg bg-primary/10 hover:bg-primary/20 transition-all border-none cursor-pointer">
                <Shield size={14} className="text-primary" />
                <span className="font-bold text-[11px] text-primary uppercase tracking-widest">Reveal One-Time View</span>
              </button>
            ) : (
              <div className="whitespace-pre-wrap break-words">{parsed.text || message.content}</div>
            )}

            {isOneTime && !isViewed && (
              <div className="absolute top-0 right-0 p-1 bg-background/10 rounded-bl-lg backdrop-blur-md">
                <Eye size={10} className={isMe ? 'text-primary-foreground' : 'text-primary'} />
              </div>
            )}
          </div>

          {/* BUG 4 FIX: status icon driven by read_at */}
          {isMe && (
            <div className="flex flex-col items-center opacity-40 group-hover/msg:opacity-100 transition-opacity mb-1">
              <ReadStatusIcon status={message.status} readAt={message.read_at} />
            </div>
          )}
        </div>

        {/* Reaction pills */}
        {reactionEntries.length > 0 && (
          <div className="flex flex-wrap gap-1 mt-1 px-1">
            {reactionEntries.map(([emoji, users]) => (
              <button key={emoji} onClick={() => onReact?.(message.id, emoji)}
                className={cn(
                  'flex items-center gap-0.5 text-[11px] px-2 py-0.5 rounded-full border transition-colors',
                  users.includes(currentUserId)
                    ? 'bg-primary/15 border-primary/30 text-primary'
                    : 'bg-muted/60 border-border text-muted-foreground hover:bg-muted',
                )}>
                {emoji}{users.length > 1 && <span className="font-bold ml-0.5">{users.length}</span>}
              </button>
            ))}
          </div>
        )}

        {/* Hint when no reactions */}
        {showEmojiBar && reactionEntries.length === 0 && onReact && (
          <div className="flex items-center gap-1 mt-1 px-1 opacity-50">
            <SmilePlus size={10} className="text-muted-foreground" />
            <span className="text-[9px] text-muted-foreground">Add reaction</span>
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect, useMemo, useRef } from 'react';
import { BusinessObjectCard } from '@/features/chat/components/BusinessObjectCard';
import { MessageItem } from '@/features/chat/components/MessageItem';
import { UnreadDivider } from '@/features/chat/components/UnreadDivider';
import type { TimelineItem, ChatBusinessObject } from '@/features/chat/lib/types';

interface Props {
  messages: TimelineItem[];
  currentUserId: string;
  unreadMessageId: string | null;
  reactionsByMessage: Record<string, string[]>;
  pinnedSet: Set<string>;
  onReact: (messageId: string, emoji: string, remove?: boolean) => void;
  onPinToggle: (messageId: string, pinned: boolean) => void;
  onMarkRead: (messageId: string) => void;
  onDeleteForMe: (messageId: string) => void;
  onDeleteForEveryone: (messageId: string) => void;
  onCreateOrder: (messageId: string) => void;
  onCreateTask: (messageId: string) => void;
  onAcceptDeal?: (id: string) => void;
  onConvert?: (messageId: string, type: 'task' | 'order') => void;
  onReply?: (message: any) => void;
  disableForward?: boolean;
}

export function MessageList(props: Props) {
  const lastReadMutationRef = useRef<string | null>(null);
  const unreadCount = useMemo(() => {
    if (!props.unreadMessageId) return 0;
    const idx = props.messages.findIndex((m) => m.id === props.unreadMessageId);
    if (idx === -1) return 0;
    return props.messages.length - idx;
  }, [props.messages, props.unreadMessageId]);

  useEffect(() => {
    const candidate = [...props.messages]
      .reverse()
      .find((m: any) => {
        const senderId = m.sender_id || m.sender_merchant_id;
        return senderId !== props.currentUserId && !m.read_at;
      }) as any;
    if (!candidate) return;
    if (lastReadMutationRef.current === candidate.id) return;

    const element = document.getElementById(`msg-${candidate.id}`);
    if (!element) return;
    const rect = element.getBoundingClientRect();
    const visible = rect.top < window.innerHeight && rect.bottom > 0;
    if (!visible) return;

    const timer = window.setTimeout(() => {
      lastReadMutationRef.current = candidate.id;
      props.onMarkRead(candidate.id);
    }, 250);

    return () => window.clearTimeout(timer);
  }, [props.messages, props.currentUserId, props.onMarkRead]);

  return (
    <div className="flex-1 overflow-auto py-2">
      {props.messages.map((m) => {
        if (m.type === 'business_object') {
          return (
            <BusinessObjectCard
              key={m.id}
              obj={m as ChatBusinessObject}
              onAccept={() => props.onAcceptDeal?.(m.id)}
            />
          );
        }

        const showUnread = props.unreadMessageId === m.id;
        const msg = m as any;
        return (
          <div key={m.id} id={`msg-${m.id}`}>
            {showUnread && unreadCount > 0 && <UnreadDivider count={unreadCount} />}
            <MessageItem
              message={{
                id: msg.id,
                content: msg.content || msg.body || '',
                sender_id: msg.sender_id || msg.sender_merchant_id || '',
                created_at: msg.created_at,
                type: msg.message_type,
                status: msg.status,
                expires_at: msg.expires_at,
                metadata: msg.metadata,
                read_at: msg.read_at ?? null,   // BUG 4 FIX: pass read_at for receipt
              }}
              currentUserId={props.currentUserId}
              reactions={props.reactionsByMessage[msg.id] as any ?? {}}
              onReact={(id, emoji) => props.onReact(id, emoji)}
              onDeleteForMe={(id) => props.onDeleteForMe(id)}
            />
          </div>
        );
      })}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   MessageTimeline — scrollable message list with date separators,
   unread dividers, anchor navigation, jump-to-latest
   ═══════════════════════════════════════════════════════════════ */

import { useEffect, useRef, useState, useMemo, useCallback } from 'react';
import { useChatStore } from '@/lib/chat-store';
import type { ChatMessage } from '@/lib/chat-store';
import { groupMessagesByDate } from '../lib/message-codec';
import { MessageItem } from './MessageItem';
import { UnreadDivider } from './UnreadDivider';
import { JumpToLatestButton } from './JumpToLatestButton';
import { TypingIndicator } from './TypingIndicator';

interface Props {
  messages: ChatMessage[];
  currentUserId: string;
  counterpartyName: string;
  scrollRef: (el: HTMLDivElement | null) => void;
  onReply: (msg: ChatMessage) => void;
  onForward?: (msg: ChatMessage) => void;
  relationshipId?: string;
}

export function MessageTimeline({
  messages, currentUserId, counterpartyName, scrollRef, onReply, onForward, relationshipId,
}: Props) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const [isAtBottom, setIsAtBottom] = useState(true);
  const highlightId = useChatStore((s) => s.highlightMessageId);
  const anchorId = useChatStore((s) => s.activeMessageAnchor);
  const clearHighlight = useChatStore((s) => s.clearHighlight);
  const setAnchor = useChatStore((s) => s.setAnchor);
  const activeConvId = useChatStore((s) => s.activeConversationId);
  const typingUsers = useChatStore((s) => {
    const id = s.activeConversationId;
    if (!id) return undefined;
    return s.typingByConversation[id];
  });
  const typing = typingUsers ?? [];

  const firstUnreadId = useMemo(() => {
    for (const m of messages) {
      if (m.sender_id !== currentUserId && !m.read_at) return m.id;
    }
    return null;
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeConvId]);

  const unreadCount = useMemo(
    () => messages.filter((m) => m.sender_id !== currentUserId && !m.read_at).length,
    [messages, currentUserId]
  );

  const groups = useMemo(() => groupMessagesByDate(messages), [messages]);

  const handleScroll = useCallback(() => {
    const el = containerRef.current;
    if (!el) return;
    setIsAtBottom(el.scrollHeight - el.scrollTop - el.clientHeight < 120);
  }, []);

  const setCombinedRef = useCallback(
    (el: HTMLDivElement | null) => { containerRef.current = el; scrollRef(el); },
    [scrollRef]
  );

  useEffect(() => {
    if (isAtBottom && containerRef.current) containerRef.current.scrollTop = containerRef.current.scrollHeight;
  }, [messages.length, isAtBottom]);

  useEffect(() => {
    if (containerRef.current) { containerRef.current.scrollTop = containerRef.current.scrollHeight; setIsAtBottom(true); }
  }, [activeConvId]);

  useEffect(() => {
    if (!anchorId) return;
    const attempt = () => {
      const el = containerRef.current?.querySelector(`[data-msg-id="${anchorId}"]`);
      if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); setTimeout(() => clearHighlight(), 2000); setAnchor(null); return true; }
      return false;
    };
    if (!attempt()) { const timer = setTimeout(attempt, 300); return () => clearTimeout(timer); }
  }, [anchorId, clearHighlight, setAnchor]);

  const scrollToBottom = () => {
    containerRef.current?.scrollTo({ top: containerRef.current.scrollHeight, behavior: 'smooth' });
  };

  const scrollToMessage = (id: string) => {
    const el = containerRef.current?.querySelector(`[data-msg-id="${id}"]`);
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      useChatStore.getState().setAnchor(id);
      setTimeout(() => useChatStore.getState().clearHighlight(), 2000);
    }
  };

  return (
    <div className="flex-1 relative min-h-0 overflow-hidden bg-background">
      <div
        ref={setCombinedRef}
        onScroll={handleScroll}
        className="h-full overflow-y-auto overflow-x-hidden py-2"
      >
        {messages.length === 0 ? (
          <div className="flex items-center justify-center h-full text-muted-foreground text-xs">
            No messages yet. Say hello!
          </div>
        ) : (
          groups.map((group) => (
            <div key={group.date}>
              {/* Sticky date separator */}
              <div className="sticky top-0 z-10 flex justify-center py-2">
                <span className="text-[10px] font-bold text-muted-foreground bg-card px-3 py-0.5 rounded-full border border-border">
                  {group.label}
                </span>
              </div>

              {group.messages.map((msg, idx) => {
                const prev = group.messages[idx - 1];
                const next = group.messages[idx + 1];
                const isOwn = msg.sender_id === currentUserId;
                const isFirst = !prev || prev.sender_id !== msg.sender_id;
                const isLast = !next || next.sender_id !== msg.sender_id;
                const showUnreadDivider = msg.id === firstUnreadId;

                return (
                  <div key={msg.id}>
                    {showUnreadDivider && <UnreadDivider count={unreadCount} />}
                    <MessageItem
                      message={{ id: msg.id, content: msg.content, sender_id: msg.sender_id, created_at: msg.created_at, type: (msg as any).msg_type, status: (msg as any).status, expires_at: (msg as any).expires_at }}
                      currentUserId={currentUserId}
                    />
                  </div>
                );
              })}
            </div>
          ))
        )}
        <TypingIndicator users={typing} />
      </div>

      {!isAtBottom && <JumpToLatestButton unreadCount={unreadCount} onClick={scrollToBottom} />}

      <style>{`
        .msg-highlight {
          background: hsl(var(--primary) / 0.12) !important;
          transition: background 2s ease-out;
        }
      `}</style>
    </div>
  );
}

/**
 * useRoomMessages
 *
 * BUG 1 FIX: Real-time INSERT subscription — new messages from counterparty
 *            appear instantly without page refresh.
 * BUG 1 FIX: Real-time UPDATE subscription — read_at changes (read receipts)
 *            propagate to the sender's UI immediately.
 * BUG 2 FIX: onError rollback restores optimistic cache snapshot and shows
 *            a toast so users know the send failed.
 */

import { useEffect, useCallback } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { getRoomMessages, markMessagesReadUpTo, sendMessage } from '@/features/chat/api/messages';
import { randomUUID } from '@/features/chat/utils/uuid';
import { useAuth } from '@/features/auth/auth-context';
import { setRoomUnreadCountInCache } from '@/features/chat/api/rooms';
import { toast } from 'sonner';

type CacheMsg = Record<string, unknown>;

/** Shape the raw realtime row into the same format getRoomMessages returns */
function normalizeRealtimeRow(row: Record<string, unknown>): CacheMsg {
  return { ...row, body: row.content, sender_name: row.sender_merchant_id };
}

export function useRoomMessages(roomId: string | null) {
  const qc = useQueryClient();
  const { userId, merchantProfile } = useAuth();
  const actorId = merchantProfile?.merchant_id || userId;

  // ── Initial fetch ──────────────────────────────────────────────────────

  const query = useQuery({
    queryKey: ['chat', 'messages', roomId],
    enabled: !!roomId,
    queryFn: async () => {
      const res = await getRoomMessages(roomId!);
      if (!res.ok) throw new Error(res.error ?? 'Fetch failed');
      return res.data || [];
    },
  });

  // ── BUG 1 FIX: Real-time subscription ─────────────────────────────────

  useEffect(() => {
    if (!roomId) return;

    const channel = supabase
      .channel(`room-messages-rt-${roomId}`)
      // New messages — append to cache for instant delivery
      .on(
        'postgres_changes' as any,
        { event: 'INSERT', schema: 'public', table: 'os_messages', filter: `room_id=eq.${roomId}` },
        (payload: any) => {
          const row = payload.new as Record<string, unknown>;
          // Own messages are handled by onSettled refetch; skip to avoid transient duplicate
          if (row.sender_merchant_id === actorId) return;
          qc.setQueryData(['chat', 'messages', roomId], (old: CacheMsg[] | undefined) => {
            const existing = old ?? [];
            if (existing.some((m) => m.id === row.id)) return existing; // strict dedup
            return [...existing, normalizeRealtimeRow(row)];
          });
          // Keep sidebar last-message preview fresh
          qc.invalidateQueries({ queryKey: ['chat', 'rooms'] });
        },
      )
      // read_at updates — sender sees ✓✓ turn blue when counterparty reads
      .on(
        'postgres_changes' as any,
        { event: 'UPDATE', schema: 'public', table: 'os_messages', filter: `room_id=eq.${roomId}` },
        (payload: any) => {
          const row = payload.new as Record<string, unknown>;
          qc.setQueryData(['chat', 'messages', roomId], (old: CacheMsg[] | undefined) => {
            if (!old) return old;
            return old.map((m) => m.id === row.id ? { ...m, ...row, body: row.content } : m);
          });
        },
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [roomId, actorId, qc]);

  // ── Send (BUG 2 FIX: onError restores snapshot) ───────────────��────────

  const send = useMutation({
    mutationFn: async (payload: {
      content: string;
      type?: string;
      bodyJson?: Record<string, unknown>;
      expiresAt?: string | null;
      replyToMessageId?: string | null;
    }) => {
      if (!roomId) throw new Error('No active room');
      const clientNonce = randomUUID();
      const res = await sendMessage({
        roomId,
        clientNonce,
        body: payload.content,
        messageType: payload.type ?? 'text',
        bodyJson: payload.bodyJson,
        expiresAt: payload.expiresAt,
        replyToMessageId: payload.replyToMessageId,
      });
      if (!res.ok) throw new Error(res.error ?? 'Send failed');
      return res.data;
    },

    onMutate: async (newMsg) => {
      await qc.cancelQueries({ queryKey: ['chat', 'messages', roomId] });
      const previous = qc.getQueryData(['chat', 'messages', roomId]);
      qc.setQueryData(['chat', 'messages', roomId], (old: CacheMsg[] | undefined) => [
        ...(old ?? []),
        {
          id: `temp-${Date.now()}`,
          room_id: roomId,
          sender_id: actorId,
          sender_merchant_id: actorId,
          content: newMsg.content,
          body: newMsg.content,
          body_json: newMsg.bodyJson ?? {},
          message_type: newMsg.type ?? 'text',
          status: 'sending',
          created_at: new Date().toISOString(),
          read_at: null,
        },
      ]);
      return { previous };
    },

    // BUG 2 FIX: restore previous cache and alert the user
    onError: (_err, _vars, context: { previous: unknown } | undefined) => {
      if (context?.previous !== undefined) {
        qc.setQueryData(['chat', 'messages', roomId], context.previous);
      }
      toast.error('Message failed to send — please try again');
    },

    onSettled: () => {
      qc.invalidateQueries({ queryKey: ['chat', 'messages', roomId] });
    },
  });

  // ── Mark read ──────────────────────────────────────────────────────────

  const read = useMutation({
    mutationFn: async (messageId: string) => {
      if (!roomId) return false;
      const res = await markMessagesReadUpTo(roomId, messageId);
      return res.ok;
    },
    onMutate: async (messageId: string) => {
      if (!roomId) return;
      qc.setQueryData(['chat', 'messages', roomId], (old: CacheMsg[] | undefined) => {
        if (!old) return old;
        const target = old.find((m) => m.id === messageId);
        if (!target) return old;
        const cutoff = new Date(target.created_at as string).getTime();
        const readAt = new Date().toISOString();
        return old.map((m) =>
          new Date(m.created_at as string).getTime() <= cutoff && !m.read_at
            ? { ...m, read_at: readAt }
            : m,
        );
      });
      setRoomUnreadCountInCache(qc, roomId, 0);
    },
    onSettled: () => {
      qc.invalidateQueries({ queryKey: ['chat', 'messages', roomId] });
      qc.invalidateQueries({ queryKey: ['chat', 'rooms'] });
    },
  });

  // ── Delete for me (local optimistic — BUG 3 partial fix) ──────────────

  const deleteForMe = useCallback((messageId: string) => {
    qc.setQueryData(['chat', 'messages', roomId], (old: CacheMsg[] | undefined) => {
      if (!old) return old;
      return old.filter((m) => m.id !== messageId);
    });
  }, [qc, roomId]);

  return { ...query, send, read, deleteForMe };
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useCallStore } from '@/lib/call-store';
import { toast } from 'sonner';

interface Props {
  roomId: string | null;
  userId: string;
  onTimelineEvent?: (eventType: string) => void;
}

const CALL_TIMEOUT_MS = 30_000;

export function useWebRTC({ roomId, userId, onTimelineEvent }: Props) {
  const { callState, isIncoming, activeSessionId, callerId, isVideo, setCall, resetCall } = useCallStore();
  const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);
  const [localStream, setLocalStream] = useState<MediaStream | null>(null);

  const pcRef = useRef<RTCPeerConnection | null>(null);
  const channelRef = useRef<any>(null);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const cleanup = useCallback((reason: string = 'ended') => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    pcRef.current?.close();
    pcRef.current = null;
    localStream?.getTracks().forEach((t) => t.stop());
    setLocalStream(null);
    setRemoteStream(null);
    if (reason !== 'silent') onTimelineEvent?.(reason);
    resetCall();
  }, [localStream, resetCall, onTimelineEvent]);

  const setupPC = useCallback((sessionId: string) => {
    const pc = new RTCPeerConnection({
      iceServers: [{ urls: 'stun:stun.l.google.com:19302' }],
    });

    pc.onicecandidate = (e) => {
      if (e.candidate && roomId) {
        channelRef.current?.send({
          type: 'broadcast',
          event: 'candidate',
          payload: { candidate: e.candidate, sessionId, from: userId },
        });
      }
    };

    pc.ontrack = (e) => {
      if (e.streams[0]) setRemoteStream(e.streams[0]);
    };

    pc.onconnectionstatechange = () => {
      if (pc.connectionState === 'connected') setCall('connected', isIncoming, callerId, sessionId, isVideo);
      if (pc.connectionState === 'failed' || pc.connectionState === 'disconnected') cleanup('call_failed');
    };

    pcRef.current = pc;
    return pc;
  }, [roomId, userId, setCall, isIncoming, callerId, isVideo, cleanup]);

  const initiateCall = useCallback(async (is_video: boolean) => {
    if (!roomId) return;
    try {
      const sessionId = Math.random().toString(36).slice(2);
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: is_video });
      setLocalStream(stream);
      setCall('ringing', false, userId, sessionId, is_video);
      
      const pc = setupPC(sessionId);
      stream.getTracks().forEach((t) => pc.addTrack(t, stream));

      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);

      channelRef.current?.send({
        type: 'broadcast',
        event: 'offer',
        payload: { offer, sessionId, from: userId, is_video },
      });

      timeoutRef.current = setTimeout(() => cleanup('call_missed'), CALL_TIMEOUT_MS);
    } catch (err) {
      toast.error("Microphone/Camera access denied");
    }
  }, [roomId, userId, setupPC, setCall, cleanup]);

  const acceptCall = useCallback(async () => {
    if (!activeSessionId || !pcRef.current) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: isVideo });
      setLocalStream(stream);
      stream.getTracks().forEach((t) => pcRef.current?.addTrack(t, stream));
      
      const answer = await pcRef.current.createAnswer();
      await pcRef.current.setLocalDescription(answer);

      channelRef.current?.send({
        type: 'broadcast',
        event: 'answer',
        payload: { answer, sessionId: activeSessionId, from: userId },
      });
    } catch (err) {
      cleanup('call_failed');
    }
  }, [activeSessionId, isVideo, userId, cleanup]);

  const toggleMute = useCallback((muted: boolean) => {
    localStream?.getAudioTracks().forEach(t => t.enabled = !muted);
  }, [localStream]);

  useEffect(() => {
    if (!roomId) return;
    const channel = supabase.channel(`room:${roomId}:calls`);
    
    channel
      .on('broadcast', { event: 'offer' }, async ({ payload }) => {
        if (payload.from === userId) return;
        setCall('ringing', true, payload.from, payload.sessionId, payload.is_video);
        const pc = setupPC(payload.sessionId);
        await pc.setRemoteDescription(new RTCSessionDescription(payload.offer));
      })
      .on('broadcast', { event: 'answer' }, async ({ payload }) => {
        if (payload.from !== userId && pcRef.current) {
          await pcRef.current.setRemoteDescription(new RTCSessionDescription(payload.answer));
        }
      })
      .on('broadcast', { event: 'candidate' }, async ({ payload }) => {
        if (payload.from !== userId && pcRef.current) {
          await pcRef.current.addIceCandidate(new RTCIceCandidate(payload.candidate));
        }
      })
      .on('broadcast', { event: 'hangup' }, () => cleanup('call_ended'))
      .subscribe();

    channelRef.current = channel;

    return () => {
      supabase.removeChannel(channel);
      // BUG 6 FIX: close the RTCPeerConnection when room changes.
      // Previously only the signalling channel was removed, leaving orphaned
      // peer connections and media streams accumulating across room switches.
      if (pcRef.current) {
        pcRef.current.close();
        pcRef.current = null;
      }
    };
  }, [roomId, userId, setupPC, setCall, cleanup]);

  return { callState, isIncoming, callerId, remoteStream, initiateCall, acceptCall, endCall: () => cleanup('call_ended'), toggleMute };
}

export type MessageStatus = 'sending' | 'sent' | 'delivered' | 'read' | 'failed';
export type RoomKind = 'direct' | 'group' | 'system';
export type CallStatus = 'ringing' | 'active' | 'ended' | 'missed' | 'cancelled';

export interface ChatCallSession {
  id: string;
  room_id: string;
  initiated_by: string;
  status: CallStatus;
  started_at: string;
  ended_at?: string;
}

export type InboxLane = 'Personal' | 'Team' | 'Customers' | 'Deals' | 'Alerts' | 'Archived';

export interface SecurityPolicies {
  disable_forwarding: boolean;
  disable_copy: boolean;
  disable_export: boolean;
  watermark: boolean;
}

export type RetentionPolicy = 'indefinite' | '30d' | '7d' | '24h' | 'view_once';

export interface ChatRoom {
  room_id: string;
  kind: RoomKind;
  lane: InboxLane;
  title: string | null;
  relationship_id: string | null;
  member_role: 'owner' | 'admin' | 'member';
  unread_count: number;
  last_message_id: string | null;
  last_message_body: string | null;
  last_message_at: string | null;
  updated_at: string;
  security_policies?: SecurityPolicies;
  retention_policy?: RetentionPolicy;
  type?: 'standard' | 'broadcast' | 'approval' | 'incident' | 'deal' | 'temporary';
}

export interface ChatMessage {
  id: string;
  room_id: string;
  sender_id: string;
  sender_identity_id?: string;
  body: string;
  body_json: Record<string, unknown>;
  message_type: string;
  status: MessageStatus;
  reply_to_message_id: string | null;
  client_nonce: string | null;
  created_at: string;
  delivered_at: string | null;
  deleted_for_everyone_at: string | null;
  expires_at?: string;
  permissions?: {
    forwardable: boolean;
    exportable: boolean;
    copyable: boolean;
    ai_readable: boolean;
  };
  metadata?: {
    is_edited?: boolean;
    edited_at?: string;
    vanish_at?: string;
    is_forwarded?: boolean;
    original_sender_name?: string;
    voice_duration?: number;
    poll_question?: string;
    poll_options?: string[];
  };
}

export interface ChatBusinessObject {
  id: string;
  room_id: string;
  type: 'business_object';
  object_type: 'order' | 'payment' | 'agreement' | 'dispute' | 'task' | 'deal_offer' | 'snapshot';
  source_message_id?: string;
  created_by: string;
  state_snapshot_hash?: string; 
  payload: any;
  status: 'pending' | 'accepted' | 'rejected' | 'completed' | 'locked';
  created_at: string;
}

export type TimelineItem = (ChatMessage & { type?: 'message' }) | ChatBusinessObject;

export interface DeterministicResult<T> {
  ok: boolean;
  data: T;
  error: string | null;
}

export function ok<T>(data: T): DeterministicResult<T> {
  return { ok: true, data, error: null };
}

export function fail<T>(fallback: T, error: unknown): DeterministicResult<T> {
  const msg = error instanceof Error ? error.message : String(error ?? 'Unknown error');
  return { ok: false, data: fallback, error: msg };
}

/**
 * ChatWorkspacePage
 *
 * BUG 3 FIX: Wire real reaction mutations (addReaction/removeReaction RPCs exist)
 *            and real deleteForMe (local cache removal). Previously all callbacks
 *            were () => {} stubs so every interaction was silently dropped.
 *
 * BUG 9 FIX: /pnl command reads actual tracker KPIs instead of sending the
 *            hardcoded "+2.4% | Volume: 45k USDT" string.
 */

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import { useIsMobile } from '@/hooks/use-mobile';
import { useRooms } from '@/features/chat/hooks/useRooms';
import { useRoomMessages } from '@/features/chat/hooks/useRoomMessages';
import { useUnreadState } from '@/features/chat/hooks/useUnreadState';
import { ConversationSidebar } from '@/features/chat/components/ConversationSidebar';
import { ConversationHeader } from '@/features/chat/components/ConversationHeader';
import { MessageComposer } from '@/features/chat/components/MessageComposer';
import { MessageList } from '@/features/chat/components/MessageList';
import { CallOrchestrator } from '@/features/chat/components/CallOrchestrator';
import { ContextPanel } from '@/features/chat/components/ContextPanel';
import { SecureWatermark } from '@/features/chat/components/SecureWatermark';
import { useWebRTC } from '@/features/chat/hooks/useWebRTC';
import { useChatStore } from '@/lib/chat-store';
import { addReaction, removeReaction } from '@/features/chat/api/reactions';
import { useTrackerState } from '@/lib/useTrackerState';
import { kpiFor, fmtU, fmtPct } from '@/lib/tracker-helpers';
import { useTheme } from '@/lib/theme-context';
import { Shield } from 'lucide-react';
import { toast } from 'sonner';

export default function ChatWorkspacePage() {
  const [searchParams] = useSearchParams();
  const navigate       = useNavigate();
  const qc             = useQueryClient();
  const { userId: authUserId, merchantProfile } = useAuth();
  const userId  = merchantProfile?.merchant_id || authUserId || '';
  const isMobile = useIsMobile();
  const { settings } = useTheme();

  const roomsQuery = useRooms();
  const rooms = roomsQuery.data ?? [];

  const [activeRoomId, setActiveRoomId] = useState<string | null>(searchParams.get('roomId'));
  const [showContext,  setShowContext]  = useState(!isMobile);
  const [showSidebar,  setShowSidebar]  = useState(true);

  const setActiveConversation = useChatStore((s) => s.setActiveConversation);

  // Auto-select first room if none chosen
  useEffect(() => {
    if (!activeRoomId && rooms.length > 0) {
      setActiveRoomId(String(rooms[0].room_id));
    }
  }, [rooms, activeRoomId]);

  useEffect(() => {
    setActiveConversation(activeRoomId);
  }, [activeRoomId, setActiveConversation]);

  // ── Messages ─────────────────────────────────────────────────────────────

  const messages = useRoomMessages(activeRoomId);
  const { firstUnreadMessageId: firstUnread } = useUnreadState(activeRoomId);

  // ── BUG 9 FIX: real P&L for /pnl command ─────────────────────────────────

  const { state: trackerState, derived } = useTrackerState({
    lowStockThreshold:   settings.lowStockThreshold,
    priceAlertThreshold: settings.priceAlertThreshold,
    range:               settings.range,
    currency:            settings.currency,
  });

  const pnlSummary = useMemo(() => {
    const d = kpiFor(trackerState, derived, settings.range);
    const stock = fmtU(derived.stockBalance);
    const net   = `${d.net >= 0 ? '+' : ''}${fmtU(d.net)} USDT`;
    const margin = fmtPct(d.count > 0 ? d.net / Math.max(d.rev, 1) : 0);
    const trades = d.count;
    return `Net P&L: ${net} · Margin: ${margin} · Trades: ${trades} · Stock: ${stock} USDT`;
  }, [trackerState, derived, settings.range]);

  // ── BUG 3 FIX: reaction mutations ────────────────────────────────────────

  // Track reactions per message in local state (loaded per room)
  const [reactionsByMessage, setReactionsByMessage] = useState<Record<string, Record<string, string[]>>>({});

  // Load reactions when room changes
  useEffect(() => {
    if (!activeRoomId) return;
    (async () => {
      const { addReaction: _a, removeReaction: _r, getMessageReactions } = await import('@/features/chat/api/reactions');
      const res = await getMessageReactions(activeRoomId);
      if (!res.ok) return;
      const grouped: Record<string, Record<string, string[]>> = {};
      for (const r of res.data) {
        if (!grouped[r.message_id]) grouped[r.message_id] = {};
        if (!grouped[r.message_id][r.reaction]) grouped[r.message_id][r.reaction] = [];
        grouped[r.message_id][r.reaction].push(r.user_id);
      }
      setReactionsByMessage(grouped);
    })();
  }, [activeRoomId]);

  const handleReact = useCallback(async (messageId: string, emoji: string) => {
    if (!activeRoomId) return;
    const existing = reactionsByMessage[messageId]?.[emoji] ?? [];
    const alreadyReacted = existing.includes(userId);

    // Optimistic update
    setReactionsByMessage((prev) => {
      const msgReactions = { ...(prev[messageId] ?? {}) };
      if (alreadyReacted) {
        msgReactions[emoji] = (msgReactions[emoji] ?? []).filter((u) => u !== userId);
      } else {
        msgReactions[emoji] = [...(msgReactions[emoji] ?? []), userId];
      }
      return { ...prev, [messageId]: msgReactions };
    });

    // Persist
    const res = alreadyReacted
      ? await removeReaction(activeRoomId, messageId, emoji)
      : await addReaction(activeRoomId, messageId, emoji);

    if (!res.ok) {
      toast.error('Reaction failed');
      // Rollback optimistic update
      setReactionsByMessage((prev) => {
        const msgReactions = { ...(prev[messageId] ?? {}) };
        if (alreadyReacted) {
          msgReactions[emoji] = [...(msgReactions[emoji] ?? []), userId];
        } else {
          msgReactions[emoji] = (msgReactions[emoji] ?? []).filter((u) => u !== userId);
        }
        return { ...prev, [messageId]: msgReactions };
      });
    }
  }, [activeRoomId, userId, reactionsByMessage]);

  // ── BUG 3 FIX: delete for me (local cache removal, exported from hook) ───

  const handleDeleteForMe = useCallback((messageId: string) => {
    messages.deleteForMe(messageId);
  }, [messages]);

  // ── WebRTC ────────────────────────────────────────────────────────────────

  const {
    callState, isIncoming, callerId, remoteStream,
    initiateCall, acceptCall, endCall, toggleMute,
  } = useWebRTC({
    roomId: activeRoomId,
    userId,
    onTimelineEvent: (type) => messages.send.mutate({
      content: `||SYS_CALL||${type}||/SYS_CALL||`,
      type: 'system',
    }),
  });

  // ── Relationship metadata (for header title) ──────────────────────────────

  const { data: relationship } = useQuery({
    queryKey: ['chat-relationship', activeRoomId],
    queryFn: async () => {
      if (!activeRoomId) return null;
      const { data: rel } = await supabase
        .from('merchant_relationships')
        .select('*')
        .eq('id', activeRoomId)
        .maybeSingle();
      if (!rel) return null;
      const cpId = rel.merchant_a_id === merchantProfile?.merchant_id
        ? rel.merchant_b_id
        : rel.merchant_a_id;
      const { data: cp } = await supabase
        .from('merchant_profiles')
        .select('display_name, nickname')
        .eq('merchant_id', cpId)
        .maybeSingle();
      return {
        ...rel,
        counterparty_name:     cp?.display_name || cpId,
        counterparty_nickname: cp?.nickname     || cpId,
      };
    },
    enabled: !!activeRoomId && !!merchantProfile,
  });

  // ─────────────────────────────────────────────────────────────────────────

  return (
    <div className="flex h-screen w-full overflow-hidden bg-background select-none">
      <CallOrchestrator
        callState={callState} isIncoming={isIncoming} callerId={callerId}
        remoteStream={remoteStream} acceptCall={acceptCall} rejectCall={endCall}
        toggleMute={toggleMute} endCall={endCall}
      />

      {/* Col 1: Inbox */}
      {(!isMobile || showSidebar) && (
        <ConversationSidebar
          rooms={rooms}
          activeRoomId={activeRoomId}
          onSelectRoom={(id) => { setActiveRoomId(id); if (isMobile) setShowSidebar(false); }}
          currentUserId={userId}
          isMobile={isMobile}
        />
      )}

      {/* Col 2: Timeline */}
      {(!isMobile || !showSidebar) && (
        <main className="flex-1 flex flex-col min-w-0 bg-background border-l border-border relative">
          {activeRoomId ? (
            <>
              <ConversationHeader
                title={relationship?.counterparty_name}
                onDashboardToggle={() => setShowContext(!showContext)}
                onCallVoice={() => initiateCall(false)}
                onCallVideo={() => initiateCall(true)}
                onBack={isMobile ? () => setShowSidebar(true) : undefined}
                showDashboard={showContext}
              />
              <div className="flex-1 overflow-hidden relative flex flex-col">
                <SecureWatermark enabled={true} />
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                  <MessageList
                    messages={messages.data ?? []}
                    currentUserId={userId}
                    unreadMessageId={firstUnread}
                    reactionsByMessage={reactionsByMessage[activeRoomId ?? ''] as any ?? {}}
                    pinnedSet={new Set()}
                    onReact={handleReact}                  // BUG 3 FIX: wired
                    onPinToggle={() => {}}                 // needs backend: fn_chat_pin_message RPC
                    onMarkRead={(id) => messages.read.mutate(id)}
                    onDeleteForMe={handleDeleteForMe}      // BUG 3 FIX: wired
                    onDeleteForEveryone={() => {}}         // needs backend: fn_chat_delete_message RPC
                    onCreateOrder={() => navigate('/trading/orders?new=true')}
                    onCreateTask={() => navigate('/trading/orders')}
                  />
                </div>
                <MessageComposer
                  sending={messages.send.isPending}
                  onTyping={() => {}}
                  onSend={(p) => messages.send.mutate(p)}
                  pnlSummary={pnlSummary}                 // BUG 9 FIX: real data
                />
              </div>
            </>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center space-y-4 opacity-40">
              <Shield size={48} className="text-muted-foreground" />
              <p className="text-[10px] font-black uppercase tracking-[0.3em]">Secure Environment Ready</p>
            </div>
          )}
        </main>
      )}

      {/* Col 3: Context panel */}
      {!isMobile && showContext && activeRoomId && (
        <ContextPanel relationship={relationship ?? null} />
      )}
    </div>
  );
}

// ─── Global Agreements Tab ──────────────────────────────────────────
// Rendered in MerchantsPage's Agreements tab. Shows all agreements
// across relationships and allows creating new ones with a relationship picker.
// Now includes inline View/Edit/Expire/Reject actions matching the workspace.

import React, { useState, useMemo } from 'react';
import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { isAgreementActive } from '@/lib/deal-engine';
import { fmtU, getWACOP, fmtQWithUnit } from '@/lib/tracker-helpers';
import { useTrackerState } from '@/lib/useTrackerState';
import { AgreementsTab } from './AgreementsTab';
import { useUpdateAgreementStatus } from '@/hooks/useProfitShareAgreements';
import { calculateOperatorPriorityProfit } from '@/lib/trading/operator-priority';
import { toast } from 'sonner';
import type { ProfitShareAgreement } from '@/types/domain';
import { useTheme } from '@/lib/theme-context';

interface Props {
  relationships: any[];
  allAgreements: ProfitShareAgreement[];
  activeAgreementCount: number;
  onOpenRelationship: (id: string) => void;
}

export function AgreementsGlobalTab({ relationships, allAgreements, activeAgreementCount, onOpenRelationship }: Props) {
  const t = useT();
  const { settings } = useTheme();
  const { userId, merchantProfile } = useAuth();
  const myMerchantId = merchantProfile?.merchant_id;
  const [createForRelId, setCreateForRelId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [simProfit, setSimProfit] = useState<string>('1000');
  const updateStatus = useUpdateAgreementStatus();

  const selectedRel = relationships.find((r: any) => r.id === createForRelId);

  // FIFO avg buy price for QAR↔USDT conversion
  const { derived } = useTrackerState({});
  const avgRate = useMemo(() => getWACOP(derived), [derived]);

  const agreementDisplayLabel = (a: ProfitShareAgreement) => {
    if ((a as any).agreement_type === 'operator_priority') {
      return `⚙️ ${t('operatorPriorityLabel')} · ${(a as any).operator_ratio ?? 0}% ${t('feeLabel')}`;
    }
    return `🤝 ${a.partner_ratio}/${a.merchant_ratio}`;
  };

  const cadenceLabel = (c: string) =>
    c === 'per_order' ? t('perOrderCadence') : c === 'weekly' ? t('weeklyCadence') : t('monthlyCadence');

  const handleExpire = async (id: string) => {
    try {
      await updateStatus.mutateAsync({ agreementId: id, status: 'expired' });
      toast.success(t('agreementExpiredSuccess'));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleReject = async (id: string) => {
    try {
      await updateStatus.mutateAsync({ agreementId: id, status: 'rejected' });
      toast.success(t('agreementRejectedSuccess'));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleApprove = async (id: string) => {
    try {
      await updateStatus.mutateAsync({ agreementId: id, status: 'approved' });
      toast.success(t('agreementApprovedSuccess'));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  // ─── Simulator Panel (mirrors workspace) ──
  const renderSimPanel = (a: any, cpName: string) => {
    const gross = parseFloat(simProfit) || 0;
    const fifoRate = avgRate ?? 0;
    const isOpPriority = a.agreement_type === 'operator_priority';
    const opRatio = a.operator_ratio ?? 0;
    const opContrib = a.operator_contribution ?? 0;
    const lnContrib = a.lender_contribution ?? 0;
    const investedCap = a.invested_capital ?? 0;
    const opDefault = a.operator_default_profit_handling ?? 'reinvest';
    const cpDefault = a.counterparty_default_profit_handling ?? 'withdraw';
    const isOperator = a.operator_merchant_id === myMerchantId;

    let myShare = 0, partnerShare = 0, opFee = 0, remaining = 0;
    let myPct = 0, partnerPct = 0;
    let myHandling = '', partnerHandling = '';

    if (isOpPriority) {
      const result = calculateOperatorPriorityProfit({
        grossProfit: gross,
        operatorRatio: opRatio,
        operatorContribution: opContrib,
        lenderContribution: lnContrib,
      });
      opFee = result.operatorFee;
      remaining = result.remainingProfit;
      if (isOperator) {
        myShare = result.operatorTotal; partnerShare = result.lenderTotal;
        myPct = result.operatorWeightPct; partnerPct = result.lenderWeightPct;
        myHandling = opDefault; partnerHandling = cpDefault;
      } else {
        myShare = result.lenderTotal; partnerShare = result.operatorTotal;
        myPct = result.lenderWeightPct; partnerPct = result.operatorWeightPct;
        myHandling = cpDefault; partnerHandling = opDefault;
      }
    } else {
      const mRatio = a.merchant_ratio ?? 50;
      const pRatio = a.partner_ratio ?? 50;
      const isCreator = a.created_by === userId;
      myShare = gross * (isCreator ? mRatio : pRatio) / 100;
      partnerShare = gross * (isCreator ? pRatio : mRatio) / 100;
      myPct = isCreator ? mRatio : pRatio;
      partnerPct = isCreator ? pRatio : mRatio;
      remaining = gross;
      const sw = a.settlement_way || 'withdraw';
      myHandling = sw; partnerHandling = sw;
    }

    const myReinvested = myHandling === 'reinvest' ? myShare : 0;
    const myWithdrawn = myHandling === 'withdraw' ? myShare : 0;
    const partnerReinvested = partnerHandling === 'reinvest' ? partnerShare : 0;
    const partnerWithdrawn = partnerHandling === 'withdraw' ? partnerShare : 0;
    const myCurrentCap = isOpPriority ? (isOperator ? opContrib : lnContrib) : investedCap;
    const partnerCurrentCap = isOpPriority ? (isOperator ? lnContrib : opContrib) : investedCap;
    const totalCap = isOpPriority ? opContrib + lnContrib : investedCap;
    const myShareQar = myShare * fifoRate;
    const partnerShareQar = partnerShare * fifoRate;

    const panelStyle: React.CSSProperties = {
      padding: '12px 16px', background: 'color-mix(in srgb, var(--brand) 4%, var(--surface))',
      border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)',
      borderRadius: 6, margin: '4px 0 8px',
    };
    const gridStyle: React.CSSProperties = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px 16px', fontSize: 10 };
    const lblStyle: React.CSSProperties = { color: 'var(--muted)', fontSize: 9 };
    const valStyle: React.CSSProperties = { fontWeight: 700, fontSize: 11 };
    const sectionTitle: React.CSSProperties = { fontSize: 10, fontWeight: 700, color: 'var(--brand)', marginTop: 10, marginBottom: 4, textTransform: 'uppercase', letterSpacing: '.5px' };

    return (
      <div style={panelStyle}>
        {/* Agreement Details */}
        <div style={{ ...sectionTitle, marginTop: 0 }}>📋 {t('agreementDetails')}</div>
        <div style={gridStyle}>
          <div><span style={lblStyle}>{t('simType')}</span><br /><span style={valStyle}>{isOpPriority ? 'Operator Priority' : 'Standard'}</span></div>
          <div><span style={lblStyle}>{t('simSettlementCadence')}</span><br /><span style={valStyle}>{cadenceLabel(a.settlement_cadence)}</span></div>
          <div><span style={lblStyle}>{t('simEffectiveFrom')}</span><br /><span style={valStyle}>{new Date(a.effective_from).toLocaleDateString()}</span></div>
          <div><span style={lblStyle}>{t('simInvestedCapital')}</span><br /><span style={valStyle}>{fmtU(totalCap)} USDT</span></div>
          {isOpPriority && (
            <>
              <div><span style={lblStyle}>{t('simOperator')} ({isOperator ? t('you') : cpName})</span><br /><span style={valStyle}>{fmtU(opContrib)} USDT · {opRatio}% {t('fee')}</span></div>
              <div><span style={lblStyle}>{t('simLender')} ({!isOperator ? t('you') : cpName})</span><br /><span style={valStyle}>{fmtU(lnContrib)} USDT</span></div>
            </>
          )}
          <div><span style={lblStyle}>{t('simDefaultHandling')} ({t('you')})</span><br /><span style={valStyle}>{myHandling === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}</span></div>
          <div><span style={lblStyle}>{t('simDefaultHandling')} ({cpName})</span><br /><span style={valStyle}>{partnerHandling === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}</span></div>
        </div>

        {/* Conversion Info */}
        <div style={sectionTitle}>💱 {t('simConversionRate')}</div>
        <div style={gridStyle}>
          <div><span style={lblStyle}>{t('simFifoRate')}</span><br /><span style={valStyle}>{fifoRate > 0 ? `1 USDT = ${fifoRate.toFixed(4)} QAR` : '—'}</span></div>
          <div><span style={lblStyle}>{t('source')}</span><br /><span style={{ ...valStyle, color: fifoRate > 0 ? 'var(--good)' : 'var(--muted)' }}>{fifoRate > 0 ? 'FIFO Stock Avg Buy' : t('noRateAvailable')}</span></div>
        </div>

        {/* What-If Simulator */}
        <div style={sectionTitle}>🧮 {t('simulatorTitle')}</div>
        <div style={{ marginBottom: 8, fontSize: 9, color: 'var(--muted)' }}>{t('simEnterProfit')}</div>
        <input
          type="number"
          value={simProfit}
          onChange={e => setSimProfit(e.target.value)}
          placeholder="e.g. 9000"
          style={{ width: 160, marginBottom: 8, padding: '4px 8px', borderRadius: 4, border: '1px solid color-mix(in srgb, var(--muted) 30%, transparent)', background: 'var(--surface)', color: 'var(--foreground)', fontSize: 12, fontWeight: 700 }}
        />

        {gross > 0 && (
          <div style={{ background: 'color-mix(in srgb, var(--surface) 80%, transparent)', borderRadius: 6, padding: 10, border: '1px solid color-mix(in srgb, var(--muted) 10%, transparent)' }}>
            {isOpPriority && (
              <div style={{ marginBottom: 8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10 }}>
                  <span style={lblStyle}>{t('simOperatorFee')} ({opRatio}%)</span>
                  <span style={{ color: 'var(--warn)', fontWeight: 700 }}>{fmtU(opFee)} USDT</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10 }}>
                  <span style={lblStyle}>{t('simRemainingProfit')}</span>
                  <span style={{ fontWeight: 700 }}>{fmtU(remaining)} USDT</span>
                </div>
                <div style={{ height: 1, background: 'color-mix(in srgb, var(--muted) 15%, transparent)', margin: '6px 0' }} />
              </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
              {/* My share */}
              <div style={{ padding: 8, borderRadius: 4, background: 'color-mix(in srgb, var(--good) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--good) 15%, transparent)' }}>
                <div style={{ fontSize: 9, color: 'var(--muted)', marginBottom: 2 }}>{t('simMyShare')} ({myPct}%{isOpPriority ? ` ${t('simWeight')}` : ''})</div>
                <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--good)' }}>{fmtU(myShare)} USDT</div>
                {fifoRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round(myShareQar).toLocaleString()} QAR</div>}
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 4 }}>
                  {myHandling === 'reinvest' ? `🔄 ${t('simReinvestedCapital')}: ${fmtU(myReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(myWithdrawn)}`}
                </div>
              </div>
              {/* Partner share */}
              <div style={{ padding: 8, borderRadius: 4, background: 'color-mix(in srgb, var(--brand) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)' }}>
                <div style={{ fontSize: 9, color: 'var(--muted)', marginBottom: 2 }}>{cpName} ({partnerPct}%{isOpPriority ? ` ${t('simWeight')}` : ''})</div>
                <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--brand)' }}>{fmtU(partnerShare)} USDT</div>
                {fifoRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round(partnerShareQar).toLocaleString()} QAR</div>}
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 4 }}>
                  {partnerHandling === 'reinvest' ? `🔄 ${t('simReinvestedCapital')}: ${fmtU(partnerReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(partnerWithdrawn)}`}
                </div>
              </div>
            </div>

            {/* Capital projection per party */}
            <div style={{ marginTop: 8 }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--foreground)', marginBottom: 6 }}>📊 {t('simCapitalProjection')}</div>
              <div style={{ padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--muted) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--muted) 12%, transparent)', marginBottom: 6 }}>
                <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('simTotalInvestedCapital')}</div>
                <div style={{ fontSize: 13, fontWeight: 700 }}>{fmtU(totalCap)} USDT</div>
                {fifoRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round(totalCap * fifoRate).toLocaleString()} QAR</div>}
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
                <div style={{ padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--good) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--good) 12%, transparent)' }}>
                  <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('you')} — {t('simReinvestedCapital')}</div>
                  <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 2 }}>{t('simCurrentCapital')}: <strong>{fmtU(myCurrentCap)}</strong></div>
                  <div style={{ fontSize: 9, color: myReinvested > 0 ? 'var(--good)' : 'var(--muted)', marginTop: 1 }}>
                    {myHandling === 'reinvest' ? `🔄 +${fmtU(myReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(myWithdrawn)}`}
                  </div>
                  <div style={{ fontSize: 11, fontWeight: 700, marginTop: 2, color: 'var(--good)' }}>→ {fmtU(myCurrentCap + myReinvested)} USDT</div>
                </div>
                <div style={{ padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--brand) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--brand) 12%, transparent)' }}>
                  <div style={{ fontSize: 9, color: 'var(--muted)' }}>{cpName} — {t('simReinvestedCapital')}</div>
                  <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 2 }}>{t('simCurrentCapital')}: <strong>{fmtU(partnerCurrentCap)}</strong></div>
                  <div style={{ fontSize: 9, color: partnerReinvested > 0 ? 'var(--brand)' : 'var(--muted)', marginTop: 1 }}>
                    {partnerHandling === 'reinvest' ? `🔄 +${fmtU(partnerReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(partnerWithdrawn)}`}
                  </div>
                  <div style={{ fontSize: 11, fontWeight: 700, marginTop: 2, color: 'var(--brand)' }}>→ {fmtU(partnerCurrentCap + partnerReinvested)} USDT</div>
                </div>
              </div>
              {(myReinvested > 0 || partnerReinvested > 0) && (
                <div style={{ marginTop: 6, padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--warn) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--warn) 15%, transparent)' }}>
                  <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('simNewCapitalBase')}</div>
                  <div style={{ fontSize: 12, fontWeight: 700 }}>
                    {fmtU(totalCap)} + {fmtU(myReinvested + partnerReinvested)} = <span style={{ color: 'var(--good)' }}>{fmtU(totalCap + myReinvested + partnerReinvested)} USDT</span>
                  </div>
                  {fifoRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round((totalCap + myReinvested + partnerReinvested) * fifoRate).toLocaleString()} QAR</div>}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    );
  };

  return (
    <>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8, flexWrap: 'wrap', gap: 8 }}>
        <div>
          <div style={{ fontSize: 12, fontWeight: 700 }}>💛 {t('profitShareAgreements')}</div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>
            {t('standingAgreementsAllRels')} · {activeAgreementCount} {t('active')}
          </div>
        </div>

        {!createForRelId ? (
          <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
            <select
              id="rel-picker"
              style={{
                padding: '6px 10px', fontSize: 10, borderRadius: 4,
                border: '1px solid var(--line)', background: 'var(--bg)', color: 'var(--t1)',
                maxWidth: 200,
              }}
              defaultValue=""
              onChange={e => { if (e.target.value) setCreateForRelId(e.target.value); }}
            >
              <option value="" disabled>{t('selectMerchant')}</option>
              {relationships.filter((r: any) => r.status === 'active').map((r: any) => (
                <option key={r.id} value={r.id}>{r.counterparty_name}</option>
              ))}
            </select>
            <span style={{ fontSize: 9, color: 'var(--muted)' }}>← {t('pickToCreateAgreement')}</span>
          </div>
        ) : (
          <button className="btn secondary" onClick={() => setCreateForRelId(null)} style={{ fontSize: 10 }}>
            ✕ {t('close')}
          </button>
        )}
      </div>

      {createForRelId && selectedRel && (
        <div style={{
          marginBottom: 12, padding: 12, borderRadius: 8,
          border: '1px solid var(--brand)',
          background: 'color-mix(in srgb, var(--brand) 3%, var(--cardBg))',
        }}>
          <div style={{ fontSize: 11, fontWeight: 700, marginBottom: 8 }}>
            📝 {t('newAgreement')} — {selectedRel.counterparty_name}
          </div>
          <AgreementsTab
            relationshipId={createForRelId}
            counterpartyName={selectedRel.counterparty_name}
            counterpartyMerchantId={
              selectedRel.merchant_a_id === myMerchantId
                ? selectedRel.merchant_b_id
                : selectedRel.merchant_a_id
            }
          />
        </div>
      )}

      <div style={{
        padding: '8px 12px', borderRadius: 6, fontSize: 10, lineHeight: 1.5, marginBottom: 10,
        background: 'color-mix(in srgb, var(--brand) 6%, transparent)',
        border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)',
        color: 'var(--muted)',
      }}>
        <strong style={{ color: 'var(--brand)' }}>{t('profitShareAgreementsGlobal')}</strong> {t('agreementsCreatedInWorkspace')}
      </div>

      {allAgreements.length === 0 && !createForRelId ? (
        <div className="empty">
          <div className="empty-t">{t('noAgreementsGlobal')}</div>
          <div className="empty-s">{t('selectMerchantAbove')}</div>
        </div>
      ) : allAgreements.length > 0 && (
        <div className="tableWrap">
          <table>
            <thead>
              <tr>
                <th>{t('merchant')}</th>
                <th>{t('agreement')}</th>
                <th>{t('cadence')}</th>
                <th>{t('effective')}</th>
                <th>{t('expires')}</th>
                <th>{t('status')}</th>
                <th>{t('actions')}</th>
              </tr>
            </thead>
            <tbody>
              {allAgreements.map(a => {
                const rel = relationships.find((r: any) => r.id === a.relationship_id);
                const cpName = rel?.counterparty_name || '—';
                const active = a.status === 'approved' && isAgreementActive(a);
                const isPending = a.status === 'pending';
                const isCreator = a.created_by === userId;
                const statusCls = active ? 'good' : isPending ? 'info' : a.status === 'rejected' ? 'bad' : 'warn';
                const statusLabel = active ? t('activeStatus') : isPending ? (t('pendingStatus' as any) || 'Pending') : a.status === 'rejected' ? t('rejectedStatus') : a.status === 'expired' ? t('expiredStatus') : t('inactiveStatus');
                const isExpanded = expandedId === a.id;

                return (
                  <React.Fragment key={a.id}>
                    <tr style={{ opacity: active || isPending ? 1 : 0.6 }}>
                      <td>
                        <div style={{ fontWeight: 700, fontSize: 11 }}>{cpName}</div>
                      </td>
                      <td>
                        <div style={{ fontWeight: 700, fontSize: 11 }}>
                          {agreementDisplayLabel(a)}
                        </div>
                        <div style={{ fontSize: 9, color: 'var(--muted)' }}>
                          {(a as any).agreement_type === 'operator_priority' ? (
                            <>{t('operatorFeeFirst')} {(a as any).operator_ratio}% · {t('thenCapitalSplit')}</>
                          ) : (
                            <>{t('partner')} {a.partner_ratio}% · {t('you')} {a.merchant_ratio}% · {t('capitalLabel')} {fmtQWithUnit((a as any).invested_capital ?? 0, settings.currency, avgRate)} · {(a as any).settlement_way ? ((a as any).settlement_way === 'reinvest' ? t('reinvestOption') : t('withdrawOption')) : '—'}</>
                          )}
                        </div>
                      </td>
                      <td style={{ fontSize: 10 }}>
                        {cadenceLabel(a.settlement_cadence)}
                      </td>
                      <td className="mono" style={{ fontSize: 10 }}>{new Date(a.effective_from).toLocaleDateString()}</td>
                      <td className="mono" style={{ fontSize: 10 }}>{a.expires_at ? new Date(a.expires_at).toLocaleDateString() : '—'}</td>
                      <td><span className={`pill ${statusCls}`}>{statusLabel}</span></td>
                      <td>
                        <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                          <button className="rowBtn" onClick={() => setExpandedId(isExpanded ? null : a.id)}>{t('viewDetailsAction')}</button>
                          {isPending && !isCreator && (
                            <button className="rowBtn" style={{ color: 'var(--good)', fontWeight: 700 }} onClick={() => handleApprove(a.id)}>{t('approveAction')}</button>
                          )}
                          {isPending && isCreator && rel && (
                            <button className="rowBtn" onClick={() => onOpenRelationship(rel.id)}>{t('editAction')}</button>
                          )}
                          {active && (
                            <button className="rowBtn" style={{ color: 'var(--warn)' }} onClick={() => handleExpire(a.id)}>{t('expireAction')}</button>
                          )}
                          {(active || isPending) && (
                            <button className="rowBtn" style={{ color: 'var(--bad)' }} onClick={() => handleReject(a.id)}>{t('rejectAction')}</button>
                          )}
                        </div>
                      </td>
                    </tr>
                    {isExpanded && (
                      <tr><td colSpan={7} style={{ padding: 0 }}>
                        {renderSimPanel(a, cpName)}
                      </td></tr>
                    )}
                  </React.Fragment>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </>
  );
}

// ─── Agreements Tab ─────────────────────────────────────────────────
// Manages Profit Share standing agreements for a merchant relationship.
// This is the ONLY place where profit share agreements are created.
// Agreements have 3 statuses: approved, rejected, expired.
// Supports two agreement types: standard and operator_priority.

import React, { useState, useMemo, useCallback } from 'react';
import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { fmtU, getWACOP, fmtQWithUnit } from '@/lib/tracker-helpers';
import { useTrackerState } from '@/lib/useTrackerState';
import {
  useProfitShareAgreements,
  useCreateAgreement,
  useUpdateAgreement,
  useUpdateAgreementStatus,
} from '@/hooks/useProfitShareAgreements';
import { isAgreementActive, getAgreementLabel } from '@/lib/deal-engine';
import { buildOperatorPrioritySnapshot, calculateOperatorPriorityProfit } from '@/lib/trading/operator-priority';
import type { ProfitShareAgreementType } from '@/types/domain';
import { buildSharedProfitShareFields } from '@/lib/profit-share-fields';
import { toast } from 'sonner';
import { useTheme } from '@/lib/theme-context';
import '@/styles/tracker.css';

interface Props {
  relationshipId: string;
  counterpartyName?: string;
  counterpartyMerchantId?: string;
}

export function AgreementsTab({ relationshipId, counterpartyName, counterpartyMerchantId }: Props) {
  const t = useT();
  const { settings } = useTheme();
  const { userId, merchantProfile } = useAuth();
  const { data: agreements = [], isLoading } = useProfitShareAgreements(relationshipId);
  const createAgreement = useCreateAgreement();
  const updateAgreement = useUpdateAgreement();
  const updateStatus = useUpdateAgreementStatus();

  const [showForm, setShowForm] = useState(false);
  const [agreementType, setAgreementType] = useState<ProfitShareAgreementType>('standard');
  const [partnerRatio, setPartnerRatio] = useState('50');
  const [cadence, setCadence] = useState<'monthly' | 'weekly' | 'per_order'>('monthly');
  const [effectiveFrom, setEffectiveFrom] = useState(() => new Date().toISOString().slice(0, 10));
  const [expiresAt, setExpiresAt] = useState('');
  const [notes, setNotes] = useState('');
  const [investedCapital, setInvestedCapital] = useState('');
  const [capitalCurrency, setCapitalCurrency] = useState<'USDT' | 'QAR'>('USDT');
  const [settlementWay, setSettlementWay] = useState<'reinvest' | 'withdraw'>('reinvest');

  // FIFO avg buy price for QAR↔USDT conversion
  const { derived } = useTrackerState({});
  const avgRate = useMemo(() => {
    return getWACOP(derived);
  }, [derived]);

  // Convert invested capital to USDT for storage
  const investedCapitalUsdt = useMemo(() => {
    const raw = parseFloat(investedCapital) || 0;
    if (capitalCurrency === 'USDT') return raw;
    if (!avgRate || avgRate <= 0) return 0;
    return Math.round((raw / avgRate) * 100) / 100;
  }, [investedCapital, capitalCurrency, avgRate]);
  const [editingAgreementId, setEditingAgreementId] = useState<string | null>(null);
  const [expandedAgreementId, setExpandedAgreementId] = useState<string | null>(null);
  const [simProfit, setSimProfit] = useState<string>('1000');

  // ── Operator Priority fields ──
  const [operatorRatio, setOperatorRatio] = useState('20');
  const [operatorIsMe, setOperatorIsMe] = useState(true);
  const [operatorContribution, setOperatorContribution] = useState('');
  const [lenderContribution, setLenderContribution] = useState('');
  // ── Monthly profit handling defaults ──
  const [operatorDefaultHandling, setOperatorDefaultHandling] = useState<'reinvest' | 'withdraw'>('reinvest');
  const [counterpartyDefaultHandling, setCounterpartyDefaultHandling] = useState<'reinvest' | 'withdraw'>('withdraw');

  // Group agreements by status
  const pending = agreements.filter(a => a.status === 'pending');
  const approved = agreements.filter(a => a.status === 'approved' && isAgreementActive(a));
  const expired = agreements.filter(a => a.status === 'expired' || (a.status === 'approved' && !isAgreementActive(a)));
  const rejected = agreements.filter(a => a.status === 'rejected');

  // ─── Simulator Panel ──
  const renderSimulatorPanel = (a: any) => {
    const gross = parseFloat(simProfit) || 0;
    const fifoRate = avgRate;
    const isOpPriority = a.agreement_type === 'operator_priority';
    const opRatio = a.operator_ratio ?? 0;
    const opContrib = a.operator_contribution ?? 0;
    const lnContrib = a.lender_contribution ?? 0;
    const investedCap = (a as any).invested_capital ?? 0;
    const settWay = (a as any).settlement_way;
    const opDefault = a.operator_default_profit_handling ?? 'reinvest';
    const cpDefault = a.counterparty_default_profit_handling ?? 'withdraw';
    const isOperator = a.operator_merchant_id === merchantProfile?.merchant_id;

    let myShare = 0, partnerShare = 0, opFee = 0, remaining = 0;
    let myLabel = t('you'), partnerLabel = counterpartyName || t('partner');
    let myPct = 0, partnerPct = 0;
    let myHandling = '', partnerHandling = '';

    if (isOpPriority) {
      const result = calculateOperatorPriorityProfit({
        grossProfit: gross,
        operatorRatio: opRatio,
        operatorContribution: opContrib,
        lenderContribution: lnContrib,
      });
      opFee = result.operatorFee;
      remaining = result.remainingProfit;
      if (isOperator) {
        myShare = result.operatorTotal;
        partnerShare = result.lenderTotal;
        myPct = result.operatorWeightPct;
        partnerPct = result.lenderWeightPct;
        myHandling = opDefault;
        partnerHandling = cpDefault;
      } else {
        myShare = result.lenderTotal;
        partnerShare = result.operatorTotal;
        myPct = result.lenderWeightPct;
        partnerPct = result.operatorWeightPct;
        myHandling = cpDefault;
        partnerHandling = opDefault;
      }
    } else {
      // Standard split
      const mRatio = a.merchant_ratio ?? 50;
      const pRatio = a.partner_ratio ?? 50;
      const isCreator = a.created_by === userId;
      myShare = gross * (isCreator ? mRatio : pRatio) / 100;
      partnerShare = gross * (isCreator ? pRatio : mRatio) / 100;
      myPct = isCreator ? mRatio : pRatio;
      partnerPct = isCreator ? pRatio : mRatio;
      remaining = gross;
      myHandling = settWay || 'withdraw';
      partnerHandling = settWay || 'withdraw';
    }

    const myReinvested = myHandling === 'reinvest' ? myShare : 0;
    const myWithdrawn = myHandling === 'withdraw' ? myShare : 0;
    const partnerReinvested = partnerHandling === 'reinvest' ? partnerShare : 0;
    const partnerWithdrawn = partnerHandling === 'withdraw' ? partnerShare : 0;
    const newCapitalBase = investedCap + myReinvested + partnerReinvested;

    const qarRate = fifoRate ?? 0;
    const myShareQar = myShare * qarRate;
    const partnerShareQar = partnerShare * qarRate;

    const panelStyle: React.CSSProperties = {
      padding: '12px 16px', background: 'color-mix(in srgb, var(--brand) 4%, var(--surface))',
      border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)',
      borderRadius: 6, margin: '4px 0 8px',
    };
    const gridStyle: React.CSSProperties = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px 16px', fontSize: 10 };
    const lblStyle: React.CSSProperties = { color: 'var(--muted)', fontSize: 9 };
    const valStyle: React.CSSProperties = { fontWeight: 700, fontSize: 11 };
    const sectionTitle: React.CSSProperties = { fontSize: 10, fontWeight: 700, color: 'var(--brand)', marginTop: 10, marginBottom: 4, textTransform: 'uppercase', letterSpacing: '.5px' };

    return (
      <div style={panelStyle}>
        {/* ── Agreement Details ── */}
        <div style={{ ...sectionTitle, marginTop: 0 }}>📋 {t('agreementDetails')}</div>
        <div style={gridStyle}>
          <div><span style={lblStyle}>{t('simType')}</span><br /><span style={valStyle}>{isOpPriority ? 'Operator Priority' : 'Standard'}</span></div>
          <div><span style={lblStyle}>{t('simSettlementCadence')}</span><br /><span style={valStyle}>{cadenceLabel(a.settlement_cadence)}</span></div>
          <div><span style={lblStyle}>{t('simEffectiveFrom')}</span><br /><span style={valStyle}>{new Date(a.effective_from).toLocaleDateString()}</span></div>
          <div><span style={lblStyle}>{t('simInvestedCapital')}</span><br /><span style={valStyle}>{fmtU(investedCap)} USDT</span></div>
          {isOpPriority && (
            <>
              <div><span style={lblStyle}>{t('simOperator')} ({a.operator_merchant_id === merchantProfile?.merchant_id ? t('you') : (counterpartyName || t('partner'))})</span><br /><span style={valStyle}>{fmtU(opContrib)} USDT · {opRatio}% {t('fee')}</span></div>
              <div><span style={lblStyle}>{t('simLender')} ({a.operator_merchant_id !== merchantProfile?.merchant_id ? t('you') : (counterpartyName || t('partner'))})</span><br /><span style={valStyle}>{fmtU(lnContrib)} USDT</span></div>
            </>
          )}
          {!isOpPriority && (
            <>
              <div><span style={lblStyle}>{t('simMyShare')}</span><br /><span style={valStyle}>{myPct}%</span></div>
              <div><span style={lblStyle}>{t('simPartnerShare')}</span><br /><span style={valStyle}>{partnerPct}%</span></div>
            </>
          )}
          <div><span style={lblStyle}>{t('simDefaultHandling')} ({t('you')})</span><br /><span style={valStyle}>{myHandling === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}</span></div>
          <div><span style={lblStyle}>{t('simDefaultHandling')} ({counterpartyName || t('partner')})</span><br /><span style={valStyle}>{partnerHandling === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}</span></div>
        </div>

        {/* ── Conversion Info ── */}
        <div style={sectionTitle}>💱 {t('simConversionRate')}</div>
        <div style={gridStyle}>
          <div><span style={lblStyle}>{t('simFifoRate')}</span><br /><span style={valStyle}>{qarRate > 0 ? `1 USDT = ${qarRate.toFixed(4)} QAR` : '—'}</span></div>
          <div><span style={lblStyle}>{t('source')}</span><br /><span style={{ ...valStyle, color: qarRate > 0 ? 'var(--good)' : 'var(--muted)' }}>{qarRate > 0 ? 'FIFO Stock Avg Buy' : t('noRateAvailable')}</span></div>
        </div>

        {/* ── What-If Simulator ── */}
        <div style={sectionTitle}>🧮 {t('simulatorTitle')}</div>
        <div style={{ marginBottom: 8, fontSize: 9, color: 'var(--muted)' }}>{t('simEnterProfit')}</div>
        <input
          type="number"
          value={simProfit}
          onChange={e => setSimProfit(e.target.value)}
          placeholder="e.g. 9000"
          style={{ width: 160, marginBottom: 8, padding: '4px 8px', borderRadius: 4, border: '1px solid color-mix(in srgb, var(--muted) 30%, transparent)', background: 'var(--surface)', color: 'var(--foreground)', fontSize: 12, fontWeight: 700 }}
        />

        {gross > 0 && (
          <div style={{ background: 'color-mix(in srgb, var(--surface) 80%, transparent)', borderRadius: 6, padding: 10, border: '1px solid color-mix(in srgb, var(--muted) 10%, transparent)' }}>
            {isOpPriority && (
              <div style={{ marginBottom: 8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10 }}>
                  <span style={lblStyle}>{t('simOperatorFee')} ({opRatio}%)</span>
                  <span style={{ color: 'var(--warn)', fontWeight: 700 }}>{fmtU(opFee)} USDT</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10 }}>
                  <span style={lblStyle}>{t('simRemainingProfit')}</span>
                  <span style={{ fontWeight: 700 }}>{fmtU(remaining)} USDT</span>
                </div>
                <div style={{ height: 1, background: 'color-mix(in srgb, var(--muted) 15%, transparent)', margin: '6px 0' }} />
              </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
              {/* My share */}
              <div style={{ padding: 8, borderRadius: 4, background: 'color-mix(in srgb, var(--good) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--good) 15%, transparent)' }}>
                <div style={{ fontSize: 9, color: 'var(--muted)', marginBottom: 2 }}>{t('simMyShare')} ({myPct}%{isOpPriority ? ` ${t('simWeight')}` : ''})</div>
                <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--good)' }}>{fmtU(myShare)} USDT</div>
                {qarRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round(myShareQar).toLocaleString()} QAR</div>}
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 4 }}>
                  {myHandling === 'reinvest' ? `🔄 ${t('simReinvestedCapital')}: ${fmtU(myReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(myWithdrawn)}`}
                </div>
              </div>
              {/* Partner share */}
              <div style={{ padding: 8, borderRadius: 4, background: 'color-mix(in srgb, var(--brand) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)' }}>
                <div style={{ fontSize: 9, color: 'var(--muted)', marginBottom: 2 }}>{counterpartyName || t('partner')} ({partnerPct}%{isOpPriority ? ` ${t('simWeight')}` : ''})</div>
                <div style={{ fontSize: 14, fontWeight: 700, color: 'var(--brand)' }}>{fmtU(partnerShare)} USDT</div>
                {qarRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round(partnerShareQar).toLocaleString()} QAR</div>}
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 4 }}>
                  {partnerHandling === 'reinvest' ? `🔄 ${t('simReinvestedCapital')}: ${fmtU(partnerReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(partnerWithdrawn)}`}
                </div>
              </div>
            </div>

            {/* Capital projection per party */}
            <div style={{ marginTop: 8 }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--foreground)', marginBottom: 6 }}>📊 {t('simCapitalProjection')}</div>

              {/* Total invested capital */}
              <div style={{ padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--muted) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--muted) 12%, transparent)', marginBottom: 6 }}>
                <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('simTotalInvestedCapital')}</div>
                <div style={{ fontSize: 13, fontWeight: 700 }}>{fmtU(isOpPriority ? opContrib + lnContrib : investedCap)} USDT</div>
                {qarRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round((isOpPriority ? opContrib + lnContrib : investedCap) * qarRate).toLocaleString()} QAR</div>}
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
                {/* My capital */}
                <div style={{ padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--good) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--good) 12%, transparent)' }}>
                  <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('you')} — {t('simReinvestedCapital')}</div>
                  <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 2 }}>
                    {t('simCurrentCapital')}: <strong>{fmtU(isOpPriority ? (isOperator ? opContrib : lnContrib) : investedCap)}</strong>
                  </div>
                  <div style={{ fontSize: 9, color: myReinvested > 0 ? 'var(--good)' : 'var(--muted)', marginTop: 1 }}>
                    {myHandling === 'reinvest' ? `🔄 +${fmtU(myReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(myWithdrawn)}`}
                  </div>
                  <div style={{ fontSize: 11, fontWeight: 700, marginTop: 2, color: 'var(--good)' }}>
                    → {fmtU((isOpPriority ? (isOperator ? opContrib : lnContrib) : investedCap) + myReinvested)} USDT
                  </div>
                </div>
                {/* Partner capital */}
                <div style={{ padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--brand) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--brand) 12%, transparent)' }}>
                  <div style={{ fontSize: 9, color: 'var(--muted)' }}>{counterpartyName || t('partner')} — {t('simReinvestedCapital')}</div>
                  <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 2 }}>
                    {t('simCurrentCapital')}: <strong>{fmtU(isOpPriority ? (isOperator ? lnContrib : opContrib) : investedCap)}</strong>
                  </div>
                  <div style={{ fontSize: 9, color: partnerReinvested > 0 ? 'var(--brand)' : 'var(--muted)', marginTop: 1 }}>
                    {partnerHandling === 'reinvest' ? `🔄 +${fmtU(partnerReinvested)}` : `💰 ${t('simWithdrawn')}: ${fmtU(partnerWithdrawn)}`}
                  </div>
                  <div style={{ fontSize: 11, fontWeight: 700, marginTop: 2, color: 'var(--brand)' }}>
                    → {fmtU((isOpPriority ? (isOperator ? lnContrib : opContrib) : investedCap) + partnerReinvested)} USDT
                  </div>
                </div>
              </div>

              {/* New total after reinvestment */}
              {(myReinvested > 0 || partnerReinvested > 0) && (
                <div style={{ marginTop: 6, padding: '6px 8px', borderRadius: 4, background: 'color-mix(in srgb, var(--warn) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--warn) 15%, transparent)' }}>
                  <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('simNewCapitalBase')}</div>
                  <div style={{ fontSize: 12, fontWeight: 700 }}>
                    {fmtU(isOpPriority ? opContrib + lnContrib : investedCap)} + {fmtU(myReinvested + partnerReinvested)} = <span style={{ color: 'var(--good)' }}>{fmtU((isOpPriority ? opContrib + lnContrib : investedCap) + myReinvested + partnerReinvested)} USDT</span>
                  </div>
                  {qarRate > 0 && <div style={{ fontSize: 9, color: 'var(--muted)' }}>≈ {Math.round(((isOpPriority ? opContrib + lnContrib : investedCap) + myReinvested + partnerReinvested) * qarRate).toLocaleString()} QAR</div>}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    );
  };

  const handleCreate = async () => {
    const ratio = parseFloat(partnerRatio);
    if (agreementType === 'standard') {
      if (isNaN(ratio) || ratio <= 0 || ratio >= 100) {
        toast.error(t('ratioValidation'));
        return;
      }
    }

    if (agreementType === 'operator_priority') {
      const opRatio = parseFloat(operatorRatio);
      if (isNaN(opRatio) || opRatio < 0 || opRatio > 100) {
        toast.error(t('operatorRatioRequired'));
        return;
      }
      const opContrib = parseFloat(operatorContribution) || 0;
      const lnContrib = parseFloat(lenderContribution) || 0;
      if (opContrib + lnContrib <= 0) {
        toast.error(t('contributionRequired'));
        return;
      }
    }

    const operatorMerchantId = operatorIsMe
      ? merchantProfile?.merchant_id
      : counterpartyMerchantId;

    try {
      const sharedFields = buildSharedProfitShareFields({
        agreementType,
        investedCapitalRaw: investedCapital,
        settlementWay,
      });
      const opRatioNum = parseFloat(operatorRatio) || 0;
      const opContribNum = parseFloat(operatorContribution) || 0;
      const lnContribNum = parseFloat(lenderContribution) || 0;

      const termsSnapshot = agreementType === 'operator_priority'
        ? buildOperatorPrioritySnapshot({
            operator_merchant_id: operatorMerchantId || '',
            operator_ratio: opRatioNum,
            operator_contribution: opContribNum,
            lender_contribution: lnContribNum,
            partner_ratio: 0,
            merchant_ratio: 0,
            settlement_cadence: cadence,
          }) as unknown as Record<string, unknown>
        : null;

      const payloadRatio = agreementType === 'standard' ? ratio : 0;

      const payload = {
        relationship_id: relationshipId,
        partner_ratio: payloadRatio,
        merchant_ratio: agreementType === 'standard' ? 100 - ratio : 0,
        settlement_cadence: cadence,
        invested_capital: agreementType === 'operator_priority'
          ? (opContribNum + lnContribNum)
          : investedCapitalUsdt,
        settlement_way: sharedFields.settlementWay,
        effective_from: new Date(effectiveFrom).toISOString(),
        expires_at: expiresAt ? new Date(expiresAt).toISOString() : null,
        notes: notes.trim() || null,
        agreement_type: agreementType,
        ...(agreementType === 'operator_priority' ? {
          operator_ratio: opRatioNum,
          operator_merchant_id: operatorMerchantId || null,
          operator_contribution: opContribNum,
          lender_contribution: lnContribNum,
          terms_snapshot: termsSnapshot,
          operator_default_profit_handling: operatorDefaultHandling,
          counterparty_default_profit_handling: counterpartyDefaultHandling,
        } : {}),
      };

      if (editingAgreementId) {
        await updateAgreement.mutateAsync({
          agreementId: editingAgreementId,
          ...payload,
        });
        toast.success(t('agreementUpdatedSuccess'));
      } else {
        await createAgreement.mutateAsync(payload);
        toast.success(t('agreementCreatedSuccess'));
      }

      setShowForm(false);
      resetForm();
    } catch (err: any) {
      toast.error(err.message || t('failedToCreate'));
    }
  };

  const handleReject = async (id: string) => {
    try {
      await updateStatus.mutateAsync({ agreementId: id, status: 'rejected' });
      toast.success(t('agreementRejectedSuccess'));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleApprove = async (id: string) => {
    try {
      await updateStatus.mutateAsync({ agreementId: id, status: 'approved' });
        toast.success(t('agreementApprovedSuccess'));
      } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleExpire = async (id: string) => {
    try {
      await updateStatus.mutateAsync({ agreementId: id, status: 'expired' });
      toast.success(t('agreementExpiredSuccess'));
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const resetForm = () => {
    setAgreementType('standard');
    setPartnerRatio('50');
    setCadence('monthly');
    setEffectiveFrom(new Date().toISOString().slice(0, 10));
    setExpiresAt('');
    setNotes('');
    setInvestedCapital('');
    setCapitalCurrency('USDT');
    setSettlementWay('reinvest');
    setOperatorRatio('20');
    setOperatorIsMe(true);
    setOperatorContribution('');
    setLenderContribution('');
    setOperatorDefaultHandling('reinvest');
    setCounterpartyDefaultHandling('withdraw');
    setEditingAgreementId(null);
  };

  const handleEditAgreement = (agreement: any) => {
    setEditingAgreementId(agreement.id);
    setAgreementType(agreement.agreement_type ?? 'standard');
    setPartnerRatio(String(agreement.partner_ratio ?? 50));
    setCadence(agreement.settlement_cadence ?? 'monthly');
    setEffectiveFrom(new Date(agreement.effective_from).toISOString().slice(0, 10));
    setExpiresAt(agreement.expires_at ? new Date(agreement.expires_at).toISOString().slice(0, 10) : '');
    setNotes(agreement.notes ?? '');
    setInvestedCapital(agreement.invested_capital != null ? String(agreement.invested_capital) : '');
    setSettlementWay((agreement.settlement_way === 'withdraw' ? 'withdraw' : 'reinvest'));
    setOperatorRatio(String(agreement.operator_ratio ?? 20));
    setOperatorIsMe((agreement.operator_merchant_id ?? merchantProfile?.merchant_id) === merchantProfile?.merchant_id);
    setOperatorContribution(String(agreement.operator_contribution ?? ''));
    setLenderContribution(String(agreement.lender_contribution ?? ''));
    setOperatorDefaultHandling(agreement.operator_default_profit_handling === 'withdraw' ? 'withdraw' : 'reinvest');
    setCounterpartyDefaultHandling(agreement.counterparty_default_profit_handling === 'reinvest' ? 'reinvest' : 'withdraw');
    setShowForm(true);
  };

  const statusPill = (status: string, isActive: boolean) => {
    if (status === 'pending') return <span className="pill info">{t('pendingStatus') || 'Pending'}</span>;
    if (status === 'approved' && isActive) return <span className="pill good">{t('activeStatus')}</span>;
    if (status === 'approved' && !isActive) return <span className="pill warn">{t('inactiveStatus')}</span>;
    if (status === 'expired') return <span className="pill warn">{t('expiredStatus')}</span>;
    if (status === 'rejected') return <span className="pill bad">{t('rejectedStatus')}</span>;
    return <span className="pill">{status}</span>;
  };

  const cadenceLabel = (c: string) => {
    if (c === 'per_order') return t('perOrderCadence');
    if (c === 'weekly') return t('weeklyCadence');
    return t('monthlyCadence');
  };

  const agreementDisplayLabel = (a: any) => {
    if (a.agreement_type === 'operator_priority') {
      return `⚙️ ${t('operatorPriorityLabel')} · ${a.operator_ratio ?? 0}% ${t('feeLabel')}`;
    }
    return `🤝 ${a.partner_ratio}/${a.merchant_ratio}`;
  };

  if (isLoading) {
    return (
      <div className="empty">
        <div className="empty-t">{t('loading')}</div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontSize: 12, fontWeight: 700 }}>{t('profitShareAgreements')}</div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>
            {t('standingAgreementsWith')} {counterpartyName || t('partner')} · {approved.length} {t('active')}
          </div>
        </div>
        <button className="btn" onClick={() => setShowForm(v => !v)}>
          {showForm ? t('close') : `+ ${t('newAgreement')}`}
        </button>
      </div>

      <div style={{
        padding: '8px 12px', borderRadius: 6, fontSize: 10, lineHeight: 1.5,
        background: 'color-mix(in srgb, var(--brand) 6%, transparent)',
        border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)',
        color: 'var(--muted)',
      }}>
        <strong style={{ color: 'var(--brand)' }}>{t('howItWorksAgreement')}</strong> {t('howItWorksDesc')}
      </div>

      {showForm && (
        <div style={{
          padding: 14, borderRadius: 8,
          border: '1px solid var(--brand)',
          background: 'color-mix(in srgb, var(--brand) 3%, var(--cardBg))',
        }}>
          <div style={{ fontSize: 11, fontWeight: 700, marginBottom: 10 }}>
            {editingAgreementId ? t('editAgreementTitle') : t('newProfitShareAgreement')}
          </div>

          <div style={{ marginBottom: 10 }}>
            <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '.5px' }}>
              {t('agreementTypeLabel')}
            </div>
            <div style={{ display: 'flex', gap: 6 }}>
              <button
                className={`pill ${agreementType === 'standard' ? 'good' : ''}`}
                style={{ cursor: 'pointer', padding: '4px 10px', fontSize: 10, fontWeight: 700 }}
                onClick={() => setAgreementType('standard')}
              >
                🤝 {t('standardProfitShare')}
              </button>
              <button
                className={`pill ${agreementType === 'operator_priority' ? 'good' : ''}`}
                style={{ cursor: 'pointer', padding: '4px 10px', fontSize: 10, fontWeight: 700 }}
                onClick={() => setAgreementType('operator_priority')}
              >
                ⚙️ {t('operatorPriorityLabel')}
              </button>
            </div>
            {agreementType === 'operator_priority' && (
              <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 4, lineHeight: 1.4 }}>
                {t('operatorPriorityDesc')}
              </div>
            )}
          </div>

          {agreementType === 'standard' && (
            <div style={{ marginBottom: 10 }}>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '.5px' }}>{t('quickPresets')}</div>
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                {[30, 40, 50, 60, 70].map(r => (
                  <button
                    key={r}
                    className={`pill ${partnerRatio === String(r) ? 'good' : ''}`}
                    style={{ cursor: 'pointer', padding: '4px 10px', fontSize: 10, fontWeight: 700 }}
                    onClick={() => setPartnerRatio(String(r))}
                  >
                    {r}/{100 - r}
                  </button>
                ))}
              </div>
            </div>
          )}

          {agreementType === 'standard' && (
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginBottom: 10 }}>
            <div>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                {t('partnerSharePct')} — {counterpartyName || t('partner')}
              </div>
              <div className="inputBox" style={{ padding: '6px 10px' }}>
                <input
                  type="number"
                  min="1"
                  max="99"
                  value={partnerRatio}
                  onChange={e => setPartnerRatio(e.target.value)}
                  style={{ fontWeight: 700, color: 'var(--bad)' }}
                />
              </div>
            </div>
            <div>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                {t('yourSharePct')} — {t('you')}
              </div>
              <div className="inputBox" style={{ padding: '6px 10px' }}>
                <input
                  type="number"
                  readOnly
                  value={100 - (parseFloat(partnerRatio) || 0)}
                  style={{ fontWeight: 700, color: 'var(--good)', cursor: 'not-allowed', opacity: 0.7 }}
                />
              </div>
            </div>
          </div>
          )}

          {agreementType === 'operator_priority' && (
            <div style={{
              padding: 12, borderRadius: 6, marginBottom: 10,
              border: '1px solid color-mix(in srgb, var(--warn) 30%, transparent)',
              background: 'color-mix(in srgb, var(--warn) 4%, transparent)',
            }}>
              <div style={{ fontSize: 10, fontWeight: 700, marginBottom: 8, color: 'var(--warn)' }}>
                ⚙️ {t('operatorPriorityLabel')}
              </div>

              <div style={{ marginBottom: 8 }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                  {t('operatorMerchantLabel')}
                </div>
                <div style={{ display: 'flex', gap: 6 }}>
                  <button
                    className={`pill ${operatorIsMe ? 'good' : ''}`}
                    style={{ cursor: 'pointer', padding: '4px 10px', fontSize: 10 }}
                    onClick={() => setOperatorIsMe(true)}
                  >
                    {t('youAreOperator')}
                  </button>
                  <button
                    className={`pill ${!operatorIsMe ? 'good' : ''}`}
                    style={{ cursor: 'pointer', padding: '4px 10px', fontSize: 10 }}
                    onClick={() => setOperatorIsMe(false)}
                  >
                    {t('partnerIsOperator')}
                  </button>
                </div>
              </div>

              <div style={{ marginBottom: 8 }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                  {t('operatorRatioLabel')}
                </div>
                <div className="inputBox" style={{ padding: '6px 10px' }}>
                  <input
                    type="number"
                    min="0"
                    max="100"
                    value={operatorRatio}
                    onChange={e => setOperatorRatio(e.target.value)}
                    style={{ fontWeight: 700 }}
                  />
                </div>
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 2 }}>
                  {t('operatorRatioHint')}
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
                <div>
                  <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                    {t('operatorContribLabel')}
                  </div>
                  <div className="inputBox" style={{ padding: '6px 10px' }}>
                    <input
                      type="number"
                      min="0"
                      value={operatorContribution}
                      onChange={e => setOperatorContribution(e.target.value)}
                      placeholder="0"
                      style={{ fontWeight: 700 }}
                    />
                  </div>
                </div>
                <div>
                  <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                    {t('lenderContribLabel')}
                  </div>
                  <div className="inputBox" style={{ padding: '6px 10px' }}>
                    <input
                      type="number"
                      min="0"
                      value={lenderContribution}
                      onChange={e => setLenderContribution(e.target.value)}
                      placeholder="0"
                      style={{ fontWeight: 700 }}
                    />
                  </div>
                </div>
              </div>

              <div style={{ marginTop: 10, padding: 10, borderRadius: 6, border: '1px solid color-mix(in srgb, var(--brand) 20%, transparent)', background: 'color-mix(in srgb, var(--brand) 3%, transparent)' }}>
                <div style={{ fontSize: 10, fontWeight: 700, marginBottom: 6 }}>
                  📅 {t('defaultProfitHandling')}
                </div>
                <div style={{ fontSize: 8, color: 'var(--muted)', marginBottom: 8, lineHeight: 1.4 }}>
                  {t('defaultHandlingHint')}
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
                  <div>
                    <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                      {t('operatorDefaultHandling')}
                    </div>
                    <div style={{ display: 'flex', gap: 4 }}>
                      <button
                        className={`pill ${operatorDefaultHandling === 'reinvest' ? 'good' : ''}`}
                        style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
                        onClick={() => setOperatorDefaultHandling('reinvest')}
                      >
                        🔄 {t('reinvestOption')}
                      </button>
                      <button
                        className={`pill ${operatorDefaultHandling === 'withdraw' ? 'good' : ''}`}
                        style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
                        onClick={() => setOperatorDefaultHandling('withdraw')}
                      >
                        💰 {t('withdrawOption')}
                      </button>
                    </div>
                  </div>
                  <div>
                    <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>
                      {t('counterpartyDefaultHandling')}
                    </div>
                    <div style={{ display: 'flex', gap: 4 }}>
                      <button
                        className={`pill ${counterpartyDefaultHandling === 'reinvest' ? 'good' : ''}`}
                        style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
                        onClick={() => setCounterpartyDefaultHandling('reinvest')}
                      >
                        🔄 {t('reinvestOption')}
                      </button>
                      <button
                        className={`pill ${counterpartyDefaultHandling === 'withdraw' ? 'good' : ''}`}
                        style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
                        onClick={() => setCounterpartyDefaultHandling('withdraw')}
                      >
                        💰 {t('withdrawOption')}
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 8, marginBottom: 10 }}>
            <div>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>{t('settlementCadence')}</div>
              <select
                value={cadence}
                onChange={e => setCadence(e.target.value as any)}
                style={{ width: '100%', padding: '6px 8px', fontSize: 10, borderRadius: 4, border: '1px solid var(--line)', background: 'var(--bg)', color: 'var(--t1)' }}
              >
                <option value="monthly">{t('monthlyCadence')}</option>
                <option value="weekly">{t('weeklyCadence')}</option>
                <option value="per_order">{t('perOrderCadence')}</option>
              </select>
            </div>
            <div>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>{t('effectiveFrom')}</div>
              <div className="inputBox" style={{ padding: '6px 10px' }}>
                <input type="date" value={effectiveFrom} onChange={e => setEffectiveFrom(e.target.value)} />
              </div>
            </div>
            <div>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>{t('expiresAtLabel')}</div>
              <div className="inputBox" style={{ padding: '6px 10px' }}>
                <input type="date" value={expiresAt} onChange={e => setExpiresAt(e.target.value)} />
              </div>
            </div>
          </div>

          <div style={{ marginBottom: 10 }}>
            <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>{t('notesOptionalLabel')}</div>
            <div className="inputBox" style={{ padding: '6px 10px' }}>
              <input value={notes} onChange={e => setNotes(e.target.value)} placeholder={t('optionalAgreementNotes')} />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginBottom: 10 }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}>
                <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)' }}>{t('investedCapitalLabel')}</div>
                <div style={{ display: 'flex', gap: 2 }}>
                  <button
                    className={`pill ${capitalCurrency === 'USDT' ? 'good' : ''}`}
                    style={{ cursor: 'pointer', padding: '2px 6px', fontSize: 8, fontWeight: 700 }}
                    onClick={() => setCapitalCurrency('USDT')}
                  >
                    {t('capitalInUsdt')}
                  </button>
                  <button
                    className={`pill ${capitalCurrency === 'QAR' ? 'good' : ''}`}
                    style={{ cursor: 'pointer', padding: '2px 6px', fontSize: 8, fontWeight: 700 }}
                    onClick={() => setCapitalCurrency('QAR')}
                  >
                    {t('capitalInQar')}
                  </button>
                </div>
              </div>
              <div className="inputBox" style={{ padding: '6px 10px' }}>
                <input
                  type="number"
                  min="0"
                  step="0.01"
                  value={investedCapital}
                  onChange={e => setInvestedCapital(e.target.value)}
                  placeholder="0"
                />
              </div>
              {capitalCurrency === 'QAR' && investedCapital && (
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 2 }}>
                  {avgRate
                    ? `≈ ${fmtU(investedCapitalUsdt)} USDT (${t('convertedFromQar')} ${avgRate.toFixed(2)})`
                    : t('noRateAvailable')}
                </div>
              )}
              {capitalCurrency === 'USDT' && investedCapital && avgRate && (
                <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 2 }}>
                  {t('convertedFromUsdt')}: {((parseFloat(investedCapital) || 0) * avgRate).toFixed(0)} QAR
                </div>
              )}
            </div>
            <div>
              <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)', marginBottom: 3 }}>{t('settlementWayLabel')}</div>
              <div style={{ display: 'flex', gap: 4 }}>
                <button
                  className={`pill ${settlementWay === 'reinvest' ? 'good' : ''}`}
                  style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
                  onClick={() => setSettlementWay('reinvest')}
                >
                  🔄 {t('reinvestOption')}
                </button>
                <button
                  className={`pill ${settlementWay === 'withdraw' ? 'good' : ''}`}
                  style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
                  onClick={() => setSettlementWay('withdraw')}
                >
                  💰 {t('withdrawOption')}
                </button>
              </div>
            </div>
          </div>

          {agreementType === 'standard' ? (
            <div style={{
              padding: '8px 12px', borderRadius: 6, marginBottom: 10,
              background: 'color-mix(in srgb, var(--good) 8%, transparent)',
              border: '1px solid color-mix(in srgb, var(--good) 20%, transparent)',
              fontSize: 10,
            }}>
              <strong>{t('previewAgreement')}</strong> {t('profitShareLabel')} {partnerRatio}/{100 - (parseFloat(partnerRatio) || 0)} —
              {counterpartyName || t('partner')} {t('gets')} {partnerRatio}% {t('ofNetProfit')}, {t('you')} {t('keeps')} {100 - (parseFloat(partnerRatio) || 0)}%.
              {t('settlement')}: {cadenceLabel(cadence)}.
              {' '}{t('investedLabel')}: {fmtU(investedCapitalUsdt)} · {t('settlementWayLabel')}: {settlementWay === 'reinvest' ? t('reinvestOption') : t('withdrawOption')}.
            </div>
          ) : (
            (() => {
              const opC = parseFloat(operatorContribution) || 0;
              const lnC = parseFloat(lenderContribution) || 0;
              const totalC = opC + lnC;
              const opWt = totalC > 0 ? Math.round((opC / totalC) * 100) : 0;
              const lnWt = totalC > 0 ? Math.round((lnC / totalC) * 100) : 0;
              const operatorName = operatorIsMe ? t('you') : (counterpartyName || t('partner'));
              const lenderName = operatorIsMe ? (counterpartyName || t('partner')) : t('you');
              return (
                <div style={{
                  padding: '8px 12px', borderRadius: 6, marginBottom: 10,
                  background: 'color-mix(in srgb, var(--warn) 8%, transparent)',
                  border: '1px solid color-mix(in srgb, var(--warn) 20%, transparent)',
                  fontSize: 10, lineHeight: 1.6,
                }}>
                  <strong>{t('previewAgreement')}</strong><br />
                  ① {t('operatorFeeFirst')}: {operatorRatio}% → {operatorName}<br />
                  ② {t('thenCapitalSplit')}:<br />
                  &nbsp;&nbsp;{operatorName}: {fmtU(opC)} ({opWt}% {t('weight')})<br />
                  &nbsp;&nbsp;{lenderName}: {fmtU(lnC)} ({lnWt}% {t('weight')})<br />
                  ③ {t('defaultProfitHandling')}:<br />
                  &nbsp;&nbsp;{operatorName}: {operatorDefaultHandling === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}<br />
                  &nbsp;&nbsp;{lenderName}: {counterpartyDefaultHandling === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}<br />
                  ④ {t('settlementWayLabel')}: {settlementWay === 'reinvest' ? t('reinvestOption') : t('withdrawOption')}<br />
                  {t('settlement')}: {cadenceLabel(cadence)}.
                </div>
              );
            })()
          )}

          <div style={{ display: 'flex', gap: 8 }}>
            <button className="btn" onClick={handleCreate} disabled={createAgreement.isPending || updateAgreement.isPending}>
              {createAgreement.isPending || updateAgreement.isPending
                ? (editingAgreementId ? t('savingLabel') : t('creatingAgreement'))
                : (editingAgreementId ? t('saveChangesLabel') : t('createAgreement'))}
            </button>
            <button className="btn secondary" onClick={() => { setShowForm(false); resetForm(); }}>{t('cancel')}</button>
          </div>
        </div>
      )}

      {pending.length > 0 && (
        <div style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--brand)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.5px' }}>
            ⏳ {t('pendingApprovalLabel')} ({pending.length})
          </div>
          <div className="tableWrap">
            <table>
              <thead>
                <tr>
                  <th>{t('agreement')}</th>
                  <th>{t('cadence')}</th>
                  <th>{t('effective')}</th>
                  <th>{t('proposedByLabel')}</th>
                  <th>{t('actions')}</th>
                </tr>
              </thead>
              <tbody>
                {pending.map(a => {
                  const isCreator = a.created_by === userId;
                  const isExpanded = expandedAgreementId === a.id;
                  return (
                    <React.Fragment key={a.id}>
                    <tr>
                      <td>
                        <div style={{ fontWeight: 700, fontSize: 11 }}>
                          {agreementDisplayLabel(a)}
                        </div>
                        <div style={{ fontSize: 9, color: 'var(--muted)' }}>
                          {a.agreement_type === 'operator_priority' ? (
                            <>
                              {t('operatorFeeFirst')} {a.operator_ratio}% · {t('thenCapitalSplit')}
                            </>
                          ) : (
                            <>
                              {t('partner')} {a.partner_ratio}% · {t('you')} {a.merchant_ratio}% · {t('capitalLabel')} {fmtQWithUnit((a as any).invested_capital ?? 0, settings.currency, avgRate)} · {(a as any).settlement_way ? ((a as any).settlement_way === 'reinvest' ? t('reinvestOption') : t('withdrawOption')) : '—'}
                            </>
                          )}
                        </div>
                      </td>
                      <td style={{ fontSize: 10 }}>{cadenceLabel(a.settlement_cadence)}</td>
                      <td className="mono" style={{ fontSize: 10 }}>{new Date(a.effective_from).toLocaleDateString()}</td>
                      <td style={{ fontSize: 10 }}>{isCreator ? t('you') : (counterpartyName || t('partner'))}</td>
                      <td>
                        <div style={{ display: 'flex', gap: 4 }}>
                          <button className="rowBtn" onClick={() => setExpandedAgreementId(isExpanded ? null : a.id)}>{t('viewDetailsAction')}</button>
                          {!isCreator ? (
                            <>
                              <button className="rowBtn" style={{ color: 'var(--good)', fontWeight: 700 }} onClick={() => handleApprove(a.id)}>{t('approveAction')}</button>
                              <button className="rowBtn" style={{ color: 'var(--bad)' }} onClick={() => handleReject(a.id)}>{t('rejectAction')}</button>
                            </>
                          ) : (
                            <>
                              <button className="rowBtn" onClick={() => handleEditAgreement(a)}>{t('editAction')}</button>
                              <button className="rowBtn" style={{ color: 'var(--bad)' }} onClick={() => handleReject(a.id)}>{t('cancel')}</button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                    {isExpanded && (
                      <tr><td colSpan={5} style={{ padding: 0 }}>
                        {renderSimulatorPanel(a)}
                      </td></tr>
                    )}
                    </React.Fragment>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {approved.length > 0 && (
        <div>
          <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--good)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.5px' }}>
            ✅ {t('activeAgreementsLabel')} ({approved.length})
          </div>
          <div className="tableWrap">
            <table>
              <thead>
                <tr>
                  <th>{t('agreement')}</th>
                  <th>{t('cadence')}</th>
                  <th>{t('effective')}</th>
                  <th>{t('expires')}</th>
                  <th>{t('status')}</th>
                  <th>{t('actions')}</th>
                </tr>
              </thead>
              <tbody>
                {approved.map(a => {
                  const isExpanded = expandedAgreementId === a.id;
                  return (
                    <React.Fragment key={a.id}>
                    <tr>
                      <td>
                        <div style={{ fontWeight: 700, fontSize: 11 }}>
                          {agreementDisplayLabel(a)}
                        </div>
                        <div style={{ fontSize: 9, color: 'var(--muted)' }}>
                          {a.agreement_type === 'operator_priority' ? (
                            <>
                              {t('operatorFeeFirst')} {a.operator_ratio}% · {t('thenCapitalSplit')}
                            </>
                          ) : (
                            <>
                              {t('partner')} {a.partner_ratio}% · {t('you')} {a.merchant_ratio}% · {t('capitalLabel')} {fmtQWithUnit((a as any).invested_capital ?? 0, settings.currency, avgRate)} · {(a as any).settlement_way ? ((a as any).settlement_way === 'reinvest' ? t('reinvestOption') : t('withdrawOption')) : '—'}
                            </>
                          )}
                        </div>
                      </td>
                      <td style={{ fontSize: 10 }}>{cadenceLabel(a.settlement_cadence)}</td>
                      <td className="mono" style={{ fontSize: 10 }}>{new Date(a.effective_from).toLocaleDateString()}</td>
                      <td className="mono" style={{ fontSize: 10 }}>{a.expires_at ? new Date(a.expires_at).toLocaleDateString() : '—'}</td>
                      <td>{statusPill(a.status, isAgreementActive(a))}</td>
                      <td>
                        <div style={{ display: 'flex', gap: 4 }}>
                          <button className="rowBtn" onClick={() => setExpandedAgreementId(isExpanded ? null : a.id)}>{t('viewDetailsAction')}</button>
                          <button className="rowBtn" onClick={() => handleEditAgreement(a)}>{t('editAction')}</button>
                          <button className="rowBtn" style={{ color: 'var(--warn)' }} onClick={() => handleExpire(a.id)}>{t('expireAction')}</button>
                          <button className="rowBtn" style={{ color: 'var(--bad)' }} onClick={() => handleReject(a.id)}>{t('rejectAction')}</button>
                        </div>
                      </td>
                    </tr>
                    {isExpanded && (
                      <tr><td colSpan={6} style={{ padding: 0 }}>
                        {renderSimulatorPanel(a)}
                      </td></tr>
                    )}
                    </React.Fragment>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {expired.length > 0 && (
        <div>
          <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--warn)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.5px' }}>
            ⏰ {t('expiredAgreementsLabel')} ({expired.length})
          </div>
          <div className="tableWrap">
            <table>
              <thead>
                <tr>
                  <th>{t('agreement')}</th>
                  <th>{t('cadence')}</th>
                  <th>{t('wasEffective')}</th>
                  <th>{t('expiredStatus')}</th>
                  <th>{t('status')}</th>
                </tr>
              </thead>
              <tbody>
                {expired.map(a => (
                  <tr key={a.id} style={{ opacity: 0.7 }}>
                    <td style={{ fontWeight: 700, fontSize: 11 }}>{agreementDisplayLabel(a)}</td>
                    <td style={{ fontSize: 10 }}>{cadenceLabel(a.settlement_cadence)}</td>
                    <td className="mono" style={{ fontSize: 10 }}>{new Date(a.effective_from).toLocaleDateString()}</td>
                    <td className="mono" style={{ fontSize: 10 }}>{a.expires_at ? new Date(a.expires_at).toLocaleDateString() : '—'}</td>
                    <td>{statusPill('expired', false)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {rejected.length > 0 && (
        <div>
          <div style={{ fontSize: 10, fontWeight: 700, color: 'var(--bad)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.5px' }}>
            ❌ {t('rejectedAgreementsLabel')} ({rejected.length})
          </div>
          <div className="tableWrap">
            <table>
              <thead>
                <tr>
                  <th>{t('agreement')}</th>
                  <th>{t('cadence')}</th>
                  <th>{t('created')}</th>
                  <th>{t('status')}</th>
                </tr>
              </thead>
              <tbody>
                {rejected.map(a => (
                  <tr key={a.id} style={{ opacity: 0.5 }}>
                    <td style={{ fontWeight: 700, fontSize: 11 }}>{agreementDisplayLabel(a)}</td>
                    <td style={{ fontSize: 10 }}>{cadenceLabel(a.settlement_cadence)}</td>
                    <td className="mono" style={{ fontSize: 10 }}>{new Date(a.created_at).toLocaleDateString()}</td>
                    <td>{statusPill('rejected', false)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {agreements.length === 0 && !showForm && (
        <div className="empty">
          <div className="empty-t">{t('noAgreementsYet')}</div>
          <div className="empty-s">{t('createAgreementToStart')}</div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { useDealCapital, useWithdrawFromPool } from '@/hooks/useDealCapital';
import { fmtU } from '@/lib/tracker-helpers';
import { toast } from 'sonner';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import '@/styles/tracker.css';

interface Props {
  dealId: string;
  dealAmount: number;
  dealTitle: string;
  relationshipId: string;
  isPartner: boolean;
}

export function CapitalPoolPanel({ dealId, dealAmount, dealTitle, relationshipId, isPartner }: Props) {
  const t = useT();
  const { data: capital, isLoading } = useDealCapital(dealId, dealAmount);
  const withdraw = useWithdrawFromPool();
  const [showWithdraw, setShowWithdraw] = useState(false);
  const [withdrawAmount, setWithdrawAmount] = useState('');

  const handleWithdraw = async () => {
    const amt = parseFloat(withdrawAmount);
    if (!amt || amt <= 0) { toast.error(t('invalidAmount')); return; }
    if (!capital || amt > capital.reinvestedPool) { toast.error(t('exceedsPoolBalance')); return; }
    try {
      await withdraw.mutateAsync({
        deal_id: dealId,
        relationship_id: relationshipId,
        amount: amt,
        currency: 'USDT',
        current_pool_balance: capital.reinvestedPool,
      });
      toast.success(t('withdrawnByPartner'));
      setShowWithdraw(false);
      setWithdrawAmount('');
    } catch (err: any) { toast.error(err.message); }
  };

  if (isLoading) {
    return <div className="empty"><div className="empty-t">{t('loading') || '...'}</div></div>;
  }

  if (!capital) return null;

  const typeIcon = (type: string) => type === 'reinvest' ? '🔄' : type === 'payout' ? '💰' : '📤';
  const typeLabel = (type: string) => type === 'reinvest' ? t('reinvestedToPool') : type === 'payout' ? t('paidOutToPartner') : t('withdrawnByPartner');

  return (
    <div className="panel" style={{ padding: 10, marginBottom: 10 }}>
      <div style={{ fontSize: 11, fontWeight: 700, marginBottom: 8 }}>{dealTitle}</div>

      {/* KPI cards */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        <div className="panel" style={{ flex: 1, padding: 8, textAlign: 'center' }}>
          <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('originalPrincipal')}</div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 800 }}>{fmtU(capital.originalPrincipal)}</div>
        </div>
        <div className="panel" style={{ flex: 1, padding: 8, textAlign: 'center' }}>
          <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('reinvestedPool')}</div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 800, color: capital.reinvestedPool > 0 ? 'var(--good)' : 'var(--muted)' }}>
            {fmtU(capital.reinvestedPool)}
          </div>
        </div>
        <div className="panel" style={{ flex: 1, padding: 8, textAlign: 'center' }}>
          <div style={{ fontSize: 9, color: 'var(--muted)' }}>{t('workingCapital')}</div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 800 }}>{fmtU(capital.workingCapital)}</div>
        </div>
      </div>

      {/* Withdraw button for partner */}
      {isPartner && capital.reinvestedPool > 0 && (
        <button className="btn" onClick={() => setShowWithdraw(true)} style={{ fontSize: 10, marginBottom: 8 }}>
          📤 {t('withdrawFromPool')}
        </button>
      )}

      {/* Capital ledger */}
      {capital.ledger.length > 0 && (
        <>
          <div style={{ fontSize: 10, fontWeight: 700, marginBottom: 4 }}>{t('capitalLedger')}</div>
          <div className="tableWrap">
            <table>
              <thead>
                <tr>
                  <th>{t('type') || 'Type'}</th>
                  <th className="r">{t('amount')}</th>
                  <th>{t('notes')}</th>
                  <th className="r">{t('poolBalance')}</th>
                  <th>{t('date')}</th>
                </tr>
              </thead>
              <tbody>
                {capital.ledger.map(e => (
                  <tr key={e.id}>
                    <td style={{ fontSize: 10 }}>{typeIcon(e.type)} {typeLabel(e.type)}</td>
                    <td className="mono r" style={{ color: e.type === 'withdrawal' ? 'var(--bad)' : 'var(--good)' }}>
                      {e.type === 'withdrawal' ? '−' : '+'}{fmtU(e.amount)}
                    </td>
                    <td style={{ fontSize: 9, color: 'var(--muted)', maxWidth: 120, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {e.note || '—'}
                    </td>
                    <td className="mono r">{fmtU(e.pool_balance_after)}</td>
                    <td className="mono" style={{ fontSize: 9 }}>{new Date(e.created_at).toLocaleDateString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      {/* Withdraw dialog */}
      <Dialog open={showWithdraw} onOpenChange={setShowWithdraw}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle className="text-sm">{t('withdrawFromPool')}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <div style={{ fontSize: 10, color: 'var(--muted)' }}>
              {t('poolBalance')}: <span className="mono" style={{ fontWeight: 700 }}>{fmtU(capital.reinvestedPool)}</span>
            </div>
            <div>
              <Label className="text-xs">{t('withdrawalAmount')}</Label>
              <Input
                type="number"
                value={withdrawAmount}
                onChange={e => setWithdrawAmount(e.target.value)}
                className="text-xs"
                max={capital.reinvestedPool}
              />
            </div>
            <Button size="sm" onClick={handleWithdraw} disabled={withdraw.isPending}>
              📤 {t('withdrawFromPool')}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { useRelationshipMessages, useSendMessage } from '@/hooks/useRelationshipMessages';
import { Send, MessageCircle } from 'lucide-react';

interface Props {
  relationshipId: string;
}

function formatMessageTime(dateStr: string): string {
  return new Date(dateStr).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

function dateSeparator(dateStr: string): string {
  const d = new Date(dateStr);
  const now = new Date();
  const diffDays = Math.floor((now.getTime() - d.getTime()) / 86400000);
  if (diffDays === 0) return 'Today';
  if (diffDays === 1) return 'Yesterday';
  return d.toLocaleDateString([], { weekday: 'long', month: 'short', day: 'numeric' });
}

export function ChatTab({ relationshipId }: Props) {
  const t = useT();
  const { userId } = useAuth();
  const { data: messages, isLoading } = useRelationshipMessages(relationshipId);
  const sendMessage = useSendMessage();
  const [text, setText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = useCallback(async () => {
    if (!text.trim()) return;
    try {
      await sendMessage.mutateAsync({ relationship_id: relationshipId, content: text.trim() });
      setText('');
      if (inputRef.current) {
        inputRef.current.style.height = 'auto';
      }
      setTimeout(() => inputRef.current?.focus(), 50);
    } catch (err: any) {
      console.error('Send failed:', err);
    }
  }, [text, relationshipId, sendMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  const handleTextChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setText(e.target.value);
    const el = e.target;
    el.style.height = 'auto';
    el.style.height = Math.min(el.scrollHeight, 120) + 'px';
  }, []);

  // Group by date
  const groupedByDate = useMemo(() => {
    if (!messages?.length) return [];
    const groups: { date: string; messages: typeof messages }[] = [];
    for (const m of messages) {
      const dateKey = new Date(m.created_at).toDateString();
      const last = groups[groups.length - 1];
      if (last && last.date === dateKey) {
        last.messages.push(m);
      } else {
        groups.push({ date: dateKey, messages: [m] });
      }
    }
    return groups;
  }, [messages]);

  return (
    <div className="chat-drawer-container">
      {/* ── Messages area ── */}
      <div className="chat-drawer-messages">
        {isLoading ? (
          <div className="flex items-center justify-center h-full">
            <div className="h-8 w-8 rounded-full border-2 border-primary/20 border-t-primary animate-spin" />
          </div>
        ) : !messages?.length ? (
          <div className="flex flex-col items-center justify-center h-full gap-3 text-muted-foreground py-12">
            <div className="h-14 w-14 rounded-full bg-primary/10 flex items-center justify-center">
              <MessageCircle className="h-7 w-7 text-primary/40" />
            </div>
            <p className="text-sm font-medium">{t('noMessagesChat') || 'No messages yet'}</p>
            <p className="text-[11px] opacity-60">{t('typeMessageChat') || 'Send a message to start chatting'}</p>
          </div>
        ) : (
          <>
            {groupedByDate.map((group) => (
              <div key={group.date}>
                <div className="chat-date-separator">
                  <span>{dateSeparator(group.messages[0].created_at)}</span>
                </div>
                {group.messages.map((m, idx) => {
                  const isOwn = m.sender_id === userId;
                  const prev = idx > 0 ? group.messages[idx - 1] : null;
                  const next = idx < group.messages.length - 1 ? group.messages[idx + 1] : null;
                  const isFirst = prev?.sender_id !== m.sender_id;
                  const isLast = next?.sender_id !== m.sender_id;

                  return (
                    <div
                      key={m.id}
                      className={`chat-bubble-row ${isOwn ? 'own' : 'other'} ${isFirst ? 'first' : ''} ${isLast ? 'last' : ''}`}
                      style={{ marginTop: isFirst ? 8 : 1 }}
                    >
                      <div className={`chat-bubble ${isOwn ? 'own' : 'other'}`}>
                        <div className="chat-bubble-content">{m.content}</div>
                        <div className="chat-bubble-meta">
                          <span>{formatMessageTime(m.created_at)}</span>
                          {isOwn && (
                            <span className="chat-read-status">
                              {m.read_at ? (
                                <svg width="16" height="11" viewBox="0 0 16 11" fill="none"><path d="M11.07 0.65L4.98 6.73L1.68 3.43L0.27 4.84L4.98 9.55L12.48 2.05L11.07 0.65Z" fill="currentColor"/><path d="M14.07 0.65L7.98 6.73L6.78 5.53L5.37 6.94L7.98 9.55L15.48 2.05L14.07 0.65Z" fill="currentColor"/></svg>
                              ) : (
                                <svg width="11" height="11" viewBox="0 0 16 11" fill="none"><path d="M11.07 0.65L4.98 6.73L1.68 3.43L0.27 4.84L4.98 9.55L12.48 2.05L11.07 0.65Z" fill="currentColor"/></svg>
                              )}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            ))}
            <div ref={messagesEndRef} />
          </>
        )}
      </div>

      {/* ── Input bar ── */}
      <div className="chat-messenger-input">
        <div className="chat-input-wrap">
          <textarea
            ref={inputRef}
            value={text}
            onChange={handleTextChange}
            onKeyDown={handleKeyDown}
            placeholder={t('typeMessageChat') || 'Type a message...'}
            rows={1}
            className="chat-input-field"
          />
        </div>
        <button
          onClick={handleSend}
          disabled={sendMessage.isPending || !text.trim()}
          className="chat-send-btn"
        >
          <Send className="h-4 w-4" />
        </button>
      </div>
    </div>
  );
}

import { useT } from '@/lib/i18n';
import { fmtU } from '@/lib/tracker-helpers';
import { DEAL_TYPE_CONFIGS } from '@/lib/deal-engine';
import '@/styles/tracker.css';

interface AgreementRow {
  id: string;
  relationship_id: string;
  title: string;
  deal_type: string;
  amount: number;
  currency: string;
  status: string;
  created_at: string;
  counterparty_name?: string;
}

interface Props {
  relationshipId: string;
  agreements: AgreementRow[];
}

/**
 * DealsTab — Read-only view of legacy merchant deals for a relationship.
 * All new order creation happens exclusively on the Orders page.
 */
export function DealsTab({ relationshipId, agreements }: Props) {
  const t = useT();

  const relDeals = agreements.filter(a => a.relationship_id === relationshipId && a.status !== 'cancelled');

  const dealTypeLabel = (dt: string) => {
    const cfg = DEAL_TYPE_CONFIGS[dt as keyof typeof DEAL_TYPE_CONFIGS];
    return cfg ? `${cfg.icon} ${cfg.label}` : dt;
  };

  const statusPill = (status: string) => {
    const cls = status === 'active' || status === 'approved' ? 'good'
      : status === 'pending' ? 'warn'
      : status === 'rejected' || status === 'cancelled' ? 'bad'
      : '';
    return <span className={`pill ${cls}`}>{status}</span>;
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontSize: 12, fontWeight: 700 }}>{t('dealsLabel')}</div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>{relDeals.length} {t('activeLabel') || 'active'}</div>
        </div>
      </div>

      {/* Info: orders are created from Orders page */}
      <div style={{
        padding: '8px 12px', borderRadius: 6, fontSize: 10, lineHeight: 1.5,
        background: 'color-mix(in srgb, var(--brand) 6%, transparent)',
        border: '1px solid color-mix(in srgb, var(--brand) 15%, transparent)',
        color: 'var(--muted)',
      }}>
        <strong style={{ color: 'var(--brand)' }}>{t('howItWorksAgreement')}</strong>{' '}
        {t('ordersPageOnlyExecution')}
      </div>

      {relDeals.length === 0 ? (
        <div className="empty">
          <div className="empty-t">{t('noDealsYet')}</div>
        </div>
      ) : (
        <div className="tableWrap">
          <table>
            <thead>
              <tr>
                <th>{t('title') || 'Title'}</th>
                <th>{t('type') || 'Type'}</th>
                <th>{t('settlementCadence')}</th>
                <th className="r">{t('amount')}</th>
                <th>{t('status')}</th>
                <th>{t('date')}</th>
              </tr>
            </thead>
            <tbody>
              {relDeals.map(d => (
                <tr key={d.id}>
                  <td style={{ fontWeight: 700, fontSize: 11 }}>{d.title}</td>
                  <td><span className="pill">{dealTypeLabel(d.deal_type)}</span></td>
                  <td>
                    {d.deal_type === 'capital_transfer' ? (
                      <span className="pill">💸 {t('capitalTransfer')}</span>
                    ) : (
                      <span className={`pill ${(d as any).settlement_cadence === 'per_order' ? 'warn' : ''}`}>
                        {(d as any).settlement_cadence === 'per_order' ? '⚡ ' + t('perTrade') : (d as any).settlement_cadence === 'weekly' ? '📆 ' + t('weekly') : '📅 ' + t('monthly')}
                      </span>
                    )}
                  </td>
                  <td className="mono r">{fmtU(d.amount)} {d.currency}</td>
                  <td>{statusPill(d.status)}</td>
                  <td className="mono" style={{ fontSize: 10 }}>{new Date(d.created_at).toLocaleDateString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ─── Settlement Decision Card ───────────────────────────────────────
// Renders monthly profit handling decisions for operator priority periods.
// Shows decision status, allows merchant to choose reinvest/withdraw.

import { useState } from 'react';
import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { useSettlementDecisions, useSubmitDecision, type SettlementDecision } from '@/hooks/useSettlementDecisions';
import { fmtU } from '@/lib/tracker-helpers';
import { toast } from 'sonner';
import '@/styles/tracker.css';

interface Props {
  periodId: string;
  periodKey: string;
}

export function DecisionCard({ periodId, periodKey }: Props) {
  const t = useT();
  const { merchantProfile } = useAuth();
  const myMerchantId = merchantProfile?.merchant_id;
  const { data: decisions = [], isLoading } = useSettlementDecisions(periodId);
  const submitDecision = useSubmitDecision();

  if (isLoading || decisions.length === 0) return null;

  return (
    <div style={{
      padding: 10, borderRadius: 6, marginTop: 6,
      border: '1px solid color-mix(in srgb, var(--brand) 20%, transparent)',
      background: 'color-mix(in srgb, var(--brand) 3%, transparent)',
    }}>
      <div style={{ fontSize: 10, fontWeight: 700, marginBottom: 6 }}>
        📅 {t('monthlyDecisionRequired')} · {periodKey}
      </div>
      {decisions.map(d => (
        <DecisionRow
          key={d.id}
          decision={d}
          isMe={d.merchant_id === myMerchantId}
          onSubmit={async (choice) => {
            try {
              await submitDecision.mutateAsync({
                decisionId: d.id,
                decision: choice,
                periodId,
              });
              toast.success(t('decisionSaved'));
            } catch (err: any) {
              toast.error(err.message);
            }
          }}
          isPending={submitDecision.isPending}
        />
      ))}
    </div>
  );
}

function DecisionRow({ decision, isMe, onSubmit, isPending }: {
  decision: SettlementDecision;
  isMe: boolean;
  onSubmit: (choice: 'reinvest' | 'withdraw') => void;
  isPending: boolean;
}) {
  const t = useT();
  const [selected, setSelected] = useState<'reinvest' | 'withdraw' | null>(null);

  const isFinalized = !!decision.finalized_at;
  const isDecided = decision.decision !== 'pending';
  const roleLabel = decision.role === 'operator' ? '⚙️ Operator' : '🏦 Lender';

  return (
    <div style={{
      padding: 8, borderRadius: 4, marginBottom: 4,
      background: isMe ? 'color-mix(in srgb, var(--brand) 6%, transparent)' : 'transparent',
      border: isMe ? '1px solid color-mix(in srgb, var(--brand) 15%, transparent)' : '1px solid var(--line)',
    }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
        <div style={{ fontSize: 10, fontWeight: 700 }}>
          {roleLabel} {isMe && <span style={{ color: 'var(--brand)' }}>({t('you')})</span>}
        </div>
        <div className="mono" style={{ fontSize: 11, fontWeight: 700 }}>
          {fmtU(decision.profit_amount)}
        </div>
      </div>

      {/* Decision state */}
      {isFinalized ? (
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', fontSize: 10 }}>
          <span className={`pill ${decision.decision === 'reinvest' ? 'good' : 'warn'}`}>
            {decision.decision === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}
          </span>
          {decision.finalization_snapshot && (decision.finalization_snapshot as any).auto_finalized && (
            <span style={{ fontSize: 8, color: 'var(--muted)' }}>({t('autoFinalizedLabel')})</span>
          )}
          <span className="mono" style={{ fontSize: 9, color: 'var(--muted)' }}>
            {t('effectiveCapitalLabel')}: {fmtU(decision.effective_capital_before)} → {fmtU(decision.effective_capital_after)}
          </span>
        </div>
      ) : isDecided ? (
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', fontSize: 10 }}>
          <span className={`pill ${decision.decision === 'reinvest' ? 'good' : 'warn'}`}>
            {decision.decision === 'reinvest' ? `🔄 ${t('reinvestOption')}` : `💰 ${t('withdrawOption')}`}
          </span>
          <span style={{ fontSize: 8, color: 'var(--muted)' }}>{t('decidedLabel')}</span>
        </div>
      ) : isMe ? (
        <div>
          <div style={{ display: 'flex', gap: 6, marginBottom: 4 }}>
            <button
              className={`pill ${selected === 'reinvest' ? 'good' : ''}`}
              style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
              onClick={() => setSelected('reinvest')}
            >
              🔄 {t('reinvestOption')}
            </button>
            <button
              className={`pill ${selected === 'withdraw' ? 'good' : ''}`}
              style={{ cursor: 'pointer', padding: '3px 8px', fontSize: 9 }}
              onClick={() => setSelected('withdraw')}
            >
              💰 {t('withdrawOption')}
            </button>
            {selected && (
              <button
                className="btn"
                style={{ fontSize: 9, padding: '3px 10px' }}
                onClick={() => onSubmit(selected)}
                disabled={isPending}
              >
                {t('confirmDecisionBtn')}
              </button>
            )}
          </div>
          {decision.decision_due_at && (
            <div style={{ fontSize: 8, color: 'var(--muted)' }}>
              {t('decisionDueBy')}: {new Date(decision.decision_due_at).toLocaleDateString()}
              {' · '}{t('defaultHandlingHint')}: {decision.default_behavior === 'reinvest' ? t('reinvestOption') : t('withdrawOption')}
            </div>
          )}
        </div>
      ) : (
        <div style={{ fontSize: 9, color: 'var(--muted)' }}>
          {t('pendingDecisionLabel')}
        </div>
      )}
    </div>
  );
}

import { useT } from '@/lib/i18n';
import { useAuth } from '@/features/auth/auth-context';
import { DealsTab } from './DealsTab';
import { SettlementTab } from './SettlementTab';
import { ProfitDistributionPanel } from './ProfitDistributionPanel';
import { CapitalPoolPanel } from './CapitalPoolPanel';
import { BalanceLedger } from './BalanceLedger';
import { ChatTab } from './ChatTab';
import { useState, useMemo } from 'react';
import '@/styles/tracker.css';

interface AgreementRow {
  id: string;
  relationship_id: string;
  title: string;
  deal_type: string;
  amount: number;
  currency: string;
  status: string;
  created_at: string;
  counterparty_name?: string;
  settlement_cadence?: string;
}

interface RelationshipDrawerProps {
  relationship: {
    id: string;
    counterparty_name: string;
    counterparty_nickname: string;
    counterparty_code: string;
    status: string;
    created_at: string;
    merchant_a_id: string;
    merchant_b_id: string;
  };
  agreements: AgreementRow[];
  onClose: () => void;
  trackerTrades?: Array<{
    id: string;
    ts: number;
    linkedDealId?: string;
    amountUSDT: number;
    sellPriceQAR: number;
    feeQAR: number;
    voided: boolean;
  }>;
  tradeCalc?: Map<string, any>;
}

type DrawerTab = 'deals' | 'settlements' | 'pnl' | 'capital' | 'chat';

export function RelationshipDrawer({ relationship, agreements, onClose, trackerTrades, tradeCalc }: RelationshipDrawerProps) {
  const t = useT();
  const { merchantProfile } = useAuth();
  const [activeTab, setActiveTab] = useState<DrawerTab>('deals');

  const relDeals = useMemo(() =>
    agreements
      .filter(a => a.relationship_id === relationship.id && a.status !== 'cancelled')
      .map(d => ({
        id: d.id,
        title: d.title,
        deal_type: d.deal_type,
        settlement_cadence: d.settlement_cadence || 'monthly',
        amount: d.amount,
        created_at: d.created_at,
      })),
    [agreements, relationship.id]
  );

  const isPartner = merchantProfile?.merchant_id !== relationship.merchant_a_id;

  const tabs: { key: DrawerTab; label: string; icon: string }[] = [
    { key: 'deals', label: t('dealsLabel'), icon: '📋' },
    { key: 'settlements', label: t('settlements'), icon: '💰' },
    { key: 'pnl', label: t('pnl'), icon: '📊' },
    { key: 'capital', label: t('capitalTab'), icon: '🏦' },
    { key: 'chat', label: t('chatTab'), icon: '💬' },
  ];

  return (
    <>
      {/* Backdrop */}
      <div className="rel-drawer-backdrop" onClick={onClose} />

      {/* Drawer */}
      <div className="rel-drawer tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'}>
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}>
          <button className="rowBtn" onClick={onClose} style={{ fontSize: 14 }}>←</button>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 14, fontWeight: 800 }}>{relationship.counterparty_name}</div>
            <div style={{ fontSize: 10, color: 'var(--muted)' }}>
              @{relationship.counterparty_nickname} · {t('code') || 'Code'}: <span className="mono" style={{ fontWeight: 700 }}>{relationship.counterparty_code || '—'}</span>
            </div>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 2 }}>
            <span className={`pill ${relationship.status === 'active' ? 'good' : 'warn'}`}>{relationship.status}</span>
            <span style={{ fontSize: 9, color: 'var(--muted)' }}>
              {t('since') || 'Since'}: {new Date(relationship.created_at).toLocaleDateString()}
            </span>
          </div>
        </div>

        {/* Tab bar */}
        <div style={{ display: 'flex', gap: 0, borderBottom: '1px solid var(--line)', marginBottom: 12, overflowX: 'auto' }}>
          {tabs.map(({ key, label, icon }) => (
            <button
              key={key}
              onClick={() => setActiveTab(key)}
              style={{
                padding: '8px 12px', fontSize: 10, fontWeight: activeTab === key ? 700 : 500,
                color: activeTab === key ? 'var(--brand)' : 'var(--muted)',
                borderBottom: activeTab === key ? '2px solid var(--brand)' : '2px solid transparent',
                background: 'transparent', border: 'none', borderBottomStyle: 'solid', cursor: 'pointer',
                transition: 'all 0.15s',
                display: 'flex', alignItems: 'center', gap: 4, whiteSpace: 'nowrap',
              }}
            >
              {icon} {label}
            </button>
          ))}
        </div>

        {/* Tab content */}
        <div style={{ flex: 1, overflowY: 'auto' }}>
          {activeTab === 'deals' && (
            <DealsTab
              relationshipId={relationship.id}
              agreements={agreements}
            />
          )}
          {activeTab === 'settlements' && (
            <SettlementTab
              relationshipId={relationship.id}
              deals={relDeals}
              isPartner={isPartner}
              trades={trackerTrades || []}
              tradeCalc={tradeCalc || new Map()}
            />
          )}
          {activeTab === 'pnl' && (
            <ProfitDistributionPanel relationshipId={relationship.id} />
          )}
          {activeTab === 'capital' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {/* Unified balance ledger */}
              <BalanceLedger relationshipId={relationship.id} />

              {/* Per-deal capital pools (exclude capital_transfer deals) */}
              {relDeals.filter(d => d.deal_type !== 'capital_transfer').length > 0 && (
                <>
                  <div style={{ fontSize: 11, fontWeight: 700, marginTop: 8 }}>{t('perDealCapital') || 'Per-Deal Capital'}</div>
                  {relDeals.filter(d => d.deal_type !== 'capital_transfer').map(d => (
                    <CapitalPoolPanel
                      key={d.id}
                      dealId={d.id}
                      dealAmount={d.amount}
                      dealTitle={d.title}
                      relationshipId={relationship.id}
                      isPartner={isPartner}
                    />
                  ))}
                </>
              )}

              {relDeals.filter(d => d.deal_type !== 'capital_transfer').length === 0 && (
                <div className="empty">
                  <div className="empty-t">{t('noDeals')}</div>
                </div>
              )}
            </div>
          )}
          {activeTab === 'chat' && (
            <ChatTab relationshipId={relationship.id} />
          )}
        </div>
      </div>
    </>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { useT } from '@/lib/i18n';
import { useSettlementPeriods, useSyncSettlementPeriods, type SettlementPeriod } from '@/hooks/useSettlementPeriods';
import { useDealCapital, useReinvestProfit, usePayoutProfit } from '@/hooks/useDealCapital';
import { fmtU, fmtQWithUnit, getWACOP } from '@/lib/tracker-helpers';
import { toast } from 'sonner';
import type { Cadence } from '@/lib/settlement-periods';
import { DecisionCard } from './DecisionCard';
import { useTheme } from '@/lib/theme-context';
import { useTrackerState } from '@/lib/useTrackerState';
import '@/styles/tracker.css';

interface DealInfo {
  id: string;
  title: string;
  deal_type: string;
  settlement_cadence: string;
  amount: number;
  created_at: string;
}

interface Props {
  relationshipId: string;
  deals: DealInfo[];
  isPartner: boolean;
  trades: Array<{
    id: string;
    ts: number;
    linkedDealId?: string;
    amountUSDT: number;
    sellPriceQAR: number;
    feeQAR: number;
    voided: boolean;
  }>;
  tradeCalc: Map<string, any>;
}

function PeriodCard({ period, dealAmount, relationshipId, isPartner, dealType, wacop }: {
  period: SettlementPeriod;
  dealAmount: number;
  relationshipId: string;
  isPartner: boolean;
  dealType: string;
  wacop: number | null;
}) {
  const t = useT();
  const { settings } = useTheme();
  const { data: capital } = useDealCapital(period.deal_id, dealAmount);
  const reinvest = useReinvestProfit();
  const payout = usePayoutProfit();

  const statusCls = period.status === 'settled' ? 'good'
    : period.status === 'overdue' ? 'bad'
    : period.status === 'due' ? 'warn'
    : '';

  const poolBalance = capital?.reinvestedPool || 0;

  const handlePayout = async () => {
    if (period.partner_amount <= 0) return;
    try {
      await payout.mutateAsync({
        deal_id: period.deal_id,
        relationship_id: relationshipId,
        period_id: period.id,
        amount: period.partner_amount,
        currency: 'USDT',
        current_pool_balance: poolBalance,
      });
      toast.success(t('paidOutToPartner'));
    } catch (err: any) { toast.error(err.message); }
  };

  const handleReinvest = async () => {
    if (period.partner_amount <= 0) return;
    try {
      await reinvest.mutateAsync({
        deal_id: period.deal_id,
        relationship_id: relationshipId,
        period_id: period.id,
        amount: period.partner_amount,
        currency: 'USDT',
        current_pool_balance: poolBalance,
      });
      toast.success(t('reinvestedToPool'));
    } catch (err: any) { toast.error(err.message); }
  };

  const showActions = (period.status === 'due' || period.status === 'overdue') && period.partner_amount > 0;

  const renderActions = () => {
    if (!showActions) return null;

    if (dealType === 'arbitrage') {
      if (!isPartner) {
        return (
          <button className="btn" onClick={handlePayout} disabled={payout.isPending} style={{ fontSize: 10 }}>
            💰 {t('settleAmount')} {fmtQWithUnit(period.partner_amount, settings.currency, wacop)}
          </button>
        );
      }
      return (
        <div style={{ fontSize: 10, color: 'var(--muted)' }}>
          {t('waitingForMerchantToSettle')}
        </div>
      );
    }

    if (dealType === 'partnership') {
      if (isPartner) {
        return (
          <div style={{ display: 'flex', gap: 6 }}>
            <button className="btn" onClick={handlePayout} disabled={payout.isPending} style={{ fontSize: 10 }}>
              💰 {t('takeProfit')} {fmtQWithUnit(period.partner_amount, settings.currency, wacop)}
            </button>
            <button className="btn" onClick={handleReinvest} disabled={reinvest.isPending} style={{ fontSize: 10 }}>
              🔄 {t('addToCapital')} {fmtQWithUnit(period.partner_amount, settings.currency, wacop)}
            </button>
          </div>
        );
      }
      return (
        <div style={{ fontSize: 10, color: 'var(--muted)' }}>
          {t('waitingForLenderDecision')}
        </div>
      );
    }

    return (
      <div style={{ display: 'flex', gap: 6 }}>
        <button className="btn" onClick={handlePayout} disabled={payout.isPending} style={{ fontSize: 10 }}>
          💰 {t('payOut')} {fmtQWithUnit(period.partner_amount, settings.currency, wacop)}
        </button>
        <button className="btn" onClick={handleReinvest} disabled={reinvest.isPending} style={{ fontSize: 10 }}>
          🔄 {t('reinvest')} {fmtQWithUnit(period.partner_amount, settings.currency, wacop)}
        </button>
      </div>
    );
  };

  return (
    <div className="panel" style={{ padding: 10 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
        <div>
          <div style={{ fontSize: 11, fontWeight: 700 }}>{period.deal_title || '—'}</div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>
            {period.period_key} · {period.cadence === 'per_order' ? t('perTrade') : period.cadence === 'weekly' ? t('weekly') : t('monthly')}
          </div>
        </div>
        <span className={`pill ${statusCls}`}>
          {period.status === 'overdue' && '⚠️ '}{period.status}
        </span>
      </div>

      <div style={{ display: 'flex', gap: 16, fontSize: 10, marginBottom: 8 }}>
        <div><span className="muted">{t('periodTrades')}:</span> <span className="mono">{period.trade_count}</span></div>
        <div><span className="muted">{t('periodVolume')}:</span> <span className="mono">{fmtQWithUnit(period.gross_volume, settings.currency, wacop)}</span></div>
        <div><span className="muted">{t('periodProfit')}:</span> <span className="mono" style={{ color: period.net_profit >= 0 ? 'var(--good)' : 'var(--bad)' }}>{fmtQWithUnit(period.net_profit, settings.currency, wacop)}</span></div>
      </div>

      {capital && (
        <div style={{ display: 'flex', gap: 16, fontSize: 10, marginBottom: 8, color: 'var(--muted)' }}>
          <div>{t('originalPrincipal')}: <span className="mono">{fmtQWithUnit(capital.originalPrincipal, settings.currency, wacop)}</span></div>
          <div>{t('reinvestedPool')}: <span className="mono">{fmtQWithUnit(capital.reinvestedPool, settings.currency, wacop)}</span></div>
          <div>{t('workingCapital')}: <span className="mono" style={{ fontWeight: 700, color: 'var(--fg)' }}>{fmtQWithUnit(capital.workingCapital, settings.currency, wacop)}</span></div>
        </div>
      )}

      <div style={{ display: 'flex', gap: 16, fontSize: 10, marginBottom: 8 }}>
        <div>{t('partnerShare')}: <span className="mono" style={{ fontWeight: 700 }}>{fmtQWithUnit(period.partner_amount, settings.currency, wacop)}</span></div>
        <div>{t('merchantShareDist')}: <span className="mono">{fmtQWithUnit(period.merchant_amount, settings.currency, wacop)}</span></div>
      </div>

      {period.status === 'settled' ? (
        <div style={{ fontSize: 10, display: 'flex', gap: 8, alignItems: 'center' }}>
          <span className="pill good">
            {period.resolution === 'payout' ? '💰 ' + t('paidOutToPartner') : '🔄 ' + t('reinvestedToPool')}
          </span>
          <span className="mono" style={{ color: 'var(--good)' }}>{fmtQWithUnit(period.settled_amount, settings.currency, wacop)}</span>
        </div>
      ) : (
        renderActions()
      )}

      {period.status === 'overdue' && (
        <div style={{ fontSize: 9, color: 'var(--bad)', marginTop: 4 }}>⚠️ {t('graceExpired')}</div>
      )}

      {dealType === 'partnership' && (period.status === 'due' || period.status === 'overdue' || period.status === 'settled') && (
        <DecisionCard periodId={period.id} periodKey={period.period_key} />
      )}
    </div>
  );
}

export function SettlementTab({ relationshipId, deals, isPartner, trades, tradeCalc }: Props) {
  const t = useT();
  const { settings } = useTheme();
  const { data: periods, isLoading } = useSettlementPeriods(relationshipId);
  const syncPeriods = useSyncSettlementPeriods(relationshipId);
  const [filterDealId, setFilterDealId] = useState<string>('all');

  const { derived } = useTrackerState({});
  const wacop = useMemo(() => getWACOP(derived), [derived]);

  useEffect(() => {
    if (deals.length > 0) {
      syncPeriods.mutate({
        deals: deals.map(d => ({
          id: d.id,
          settlement_cadence: (d.settlement_cadence || 'monthly') as Cadence,
          created_at: d.created_at,
        })),
        trades,
        tradeCalc,
      });
    }
  }, [deals.length]);

  const filtered = (periods || []).filter(p =>
    filterDealId === 'all' || p.deal_id === filterDealId
  );

  const dueCount = filtered.filter(p => p.status === 'due').length;
  const overdueCount = filtered.filter(p => p.status === 'overdue').length;
  const settledCount = filtered.filter(p => p.status === 'settled').length;
  const totalSettled = filtered.filter(p => p.status === 'settled').reduce((s, p) => s + Number(p.settled_amount), 0);

  const dealAmountMap = new Map(deals.map(d => [d.id, d.amount]));
  const dealTypeMap = new Map(deals.map(d => [d.id, d.deal_type]));

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
      <div className="kpi-band">
        <div className="kpi-band-title">{t('settlementTracker')}</div>
        <div className="kpi-band-cols">
          <div>
            <div className="kpi-period">{t('dueNow')}</div>
            <div className="kpi-cell-val" style={{ color: dueCount > 0 ? 'var(--warn-text, orange)' : 'var(--muted)' }}>{dueCount}</div>
          </div>
          <div>
            <div className="kpi-period">{t('overdueSettlement')}</div>
            <div className="kpi-cell-val" style={{ color: overdueCount > 0 ? 'var(--bad)' : 'var(--muted)' }}>{overdueCount}</div>
          </div>
          <div>
            <div className="kpi-period">{t('settled')}</div>
            <div className="kpi-cell-val">{settledCount}</div>
          </div>
          <div>
            <div className="kpi-period">{t('totalSettled')}</div>
            <div className="kpi-cell-val" style={{ color: 'var(--good)' }}>{fmtQWithUnit(totalSettled, settings.currency, wacop)}</div>
          </div>
        </div>
      </div>

      {deals.length > 1 && (
        <select
          value={filterDealId}
          onChange={e => setFilterDealId(e.target.value)}
          className="w-full p-2 text-xs border rounded bg-background text-foreground"
          style={{ maxWidth: 300 }}
        >
          <option value="all">{t('allDeals') || 'All Deals'}</option>
          {deals.map(d => (
            <option key={d.id} value={d.id}>{d.title}</option>
          ))}
        </select>
      )}

      {isLoading ? (
        <div className="empty"><div className="empty-t">{t('loading') || '...'}</div></div>
      ) : filtered.length === 0 ? (
        <div className="empty">
          <div className="empty-t">{t('noDeals')}</div>
          <div className="empty-s">{t('createDealsFromWorkspace')}</div>
        </div>
      ) : (
        filtered.map(p => (
          <PeriodCard
            key={p.id}
            period={p}
            dealAmount={dealAmountMap.get(p.deal_id) || 0}
            relationshipId={relationshipId}
            isPartner={isPartner}
            dealType={dealTypeMap.get(p.deal_id) || p.deal_type || 'partnership'}
            wacop={wacop}
          />
        ))
      )}
    </div>
  );
}

