import { P2POffer } from '../types';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { TrendingUp, TrendingDown } from 'lucide-react';
import { fmtPrice, fmtTotal } from '@/lib/tracker-helpers';

interface Props {
  offers: P2POffer[];
  type: 'sell' | 'buy';
  t: any;
}

function formatOfferLimit(value: number): string {
  if (!Number.isFinite(value) || value <= 0) return '∞';
  if (value >= 1_000_000) return `${fmtPrice(value / 1_000_000)}M`;
  if (value >= 1_000) return `${fmtTotal(value / 1_000)}K`;
  return fmtTotal(value);
}

export function P2POfferTable({ offers, type, t }: Props) {
  const isSell = type === 'sell';
  const maxAvailable = Math.max(...(offers.map(o => o.available) || [1]));

  return (
    <Card className="border-border/50">
      <CardHeader className="pb-1 pt-2.5 px-3">
        <div className="flex items-center justify-between">
          <CardTitle className={`text-[11px] font-semibold flex items-center gap-1.5 ${isSell ? 'text-success' : 'text-destructive'}`}>
            {isSell ? <TrendingUp className="h-3 w-3" /> : <TrendingDown className="h-3 w-3" />}
            {isSell ? t('p2pSellOffers') : t('p2pRestockOffers')}
          </CardTitle>
          <Badge className="text-[8px] px-1.5 py-0.5" variant={isSell ? 'default' : 'destructive'}>
            {isSell ? t('p2pHighestFirst') : t('p2pCheapestFirst')}
          </Badge>
        </div>
      </CardHeader>
      <CardContent className="p-0">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="text-[9px] uppercase tracking-wider font-semibold">{t('p2pTrader')}</TableHead>
              <TableHead className="text-[9px] uppercase tracking-wider font-semibold">{t('p2pPrice')}</TableHead>
              <TableHead className="text-[9px] uppercase tracking-wider font-semibold text-right">{t('p2pMin')}</TableHead>
              <TableHead className="text-[9px] uppercase tracking-wider font-semibold text-right">{t('p2pMax')}</TableHead>
              <TableHead className="text-[9px] uppercase tracking-wider font-semibold">{t('p2pMethods')}</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {offers.map((o, i) => {
              const depthPct = maxAvailable > 0 ? Math.min(100, (o.available / maxAvailable) * 100) : 0;
              return (
                <TableRow key={`${type}-${i}`} className="h-7">
                  <TableCell className="text-[11px] font-medium whitespace-nowrap py-1">{o.nick}</TableCell>
                  <TableCell className="py-1">
                    <div className="flex items-center gap-1">
                      <span className="font-bold font-mono text-[11px]">{fmtPrice(o.price)}</span>
                      <div className="w-10 h-1 rounded bg-muted overflow-hidden">
                        <div className="h-full rounded" style={{ width: `${depthPct}%`, background: isSell ? 'hsl(var(--success))' : 'hsl(var(--destructive))' }} />
                      </div>
                    </div>
                  </TableCell>
                  <TableCell className="text-right font-mono text-[11px] py-1">{o.min > 0 ? o.min.toLocaleString() : '—'}</TableCell>
                  <TableCell className="text-right font-mono text-[11px] py-1">{formatOfferLimit(o.max)}</TableCell>
                  <TableCell className="text-[10px] text-muted-foreground py-1 truncate max-w-[100px]">{o.methods.join(' ')}</TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import { P2PHistoryPoint } from '../types';
import { fmtPrice } from '@/lib/tracker-helpers';

interface Props {
  history: P2PHistoryPoint[];
  dataAgeLabel: string | null;
  t: any;
}

export function PriceHistorySparklines({ history, dataAgeLabel, t }: Props) {
  const [hoveredBar, setHoveredBar] = useState<{ type: 'sell' | 'buy'; index: number } | null>(null);

  const priceBarData = useMemo(() => {
    const cutoff = Date.now() - 24 * 60 * 60 * 1000;
    const last24h = history.filter(h => h.ts >= cutoff);
    if (!last24h.length) return { sellBars: [], buyBars: [], sellValues: [], buyValues: [], sellLatest: 0, buyLatest: 0, sellChange: 0, buyChange: 0 };
    
    const sellPts = last24h.filter(p => p.sellAvg != null).map(p => p.sellAvg!);
    const buyPts = last24h.filter(p => p.buyAvg != null).map(p => p.buyAvg!);
    const sellLatest = sellPts.length ? sellPts[sellPts.length - 1] : 0;
    const buyLatest = buyPts.length ? buyPts[buyPts.length - 1] : 0;
    const sellFirst = sellPts.length ? sellPts[0] : sellLatest;
    const buyFirst = buyPts.length ? buyPts[0] : buyLatest;

    const numBars = 12;
    const makeBarArray = (pts: number[]) => {
      if (!pts.length) return Array(numBars).fill(0);
      const step = Math.max(1, Math.floor(pts.length / numBars));
      const bars: number[] = [];
      for (let i = 0; i < pts.length && bars.length < numBars; i += step) bars.push(pts[i]);
      while (bars.length < numBars) bars.push(pts[pts.length - 1]);
      return bars;
    };

    const sellMin = sellPts.length ? Math.min(...sellPts) : 0;
    const sellMax = sellPts.length ? Math.max(...sellPts) : 1;
    const buyMin = buyPts.length ? Math.min(...buyPts) : 0;
    const buyMax = buyPts.length ? Math.max(...buyPts) : 1;

    const normalize = (vals: number[], min: number, max: number) => {
      const range = max - min || 0.01;
      return vals.map(v => Math.max(5, ((v - min) / range) * 100));
    };

    const sellValues = makeBarArray(sellPts);
    const buyValues = makeBarArray(buyPts);

    return {
      sellBars: normalize(sellValues, sellMin, sellMax),
      buyBars: normalize(buyValues, buyMin, buyMax),
      sellValues,
      buyValues,
      sellLatest,
      buyLatest,
      sellChange: sellLatest - sellFirst,
      buyChange: buyLatest - buyFirst,
    };
  }, [history]);

  return (
    <div className="tracker-root panel">
      <div className="panel-head" style={{ padding: '8px 12px' }}>
        <h2 style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 11 }}>{t('p2pPriceHistory')}</h2>
        <span className="pill" style={{ fontSize: 9 }}>
          24h Trend {dataAgeLabel && <> · {dataAgeLabel}</>}
        </span>
      </div>
      <div className="panel-body" style={{ padding: '8px 12px 12px', minHeight: 150, display: 'flex', flexDirection: 'column', gap: 10 }}>
        <div className="flex items-start justify-between gap-2">
          <span className="text-[9px] font-extrabold tracking-[0.14em] uppercase muted">{t('p2pSellAvgLabel')}</span>
          <span className="font-mono text-[14px] font-extrabold" style={{ color: 'var(--good)' }}>{priceBarData.sellLatest ? fmtPrice(priceBarData.sellLatest) : '—'}</span>
        </div>
        <div className="flex items-end gap-1 h-5 relative">
          {priceBarData.sellBars.map((pct, i) => (
            <div
              key={`sell-${i}`}
              className="flex-1 rounded-sm cursor-pointer transition-all duration-100"
              style={{
                height: `${Math.max(2, pct * 0.22)}px`,
                background: hoveredBar?.type === 'sell' && hoveredBar.index === i
                  ? 'color-mix(in srgb, var(--good) 100%, transparent)'
                  : 'color-mix(in srgb, var(--good) 82%, transparent)',
                transform: hoveredBar?.type === 'sell' && hoveredBar.index === i ? 'scaleY(1.3)' : 'scaleY(1)',
                transformOrigin: 'bottom',
              }}
              onMouseEnter={() => setHoveredBar({ type: 'sell', index: i })}
              onMouseLeave={() => setHoveredBar(null)}
            />
          ))}
        </div>
        <div className="flex items-start justify-between gap-2">
          <span className="text-[9px] font-extrabold tracking-[0.14em] uppercase muted">{t('p2pBuyAvgLabel')}</span>
          <span className="font-mono text-[14px] font-extrabold" style={{ color: 'var(--bad)' }}>{priceBarData.buyLatest ? fmtPrice(priceBarData.buyLatest) : '—'}</span>
        </div>
        <div className="flex items-end gap-1 h-5 relative">
          {priceBarData.buyBars.map((pct, i) => (
            <div
              key={`buy-${i}`}
              className="flex-1 rounded-sm cursor-pointer transition-all duration-100"
              style={{
                height: `${Math.max(2, pct * 0.22)}px`,
                background: hoveredBar?.type === 'buy' && hoveredBar.index === i
                  ? 'color-mix(in srgb, var(--bad) 100%, transparent)'
                  : 'color-mix(in srgb, var(--bad) 82%, transparent)',
                transform: hoveredBar?.type === 'buy' && hoveredBar.index === i ? 'scaleY(1.3)' : 'scaleY(1)',
                transformOrigin: 'bottom',
              }}
              onMouseEnter={() => setHoveredBar({ type: 'buy', index: i })}
              onMouseLeave={() => setHoveredBar(null)}
            />
          ))}
        </div>
        <div className="flex gap-2">
          <span className="pill" style={{ fontSize: 9 }}>{t('sell')} {priceBarData.sellChange >= 0 ? '+' : ''}{fmtPrice(priceBarData.sellChange)}</span>
          <span className="pill" style={{ fontSize: 9 }}>{t('buy')} {priceBarData.buyChange >= 0 ? '+' : ''}{fmtPrice(priceBarData.buyChange)}</span>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { MarketId, P2PSnapshot, P2PHistoryPoint, MerchantStat, EMPTY_SNAPSHOT } from '../types';
import { toSnapshot, toFiniteNumber, toOffer } from '../utils/converters';

export function useP2PMarketData(market: MarketId) {
  const [snapshot, setSnapshot] = useState<P2PSnapshot | null>(null);
  const [history, setHistory] = useState<P2PHistoryPoint[]>([]);
  const [merchantStats, setMerchantStats] = useState<MerchantStat[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);  // ISSUE 8 FIX: expose error state
  const [latestFetchedAt, setLatestFetchedAt] = useState<string | null>(null);
  const [qatarRates, setQatarRates] = useState<{ sellAvg: number; buyAvg: number } | null>(null);

  const loadFromDb = useCallback(async () => {
    try {
      const { data: latestRow } = await supabase
        .from('p2p_snapshots')
        .select('*')
        .eq('market', market)
        .order('fetched_at', { ascending: false })
        .limit(1)
        .maybeSingle();

      if (latestRow?.data) {
        setSnapshot(toSnapshot(latestRow.data, latestRow.fetched_at));
        setLatestFetchedAt(latestRow.fetched_at ?? null);
      } else {
        setSnapshot(EMPTY_SNAPSHOT);
        setLatestFetchedAt(null);
      }

      if (market !== 'qatar') {
        const { data: qatarRow } = await supabase
          .from('p2p_snapshots')
          .select('data, fetched_at')
          .eq('market', 'qatar')
          .order('fetched_at', { ascending: false })
          .limit(1)
          .maybeSingle();
        if (qatarRow?.data) {
          const qSnap = toSnapshot(qatarRow.data, qatarRow.fetched_at);
          setQatarRates(qSnap.sellAvg != null && qSnap.buyAvg != null ? { sellAvg: qSnap.sellAvg, buyAvg: qSnap.buyAvg } : null);
        }
      }

      const cutoff = new Date(Date.now() - 15 * 24 * 60 * 60 * 1000).toISOString();
      const { data: histRowsDesc } = await (supabase
        .from('p2p_snapshots') as any)
        .select('fetched_at, ts_val:data->>ts, sell_avg:data->>sellAvg, buy_avg:data->>buyAvg, spread_val:data->>spread, spread_pct_val:data->>spreadPct')
        .eq('market', market)
        .gte('fetched_at', cutoff)
        .order('fetched_at', { ascending: false })
        .limit(10000);

      const historyPoints = (histRowsDesc || []).reverse().flatMap((row: any) => {
        const ts = row.fetched_at ? new Date(row.fetched_at).getTime() : toFiniteNumber(row.ts_val);
        if (!ts) return [];
        return [{
          ts: ts < 1e12 ? ts * 1000 : ts,
          sellAvg: toFiniteNumber(row.sell_avg),
          buyAvg: toFiniteNumber(row.buy_avg),
          spread: toFiniteNumber(row.spread_val),
          spreadPct: toFiniteNumber(row.spread_pct_val),
        }];
      });
      setHistory(historyPoints);

      const cutoff24h = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      const { data: merchantRowsDesc } = await (supabase
        .from('p2p_snapshots') as any)
        .select('sell_offers:data->sellOffers, buy_offers:data->buyOffers')
        .eq('market', market)
        .gte('fetched_at', cutoff24h)
        .order('fetched_at', { ascending: false })
        .limit(2500);

      const rows = (merchantRowsDesc || []) as any[];
      const marketPolls = Math.max(rows.length, 1);
      const merchantMap = new Map<string, { appearances: number; totalAvailable: number; sampleCount: number; maxAvailable: number }>();

      for (const row of rows) {
        const seenInSnapshot = new Set<string>();
        const offers = [...(row.sell_offers || []), ...(row.buy_offers || [])].map(toOffer).filter(o => o !== null);
        for (const offer of offers) {
          const nick = offer.nick.trim();
          if (!nick) continue;
          let stat = merchantMap.get(nick);
          if (!stat) {
            stat = { appearances: 0, totalAvailable: 0, sampleCount: 0, maxAvailable: 0 };
            merchantMap.set(nick, stat);
          }
          if (!seenInSnapshot.has(nick)) {
            stat.appearances += 1;
            seenInSnapshot.add(nick);
          }
          stat.totalAvailable += offer.available;
          stat.sampleCount += 1;
          stat.maxAvailable = Math.max(stat.maxAvailable, offer.available);
        }
      }

      setMerchantStats(Array.from(merchantMap.entries()).map(([nick, stat]) => ({
        nick,
        appearances: stat.appearances,
        availabilityRatio: stat.appearances / marketPolls,
        avgAvailable: stat.sampleCount > 0 ? stat.totalAvailable / stat.sampleCount : 0,
        maxAvailable: stat.maxAvailable,
      })));
    } catch (err) {
      // ISSUE 8 FIX: surface error to consumers so the UI can show an error
      // state instead of silently rendering empty/stale charts.
      const msg = err instanceof Error ? err.message : 'Unknown P2P load error';
      console.error('P2P load error:', err);
      setError(msg);
    } finally {
      setLoading(false);
    }
  }, [market]);

  useEffect(() => {
    setLoading(true);
    setError(null);   // ISSUE 8 FIX: reset error on market change
    loadFromDb();

    const channel = supabase
      .channel(`p2p_snapshots_${market}`)
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'p2p_snapshots', filter: `market=eq.${market}` }, () => {
        void loadFromDb();
      })
      .subscribe();

    return () => { void supabase.removeChannel(channel); };
  }, [market, loadFromDb]);

  return { snapshot, history, merchantStats, loading, error, latestFetchedAt, qatarRates, refresh: loadFromDb };
}

import { useState, useEffect } from 'react';
import { useAuth } from '@/features/auth/auth-context';
import { useT } from '@/lib/i18n';
import { getCurrentTrackerState } from '@/lib/tracker-backup';
import {
  Dialog,
  DialogContent,
  DialogTitle,
} from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import {
  User,
  Mail,
  Hash,
  Globe,
  Coins,
  TrendingUp,
  Package,
  Users,
  Truck,
  Clock,
  LogIn,
  Cloud,
  CloudDownload,
  Database,
  CalendarDays,
  ShieldCheck,
} from 'lucide-react';

interface ProfileData {
  firstSeen: number;
  loginCount: number;
  lastLogin: number;
  lastCloudBackup: number;
  lastCloudRestore: number;
  sessions: number;
  trades: number;
  batches: number;
  customers: number;
  suppliers: number;
  stateKB: number;
  uid5: string;
}

const FS_KEY = 'taheito_first_seen_ts';
const LC_KEY = 'taheito_login_count';
const LL_KEY = 'taheito_last_login_ts';
const LB_KEY = 'taheito_last_cloud_backup_ts';
const LR_KEY = 'taheito_last_cloud_restore_ts';

export function touchLogin() {
  try {
    const now = Date.now();
    if (!localStorage.getItem(FS_KEY)) localStorage.setItem(FS_KEY, String(now));
    const lc = (+localStorage.getItem(LC_KEY)! || 0) + 1;
    localStorage.setItem(LC_KEY, String(lc));
    localStorage.setItem(LL_KEY, String(now));
  } catch {}
}

function getProfileData(email: string, merchantId: string): ProfileData {
  const fs = +localStorage.getItem(FS_KEY)! || Date.now();
  if (!localStorage.getItem(FS_KEY)) localStorage.setItem(FS_KEY, String(fs));
  const lc = +localStorage.getItem(LC_KEY)! || 0;
  const ll = +localStorage.getItem(LL_KEY)! || 0;
  const lb = +localStorage.getItem(LB_KEY)! || 0;
  const lr = +localStorage.getItem(LR_KEY)! || 0;
  let sess = 0;
  try {
    const arr = JSON.parse(localStorage.getItem('taheito_sessions_v1') || '[]');
    sess = Array.isArray(arr) ? arr.length : 0;
  } catch {}
  const st = getCurrentTrackerState(localStorage) as any;
  const trades = Array.isArray(st?.trades) ? st.trades.length : 0;
  const batches = Array.isArray(st?.batches) ? st.batches.length : 0;
  const customers = Array.isArray(st?.customers) ? st.customers.length : 0;
  const suppliers = Array.isArray(st?.suppliers) ? st.suppliers.length : 0;
  let szKB = 0;
  try { szKB = Math.max(1, Math.ceil(JSON.stringify(st || {}).length / 1024)); } catch {}

  let uid5 = '';
  const rawMid = String(merchantId || '').trim();
  const midDigits = rawMid.replace(/\D/g, '');
  if (midDigits.length >= 5) uid5 = midDigits.slice(-5);
  if (!uid5) {
    const base = String((email || rawMid || 'guest') + '|uid5');
    let h = 0;
    for (let i = 0; i < base.length; i++) { h = ((h << 5) - h) + base.charCodeAt(i); h |= 0; }
    uid5 = String(Math.abs(h) % 90000 + 10000);
  }
  localStorage.setItem('taheito_uid5', uid5);

  return { firstSeen: fs, loginCount: lc, lastLogin: ll, lastCloudBackup: lb, lastCloudRestore: lr, sessions: sess, trades, batches, customers, suppliers, stateKB: szKB, uid5 };
}

function fmtDate(ts: number, isAr: boolean) {
  if (!ts) return '—';
  return new Date(ts).toLocaleDateString(isAr ? 'ar' : 'en-GB', {
    year: 'numeric', month: 'short', day: 'numeric',
  });
}

function fmtDateTime(ts: number, isAr: boolean) {
  if (!ts) return '—';
  return new Date(ts).toLocaleString(isAr ? 'ar' : 'en-GB', {
    year: 'numeric', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit',
  });
}

function getInitials(name: string) {
  return name
    .split(/\s+/)
    .slice(0, 2)
    .map(w => w[0]?.toUpperCase() ?? '')
    .join('');
}

interface StatCardProps {
  icon: React.ReactNode;
  label: string;
  value: number | string;
  color: string;
}

