import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import { playNotificationSound, requestPushPermission, showBrowserNotification } from '@/lib/notification-sound';
import { buildNotificationNavigationTarget } from '@/lib/notification-router';
import { mapNotificationRowToModel, normalizeNotificationCategory, type AppNotification, type NotificationCategoryGroup, type NotificationRow } from '@/types/notifications';
import { useChatStore, isViewingConversationMessage } from '@/lib/chat-store';

export type Notification = AppNotification;

function applyReadStateToCache(queryClient: ReturnType<typeof useQueryClient>, ids: string[], readAt: string) {
  queryClient.setQueriesData(
    { queryKey: ['notifications'] },
    (prev: Notification[] | undefined) => {
      if (!prev) return prev;
      const idSet = new Set(ids);
      return prev.map((n) => (idSet.has(n.id) ? { ...n, read_at: readAt } : n));
    },
  );
}

interface UseNotificationsOptions {
  shouldSuppressRealtimeNotification?: (notification: Notification) => boolean;
}

export function useNotifications(options: UseNotificationsOptions = {}) {
  const { userId } = useAuth();
  const queryClient = useQueryClient();
  const [hasLiveNotificationChannel, setHasLiveNotificationChannel] = useState(false);

  const query = useQuery({
    queryKey: ['notifications', userId],
    queryFn: async (): Promise<Notification[]> => {
      const { data, error } = await supabase
        .from('notifications')
        .select('id, title, body, category, read_at, created_at, conversation_id, message_id, entity_type, entity_id, anchor_id, actor_id, target_path, target_tab, target_focus, target_entity_type, target_entity_id')
        .eq('user_id', userId!)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return (data ?? []).map((row) => mapNotificationRowToModel(row as NotificationRow));
    },
    enabled: !!userId,
    staleTime: 15_000,
  });

  useEffect(() => {
    if (userId) requestPushPermission();
  }, [userId]);

  const handleRealtimeInsert = useCallback((notification: Notification) => {
    const shouldSuppressViaStore = notification.target.kind === 'chat_message'
      && Boolean(notification.target.conversationId)
      && isViewingConversationMessage(useChatStore.getState(), notification.target.conversationId!);
    const shouldSuppress = shouldSuppressViaStore || options.shouldSuppressRealtimeNotification?.(notification);
    if (shouldSuppress) return;

    playNotificationSound();
    const nav = buildNotificationNavigationTarget(notification);
    showBrowserNotification(notification.title ?? 'New notification', {
      body: notification.body ?? undefined,
      tag: `notif-${notification.id}-${notification.target.kind}-${notification.target.entityId ?? notification.target.conversationId ?? 'generic'}`,
      onClick: () => {
        if (nav.pendingChatNav) useChatStore.getState().setPendingNav(nav.pendingChatNav);
        window.location.assign(`${nav.pathname}${nav.search ?? ''}`);
      },
    });
  }, [options]);

  useEffect(() => {
    if (!userId) return;

    const channel = supabase
      .channel(`notif-badge-rt-${userId}`)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'notifications', filter: `user_id=eq.${userId}` }, (payload: any) => {
        queryClient.invalidateQueries({ queryKey: ['notifications', userId] });
        if (payload?.eventType !== 'INSERT' || !payload?.new) return;
        const row = payload.new as NotificationRow & { user_id?: string };
        if (row.user_id !== userId) return;
        handleRealtimeInsert(mapNotificationRowToModel(row));
      })
      .subscribe((status) => {
        setHasLiveNotificationChannel(status === 'SUBSCRIBED');
      });

    return () => {
      setHasLiveNotificationChannel(false);
      supabase.removeChannel(channel);
    };
  }, [userId, queryClient, handleRealtimeInsert]);

  const unreadNotificationCount = useMemo(
    () => (query.data ?? []).filter((n) => !n.read_at).length,
    [query.data],
  );

  const unreadByCategory = useMemo(() => {
    const counts: Record<NotificationCategoryGroup, number> = {
      all: unreadNotificationCount,
      agreement: 0,
      approval: 0,
      deal: 0,
      invite: 0,
      message: 0,
      order: 0,
      system: 0,
    };
    for (const n of (query.data ?? [])) {
      if (n.read_at) continue;
      counts[normalizeNotificationCategory(n.category)] += 1;
    }
    return counts;
  }, [query.data, unreadNotificationCount]);

  return {
    ...query,
    unreadCount: unreadNotificationCount,
    unreadNotificationCount,
    unreadByCategory,
    hasLiveNotificationChannel,
  };
}

export function useMarkNotificationRead() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (id: string) => {
      const readAt = new Date().toISOString();
      const { error } = await supabase.from('notifications').update({ read_at: readAt }).eq('id', id);
      if (error) throw error;
      return { id, readAt };
    },
    onMutate: async (id: string) => {
      const readAt = new Date().toISOString();
      applyReadStateToCache(queryClient, [id], readAt);
      return { id, readAt };
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['notifications'] }),
  });
}

export function useMarkNotificationsRead() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (ids: string[]) => {
      if (!ids.length) return;
      const readAt = new Date().toISOString();
      const { error } = await supabase.from('notifications').update({ read_at: readAt }).in('id', ids).is('read_at', null);
      if (error) throw error;
      return { ids, readAt };
    },
    onMutate: async (ids: string[]) => {
      const readAt = new Date().toISOString();
      applyReadStateToCache(queryClient, ids, readAt);
      return { ids, readAt };
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['notifications'] }),
  });
}

export function useMarkAllRead() {
  const { userId } = useAuth();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async () => {
      const { error } = await supabase.from('notifications').update({ read_at: new Date().toISOString() }).eq('user_id', userId!).is('read_at', null);
      if (error) throw error;
    },
    /**
     * ISSUE 9 FIX: previously there was no onMutate, so clicking "Mark all
     * as read" showed no visual change until the server responded and
     * invalidateQueries triggered a full refetch (which could take 1–2 s on
     * slow connections).  Optimistic update clears all badges immediately.
     */
    onMutate: async () => {
      const readAt = new Date().toISOString();
      applyReadStateToCache(
        queryClient,
        (queryClient.getQueryData<Notification[]>(['notifications', userId]) ?? []).map(n => n.id),
        readAt,
      );
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['notifications'] }),
  });
}

export function useMarkCategoryRead() {
  const { userId } = useAuth();
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (category: string) => {
      const { error } = await supabase
        .from('notifications')
        .update({ read_at: new Date().toISOString() })
        .eq('user_id', userId!)
        .eq('category', category)
        .is('read_at', null);
      if (error) throw error;
    },
    /**
     * ISSUE 9 FIX: same as useMarkAllRead — add optimistic update so the
     * category unread badge clears immediately on click instead of waiting
     * for the server round-trip + refetch.
     */
    onMutate: async (category: string) => {
      const readAt = new Date().toISOString();
      const all = queryClient.getQueryData<Notification[]>(['notifications', userId]) ?? [];
      const ids = all.filter(n => !n.read_at && n.category === category).map(n => n.id);
      applyReadStateToCache(queryClient, ids, readAt);
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['notifications'] }),
  });
}

// ─── Order Allocations Hook ─────────────────────────────────────────
// Manages per-merchant, per-order allocation records.

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import type { OrderAllocation, AllocationFamily } from '@/types/domain';
import { calculateOperatorPriorityProfit } from '@/lib/trading/operator-priority';

const ALLOCATIONS_KEY = 'order-allocations';

// ─── Query: Fetch allocations by order ───────────────────────────────

export function useOrderAllocations(orderId?: string) {
  return useQuery({
    queryKey: [ALLOCATIONS_KEY, 'order', orderId],
    queryFn: async (): Promise<OrderAllocation[]> => {
      if (!orderId) return [];
      try {
        const { data, error } = await supabase
          .from('order_allocations' as any)
          .select('*')
          .eq('order_id', orderId)
          .order('created_at', { ascending: true });
        if (error) { console.warn('[useOrderAllocations] Query error:', error.message); return []; }
        return (data || []) as unknown as OrderAllocation[];
      } catch (e) { console.warn('[useOrderAllocations] Failed:', e); return []; }
    },
    enabled: !!orderId,
  });
}

// ─── Query: Fetch allocations by sale group ──────────────────────────

export function useSaleGroupAllocations(saleGroupId?: string) {
  return useQuery({
    queryKey: [ALLOCATIONS_KEY, 'group', saleGroupId],
    queryFn: async (): Promise<OrderAllocation[]> => {
      if (!saleGroupId) return [];
      try {
        const { data, error } = await supabase
          .from('order_allocations' as any)
          .select('*')
          .eq('sale_group_id', saleGroupId)
          .order('created_at', { ascending: true });
        if (error) { console.warn('[useSaleGroupAllocations] Query error:', error.message); return []; }
        return (data || []) as unknown as OrderAllocation[];
      } catch (e) { console.warn('[useSaleGroupAllocations] Failed:', e); return []; }
    },
    enabled: !!saleGroupId,
  });
}

// ─── Query: Fetch allocations by relationship ────────────────────────

export function useRelationshipAllocations(relationshipId?: string) {
  const qc = useQueryClient();

  const query = useQuery({
    queryKey: [ALLOCATIONS_KEY, 'relationship', relationshipId],
    queryFn: async (): Promise<OrderAllocation[]> => {
      if (!relationshipId) return [];
      try {
        const { data, error } = await supabase
          .from('order_allocations' as any)
          .select('*')
          .eq('relationship_id', relationshipId)
          .order('created_at', { ascending: false });
        if (error) { console.warn('[useRelationshipAllocations] Query error:', error.message); return []; }
        return (data || []) as unknown as OrderAllocation[];
      } catch (e) { console.warn('[useRelationshipAllocations] Failed:', e); return []; }
    },
    enabled: !!relationshipId,
  });

  // Real-time subscription
  useEffect(() => {
    if (!relationshipId) return;

    const channel = supabase
      .channel(`oa:${relationshipId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'order_allocations',
          filter: `relationship_id=eq.${relationshipId}`,
        },
        () => {
          qc.invalidateQueries({ queryKey: [ALLOCATIONS_KEY] });
        },
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [relationshipId, qc]);

  return query;
}

// ─── Mutation: Create allocations (batch) ────────────────────────────

export interface CreateAllocationInput {
  sale_group_id: string;
  order_id: string;
  relationship_id: string;
  merchant_id: string;
  family: AllocationFamily;
  profit_share_agreement_id?: string | null;
  allocated_usdt: number;
  merchant_cost_per_usdt: number;
  sell_price: number;
  fee_share: number;
  allocation_revenue: number;
  allocation_cost: number;
  allocation_fee: number;
  allocation_net: number;
  partner_share_pct: number;
  merchant_share_pct: number;
  partner_amount: number;
  merchant_amount: number;
  agreement_ratio_snapshot?: string | null;
  deal_terms_snapshot?: Record<string, unknown> | null;
  note?: string | null;
}

export function useCreateAllocations() {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (allocations: CreateAllocationInput[]) => {
      if (allocations.length === 0) return [];

      const { data, error } = await supabase
        .from('order_allocations' as any)
        .insert(allocations.map(a => ({
          ...a,
          status: 'pending',
        })))
        .select('*');

      if (error) throw error;
      return (data || []) as unknown as OrderAllocation[];
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [ALLOCATIONS_KEY] });
    },
  });
}

// ─── Calculation helpers ─────────────────────────────────────────────

export interface AllocationCalcInput {
  allocatedUsdt: number;
  merchantCostPerUsdt: number;
  sellPrice: number;
  totalFee: number;
  totalUsdt: number;
  family: AllocationFamily;
  partnerSharePct: number;
}

export function calculateAllocationEconomics(input: AllocationCalcInput) {
  const { allocatedUsdt, merchantCostPerUsdt, sellPrice, totalFee, totalUsdt, family, partnerSharePct } = input;

  const revenue = allocatedUsdt * sellPrice;
  const cost = allocatedUsdt * merchantCostPerUsdt;
  // Prorate fee by USDT share
  const feeShare = totalUsdt > 0 ? (allocatedUsdt / totalUsdt) * totalFee : 0;
  const net = revenue - cost - feeShare;

  const merchantSharePct = 100 - partnerSharePct;

  let partnerAmount: number;
  let merchantAmount: number;

  if (family === 'profit_share') {
    // Profit Share: split NET PROFIT
    partnerAmount = net * (partnerSharePct / 100);
    merchantAmount = net - partnerAmount;
  } else if (family === 'sales_deal') {
    // Sales Deal: split NET PROFIT (same as profit share)
    partnerAmount = net * (partnerSharePct / 100);
    merchantAmount = net - partnerAmount;
  } else {
    // Capital Transfer: no split
    partnerAmount = 0;
    merchantAmount = 0;
  }

  return {
    revenue: Math.round(revenue * 100) / 100,
    cost: Math.round(cost * 100) / 100,
    feeShare: Math.round(feeShare * 100) / 100,
    net: Math.round(net * 100) / 100,
    partnerAmount: Math.round(partnerAmount * 100) / 100,
    merchantAmount: Math.round(merchantAmount * 100) / 100,
    partnerSharePct,
    merchantSharePct,
  };
}

/**
 * Operator Priority allocation: uses operator fee + capital-weighted split.
 * Call this instead of calculateAllocationEconomics when the agreement is operator_priority.
 */
export function calculateOperatorPriorityAllocationEconomics(input: AllocationCalcInput & {
  operatorRatio: number;
  operatorContribution: number;
  lenderContribution: number;
  isOperator: boolean;
}) {
  const { allocatedUsdt, merchantCostPerUsdt, sellPrice, totalFee, totalUsdt } = input;

  const revenue = allocatedUsdt * sellPrice;
  const cost = allocatedUsdt * merchantCostPerUsdt;
  const feeShare = totalUsdt > 0 ? (allocatedUsdt / totalUsdt) * totalFee : 0;
  const net = revenue - cost - feeShare;

  // Use the operator priority calculation
  const result = calculateOperatorPriorityProfit({
    grossProfit: net,
    operatorRatio: input.operatorRatio,
    operatorContribution: input.operatorContribution,
    lenderContribution: input.lenderContribution,
  });

  return {
    revenue: Math.round(revenue * 100) / 100,
    cost: Math.round(cost * 100) / 100,
    feeShare: Math.round(feeShare * 100) / 100,
    net: Math.round(net * 100) / 100,
    partnerAmount: Math.round((input.isOperator ? result.lenderTotal : result.operatorTotal) * 100) / 100,
    merchantAmount: Math.round((input.isOperator ? result.operatorTotal : result.lenderTotal) * 100) / 100,
    partnerSharePct: input.isOperator ? result.lenderWeightPct : result.operatorWeightPct,
    merchantSharePct: input.isOperator ? result.operatorWeightPct : result.lenderWeightPct,
    operatorFee: result.operatorFee,
    operatorCapitalShare: result.operatorCapitalShare,
    lenderCapitalShare: result.lenderCapitalShare,
  };
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import { getDealShares } from '@/lib/deal-templates';

export interface DealDistribution {
  dealId: string;
  dealTitle: string;
  dealType: string;
  allocationBase: 'net_profit' | 'sale_economics';
  partnerPct: number;
  merchantPct: number;
  totalOrderVolume: number;
  totalNetProfit: number;
  partnerOwed: number;
  merchantOwed: number;
  totalSettled: number;
  partnerOutstanding: number;
}

export interface RelationshipDistribution {
  relationshipId: string;
  counterpartyName: string;
  deals: DealDistribution[];
  summary: {
    totalPartnerOwed: number;
    totalMerchantOwed: number;
    totalSettled: number;
    netOutstanding: number;
  };
}

export function useProfitDistribution(relationshipId: string) {
  const { merchantProfile } = useAuth();

  return useQuery({
    queryKey: ['profit-distribution', relationshipId],
    queryFn: async (): Promise<RelationshipDistribution> => {
      const { data: deals } = await supabase
        .from('merchant_deals')
        .select('*')
        .eq('relationship_id', relationshipId)
        .in('status', ['approved', 'pending']);

      const { data: settlements } = await supabase
        .from('merchant_settlements')
        .select('*')
        .eq('relationship_id', relationshipId)
        .eq('status', 'approved');

      const { data: rel } = await supabase
        .from('merchant_relationships')
        .select('*')
        .eq('id', relationshipId)
        .single();

      const myMerchantId = merchantProfile?.merchant_id;
      const cpMerchantId = rel
        ? (rel.merchant_a_id === myMerchantId ? rel.merchant_b_id : rel.merchant_a_id)
        : null;

      let cpName = 'Counterparty';
      if (cpMerchantId) {
        const { data: cpProfile } = await supabase
          .from('merchant_profiles')
          .select('display_name')
          .eq('merchant_id', cpMerchantId)
          .maybeSingle();
        if (cpProfile) cpName = cpProfile.display_name;
      }

      // Helper to get pool balance
      async function getDealPoolBalance(dealId: string): Promise<number> {
        const { data } = await supabase
          .from('deal_capital_ledger')
          .select('pool_balance_after')
          .eq('deal_id', dealId)
          .order('created_at', { ascending: false })
          .limit(1)
          .maybeSingle();
        return data ? Number((data as any).pool_balance_after) : 0;
      }

      const dealDistributions: DealDistribution[] = [];
      for (const deal of (deals || [])) {
        const shares = getDealShares({ deal_type: deal.deal_type, notes: deal.notes });

        const dealSettlements = (settlements || [])
          .filter(s => s.deal_id === deal.id)
          .reduce((sum, s) => sum + Number(s.amount), 0);

        const poolBalance = await getDealPoolBalance(deal.id);
        const totalOrderVolume = Number(deal.amount || 0) + poolBalance;
        const totalNetProfit = Number(deal.realized_pnl || 0);

        let partnerOwed = 0;
        let merchantOwed = 0;

        if (shares.partnerPct !== null) {
          if (shares.allocationBase === 'net_profit') {
            partnerOwed = totalNetProfit * (shares.partnerPct / 100);
            merchantOwed = totalNetProfit - partnerOwed;
          } else {
            partnerOwed = totalOrderVolume * (shares.partnerPct / 100);
            merchantOwed = totalOrderVolume - partnerOwed;
          }
        }

        dealDistributions.push({
          dealId: deal.id,
          dealTitle: deal.title,
          dealType: deal.deal_type,
          allocationBase: shares.allocationBase,
          partnerPct: shares.partnerPct || 0,
          merchantPct: shares.merchantPct || 0,
          totalOrderVolume,
          totalNetProfit,
          partnerOwed,
          merchantOwed,
          totalSettled: dealSettlements,
          partnerOutstanding: partnerOwed - dealSettlements,
        });
      }

      const summary = {
        totalPartnerOwed: dealDistributions.reduce((s, d) => s + d.partnerOwed, 0),
        totalMerchantOwed: dealDistributions.reduce((s, d) => s + d.merchantOwed, 0),
        totalSettled: dealDistributions.reduce((s, d) => s + d.totalSettled, 0),
        netOutstanding: dealDistributions.reduce((s, d) => s + d.partnerOutstanding, 0),
      };

      return {
        relationshipId,
        counterpartyName: cpName,
        deals: dealDistributions,
        summary,
      };
    },
    enabled: !!relationshipId && !!merchantProfile,
    staleTime: 30_000,
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';

export interface ProfitRecord {
  id: string;
  deal_id: string;
  relationship_id: string | null;
  amount: number;
  currency: string;
  recorded_by: string;
  notes: string | null;
  status: string;
  created_at: string;
  deal_title?: string;
  deal_type?: string;
}

export function useProfitRecords(relationshipId?: string) {
  const { userId } = useAuth();

  return useQuery({
    queryKey: ['profit-records', relationshipId],
    queryFn: async (): Promise<ProfitRecord[]> => {
      let query = supabase
        .from('merchant_profits')
        .select('*')
        .order('created_at', { ascending: false });

      if (relationshipId) {
        query = query.eq('relationship_id', relationshipId);
      }

      const { data, error } = await query;
      if (error) throw error;

      // Fetch deal titles separately
      const dealIds = [...new Set((data || []).map(p => p.deal_id))];
      const dealMap = new Map<string, { title: string; deal_type: string }>();
      if (dealIds.length > 0) {
        const { data: deals } = await supabase
          .from('merchant_deals')
          .select('id, title, deal_type')
          .in('id', dealIds);
        (deals || []).forEach(d => dealMap.set(d.id, { title: d.title, deal_type: d.deal_type }));
      }

      return (data || []).map(p => ({
        ...p,
        deal_title: dealMap.get(p.deal_id)?.title,
        deal_type: dealMap.get(p.deal_id)?.deal_type,
      }));
    },
    enabled: !!userId,
  });
}

export function useSubmitProfit() {
  const qc = useQueryClient();
  const { userId } = useAuth();

  return useMutation({
    mutationFn: async (input: {
      deal_id: string;
      relationship_id: string;
      amount: number;
      currency: string;
      notes?: string;
    }) => {
      const { error } = await supabase
        .from('merchant_profits')
        .insert({
          deal_id: input.deal_id,
          relationship_id: input.relationship_id as any,
          amount: input.amount,
          currency: input.currency,
          recorded_by: userId!,
          notes: input.notes || null,
          status: 'pending' as any,
        } as any);
      if (error) throw error;
    },
    onSuccess: (_, vars) => {
      qc.invalidateQueries({ queryKey: ['profit-records', vars.relationship_id] });
      qc.invalidateQueries({ queryKey: ['profit-records'] });
    },
  });
}

export function useApproveProfit() {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: { id: string; approved: boolean }) => {
      const { error } = await supabase
        .from('merchant_profits')
        .update({ status: input.approved ? 'approved' : 'rejected' } as any)
        .eq('id', input.id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['profit-records'] });
    },
  });
}

// ─── Profit Share Agreements Hook ────────────────────────────────────
// Manages standing profit share agreements with real-time subscriptions.

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import type { ProfitShareAgreement, AgreementStatus } from '@/types/domain';

const AGREEMENTS_KEY = 'profit-share-agreements';

// ─── Query: Fetch agreements ─────────────────────────────────────────

export function useProfitShareAgreements(relationshipId?: string, overrideMerchantId?: string) {
  const { merchantProfile } = useAuth();
  const qc = useQueryClient();

  const query = useQuery({
    queryKey: [AGREEMENTS_KEY, relationshipId, overrideMerchantId],
    queryFn: async (): Promise<ProfitShareAgreement[]> => {
      try {
        // If scoping to a specific merchant (admin inspection), first get their relationship IDs
        let scopedRelIds: string[] | null = null;
        if (overrideMerchantId && !relationshipId) {
          const { data: rels } = await supabase
            .from('merchant_relationships')
            .select('id')
            .or(`merchant_a_id.eq.${overrideMerchantId},merchant_b_id.eq.${overrideMerchantId}`)
            .eq('status', 'active');
          scopedRelIds = (rels || []).map((r: any) => r.id);
          if (scopedRelIds.length === 0) return [];
        }

        let q = supabase
          .from('profit_share_agreements' as any)
          .select('*')
          .order('created_at', { ascending: false });

        if (relationshipId) {
          q = q.eq('relationship_id', relationshipId);
        } else if (scopedRelIds) {
          q = q.in('relationship_id', scopedRelIds);
        }

        const { data, error } = await q;
        if (error) {
          console.warn('[useProfitShareAgreements] Query error (table may not exist):', error.message);
          return [];
        }
        return (data || []) as unknown as ProfitShareAgreement[];
      } catch (e) {
        console.warn('[useProfitShareAgreements] Failed:', e);
        return [];
      }
    },
    enabled: !!merchantProfile?.merchant_id || !!overrideMerchantId,
  });

  // Real-time subscription
  useEffect(() => {
    const filter = relationshipId
      ? `relationship_id=eq.${relationshipId}`
      : undefined;

    const channel = supabase
      .channel(`psa:${relationshipId || 'all'}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'profit_share_agreements',
          ...(filter ? { filter } : {}),
        },
        () => {
          qc.invalidateQueries({ queryKey: [AGREEMENTS_KEY] });
        },
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [relationshipId, qc]);

  return query;
}

// ─── Query: Approved agreements for a specific relationship ──────────

export function useApprovedAgreements(relationshipId: string | undefined) {
  const { merchantProfile } = useAuth();

  return useQuery({
    queryKey: [AGREEMENTS_KEY, 'approved', relationshipId],
    queryFn: async (): Promise<ProfitShareAgreement[]> => {
      if (!relationshipId) return [];

      try {
        const { data, error } = await supabase
          .from('profit_share_agreements' as any)
          .select('*')
          .eq('relationship_id', relationshipId)
          .in('status', ['approved', 'active'])
          .order('created_at', { ascending: false });

        if (error) {
          console.warn('[useApprovedAgreements] Query error:', error.message);
          return [];
        }

        // Client-side filter: only agreements that are currently effective
        const now = new Date();
        return ((data || []) as unknown as ProfitShareAgreement[]).filter(a => {
          const from = new Date(a.effective_from);
          if (from > now) return false;
          if (a.expires_at) {
            const until = new Date(a.expires_at);
            if (until < now) return false;
          }
          return true;
        });
      } catch (e) {
        console.warn('[useApprovedAgreements] Failed:', e);
        return [];
      }
    },
    enabled: !!merchantProfile?.merchant_id && !!relationshipId,
  });
}

// ─── Mutation: Create agreement ──────────────────────────────────────

interface CreateAgreementInput {
  relationship_id: string;
  partner_ratio: number;
  merchant_ratio: number;
  settlement_cadence: 'monthly' | 'weekly' | 'per_order';
  invested_capital?: number | null;
  settlement_way?: 'reinvest' | 'withdraw' | null;
  effective_from: string;
  expires_at?: string | null;
  notes?: string | null;
  // Operator Priority fields (optional, only set for operator_priority type)
  agreement_type?: string;
  operator_ratio?: number | null;
  operator_merchant_id?: string | null;
  operator_contribution?: number | null;
  lender_contribution?: number | null;
  terms_snapshot?: Record<string, unknown> | null;
  // Monthly profit handling defaults
  operator_default_profit_handling?: string;
  counterparty_default_profit_handling?: string;
  status?: AgreementStatus;
}

const isSchemaCacheColumnError = (error: unknown): boolean => {
  const message = (error as { message?: string } | null)?.message?.toLowerCase() ?? '';
  return message.includes('schema cache') && message.includes('profit_share_agreements');
};

const stripSharedAgreementFields = <T extends Record<string, unknown>>(input: T): T => {
  const sanitized = { ...input };
  delete sanitized.invested_capital;
  delete sanitized.settlement_way;
  return sanitized;
};

export function useCreateAgreement() {
  const { userId } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: CreateAgreementInput) => {
      const fullPayload = {
        ...input,
        status: input.status || 'pending',
        created_by: userId!,
        // Approved fields should ONLY be set if the status is transition to 'approved'
        approved_by: input.status === 'approved' ? userId! : null,
        approved_at: input.status === 'approved' ? new Date().toISOString() : null,
      };

      const { data, error } = await supabase
        .from('profit_share_agreements' as any)
        .insert(fullPayload)
        .select('*')
        .single();

      if (error && isSchemaCacheColumnError(error)) {
        console.warn('[useCreateAgreement] Schema cache mismatch for "invested_capital". Retrying without shared fields. Please refresh your Supabase schema cache.', error);
        const { data: legacyData, error: legacyError } = await supabase
          .from('profit_share_agreements' as any)
          .insert(stripSharedAgreementFields(fullPayload))
          .select('*')
          .single();
        if (legacyError) throw legacyError;
        return legacyData as unknown as ProfitShareAgreement;
      }

      if (error) throw error;
      return data as unknown as ProfitShareAgreement;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: [AGREEMENTS_KEY] });
    },
  });
}

// ─── Mutation: Edit agreement terms ───────────────────────────────────

interface UpdateAgreementInput extends Partial<CreateAgreementInput> {
