/** Create settlement decisions for a period (called when period becomes due) */
export function useCreateDecisions() {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: {
      periodId: string;
      agreementId: string;
      decisions: Array<{
        merchant_id: string;
        role: string;
        profit_amount: number;
        default_behavior: DefaultProfitHandling;
        effective_capital_before: number;
        decision_due_at: string;
      }>;
    }) => {
      const rows = input.decisions.map(d => ({
        settlement_period_id: input.periodId,
        agreement_id: input.agreementId,
        merchant_id: d.merchant_id,
        role: d.role,
        profit_amount: d.profit_amount,
        decision: 'pending',
        default_behavior: d.default_behavior,
        decision_due_at: d.decision_due_at,
        effective_capital_before: d.effective_capital_before,
        effective_capital_after: d.effective_capital_before, // updated on finalization
      }));

      const { error } = await supabase
        .from('settlement_decisions' as any)
        .insert(rows);
      if (error) throw error;
    },
    onSuccess: (_, vars) => {
      qc.invalidateQueries({ queryKey: [SD_KEY, vars.periodId] });
    },
  });
}

/**
 * Finalize all decisions for a period:
 * - Pending decisions fall back to default_behavior
 * - Calculate effective_capital_after based on decision
 * - Store immutable finalization_snapshot
 */
export function useFinalizeDecisions() {
  const { userId } = useAuth();
  const qc = useQueryClient();

  return useMutation({
    mutationFn: async (input: {
      periodId: string;
      agreementId: string;
      decisions: SettlementDecision[];
      agreementSnapshot: Record<string, unknown>;
    }) => {
      /**
       * ISSUE 7 FIX: The original loop made N sequential UPDATE calls with no
       * atomic guarantee.  A failure on decision #3 of 5 would leave the period
       * half-finalized, corrupting settlement state permanently.
       *
       * Frontend fix: collect ALL errors before throwing so callers get a full
       * picture of what failed, and stop treating partial success as success.
       *
       * ⚠️ BACKEND TASK FOR LOVABLE: replace this entire loop with a single
       * fn_finalize_settlement_decisions(p_period_id, p_agreement_id,
       * p_agreement_snapshot) RPC that runs everything inside one transaction.
       * See the Supabase backend prompt for the exact function signature.
       */
      const finalizedAt = new Date().toISOString();
      const errors: string[] = [];

      for (const d of input.decisions) {
        const finalDecision: 'reinvest' | 'withdraw' =
          d.decision === 'pending' ? d.default_behavior : (d.decision as 'reinvest' | 'withdraw');

        const reinvestedAmount = finalDecision === 'reinvest' ? d.profit_amount : 0;
        const withdrawnAmount = finalDecision === 'withdraw' ? d.profit_amount : 0;
        const effectiveCapitalAfter = d.effective_capital_before + reinvestedAmount;

        const snapshot = {
          ...input.agreementSnapshot,
          merchant_id: d.merchant_id,
          role: d.role,
          profit_amount: d.profit_amount,
          final_decision: finalDecision,
          was_explicit: d.decision !== 'pending',
          default_behavior: d.default_behavior,
          reinvested_amount: reinvestedAmount,
          withdrawn_amount: withdrawnAmount,
          effective_capital_before: d.effective_capital_before,
          effective_capital_after: effectiveCapitalAfter,
          finalized_by: userId,
        };

        const { error } = await supabase
          .from('settlement_decisions' as any)
          .update({
            decision: finalDecision,
            reinvested_amount: reinvestedAmount,
            withdrawn_amount: withdrawnAmount,
            effective_capital_after: effectiveCapitalAfter,
            finalization_snapshot: snapshot,
            finalized_at: finalizedAt,
          })
          .eq('id', d.id);

        // ISSUE 7 FIX: accumulate errors instead of throwing on first failure
        if (error) errors.push(`[${d.id}] ${error.message}`);
      }

      // ISSUE 7 FIX: throw after the loop so callers know exactly which rows
      // failed; partial finalization is exposed rather than silently accepted.
      if (errors.length > 0) {
        throw new Error(`Finalization partially failed (${errors.length}/${input.decisions.length} rows): ${errors.join(' | ')}`);
      }
    },
    onSuccess: (_, vars) => {
      qc.invalidateQueries({ queryKey: [SD_KEY, vars.periodId] });
      qc.invalidateQueries({ queryKey: [SD_KEY, 'pending'] });
    },
  });
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';

export interface SettlementOverviewItem {
  period_id: string;
  deal_id: string;
  deal_title: string;
  relationship_id: string;
  counterparty_name: string;
  status: string;
  partner_amount: number;
  period_key: string;
  cadence: string;
  due_at: string | null;
}

export interface SettlementOverview {
  dueCount: number;
  overdueCount: number;
  settledThisMonth: number;
  totalOutstanding: number;
  items: SettlementOverviewItem[];
  byRelationship: Map<string, { name: string; items: SettlementOverviewItem[] }>;
}

export function useSettlementOverview(overrideMerchantId?: string) {
  const { merchantProfile } = useAuth();
  const effectiveMerchantId = overrideMerchantId || merchantProfile?.merchant_id;

  return useQuery({
    queryKey: ['settlement-overview', effectiveMerchantId],
    queryFn: async (): Promise<SettlementOverview> => {
      // When viewing as admin for a specific merchant, first get that merchant's relationships
      // to scope the settlement periods correctly
      let scopedRelIds: string[] | null = null;
      if (effectiveMerchantId) {
        const { data: myRels } = await supabase
          .from('merchant_relationships')
          .select('id')
          .eq('status', 'active')
          .or(`merchant_a_id.eq.${effectiveMerchantId},merchant_b_id.eq.${effectiveMerchantId}`);
        scopedRelIds = (myRels || []).map(r => r.id);
      }

      let periodsQuery = supabase
        .from('settlement_periods')
        .select('*')
        .in('status', ['due', 'overdue', 'pending'])
        .order('due_at', { ascending: true });

      // If we have scoped relationship IDs, filter settlement periods to only those
      if (scopedRelIds !== null) {
        if (scopedRelIds.length === 0) {
          return { dueCount: 0, overdueCount: 0, settledThisMonth: 0, totalOutstanding: 0, items: [], byRelationship: new Map() };
        }
        periodsQuery = periodsQuery.in('relationship_id', scopedRelIds);
      }

      const { data: periods } = await periodsQuery;

      const items: SettlementOverviewItem[] = [];
      const relIds = [...new Set((periods || []).map((p: any) => p.relationship_id))];
      const dealIds = [...new Set((periods || []).map((p: any) => p.deal_id))];

      // Fetch counterparty names
      const relMap = new Map<string, string>();
      if (relIds.length > 0) {
        const { data: rels } = await supabase.from('merchant_relationships').select('*').in('id', relIds);
        const myId = effectiveMerchantId;
        for (const r of (rels || []) as any[]) {
          const cpId = r.merchant_a_id === myId ? r.merchant_b_id : r.merchant_a_id;
          const { data: profile } = await supabase.from('merchant_profiles').select('display_name').eq('merchant_id', cpId).maybeSingle();
          relMap.set(r.id, profile?.display_name || cpId);
        }
      }

      // Fetch deal titles
      const dealMap = new Map<string, string>();
      if (dealIds.length > 0) {
        const { data: deals } = await supabase.from('merchant_deals').select('id, title').in('id', dealIds);
        (deals || []).forEach(d => dealMap.set(d.id, d.title));
      }

      for (const p of (periods || []) as any[]) {
        items.push({
          period_id: p.id,
          deal_id: p.deal_id,
          deal_title: dealMap.get(p.deal_id) || '—',
          relationship_id: p.relationship_id,
          counterparty_name: relMap.get(p.relationship_id) || '—',
          status: p.status,
          partner_amount: Number(p.partner_amount),
          period_key: p.period_key,
          cadence: p.cadence,
          due_at: p.due_at,
        });
      }

      const byRelationship = new Map<string, { name: string; items: SettlementOverviewItem[] }>();
      for (const item of items) {
        const existing = byRelationship.get(item.relationship_id) || { name: item.counterparty_name, items: [] };
        existing.items.push(item);
        byRelationship.set(item.relationship_id, existing);
      }

      const now = new Date();
      const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
      let settledQuery = supabase
        .from('settlement_periods')
        .select('id')
        .eq('status', 'settled')
        .gte('settled_at', monthStart.toISOString());
      if (scopedRelIds !== null && scopedRelIds.length > 0) {
        settledQuery = settledQuery.in('relationship_id', scopedRelIds);
      }
      const { data: settledThisMonthData } = await settledQuery;

      return {
        dueCount: items.filter(i => i.status === 'due').length,
        overdueCount: items.filter(i => i.status === 'overdue').length,
        settledThisMonth: settledThisMonthData?.length || 0,
        totalOutstanding: items.reduce((s, i) => s + i.partner_amount, 0),
        items,
        byRelationship,
      };
    },
    enabled: !!effectiveMerchantId,
    staleTime: 60_000,
  });
}

