      const dealMap = new Map<string, { title: string; deal_type: string }>();
      if (dealIds.length > 0) {
        const { data: deals } = await supabase
          .from('merchant_deals')
          .select('id, title, deal_type')
          .in('id', dealIds);
        (deals || []).forEach(d => dealMap.set(d.id, { title: d.title, deal_type: d.deal_type }));
      }

      return (data || []).map((p: any) => ({
        ...p,
        deal_title: dealMap.get(p.deal_id)?.title,
        deal_type: dealMap.get(p.deal_id)?.deal_type,
      })) as SettlementPeriod[];
    },
    enabled: !!relationshipId,
  });
}

/**
 * Sync settlement periods: generates missing periods for weekly/monthly deals,
 * aggregates real trade economics into each period, and updates status.
 */
export function useSyncSettlementPeriods(relationshipId: string) {
  const qc = useQueryClient();
  const { merchantProfile } = useAuth();

  return useMutation({
    mutationFn: async (input: {
      deals: { id: string; settlement_cadence: Cadence; created_at: string }[];
      trades: Array<{
        id: string;
        ts: number;
        linkedDealId?: string;
        amountUSDT: number;
        sellPriceQAR: number;
        feeQAR: number;
        voided: boolean;
      }>;
      tradeCalc: Map<string, any>;
    }) => {
      const now = new Date();
      const { deals, trades, tradeCalc } = input;

      for (const deal of deals) {
        if (deal.settlement_cadence === 'per_order') continue;

        const periods = generatePeriods(deal.settlement_cadence, deal.created_at, now);

        const { data: existing } = await supabase
          .from('settlement_periods')
          .select('period_key, id, status, settled_amount')
          .eq('deal_id', deal.id);

        const existingMap = new Map((existing || []).map((e: any) => [e.period_key, e]));

        // Find local trades linked to this deal
        const linkedTrades = trades.filter(t => !t.voided && t.linkedDealId === deal.id);

        // Fetch deal metadata once per deal for share computation
        const { data: dealMeta } = await supabase
          .from('merchant_deals')
          .select('deal_type, notes')
          .eq('id', deal.id)
          .single();

        let partnerPct = 0;
        if (dealMeta?.notes) {
          const ratioMatch = (dealMeta.notes as string).match(/(?:partner_ratio|counterparty_share_pct):\s*(\d+)/);
          if (ratioMatch) partnerPct = Number(ratioMatch[1]);
        }

        let agreement: any = null;
        // Parse agreement ID from pipe-separated notes metadata
        const agreementIdMatch = dealMeta?.notes ? (dealMeta.notes as string).match(/profit_share_agreement_id:\s*([a-f0-9-]+)/) : null;
        const agreementId = agreementIdMatch ? agreementIdMatch[1] : null;
        if (agreementId) {
          const { data: agr } = await supabase
            .from('profit_share_agreements' as any)
            .select('*')
            .eq('id', agreementId)
            .single();
          agreement = agr;
        }

        for (const period of periods) {
          const periodStart = period.start.getTime();
          const periodEnd = period.end.getTime();

          const periodTrades = linkedTrades.filter(t => t.ts >= periodStart && t.ts <= periodEnd);

          let grossVolume = 0;
          let totalCost = 0;
          let totalFees = 0;
          let netProfit = 0;

          for (const t of periodTrades) {
            const rev = t.amountUSDT * t.sellPriceQAR;
            const calc = tradeCalc.get(t.id);
            const cost = calc?.ok ? calc.slices.reduce((s, sl) => s + sl.cost, 0) : 0;
            grossVolume += rev;
            totalCost += cost;
            totalFees += t.feeQAR;
            netProfit += calc?.ok ? calc.netQAR : (rev - cost - t.feeQAR);
          }

          const allocationBase = (dealMeta as any)?.deal_type === 'partnership' ? netProfit : grossVolume;
          let partnerAmount = allocationBase * (partnerPct / 100);
          let merchantAmount = allocationBase - partnerAmount;

          if (agreement) {
            const isOperator = agreement.operator_merchant_id === merchantProfile?.merchant_id;
            const alloc = calculateAgreementAllocation(
              agreement,
              grossVolume,
              totalCost,
              totalFees,
              { isOperator },
            );
            partnerAmount = alloc.partnerAmount;
            merchantAmount = alloc.merchantAmount;
          }

          const ep = existingMap.get(period.key);

          if (!ep) {
            await supabase.from('settlement_periods').insert({
              deal_id: deal.id,
              relationship_id: relationshipId,
              cadence: deal.settlement_cadence,
              period_key: period.key,
              period_start: period.start.toISOString(),
              period_end: period.end.toISOString(),
              due_at: period.dueAt.toISOString(),
              status: computePeriodStatus(period.end, false, now),
              trade_count: periodTrades.length,
              gross_volume: grossVolume,
              total_cost: totalCost,
              net_profit: netProfit,
              total_fees: totalFees,
              partner_amount: partnerAmount,
              merchant_amount: merchantAmount,
              settled_amount: 0,
            } as any);
          } else if (ep.status !== 'settled') {
            const newStatus = computePeriodStatus(period.end, Number(ep.settled_amount) > 0, now);
            await supabase.from('settlement_periods').update({
              trade_count: periodTrades.length,
              gross_volume: grossVolume,
              total_cost: totalCost,
              net_profit: netProfit,
              total_fees: totalFees,
              partner_amount: partnerAmount,
              merchant_amount: merchantAmount,
              status: newStatus,
            } as any).eq('id', ep.id);
          }
        }
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['settlement-periods', relationshipId] });
    },
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import { useEffect } from 'react';

export interface Settlement {
  id: string;
  deal_id: string;
  relationship_id: string | null;
  amount: number;
  currency: string;
  settled_by: string;
  notes: string | null;
  status: string;
  created_at: string;
  deal_title?: string;
  deal_type?: string;
}

export function useSettlements(relationshipId?: string) {
  const { userId } = useAuth();
  const qc = useQueryClient();

  const query = useQuery({
    queryKey: ['settlements', relationshipId],
    queryFn: async (): Promise<Settlement[]> => {
      let q = supabase
        .from('merchant_settlements')
        .select('*')
        .order('created_at', { ascending: false });

      if (relationshipId) {
        q = q.eq('relationship_id', relationshipId);
      }

      const { data, error } = await q;
      if (error) throw error;

      const dealIds = [...new Set((data || []).map(s => s.deal_id))];
      const dealMap = new Map<string, { title: string; deal_type: string }>();
      if (dealIds.length > 0) {
        const { data: deals } = await supabase
          .from('merchant_deals')
          .select('id, title, deal_type')
          .in('id', dealIds);
        (deals || []).forEach(d => dealMap.set(d.id, { title: d.title, deal_type: d.deal_type }));
      }

      return (data || []).map(s => ({
        ...s,
        deal_title: dealMap.get(s.deal_id)?.title,
        deal_type: dealMap.get(s.deal_id)?.deal_type,
      }));
    },
    enabled: !!userId,
  });

  // Realtime
  useEffect(() => {
    if (!relationshipId) return;
    const channel = supabase
      .channel(`settlements:${relationshipId}`)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'merchant_settlements', filter: `relationship_id=eq.${relationshipId}` }, () => {
        qc.invalidateQueries({ queryKey: ['settlements', relationshipId] });
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [relationshipId, qc]);

  return query;
}
export function useSubmitSettlement() {
  const qc = useQueryClient();
  const { userId } = useAuth();

  return useMutation({
    mutationFn: async (input: {
      deal_id: string;
      relationship_id: string;
      amount: number;
      currency: string;
      notes?: string;
    }) => {
      const { error } = await supabase
        .from('merchant_settlements')
        .insert({
          deal_id: input.deal_id,
          relationship_id: input.relationship_id as any,
          amount: input.amount,
          currency: input.currency,
          settled_by: userId!,
          notes: input.notes || null,
          status: 'pending' as any,
        } as any);
      if (error) throw error;
    },
    onSuccess: (_, vars) => {
      qc.invalidateQueries({ queryKey: ['settlements', vars.relationship_id] });
      qc.invalidateQueries({ queryKey: ['settlements'] });
    },
  });
}

export function useApproveSettlement() {
  const qc = useQueryClient();
  const { userId } = useAuth();

  return useMutation({
    mutationFn: async (input: { id: string; approved: boolean }) => {
      if (input.approved) {
        // Risk 3: atomic RPC — approves settlement + marks period settled in one transaction
        const { error } = await supabase.rpc('approve_settlement', {
          _settlement_id: input.id,
        } as any);
        if (error) throw error;
      } else {
        // Risk 3: atomic RPC — rejects settlement + resets period + creates reversal entry
        // Also covers Risk 2 (correct pool_balance_after), Risk 4 (period reset),
        // Risk 5 (original_entry_id on reversal), Risk 6 (double-reversal guard)
        const { error } = await supabase.rpc('reject_settlement', {
          _settlement_id: input.id,
          _actor_id: userId!,
        } as any);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['settlements'] });
      qc.invalidateQueries({ queryKey: ['settlement-periods'] });
      qc.invalidateQueries({ queryKey: ['deal-capital'] });
    },
  });
}

import { supabase } from '@/integrations/supabase/client';
import type { CashAccount, CashLedgerEntry } from './tracker-helpers';

// ── Type adapters (camelCase ↔ snake_case) ──────────────────────

function accountToRow(a: CashAccount, userId: string) {
  return {
    id:              a.id,
    user_id:         userId,
    name:            a.name,
    type:            a.type,
    currency:        a.currency,
    status:          a.status,
    bank_name:       a.bankName  ?? null,
    branch:          a.branch    ?? null,
    notes:           a.notes     ?? null,
    last_reconciled: a.lastReconciled ?? null,
    merchant_id:     a.merchantId ?? null,
    relationship_id: a.relationshipId ?? null,
    purpose:         a.purpose ?? 'custody',
    is_merchant_account: a.isMerchantAccount ?? false,
    created_at:      a.createdAt,
    updated_at:      new Date().toISOString(),
  };
}

function accountToRowLegacy(a: CashAccount, userId: string) {
  return {
    id:              a.id,
    user_id:         userId,
    name:            a.name,
    type:            a.type,
    currency:        a.currency,
    status:          a.status,
    bank_name:       a.bankName  ?? null,
    branch:          a.branch    ?? null,
    notes:           a.notes     ?? null,
    last_reconciled: a.lastReconciled ?? null,
    created_at:      a.createdAt,
    updated_at:      new Date().toISOString(),
  };
}

function rowToAccount(row: Record<string, unknown>): CashAccount {
  return {
    id:             row.id as string,
    name:           row.name as string,
    type:           row.type as CashAccount['type'],
    currency:       row.currency as CashAccount['currency'],
    status:         row.status as 'active' | 'inactive',
    bankName:       (row.bank_name as string | null) ?? undefined,
    branch:         (row.branch   as string | null) ?? undefined,
    notes:          (row.notes    as string | null) ?? undefined,
    lastReconciled: (row.last_reconciled as number | null) ?? undefined,
    merchantId:     (row.merchant_id as string | null) ?? undefined,
    relationshipId: (row.relationship_id as string | null) ?? undefined,
    purpose:        (row.purpose as CashAccount['purpose']) ?? 'custody',
    isMerchantAccount: (row.is_merchant_account as boolean | null) ?? false,
    createdAt:      row.created_at as number,
  };
}

function entryToRow(e: CashLedgerEntry, userId: string) {
  return {
    id:                 e.id,
    user_id:            userId,
    account_id:         e.accountId,
    contra_account_id:  e.contraAccountId  ?? null,
    ts:                 e.ts,
    type:               e.type,
    direction:          e.direction,
    amount:             e.amount,
    currency:           e.currency,
    note:               e.note              ?? null,
    linked_entity_id:   e.linkedEntityId    ?? null,
    linked_entity_type: e.linkedEntityType  ?? null,
    merchant_id:        e.merchantId        ?? null,
    relationship_id:    e.relationshipId    ?? null,
    trade_id:           e.tradeId           ?? null,
    order_id:           e.orderId           ?? null,
    batch_id:           e.batchId           ?? null,
    settlement_id:      e.settlementId      ?? null,
  };
}

function entryToRowLegacy(e: CashLedgerEntry, userId: string) {
  return {
    id:                 e.id,
    user_id:            userId,
    account_id:         e.accountId,
    contra_account_id:  e.contraAccountId  ?? null,
    ts:                 e.ts,
    type:               e.type,
    direction:          e.direction,
    amount:             e.amount,
    currency:           e.currency,
    note:               e.note              ?? null,
    linked_entity_id:   e.linkedEntityId    ?? null,
    linked_entity_type: e.linkedEntityType  ?? null,
    trade_id:           e.tradeId           ?? null,
    order_id:           e.orderId           ?? null,
    batch_id:           e.batchId           ?? null,
    settlement_id:      e.settlementId      ?? null,
  };
}

function rowToEntry(row: Record<string, unknown>): CashLedgerEntry {
  return {
    id:               row.id as string,
    ts:               row.ts as number,
    type:             row.type as CashLedgerEntry['type'],
    accountId:        row.account_id as string,
    contraAccountId:  (row.contra_account_id as string | null) ?? undefined,
    direction:        row.direction as 'in' | 'out',
    amount:           Number(row.amount),
    currency:         row.currency as CashLedgerEntry['currency'],
    note:             (row.note as string | null) ?? undefined,
    linkedEntityId:   (row.linked_entity_id   as string | null) ?? undefined,
    linkedEntityType: (row.linked_entity_type as CashLedgerEntry['linkedEntityType']) ?? undefined,
    merchantId:       (row.merchant_id as string | null) ?? undefined,
    relationshipId:   (row.relationship_id as string | null) ?? undefined,
    tradeId:          (row.trade_id as string | null) ?? undefined,
    orderId:          (row.order_id as string | null) ?? undefined,
    batchId:          (row.batch_id as string | null) ?? undefined,
    settlementId:     (row.settlement_id as string | null) ?? undefined,
  };
}

// ── Save (full upsert) ─────────────────────────────────────────

export async function saveCashToCloud(
  accounts: CashAccount[],
  ledger:   CashLedgerEntry[],
): Promise<void> {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return;

  const uid = user.id;

  // Upsert accounts
  if (accounts.length > 0) {
    const { error: accErr } = await (supabase
      .from('cash_accounts') as any)
      .upsert(accounts.map(a => accountToRow(a, uid)), { onConflict: 'id' });
    if (accErr) {
      if (accErr.message?.includes("Could not find the 'merchant_id' column")) {
        const { error: legacyAccErr } = await (supabase
          .from('cash_accounts') as any)
          .upsert(accounts.map(a => accountToRowLegacy(a, uid)), { onConflict: 'id' });
        if (legacyAccErr) console.warn('[cash-sync] accounts upsert failed (legacy retry):', legacyAccErr.message);
      } else {
        console.warn('[cash-sync] accounts upsert failed:', accErr.message);
      }
    }
  }

  // Upsert ledger entries
  if (ledger.length > 0) {
    const { error: ledErr } = await (supabase
      .from('cash_ledger') as any)
      .upsert(ledger.map(e => entryToRow(e, uid)), { onConflict: 'id' });
    if (ledErr) {
      if (ledErr.message?.includes("Could not find the 'merchant_id' column")) {
        const { error: legacyLedErr } = await (supabase
          .from('cash_ledger') as any)
          .upsert(ledger.map(e => entryToRowLegacy(e, uid)), { onConflict: 'id' });
        if (legacyLedErr) console.warn('[cash-sync] ledger upsert failed (legacy retry):', legacyLedErr.message);
      } else {
        console.warn('[cash-sync] ledger upsert failed:', ledErr.message);
      }
    }
  }
}

// ── Load ───────────────────────────────────────────────────────

export async function loadCashFromCloud(): Promise<{
  accounts: CashAccount[];
  ledger:   CashLedgerEntry[];
} | null> {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const [accResult, ledResult] = await Promise.all([
    (supabase
      .from('cash_accounts') as any)
      .select('*')
      .eq('user_id', user.id)
      .order('created_at', { ascending: true }),
    (supabase
      .from('cash_ledger') as any)
      .select('*')
      .eq('user_id', user.id)
      .order('ts', { ascending: true }),
  ]);

  if (accResult.error) {
    console.warn('[cash-sync] load accounts failed:', accResult.error.message);
    return null;
  }
  if (ledResult.error) {
    console.warn('[cash-sync] load ledger failed:', ledResult.error.message);
    return null;
  }

  return {
    accounts: (accResult.data ?? []).map((r: any) => rowToAccount(r as Record<string,unknown>)),
    ledger:   (ledResult.data ?? []).map((r: any) => rowToEntry(r as Record<string,unknown>)),
  };
}

// ── Delete (for deactivated accounts cleanup — optional) ───────

export async function deleteCashAccountFromCloud(accountId: string): Promise<void> {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return;
  await (supabase
    .from('cash_accounts') as any)
    .delete()
    .eq('id', accountId)
    .eq('user_id', user.id);
}

import { create } from 'zustand';

export interface NotificationNavTarget {
  conversationId: string;
  messageId: string | null;
  notificationId: string;
}

export interface ConversationSummary {
  id: string;
  counterparty_name: string;
  counterparty_nickname?: string;
  last_message: string | null;
  last_message_at: string | null;
  last_sender_id: string | null;
  unread_count: number;
}

export interface ChatMessage {
  id: string;
  relationship_id: string;
  sender_id: string;
  content: string;
  msg_type: string;
  created_at: string;
  read_at: string | null;
  metadata?: Record<string, unknown>;
  reply_to?: string | null;
  sender_name?: string;
}

export interface AttentionState {
  appFocused: boolean;
  inChatModule: boolean;
  activeConversationVisible: boolean;
}

interface ChatState {
  activeConversationId: string | null;
  activeMessageAnchor: string | null;
  highlightMessageId: string | null;
  unreadCounts: Record<string, number>;
  lastReadByConversation: Record<string, string | null>;
  presenceByUser: Record<string, 'online' | 'away' | 'offline'>;
  typingByConversation: Record<string, string[]>;
  attention: AttentionState;
  pendingNotificationNav: NotificationNavTarget | null;
  pendingNotificationNavVersion: number;
}

interface ChatActions {
  setActiveConversation: (id: string | null) => void;
  setAnchor: (messageId: string | null) => void;
  clearHighlight: () => void;
  setAttention: (partial: Partial<AttentionState>) => void;
  setUnreadCount: (relationshipId: string, count: number) => void;
  incrementUnread: (relationshipId: string) => void;
  markConversationRead: (relationshipId: string, lastMsgId: string) => void;
  clearAllUnread: () => void;
  setUnreadCounts: (counts: Record<string, number>) => void;
  setPresence: (userId: string, status: 'online' | 'away' | 'offline') => void;
  setTyping: (relationshipId: string, users: string[]) => void;
  setPendingNav: (target: NotificationNavTarget | null) => void;
  reset: () => void;
}

const initialState: ChatState = {
  activeConversationId: null,
  activeMessageAnchor: null,
  highlightMessageId: null,
  unreadCounts: {},
  lastReadByConversation: {},
  presenceByUser: {},
  typingByConversation: {},
  attention: {
    appFocused: true,
    inChatModule: false,
    activeConversationVisible: false,
  },
  pendingNotificationNav: null,
  pendingNotificationNavVersion: 0,
};

export const useChatStore = create<ChatState & ChatActions>()((set) => ({
  ...initialState,
  setActiveConversation: (id) => set((s) => {
    if (s.activeConversationId === id) return s;
    return { activeConversationId: id, activeMessageAnchor: null, highlightMessageId: null };
  }),
  setAnchor: (messageId) => set({ activeMessageAnchor: messageId, highlightMessageId: messageId }),
  clearHighlight: () => set({ highlightMessageId: null }),
  setAttention: (partial) => set((s) => {
    // Basic avoid-redundant-render check
    const hasChange = Object.entries(partial).some(([k, v]) => (s.attention as any)[k] !== v);
    if (!hasChange) return s;
    return { attention: { ...s.attention, ...partial } };
  }),
  setUnreadCount: (relationshipId, count) => set((s) => ({ unreadCounts: { ...s.unreadCounts, [relationshipId]: count } })),
  incrementUnread: (relationshipId) => set((s) => ({ unreadCounts: { ...s.unreadCounts, [relationshipId]: (s.unreadCounts[relationshipId] || 0) + 1 } })),
  markConversationRead: (relationshipId, lastMsgId) => set((s) => ({
    unreadCounts: { ...s.unreadCounts, [relationshipId]: 0 },
    lastReadByConversation: { ...s.lastReadByConversation, [relationshipId]: lastMsgId },
  })),
  clearAllUnread: () => set({ unreadCounts: {} }),
  setUnreadCounts: (counts) => set({ unreadCounts: counts }),
  setPresence: (userId, status) => set((s) => ({ presenceByUser: { ...s.presenceByUser, [userId]: status } })),
  setTyping: (relationshipId, users) => set((s) => ({ typingByConversation: { ...s.typingByConversation, [relationshipId]: users } })),
  setPendingNav: (target) => set((s) => ({ pendingNotificationNav: target, pendingNotificationNavVersion: s.pendingNotificationNavVersion + 1 })),
  reset: () => set(initialState),
}));

export const selectTotalUnread = (s: ChatState) => Object.values(s.unreadCounts).reduce((sum, n) => sum + n, 0);
export const selectConversationUnread = (relationshipId: string) => (s: ChatState) => s.unreadCounts[relationshipId] || 0;
export const selectIsConversationActive = (relationshipId: string) => (s: ChatState) => s.activeConversationId === relationshipId;

export const isViewingConversationMessage = (
  state: Pick<ChatState, 'activeConversationId' | 'attention'>,
  conversationId: string,
  _messageId?: string | null,
): boolean => (
  state.activeConversationId === conversationId
  && state.attention.appFocused
  && state.attention.inChatModule
  && state.attention.activeConversationVisible
);

export const selectShouldSuppressUnread = (relationshipId: string) => (s: ChatState) =>
  isViewingConversationMessage(s, relationshipId);

// ─── Agreement Templates ────────────────────────────────────────────
// Predefined agreement configurations that traders can quick-apply
// when linking a sale to a partner agreement.
//
// Supported families:
//   - Profit Share (partnership) — splits net profit from linked sales
//   - Sales Deal (arbitrage)    — splits sale-linked economics per order

import type { SupportedDealType } from '@/types/domain';

export interface AgreementTemplate {
  id: string;
  label: { en: string; ar: string };
  description: { en: string; ar: string };
  /** Helper text shown below the template card */
  helperText: { en: string; ar: string };
  dealType: SupportedDealType;
  /** Agreement family for display */
  family: 'profit_share' | 'sales_deal' | 'capital_transfer';
  icon: string;
  /** Predefined metadata values auto-applied on agreement creation */
  defaults: {
    counterparty_share_pct?: number;
    merchant_share_pct?: number;
    partner_ratio?: number;
    merchant_ratio?: number;
    settlement_period?: string;
  };
  /** Color accent for the template card */
  accent: 'brand' | 'good';
  /** Short ratio display like "40/60" */
  ratioDisplay: string;
  /** Tags for quick filtering */
  tags: string[];
}

export const AGREEMENT_TEMPLATES: AgreementTemplate[] = [
