    });
  }, []);

  useEffect(() => { applyThemeToDOM(draft); }, [draft]);

  useEffect(() => {
    const onResize = () => { if (!settingsRef.current.autoFontDisable) applyThemeToDOM(settingsRef.current); };
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  useEffect(() => {
    import('./tracker-sync').then(({ loadPreferencesFromCloud }) => {
      loadPreferencesFromCloud().then((cloudPrefs) => {
        if (!cloudPrefs) return;
        const merged = { ...DEFAULT_SETTINGS, ...cloudPrefs } as AppSettings;
        setSaved(merged); setDraft(merged); setDirty(false);
        localStorage.setItem('tracker_settings', JSON.stringify(merged));
        applyThemeToDOM(merged);
      });
    });
  }, []);

  const autoSaveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const update = useCallback((patch: Partial<AppSettings>) => {
    const changed = (Object.keys(patch) as (keyof AppSettings)[]).filter((key) => draft[key] !== patch[key]);
    if (changed.length === 0) return;
    const next = { ...draft, ...patch };
    setDraft(next); setDirty(true);
    if (changed[0] !== 'searchQuery') {
      if (autoSaveTimer.current) clearTimeout(autoSaveTimer.current);
      autoSaveTimer.current = setTimeout(() => {
        localStorage.setItem('tracker_settings', JSON.stringify(next));
        setSaved(next); setDirty(false);
        import('./tracker-sync').then(({ savePreferencesToCloud }) => savePreferencesToCloud(next as any));
      }, 800);
    }
  }, [draft]);

  const save = useCallback(() => {
    localStorage.setItem('tracker_settings', JSON.stringify(draft));
    setSaved(draft); setDirty(false);
    import('./tracker-sync').then(({ savePreferencesNow }) => savePreferencesNow(draft as any));
  }, [draft]);

  const discard = useCallback(() => { setDraft(saved); setDirty(false); }, [saved]);

  const { layout: currentLayout, theme: currentTheme } = getTheme(draft.layout, draft.theme);

  return (
    <ThemeContext.Provider value={{
      settings: draft, update, save, discard, isDirty: dirty,
      currentLayout, currentTheme,
      logs, addLog: pushLog, clearLogs: () => setLogs([]), downloadLogs: () => {},
    }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be used within ThemeProvider');
  return ctx;
}

const TRACKER_STATE_KEYS = [
  'tracker_state',
  'p2p_tracker_state',
  'p2p_tracker',
  'taheito_tracker_state',
  'taheito_state',
] as const;

const TRACKER_STATE_PREFIXES = ['taheito', 'p2p_tracker'] as const;

const TRACKER_CLEAR_EXACT_KEYS = [
  'tracker_state',
  'tracker_settings',
  'tracker_logs',
  'p2p_tracker_state',
  'p2p_tracker',
  'taheito_tracker_state',
  'taheito_state',
  'p2p_tracker_vault_meta',
] as const;

const IMPORT_STATE_CANDIDATE_KEYS = [
  'state',
  'trackerState',
  'tracker_state',
  'data',
  'payload',
  'appState',
  'backup',
  'snapshot',
  'content',
] as const;

export const AUTO_BACKUP_KEYS = ['gasAutoSave', 'trackerAutoBackup', 'taheitoAutoBackup'] as const;

export type TrackerState = Record<string, unknown>;

function storageKeys(storage: Storage): string[] {
  const keys: string[] = [];
  for (let i = 0; i < storage.length; i += 1) {
    const key = storage.key(i);
    if (key) keys.push(key);
  }
  return keys;
}

function isObject(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function looksLikeTrackerState(value: unknown): value is TrackerState {
  if (!isObject(value)) return false;
  if (Array.isArray(value.trades) || Array.isArray(value.batches) || Array.isArray(value.customers)) return true;
  return false;
}

function extractFromSnapshots(value: Record<string, unknown>): TrackerState | null {
  if (Array.isArray(value.snapshots)) {
    for (const snap of value.snapshots) {
      if (isObject(snap) && looksLikeTrackerState(snap.state)) {
        return snap.state;
      }
    }
  }
  if (Array.isArray(value.versions)) {
    for (const version of value.versions) {
      if (isObject(version) && looksLikeTrackerState(version.state)) return version.state;
      if (isObject(version) && isObject(version.content) && looksLikeTrackerState(version.content.state)) return version.content.state;
    }
  }
  return null;
}

export function normalizeImportedTrackerState(raw: unknown): TrackerState {
  if (looksLikeTrackerState(raw)) return raw;
  if (!isObject(raw)) throw new Error('Invalid backup format');

  const fromSnapshots = extractFromSnapshots(raw);
  if (fromSnapshots) return fromSnapshots;

  for (const key of IMPORT_STATE_CANDIDATE_KEYS) {
    const candidate = raw[key];
    if (looksLikeTrackerState(candidate)) return candidate;
    if (isObject(candidate)) {
      for (const nestedKey of IMPORT_STATE_CANDIDATE_KEYS) {
        const nested = candidate[nestedKey];
        if (looksLikeTrackerState(nested)) return nested;
      }
    }
  }

  throw new Error('Invalid backup format');
}

export function findTrackerStorageKey(storage: Storage): string {
  const existing = storageKeys(storage).find((k) => TRACKER_STATE_PREFIXES.some((prefix) => k.startsWith(prefix)) || TRACKER_STATE_KEYS.includes(k as any));
  return existing || TRACKER_STATE_KEYS[0];
}

export function getCurrentTrackerState(storage: Storage): TrackerState {
  try {
    const key = findTrackerStorageKey(storage);
    const value = storage.getItem(key);
    if (!value) return {};
    return normalizeImportedTrackerState(JSON.parse(value));
  } catch {
    return {};
  }
}

export function loadAutoBackupFromStorage(storage: Storage): boolean {
  for (const key of AUTO_BACKUP_KEYS) {
    const value = storage.getItem(key);
    if (value === 'true') return true;
    if (value === 'false') return false;
  }
  return true;
}

export function saveAutoBackupToStorage(storage: Storage, value: boolean): void {
  for (const key of AUTO_BACKUP_KEYS) storage.setItem(key, String(value));
}

export function listTrackerKeysToClear(storage: Storage): string[] {
  const keys = new Set<string>([
    ...TRACKER_CLEAR_EXACT_KEYS,
    ...AUTO_BACKUP_KEYS,
  ]);

  for (const key of storageKeys(storage)) {
    if (TRACKER_STATE_PREFIXES.some((prefix) => key.startsWith(prefix))) keys.add(key);
    if (key.startsWith('tracker_')) keys.add(key);
  }

  return Array.from(keys);
}

export function clearTrackerStorage(storage: Storage): void {
  for (const key of listTrackerKeysToClear(storage)) {
    storage.removeItem(key);
  }
}

// Exact helper functions from the TRACKER_CLOUDFLARE- repo

export function num(v: any, def = 0): number {
  const n = parseFloat(v);
  return isNaN(n) ? def : n;
}

// ── Centralized number formatting ──────────────────────────────────
// Rule: TRUNCATION everywhere (not rounding) for consistency.

/**
 * Truncate a number to `dp` decimal places without rounding.
 * e.g. trunc4(3.73234) → 3.7323
 */
function truncateToDP(n: number, dp: number): number {
  const factor = Math.pow(10, dp);
  return Math.trunc(n * factor) / factor;
}

/**
 * Format a PRICE value: max 4 decimal places, truncated, no trailing zeros.
 * Examples: 3 → "3", 3.7 → "3.7", 3.7300 → "3.73", 3.73234 → "3.7323"
 */
export function fmtPrice(n: number): string {
  if (!Number.isFinite(n)) return '—';
  const truncated = truncateToDP(n, 4);
  // Use toFixed(4) then strip trailing zeros
  let s = truncated.toFixed(4);
  // Remove trailing zeros after decimal point
  if (s.includes('.')) {
    s = s.replace(/0+$/, '').replace(/\.$/, '');
  }
  return s;
}

/**
 * Format a TOTAL/aggregate value: whole number (truncated), with thousands separators.
 * Examples: 7790.00 → "7,790", 1250.75 → "1,250"
 */
export function fmtTotal(n: number): string {
  if (!Number.isFinite(n)) return '—';
  const truncated = Math.trunc(n);
  return truncated.toLocaleString(undefined, { maximumFractionDigits: 0, minimumFractionDigits: 0 });
}

export function fmtU(n: number, dp = 2): string {
  if (!Number.isFinite(n)) return '—';
  // dp === 0 → total formatting (whole number, truncated)
  if (dp === 0) return fmtTotal(n);
  // Otherwise → price formatting (max 4dp, truncated, no trailing zeros)
  return fmtPrice(n);
}

export function fmtQ(v: number): string {
  const x = num(v, 0);
  return fmtTotal(x) + ' QAR';
}

export function fmtQRaw(v: number): string {
  const x = num(v, 0);
  return fmtTotal(x);
}

export function fmtP(n: number): string {
  const x = num(n, 0);
  if (!Number.isFinite(x)) return '—';
  return fmtPrice(x);
}

export function fmtPct(n: number): string {
  if (!Number.isFinite(num(n))) return '—';
  const v = num(n);
  return (v >= 0 ? '+' : '') + Math.trunc(v).toLocaleString(undefined, { maximumFractionDigits: 0 }) + '%';
}

export function fmtDur(ms: number): string {
  if (!ms || ms < 0) return '—';
  const m = Math.floor(ms / 60000);
  const h = Math.floor(m / 60);
  const d = Math.floor(h / 24);
  if (d > 0) return d + 'd ' + (h % 24) + 'h';
  if (h > 0) return h + 'h ' + (m % 60) + 'm';
  return m + 'm';
}

export function fmtDate(ts: number): string {
  return new Date(ts).toLocaleDateString();
}

export function fmtQWithUnit(qarAmount: number, currency = 'QAR', wacop: number | null = null): string {
  const q = num(qarAmount);
  if (!Number.isFinite(q)) return '—';
  if (currency === 'USDT' && wacop && wacop > 0) {
    return fmtPrice(q / wacop) + ' USDT';
  }
  return fmtTotal(q) + ' QAR';
}

export function esc(s: any): string {
  return String(s || '');
}

export function startOfDay(ts: number): number {
  const d = new Date(ts);
  d.setHours(0, 0, 0, 0);
  return d.getTime();
}

export function uid(): string {
  return Math.random().toString(36).slice(2, 10);
}

