// ── FIFO computation ──

/** Returns true if a trade should be excluded from FIFO stock consumption */
function isTradeInactive(t: Trade): boolean {
  if (t.voided) return true;
  const status = t.approvalStatus;
  if (status === 'cancelled' || status === 'rejected') return true;
  return false;
}

/**
 * Select eligible batches for a trade using merchant-aware FIFO.
 * If the trade is linked to a merchant (via linkedMerchantId or linkedRelId),
 * prefer batches whose source matches the merchant/supplier name.
 * Fall back to all remaining batches if merchant pool is exhausted.
 */
function selectEligibleBatches(
  trade: Trade,
  sortedBatches: Batch[],
  remaining: Map<string, number>,
): Batch[] {
  // If the trade is merchant-linked, try to identify supplier-specific batches
  const merchantId = trade.linkedMerchantId;
  if (merchantId) {
    const merchantBatches = sortedBatches.filter(b => {
      const rem = remaining.get(b.id) || 0;
      if (rem <= 0) return false;
      // Match by source containing the merchant ID (case-insensitive)
      const src = (b.source || '').toLowerCase();
      return src.includes(merchantId.toLowerCase());
    });
    if (merchantBatches.length > 0) {
      // Merchant pool first, then remaining global pool as fallback
      const globalFallback = sortedBatches.filter(b => {
        const rem = remaining.get(b.id) || 0;
        return rem > 0 && !merchantBatches.includes(b);
      });
      return [...merchantBatches, ...globalFallback];
    }
  }
  // Default: global FIFO order
  return sortedBatches;
}

export function computeFIFO(batches: Batch[], trades: Trade[]): DerivedState {
  const sortedBatches = [...batches].sort((a, b) => a.ts - b.ts);
  const remaining = new Map<string, number>();
  for (const b of sortedBatches) remaining.set(b.id, b.initialUSDT);

  const tradeCalc = new Map<string, TradeCalcResult>();
  // Filter out inactive trades (voided, cancelled, rejected) from stock consumption
  const sortedTrades = [...trades].filter(t => !isTradeInactive(t) && t.usesStock).sort((a, b) => a.ts - b.ts);

  for (const t of sortedTrades) {
    let qtyLeft = t.amountUSDT;
    const slices: { batchId: string; qty: number; cost: number }[] = [];
    let totalCost = 0;

    // Use merchant-aware batch selection
    const eligibleBatches = selectEligibleBatches(t, sortedBatches, remaining);

    for (const b of eligibleBatches) {
      if (qtyLeft <= 0) break;
      const rem = remaining.get(b.id) || 0;
      if (rem <= 0) continue;
      const allocated = Math.min(rem, qtyLeft);
      slices.push({ batchId: b.id, qty: allocated, cost: allocated * b.buyPriceQAR });
      totalCost += allocated * b.buyPriceQAR;
      remaining.set(b.id, rem - allocated);
      qtyLeft -= allocated;
    }

    const rev = t.amountUSDT * t.sellPriceQAR;
    const netQAR = rev - totalCost - t.feeQAR;
    const avgBuyQAR = t.amountUSDT > 0 ? totalCost / t.amountUSDT : 0;
    const margin = rev > 0 ? (netQAR / rev) * 100 : 0;

    tradeCalc.set(t.id, {
      ok: slices.length > 0 || !t.usesStock,
      netQAR,
      avgBuyQAR,
      margin,
      ppu: rev > 0 ? netQAR / t.amountUSDT : 0,
      slices,
    });
  }

  // Non-stock trades (manual mode) — use manualBuyPrice for cost
  // Also exclude inactive trades here
  for (const t of trades.filter(t => !isTradeInactive(t) && !t.usesStock)) {
    const rev = t.amountUSDT * t.sellPriceQAR;
    const cost = t.manualBuyPrice ? t.amountUSDT * t.manualBuyPrice : 0;
    const netQAR = rev - cost - t.feeQAR;
    const avgBuyQAR = t.manualBuyPrice || 0;
    const margin = rev > 0 ? (netQAR / rev) * 100 : 0;
    tradeCalc.set(t.id, {
      ok: true,
      netQAR,
      avgBuyQAR,
      margin,
      ppu: rev > 0 ? netQAR / t.amountUSDT : 0,
      slices: [],
    });
  }

  const derivedBatches: DerivedBatch[] = sortedBatches.map(b => ({
    id: b.id,
    buyPriceQAR: b.buyPriceQAR,
    initialUSDT: b.initialUSDT,
    remainingUSDT: Math.max(0, remaining.get(b.id) || 0),
  }));

  return { batches: derivedBatches, tradeCalc };
}

export function totalStock(derived: DerivedState): number {
  return derived.batches.reduce((s, b) => s + Math.max(0, b.remainingUSDT), 0);
}

export function stockCostQAR(derived: DerivedState): number {
  return derived.batches.reduce((s, b) => s + Math.max(0, b.remainingUSDT) * b.buyPriceQAR, 0);
}

export function getWACOP(derived: DerivedState): number | null {
  const a = derived.batches.filter(b => b.remainingUSDT > 0);
  if (!a.length) return null;
  const tv = a.reduce((s, b) => s + b.remainingUSDT * b.buyPriceQAR, 0);
  const ta = a.reduce((s, b) => s + b.remainingUSDT, 0);
  return ta > 0 ? tv / ta : null;
}

export function inRange(ts: number, range: string): boolean {
  const now = new Date();
  const nowTs = now.getTime();
  const startOfThisMonth = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
  const startOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1).getTime();

  if (range === 'all') return true;
  if (range === 'today') return ts >= startOfDay(nowTs);
  if (range === '7d') return ts >= nowTs - 7 * 864e5;
  if (range === '30d') return ts >= nowTs - 30 * 864e5;
  if (range === 'this_month') return ts >= startOfThisMonth;
  if (range === 'last_month') return ts >= startOfLastMonth && ts < startOfThisMonth;
  return true;
}

/** Apply merchant share to net profit for linked trades (show only "my cut") */
function getMySharePct(trade: Trade): number {
  // Legacy rows may store 0 or invalid pct values; recover from partnerPct when possible.
  const merchantPct = Number(trade.merchantPct);
  if (Number.isFinite(merchantPct) && merchantPct > 0 && merchantPct <= 100) return merchantPct;
  const partnerPct = Number(trade.partnerPct);
  if (Number.isFinite(partnerPct) && partnerPct >= 0 && partnerPct < 100) return 100 - partnerPct;
  return 100;
}

function applyMyShare(trade: Trade, fullNet: number): number {
  if (trade.linkedDealId || trade.linkedRelId) {
    return fullNet * getMySharePct(trade) / 100;
  }
  return fullNet;
}

export function kpiFor(state: TrackerState, derived: DerivedState, range: string) {
  const trades = state.trades.filter(t => !isTradeInactive(t) && inRange(t.ts, range));
  let rev = 0, net = 0, qty = 0, fee = 0;
  for (const t of trades) {
    const c = derived.tradeCalc.get(t.id);
    const tradeRev = t.amountUSDT * t.sellPriceQAR;
    rev += tradeRev;
    qty += t.amountUSDT;
    fee += t.feeQAR;
    let fullNet = 0;
    if (c?.ok) {
      fullNet = c.netQAR;
    } else if (t.manualBuyPrice) {
      fullNet = tradeRev - (t.amountUSDT * t.manualBuyPrice) - t.feeQAR;
    }
    net += applyMyShare(t, fullNet);
  }
  const margins = trades
    .map(t => { const c = derived.tradeCalc.get(t.id); return c?.ok ? c.margin : null; })
    .filter((x): x is number => x !== null);
  const avgMgn = margins.length ? margins.reduce((s, v) => s + v, 0) / margins.length : 0;
  return { rev, net, qty, fee, count: trades.length, avgMgn };
}

export function rangeLabel(range: string): string {
  if (range === 'today') return 'Today';
  if (range === '7d') return '7 Days';
  if (range === '30d') return '30 Days';
  if (range === 'this_month') return 'This Month';
  if (range === 'last_month') return 'Last Month';
  if (range === 'all') return 'All Time';
  return range;
}

export function batchCycleTime(state: TrackerState, derived: DerivedState, id: string): number | null {
  const b = state.batches.find(x => x.id === id);
  if (!b) return null;
  const cs = state.trades.filter(t => {
    const c = derived.tradeCalc.get(t.id);
    return c?.ok && c.slices.some(s => s.batchId === id);
  });
  return cs.length ? Math.max(...cs.map(t => t.ts)) - b.ts : null;
}

// Cross-device tracker state & preferences sync via Supabase
import { supabase } from '@/integrations/supabase/client';
import { findTrackerStorageKey } from './tracker-backup';
import type { TrackerState } from './tracker-helpers';

let _saveTimer: ReturnType<typeof setTimeout> | null = null;
let _lastSavedJson = '';
let _prefTimer: ReturnType<typeof setTimeout> | null = null;
let _lastSavedPrefs = '';

function stateToJson(state: TrackerState): string {
  try {
    return JSON.stringify(state);
  } catch {
    return '';
  }
}

type TrackerSnapshotRow = {
  state: Partial<TrackerState> | null;
  updated_at?: string | null;
  user_id?: string;
};

function mergeArrayById<T>(base: T[] | undefined, incoming: T[] | undefined): T[] {
  const out = new Map<string, T>();
  for (const item of base || []) {
    const key = typeof item === 'object' && item && 'id' in (item as Record<string, unknown>)
      ? String((item as Record<string, unknown>).id)
      : JSON.stringify(item);
    out.set(key, item);
  }
  for (const item of incoming || []) {
    const key = typeof item === 'object' && item && 'id' in (item as Record<string, unknown>)
      ? String((item as Record<string, unknown>).id)
      : JSON.stringify(item);
    out.set(key, item);
  }
  return Array.from(out.values());
}

/** Merge multiple snapshot states into one merchant-scoped view. */
export function mergeTrackerStatesForMerchant(rows: TrackerSnapshotRow[]): Partial<TrackerState> | null {
  const validRows = rows
    .filter(r => r.state && typeof r.state === 'object')
    .sort((a, b) => {
      const at = new Date(a.updated_at || 0).getTime();
      const bt = new Date(b.updated_at || 0).getTime();
      return at - bt;
    });

  if (validRows.length === 0) return null;

  let merged: Partial<TrackerState> = {};
  for (const row of validRows) {
    const state = row.state!;
    merged = {
      ...merged,
      ...state,
      batches: mergeArrayById(merged.batches, Array.isArray(state.batches) ? state.batches : []),
      trades: mergeArrayById(merged.trades, Array.isArray(state.trades) ? state.trades : []),
      customers: mergeArrayById(merged.customers, Array.isArray(state.customers) ? state.customers : []),
      cashAccounts: mergeArrayById(merged.cashAccounts, Array.isArray(state.cashAccounts) ? state.cashAccounts : []),
      cashLedger: mergeArrayById(merged.cashLedger, Array.isArray(state.cashLedger) ? state.cashLedger : []),
      cashHistory: mergeArrayById(merged.cashHistory, Array.isArray(state.cashHistory) ? state.cashHistory : []),
    };
  }
  return merged;
}

/** Save tracker state to localStorage */
function persistToLocal(state: TrackerState): void {
  if (typeof window === 'undefined') return;
  try {
    const key = findTrackerStorageKey(window.localStorage);
    window.localStorage.setItem(key, stateToJson(state));
    window.localStorage.removeItem('tracker_data_cleared');
  } catch {
    // quota exceeded — silent
  }
}

/** Upsert row ensuring user_id row exists */
async function ensureRow(userId: string): Promise<void> {
  await supabase
    .from('tracker_snapshots' as any)
    .upsert(
      { user_id: userId, updated_at: new Date().toISOString() },
      { onConflict: 'user_id', ignoreDuplicates: true }
    );
}

/** Save tracker state to Supabase (upsert) — debounced */
async function persistToCloud(state: TrackerState): Promise<void> {
  const json = stateToJson(state);
  if (!json || json === _lastSavedJson) return;

  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return;

  const { error } = await supabase
    .from('tracker_snapshots' as any)
    .upsert(
      { user_id: user.id, state: state as any, updated_at: new Date().toISOString() },
      { onConflict: 'user_id' }
    );

  if (!error) {
    _lastSavedJson = json;
  } else {
    console.warn('[tracker-sync] cloud save failed:', error.message);
  }
}

/** Persist state to localStorage immediately and to cloud (debounced 2s) */
export function saveTrackerState(state: TrackerState): void {
  persistToLocal(state);

  if (_saveTimer) clearTimeout(_saveTimer);
  _saveTimer = setTimeout(() => {
    void persistToCloud(state);
  }, 2000);
}

/** Force an immediate cloud save (e.g. on import/restore) */
export async function saveTrackerStateNow(state: TrackerState): Promise<void> {
  if (_saveTimer) clearTimeout(_saveTimer);
  persistToLocal(state);
  await persistToCloud(state);
}

/** Load tracker state from cloud, returning null if none found */
export async function loadTrackerStateFromCloud(): Promise<Partial<TrackerState> | null> {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const { data: myMerchantProfile } = await supabase
    .from('merchant_profiles')
    .select('merchant_id')
    .eq('user_id', user.id)
    .maybeSingle();

  let cloudState: Partial<TrackerState> | null = null;
  const merchantId = (myMerchantProfile as any)?.merchant_id as string | undefined;

  if (merchantId) {
    const { data: merchantUsers } = await supabase
      .from('merchant_profiles')
      .select('user_id')
      .eq('merchant_id', merchantId);
    const merchantUserIds = Array.from(new Set((merchantUsers || []).map((m: any) => m.user_id).filter(Boolean)));

    const { data, error } = await supabase
      .from('tracker_snapshots' as any)
      .select('state, updated_at, user_id')
      .in('user_id', merchantUserIds.length ? merchantUserIds : [user.id]);
    if (!error && data) {
      cloudState = mergeTrackerStatesForMerchant(data as unknown as TrackerSnapshotRow[]);
    }
  } else {
    const { data, error } = await supabase
      .from('tracker_snapshots' as any)
      .select('state, updated_at')
      .eq('user_id', user.id)
      .maybeSingle();
    if (!error && data) {
      cloudState = (data as any).state as Partial<TrackerState> | null;
    }
  }

  if (!cloudState || typeof cloudState !== 'object') return null;

  // Validate it looks like tracker state
  if (!Array.isArray(cloudState.batches) && !Array.isArray(cloudState.trades) && !Array.isArray(cloudState.customers)) {
    return null;
  }

  return cloudState;
}

// ── Preferences sync ──

/** Save user preferences to cloud (debounced 1.5s) */
export function savePreferencesToCloud(prefs: Record<string, unknown>): void {
  if (_prefTimer) clearTimeout(_prefTimer);
  _prefTimer = setTimeout(() => {
    void persistPrefsToCloud(prefs);
  }, 1500);
}

/** Force immediate preference save */
export async function savePreferencesNow(prefs: Record<string, unknown>): Promise<void> {
  if (_prefTimer) clearTimeout(_prefTimer);
  await persistPrefsToCloud(prefs);
}

async function persistPrefsToCloud(prefs: Record<string, unknown>): Promise<void> {
  const json = JSON.stringify(prefs);
  if (json === _lastSavedPrefs) return;

  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return;

  const { error } = await supabase
    .from('tracker_snapshots' as any)
    .upsert(
      { user_id: user.id, preferences: prefs as any, updated_at: new Date().toISOString() },
      { onConflict: 'user_id' }
    );

  if (!error) {
    _lastSavedPrefs = json;
  } else {
    console.warn('[tracker-sync] preferences save failed:', error.message);
  }
}

/** Load preferences from cloud */
export async function loadPreferencesFromCloud(): Promise<Record<string, unknown> | null> {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const { data, error } = await supabase
    .from('tracker_snapshots' as any)
    .select('preferences')
    .eq('user_id', user.id)
    .maybeSingle();

  if (error || !data) return null;

  const prefs = (data as any).preferences as Record<string, unknown> | null;
  if (!prefs || typeof prefs !== 'object' || Object.keys(prefs).length === 0) return null;

  return prefs;
}

// React hook that provides tracker state with cross-device cloud sync
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { computeFIFO, type TrackerState, type DerivedState } from './tracker-helpers';
import { createEmptyState, buildStateFrom, mergeLocalAndCloud } from './tracker-state';
import { saveTrackerState, loadTrackerStateFromCloud } from './tracker-sync';
import { getCurrentTrackerState } from './tracker-backup';
import { useAuth } from '@/features/auth/auth-context';
import { saveCashToCloud, loadCashFromCloud } from './cash-sync';

interface UseTrackerOptions {
  lowStockThreshold?: number;
  priceAlertThreshold?: number;
  range?: string;
  currency?: 'QAR' | 'USDT';
  /** When provided (admin view), skip cloud sync and use this state directly */
  preloadedState?: any;
}

export function useTrackerState(options: UseTrackerOptions = {}) {
  const { isAuthenticated } = useAuth();
  const [cloudLoaded, setCloudLoaded] = useState(false);

  const initial = useMemo(() => createEmptyState({
    lowStockThreshold: options.lowStockThreshold,
    priceAlertThreshold: options.priceAlertThreshold,
    range: options.range,
    currency: options.currency,
  }), []);

  const [state, setState] = useState<TrackerState>(initial.state);
  const [derived, setDerived] = useState<DerivedState>(initial.derived);
  const stateRef = useRef(state);
  const cashSaveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const applyState = useCallback((next: TrackerState) => {
    // In admin preloaded mode, don't persist
    if (options.preloadedState) {
      setState(next);
      stateRef.current = next;
      setDerived(computeFIFO(next.batches, next.trades));
      return;
    }
    setState(next);
    stateRef.current = next;
    setDerived(computeFIFO(next.batches, next.trades));
    saveTrackerState(next);
    // Debounced sync to dedicated cash tables
    if (next.cashAccounts?.length || next.cashLedger?.length) {
      if (cashSaveTimer.current) clearTimeout(cashSaveTimer.current);
      cashSaveTimer.current = setTimeout(() => {
        saveCashToCloud(next.cashAccounts ?? [], next.cashLedger ?? [])
          .catch(err => console.error('[useTrackerState] saveCashToCloud failed:', err));
      }, 2500);
    }
  }, [options.preloadedState]);

  // Handle preloaded state (admin view)
  useEffect(() => {
    if (!options.preloadedState) return;
    const ps = options.preloadedState;
    const rebuilt = buildStateFrom(ps, {
      lowStockThreshold: options.lowStockThreshold,
      priceAlertThreshold: options.priceAlertThreshold,
      range: options.range,
      currency: options.currency,
    });
    setState(rebuilt.state);
    stateRef.current = rebuilt.state;
    setDerived(rebuilt.derived);
    setCloudLoaded(true);
  }, [options.preloadedState]);

  // On mount + auth, try loading from cloud and merge with local
  useEffect(() => {
    if (options.preloadedState) return; // skip cloud sync in admin mode
    if (!isAuthenticated) return;

    let cancelled = false;
    loadTrackerStateFromCloud().then((cloudState) => {
      if (cancelled) return;
      setCloudLoaded(true);

      if (!cloudState) {
        // No cloud state — push local to cloud
        saveTrackerState(stateRef.current);
        return;
      }

      const local = getCurrentTrackerState(window.localStorage) as Partial<TrackerState> | null;
      const best = mergeLocalAndCloud(local, cloudState);
      if (!best) return;

      const rebuilt = buildStateFrom(best, {
        lowStockThreshold: options.lowStockThreshold,
        priceAlertThreshold: options.priceAlertThreshold,
        range: options.range,
        currency: options.currency,
      });

      setState(rebuilt.state);
      stateRef.current = rebuilt.state;
      setDerived(rebuilt.derived);
      // Also update localStorage with merged state
      saveTrackerState(rebuilt.state);

      // Load dedicated cash tables and merge with local state (prefer cloud, keep local-only entries)
      // ISSUE 6 FIX: previously stateRef.current was never updated after the
      // async setState callback, so any call to applyState() that happened
      // immediately after the cash merge would read stale pre-cash data from
      // stateRef.current and overwrite the cloud cash values when persisting.
      loadCashFromCloud().then(cashData => {
        if (!cashData) return;
        if (cashData.accounts.length === 0 && cashData.ledger.length === 0) return;
        setState(prev => {
          const cloudIds = new Set(cashData.ledger.map((e: { id: string }) => e.id));
          const localOnly = (prev.cashLedger || []).filter(e => !cloudIds.has(e.id));
          const next = {
            ...prev,
            cashAccounts: cashData.accounts,
            cashLedger: [...cashData.ledger, ...localOnly],
          };
          stateRef.current = next;   // ← ISSUE 6 FIX: keep ref in sync with merged cash state
          return next;
        });
      }).catch((err) => { console.error('[useTrackerState] cash cloud sync failed:', err); });
    }).catch((err) => {
      console.error('[useTrackerState] cloud load failed:', err);
      setCloudLoaded(true);
    });

    return () => { cancelled = true; };
  }, [isAuthenticated, options.preloadedState]);

  return { state, derived, applyState, cloudLoaded };
}

