// ── Page ─────────────────────────────────────────────────────────────
export default function CRMPage() {
  const { settings } = useTheme();
  const t = useT();
  const navigate = useNavigate();
  const { state, applyState } = useTrackerState({
    lowStockThreshold: settings.lowStockThreshold,
    priceAlertThreshold: settings.priceAlertThreshold,
  });

  const [tab, setTab] = useState<'pipeline' | 'list' | 'suppliers'>('pipeline');
  const [search, setSearch] = useState('');

  // ── Customer modal ────────────────────────────────────────────────
  const [showCustModal, setShowCustModal] = useState(false);
  const [editingCust, setEditingCust] = useState<Customer | null>(null);
  const [custForm, setCustForm] = useState(blankCustomer());
  const [custError, setCustError] = useState('');

  // ── Supplier rename modal ─────────────────────────────────────────
  const [showSuppModal, setShowSuppModal] = useState(false);
  const [editingSupp, setEditingSupp] = useState('');
  const [suppName, setSuppName] = useState('');
  const [suppError, setSuppError] = useState('');

  // ── Supplier add modal ────────────────────────────────────────────
  const [showAddSuppModal, setShowAddSuppModal] = useState(false);
  const [newSuppName, setNewSuppName] = useState('');
  const [newSuppError, setNewSuppError] = useState('');

  // ── Derived lists ─────────────────────────────────────────────────
  const customers = state.customers ?? [];

  const filteredCustomers = useMemo(() => {
    if (!search) return customers;
    const q = search.toLowerCase();
    return customers.filter(c =>
      c.name.toLowerCase().includes(q) || c.phone.includes(q),
    );
  }, [customers, search]);

  const suppliers = useMemo(() => {
    const map = new Map<string, { name: string; batchCount: number; totalUSDT: number; avgCost: number; spentQAR: number; lastDate: number; volumePct: number }>();
    let grandTotal = 0;
    for (const b of state.batches) {
      const src = b.source.trim();
      if (!src) continue;
      const cost = b.initialUSDT * b.buyPriceQAR;
      const ex = map.get(src);
      if (ex) {
        ex.batchCount++;
        ex.totalUSDT += b.initialUSDT;
        ex.spentQAR += cost;
        ex.lastDate = Math.max(ex.lastDate, b.ts);
      } else {
        map.set(src, { name: src, batchCount: 1, totalUSDT: b.initialUSDT, avgCost: 0, spentQAR: cost, lastDate: b.ts, volumePct: 0 });
      }
      grandTotal += b.initialUSDT;
    }
    const arr = Array.from(map.values());
    for (const s of arr) {
      s.avgCost = s.totalUSDT > 0 ? s.spentQAR / s.totalUSDT : 0;
      s.volumePct = grandTotal > 0 ? (s.totalUSDT / grandTotal) * 100 : 0;
    }
    return arr.sort((a, b) => b.totalUSDT - a.totalUSDT);
  }, [state.batches]);

  const filteredSuppliers = useMemo(() => {
    if (!search) return suppliers;
    const q = search.toLowerCase();
    return suppliers.filter(s => s.name.toLowerCase().includes(q));
  }, [suppliers, search]);

  // ── Stats ─────────────────────────────────────────────────────────
  const customerStats = (cId: string) => {
    const trades = state.trades.filter(tr => !tr.voided && tr.customerId === cId);
    const totalUSDT = trades.reduce((s, tr) => s + tr.amountUSDT, 0);
    const totalRevenue = trades.reduce((s, tr) => s + tr.amountUSDT * tr.sellPriceQAR, 0);
    // Simple P&L: revenue - cost (using FIFO cost basis approximation)
    const totalCost = trades.reduce((s, tr) => {
      // If trade uses stock, approximate cost from batches avg
      const avgBuyCost = state.batches.length > 0
        ? state.batches.reduce((a, b) => a + b.buyPriceQAR * b.initialUSDT, 0) / Math.max(1, state.batches.reduce((a, b) => a + b.initialUSDT, 0))
        : 0;
      return s + tr.amountUSDT * avgBuyCost;
    }, 0);
    const pnl = totalRevenue - totalCost;
    const lastTrade = trades.length > 0 ? Math.max(...trades.map(tr => tr.ts)) : 0;
    return { trades: trades.length, totalUSDT, totalQAR: totalRevenue, pnl, lastTrade };
  };

  const kpis = useMemo(() => {
    const allTrades = state.trades.filter(tr => !tr.voided);
    const totalUSDT = allTrades.reduce((s, tr) => s + tr.amountUSDT, 0);
    const totalRevenue = allTrades.reduce((s, tr) => s + tr.amountUSDT * tr.sellPriceQAR, 0);
    const avgBuyCost = state.batches.length > 0
      ? state.batches.reduce((a, b) => a + b.buyPriceQAR * b.initialUSDT, 0) / Math.max(1, state.batches.reduce((a, b) => a + b.initialUSDT, 0))
      : 0;
    const totalCost = allTrades.reduce((s, tr) => s + tr.amountUSDT * avgBuyCost, 0);
    const netPnl = totalRevenue - totalCost;
    const linkedTrades = allTrades.filter(tr => tr.linkedRelId).length;
    const tierCounts = { A: 0, B: 0, C: 0 };
    for (const c of customers) {
      if (c.tier === 'A') tierCounts.A++;
      else if (c.tier === 'B') tierCounts.B++;
      else tierCounts.C++;
    }
    return { clients: customers.length, totalUSDT, netPnl, linkedTrades, supplierCount: suppliers.length, tierCounts };
  }, [state.trades, state.batches, customers, suppliers]);

  const maxSupplierUSDT = useMemo(() => {
    return suppliers.reduce((max, s) => Math.max(max, s.totalUSDT), 0);
  }, [suppliers]);

  // ── Customer handlers ─────────────────────────────────────────────
  const openAddCustomer = () => {
    setEditingCust(null);
    setCustForm(blankCustomer());
    setCustError('');
    setShowCustModal(true);
  };

  const openEditCustomer = (c: Customer) => {
    setEditingCust(c);
    setCustForm({ name: c.name, phone: c.phone, tier: c.tier, dailyLimitUSDT: c.dailyLimitUSDT, notes: c.notes });
    setCustError('');
    setShowCustModal(true);
  };

  const saveCustomer = () => {
    if (!custForm.name.trim()) { setCustError('Name is required.'); return; }
    const existing = customers.find(
      c => c.name.toLowerCase() === custForm.name.trim().toLowerCase() && c.id !== editingCust?.id
    );
    if (existing) { setCustError('A customer with this name already exists.'); return; }

    const next = editingCust
      ? customers.map(c => c.id === editingCust.id ? { ...c, ...custForm, name: custForm.name.trim() } : c)
      : [...customers, { id: uid(), createdAt: Date.now(), ...custForm, name: custForm.name.trim() } as Customer];

    applyState({ ...state, customers: next });
    setShowCustModal(false);
  };

  const deleteCustomer = (id: string) => {
    if (!window.confirm('Delete this customer? This cannot be undone.')) return;
    applyState({ ...state, customers: customers.filter(c => c.id !== id) });
  };

  // ── Supplier handlers ─────────────────────────────────────────────
  const openEditSupplier = (name: string) => {
    setEditingSupp(name);
    setSuppName(name);
    setSuppError('');
    setShowSuppModal(true);
  };

  const openAddSupplier = () => {
    setNewSuppName('');
    setNewSuppError('');
    setShowAddSuppModal(true);
  };

  const saveNewSupplier = () => {
    const name = newSuppName.trim();
    if (!name) { setNewSuppError('Supplier name is required.'); return; }
    const exists = suppliers.some(s => s.name.toLowerCase() === name.toLowerCase());
    if (exists) { setNewSuppError('A supplier with this name already exists.'); return; }
    const newBatch = {
      id: uid(), ts: Date.now(), source: name,
      initialUSDT: 0, remainingUSDT: 0,
      costPerUnit: 0, sold: 0, voided: false,
      note: '', buyPriceQAR: 0, revisions: [],
    };
    applyState({ ...state, batches: [...state.batches, newBatch] });
    setShowAddSuppModal(false);
  };

  const saveSupplier = () => {
    if (!suppName.trim()) { setSuppError('Name is required.'); return; }
    if (suppName.trim() !== editingSupp) {
      applyState({
        ...state,
        batches: state.batches.map(b =>
          b.source.trim() === editingSupp ? { ...b, source: suppName.trim() } : b,
        ),
      });
    }
    setShowSuppModal(false);
  };

  const deleteSupplier = (name: string) => {
    if (!window.confirm(`Delete supplier "${name}" and all associated batches? This cannot be undone.`)) return;
    applyState({
      ...state,
      batches: state.batches.filter(b => b.source.trim() !== name),
    });
  };

  // ── Tab views (Pipeline = card view, List = table view) ───────────
  const isCustomerTab = tab === 'pipeline' || tab === 'list';

  // ── Render ────────────────────────────────────────────────────────
  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'}
      style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: '100%' }}>

      {/* ── KPI Stats Bar ── */}
      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
        <KpiCard label="Clients" value={kpis.clients} />
        <KpiCard label="USDT Vol" value={fmtTotal(kpis.totalUSDT)} />
        <KpiCard label="Net P&L" value={(kpis.netPnl >= 0 ? '+' : '') + fmtTotal(kpis.netPnl)} color={kpis.netPnl >= 0 ? 'var(--good)' : 'var(--bad)'} />
        <KpiCard label="Linked Trades" value={kpis.linkedTrades} />
        <KpiCard label="Suppliers" value={kpis.supplierCount} />
        <KpiCard label="⭐ A" value={kpis.tierCounts.A} color="var(--good)" />
        <KpiCard label="🔵 B" value={kpis.tierCounts.B} color="hsl(210 80% 60%)" />
        <KpiCard label="🔴 C" value={kpis.tierCounts.C} color="var(--bad)" />
      </div>

      {/* Tab bar + search */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 10, flexWrap: 'wrap' }}>
        <div style={{ display: 'flex', gap: 4 }}>
          <button className={`btn ${tab === 'pipeline' ? '' : 'secondary'}`} onClick={() => setTab('pipeline')}>
            📊 Pipeline
          </button>
          <button className={`btn ${tab === 'list' ? '' : 'secondary'}`} onClick={() => setTab('list')}>
            ≡ List
          </button>
          <button className={`btn ${tab === 'suppliers' ? '' : 'secondary'}`} onClick={() => setTab('suppliers')}
            style={tab === 'suppliers' ? { background: 'var(--good)', color: '#000' } : {}}>
            📦 Suppliers
          </button>
        </div>
        <div className="inputBox" style={{ maxWidth: 260, padding: '6px 10px' }}>
          <input
            placeholder={isCustomerTab ? t('searchCustomers') : t('searchSuppliers')}
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>
      </div>

      {/* ── CUSTOMERS (Pipeline or List) ── */}
      {isCustomerTab && (
        <div style={{ display: 'flex', gap: 12, flex: 1, minHeight: 0 }}>
          {/* Main table area */}
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
              <div>
                <div style={{ fontSize: 13, fontWeight: 800 }}>{t('customers')}</div>
                <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('buyerManagement')}</div>
              </div>
              <button className="btn" onClick={openAddCustomer}>{t('addCustomer')}</button>
            </div>

            {filteredCustomers.length === 0 ? (
              <div className="empty">
                <div className="empty-t">{t('noCustomersFound')}</div>
                <div className="empty-s">{t('addFirstBuyer')}</div>
              </div>
            ) : (
              <div className="tableWrap">
                <table>
                  <thead>
                    <tr>
                      <th>{t('name')}</th>
                      <th>Tier</th>
                      <th className="r">{t('trades')}</th>
                      <th className="r">USDT Vol</th>
                      <th className="r">Net P&L</th>
                      <th>Last Trade</th>
                      <th>{t('actions')}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredCustomers.map(c => {
                      const s = customerStats(c.id);
                      return (
                        <tr key={c.id}>
                          <td style={{ fontWeight: 700 }}>{c.name}</td>
                          <td>
                            <span className={`pill ${c.tier === 'A' ? 'good' : c.tier === 'B' ? 'warn' : ''}`}
                              style={{
                                fontWeight: 700, fontSize: 10, minWidth: 28, textAlign: 'center',
                                display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 3,
                              }}>
                              {c.tier === 'A' ? '⭐' : c.tier === 'B' ? '＋' : '●'} {c.tier}
                            </span>
                          </td>
                          <td className="mono r">{s.trades}</td>
                          <td className="mono r">{fmtTotal(s.totalUSDT)}</td>
                          <td className="mono r" style={{ color: s.pnl >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 700 }}>
                            {s.pnl >= 0 ? '+' : ''}{fmtTotal(s.pnl)}
                          </td>
                          <td className="mono" style={{ fontSize: 10, color: 'var(--muted)' }}>
                            {s.lastTrade > 0 ? fmtDate(s.lastTrade) : '—'}
                          </td>
                          <td>
                            <div style={{ display: 'flex', gap: 4 }}>
                              <button className="rowBtn" onClick={() => openEditCustomer(c)}>Edit</button>
                              <button className="rowBtn" style={{ color: 'var(--bad)', fontWeight: 700, fontSize: 14, lineHeight: 1, padding: '2px 6px', border: '1px solid var(--bad)', borderRadius: 4 }} onClick={() => deleteCustomer(c.id)}>✕</button>
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>

          {/* Right side: Supplier summary panel (visible only in pipeline view) */}
          {tab === 'pipeline' && suppliers.length > 0 && (
            <div style={{
              width: 320, minWidth: 280, flexShrink: 0,
              display: 'flex', flexDirection: 'column', gap: 8,
              overflowY: 'auto', maxHeight: 'calc(100vh - 220px)',
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ fontSize: 13, fontWeight: 800 }}>📦 Suppliers</div>
                <span className="pill" style={{ fontSize: 10 }}>Full</span>
              </div>
              {suppliers.slice(0, 10).map(s => (
                <SupplierCard
                  key={s.name}
                  supplier={s}
                  maxUSDT={maxSupplierUSDT}
                  onEdit={() => openEditSupplier(s.name)}
                  onDelete={() => deleteSupplier(s.name)}
                />
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── SUPPLIERS TAB ── */}
      {tab === 'suppliers' && (
        <>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 800 }}>{t('suppliers')}</div>
              <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('autoTrackedFromBatches')}</div>
            </div>
            <button className="btn" onClick={openAddSupplier}>+ {t('addSupplier')}</button>
          </div>

          <div style={{ fontSize: 11, color: 'var(--muted)', background: 'color-mix(in srgb, var(--warn) 10%, transparent)', border: '1px solid color-mix(in srgb, var(--warn) 25%, transparent)', borderRadius: 8, padding: '8px 12px' }}>
            💡 Suppliers are auto-tracked from batch source names in Stock, or you can add them directly here.
          </div>

          {filteredSuppliers.length === 0 ? (
            <div className="empty">
              <div className="empty-t">{t('noSuppliersFound')}</div>
              <div className="empty-s">{t('addBatchesToTrack')}</div>
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 12 }}>
              {filteredSuppliers.map(s => (
                <SupplierCard
                  key={s.name}
                  supplier={s}
                  maxUSDT={maxSupplierUSDT}
                  onEdit={() => openEditSupplier(s.name)}
                  onDelete={() => deleteSupplier(s.name)}
                />
              ))}
            </div>
          )}
        </>
      )}

      {/* ── Customer Add/Edit Modal ── */}
      {showCustModal && (
        <CRMModal
          title={editingCust ? `Edit — ${editingCust.name}` : t('addCustomer')}
          onClose={() => setShowCustModal(false)}
          onSave={saveCustomer}
          error={custError}
        >
          <FormField label="Name *">
            <input
              className="inputBox"
              style={{ padding: '6px 10px', width: '100%' }}
              placeholder="e.g. Ahmed Al-Rashid"
              value={custForm.name}
              autoFocus
              onChange={e => setCustForm(f => ({ ...f, name: e.target.value }))}
            />
          </FormField>
          <FormField label="Phone">
            <input
              className="inputBox"
              style={{ padding: '6px 10px', width: '100%' }}
              placeholder="+974 ..."
              value={custForm.phone}
              onChange={e => setCustForm(f => ({ ...f, phone: e.target.value }))}
            />
          </FormField>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
            <FormField label="Tier">
              <select
                style={{ padding: '6px 10px', width: '100%', background: 'var(--surface)', color: 'var(--fg)', border: '1px solid var(--line)', borderRadius: 6, fontSize: 12 }}
                value={custForm.tier}
                onChange={e => setCustForm(f => ({ ...f, tier: e.target.value }))}
              >
                <option value="A">A — VIP</option>
                <option value="B">B — Regular</option>
                <option value="C">C — New</option>
              </select>
            </FormField>
            <FormField label="Daily Limit (USDT)">
              <input
                className="inputBox"
                style={{ padding: '6px 10px', width: '100%' }}
                type="number"
                min={0}
                placeholder="0"
                value={custForm.dailyLimitUSDT || ''}
                onChange={e => setCustForm(f => ({ ...f, dailyLimitUSDT: parseFloat(e.target.value) || 0 }))}
              />
            </FormField>
          </div>
          <FormField label="Notes">
            <textarea
              style={{ padding: '6px 10px', width: '100%', background: 'var(--surface)', color: 'var(--fg)', border: '1px solid var(--line)', borderRadius: 6, fontSize: 12, resize: 'vertical', minHeight: 64, fontFamily: 'inherit' }}
              placeholder="Optional notes..."
              value={custForm.notes}
              onChange={e => setCustForm(f => ({ ...f, notes: e.target.value }))}
            />
          </FormField>
        </CRMModal>
      )}

      {/* ── Supplier Rename Modal ── */}
      {showSuppModal && (
        <CRMModal
          title={`Rename Supplier — ${editingSupp}`}
          onClose={() => setShowSuppModal(false)}
          onSave={saveSupplier}
          error={suppError}
        >
          <FormField label="Supplier Name *">
            <input
              className="inputBox"
              style={{ padding: '6px 10px', width: '100%' }}
              placeholder="Supplier name"
              value={suppName}
              autoFocus
              onChange={e => setSuppName(e.target.value)}
            />
          </FormField>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>
            This renames the supplier across all batches that reference this name.
          </div>
        </CRMModal>
      )}

      {/* ── Add Supplier Modal ── */}
      {showAddSuppModal && (
        <CRMModal
          title="Add Supplier"
          onClose={() => setShowAddSuppModal(false)}
          onSave={saveNewSupplier}
          error={newSuppError}
        >
          <FormField label="Supplier Name *">
            <input
              className="inputBox"
              style={{ padding: '6px 10px', width: '100%' }}
              placeholder="e.g. Al-Fardan Exchange"
              value={newSuppName}
              autoFocus
              onChange={e => setNewSuppName(e.target.value)}
            />
          </FormField>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>
            The supplier will appear in your list. You can attach batches to them later from the Stock page.
          </div>
        </CRMModal>
      )}
    </div>
  );
}

import { useMemo, useState } from 'react';
import { useTrackerState } from '@/lib/useTrackerState';
import {
  fmtQ, fmtU, fmtP, fmtPct, fmtQWithUnit,
} from '@/lib/tracker-helpers';
import { useTheme } from '@/lib/theme-context';
import { useT } from '@/lib/i18n';
import '@/styles/tracker.css';

export default function CalendarPage() {
  const { settings } = useTheme();
  const t = useT();
  const { state, derived } = useTrackerState({
    lowStockThreshold: settings.lowStockThreshold,
    priceAlertThreshold: settings.priceAlertThreshold,
    range: settings.range,
    currency: settings.currency,
  });
  const [cal, setCal] = useState(state.cal);

  const mnKeys = ['january','february','march','april','may','june','july','august','september','october','november','december'] as const;
  const dnKeys = ['sun','mon','tue','wed','thu','fri','sat'] as const;
  const mn = mnKeys.map(k => t(k));
  const dn = dnKeys.map(k => t(k));

  const now = new Date();
  const curY = now.getFullYear(), curM = now.getMonth(), curD = now.getDate();
  const { year, month, selectedDay } = cal;
  const daysInM = new Date(year, month + 1, 0).getDate();
  const firstDay = new Date(year, month, 1).getDay();

  // Build month data
  const mData: Record<number, { profit: number; trades: number; volumeQAR: number; wins: number; losses: number; marginSum: number; tradeList: any[] }> = {};
  for (let d = 1; d <= daysInM; d++) mData[d] = { profit: 0, trades: 0, volumeQAR: 0, wins: 0, losses: 0, marginSum: 0, tradeList: [] };

  const seenTradeIds = new Set<string>();
  for (const tr of state.trades.filter(tr => !tr.voided)) {
    if (seenTradeIds.has(tr.id)) continue;
    seenTradeIds.add(tr.id);
    const dt = new Date(tr.ts);
    if (dt.getFullYear() === year && dt.getMonth() === month) {
      const c = derived.tradeCalc.get(tr.id);
      const d2 = dt.getDate();
      const rev = tr.amountUSDT * tr.sellPriceQAR;
      // Use FIFO result if available, otherwise compute from manual buy price
      let netQAR = 0;
      let margin = 0;
      let avgBuy = 0;
      if (c?.ok) {
        netQAR = c.netQAR;
        margin = c.margin;
        avgBuy = c.avgBuyQAR;
      } else if (tr.manualBuyPrice) {
        const cost = tr.amountUSDT * tr.manualBuyPrice;
        netQAR = rev - cost - tr.feeQAR;
        margin = rev > 0 ? (netQAR / rev) * 100 : 0;
        avgBuy = tr.manualBuyPrice;
      }
      // For linked/partner trades, show only my share of the profit
      if (tr.linkedDealId || tr.linkedRelId) {
        const myPct = (tr as any).merchantPct ?? 100;
        netQAR = netQAR * myPct / 100;
        margin = rev > 0 ? (netQAR / rev) * 100 : 0;
      }
      if (rev > 0 || netQAR !== 0) {
        mData[d2].profit += netQAR;
        mData[d2].volumeQAR += rev;
        mData[d2].trades++;
        mData[d2].marginSum += Number.isFinite(margin) ? margin : 0;
        (netQAR >= 0 ? mData[d2].wins++ : mData[d2].losses++);
        mData[d2].tradeList.push({
          ...tr, net: netQAR, margin, avgBuy, rev,
          isLinked: !!tr.linkedDealId || !!tr.linkedRelId,
        });
      }
    }
  }

  const totalP = Object.values(mData).reduce((s, d) => s + d.profit, 0);
  const totalT = Object.values(mData).reduce((s, d) => s + d.trades, 0);
  const totalV = Object.values(mData).reduce((s, d) => s + d.volumeQAR, 0);
  const wins = Object.values(mData).reduce((s, d) => s + d.wins, 0);
  const tradeDays = Object.values(mData).filter(d => d.trades > 0).length;
  const bestDay = Object.entries(mData).filter(([, d]) => d.trades > 0).sort((a, b) => b[1].profit - a[1].profit)[0];
  const worstDay = Object.entries(mData).filter(([, d]) => d.trades > 0).sort((a, b) => a[1].profit - b[1].profit)[0];
  const avgMargin = totalT ? Object.values(mData).reduce((s, d) => s + d.marginSum, 0) / totalT : 0;
  const winRate = totalT ? (wins / totalT) : 0;

  const selData = selectedDay ? mData[selectedDay] : null;

  const prevMonth = () => {
    let y = year, m = month - 1;
    if (m < 0) { m = 11; y--; }
    setCal({ year: y, month: m, selectedDay: null });
  };
  const nextMonth = () => {
    let y = year, m = month + 1;
    if (m > 11) { m = 0; y++; }
    setCal({ year: y, month: m, selectedDay: null });
  };
  const goToday = () => setCal({ year: now.getFullYear(), month: now.getMonth(), selectedDay: null });
  const selectDay = (d: number) => setCal(prev => ({ ...prev, selectedDay: prev.selectedDay === d ? null : d }));

  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'} style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: '100%' }}>
      {/* Stats */}
      <div className="cal-stats">
        <div className="cal-stat">
          <div className="kpi-lbl">{t('monthlyProfit')}</div>
          <div className={`kpi-val ${totalP >= 0 ? 'good' : 'bad'}`}>{(totalP >= 0 ? '+' : '') + fmtQ(totalP)}</div>
        </div>
        <div className="cal-stat">
          <div className="kpi-lbl">{t('totalTrades')}</div>
          <div className="kpi-val">{totalT}</div>
        </div>
        <div className="cal-stat">
          <div className="kpi-lbl">{t('tradingDays')}</div>
          <div className="kpi-val">
            {tradeDays}
            {bestDay && <span className="cycle-badge" style={{ marginLeft: 4 }}>{t('best')}: {mn[month].slice(0, 3)} {bestDay[0]}</span>}
            {worstDay && <span className="cycle-badge" style={{ marginLeft: 4 }}>{t('worst')}: {mn[month].slice(0, 3)} {worstDay[0]}</span>}
          </div>
        </div>
        <div className="cal-stat">
          <div className="kpi-lbl">{t('monthlyVolume')}</div>
          <div className="kpi-val">{fmtQWithUnit(totalV)}</div>
        </div>
        <div className="cal-stat">
          <div className="kpi-lbl">{t('winRate')}</div>
          <div className="kpi-val">{(winRate * 100).toFixed(0)}%</div>
        </div>
        <div className="cal-stat">
          <div className="kpi-lbl">{t('avgMargin')}</div>
          <div className="kpi-val">{fmtPct(avgMargin)}</div>
        </div>
      </div>

      {/* Calendar */}
      <div className="panel">
        <div className="panel-head">
          <h2>{mn[month]} {year}</h2>
          <div style={{ display: 'flex', gap: 6 }}>
            <button className="btn secondary" onClick={prevMonth}>{t('prev')}</button>
            <button className="btn secondary" onClick={goToday}>{t('today')}</button>
            <button className="btn secondary" onClick={nextMonth}>{t('next')}</button>
          </div>
        </div>
        <div className="panel-body">
          <div className="cal-grid">
            {dn.map(d => <div key={d} className="cal-hdr">{d}</div>)}
            {Array.from({ length: firstDay }, (_, i) => (
              <div key={`e-${i}`} className="cal-day empty-day" />
            ))}
            {Array.from({ length: daysInM }, (_, i) => {
              const d = i + 1;
              const data = mData[d];
              const hasP = data.profit > 0;
              const hasL = data.profit < 0;
              const isTdy = d === curD && year === curY && month === curM;
              const isSel = d === selectedDay;

              return (
                <div
                  key={d}
                  className={`cal-day${hasP ? ' has-profit' : hasL ? ' has-loss' : ''}${isTdy ? ' today' : ''}${isSel ? ' selected' : ''}`}
                  onClick={() => selectDay(d)}
                >
                  <div className="cal-num">{d}</div>
                  {data.trades > 0 && (
                    <>
                      <div className={`cal-profit ${hasP ? 'good' : 'bad'}`}>
                        {(data.profit >= 0 ? '+' : '') + fmtQ(data.profit)}
                      </div>
                      <div className="cal-count">{data.trades}t</div>
                    </>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Selected day detail */}
      {selectedDay && selData && selData.trades > 0 && (
        <div className="cal-detail">
          <div style={{ fontSize: 12, fontWeight: 800, marginBottom: 8 }}>
            📅 {mn[month]} {selectedDay}, {year} — {selData.trades} {t('trades')} · Vol {fmtQWithUnit(selData.volumeQAR)} · {t('net')} {(selData.profit >= 0 ? '+' : '') + fmtQ(selData.profit)} · {t('winRate')} {(selData.trades ? ((selData.wins / selData.trades) * 100).toFixed(0) : '0')}%
          </div>
          <div className="tableWrap">
            <table>
              <thead>
                <tr>
                  <th>{t('time')}</th>
                  <th className="r">{t('qty')}</th>
                  <th className="r">{t('avgBuy')}</th>
                  <th className="r">{t('sell')}</th>
                  <th className="r">{t('volume')}</th>
                  <th className="r">{t('net')}</th>
                  <th className="r">{t('margin')}</th>
                </tr>
              </thead>
              <tbody>
                {selData.tradeList.map((tr: any) => (
                  <tr key={tr.id}>
                    <td className="mono">
                      {tr.isLinked && <span title="Partner deal" style={{ marginRight: 3 }}>🤝</span>}
                      {new Date(tr.ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </td>
                    <td className="mono r">{fmtU(tr.amountUSDT)}</td>
                    <td className="mono r" style={{ color: 'var(--bad)' }}>{fmtP(tr.avgBuy)}</td>
                    <td className="mono r" style={{ color: 'var(--good)' }}>{fmtP(tr.sellPriceQAR)}</td>
                    <td className="mono r">{fmtQ(tr.rev)}</td>
                    <td className="mono r" style={{ color: tr.net >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 700 }}>
                      {(tr.net >= 0 ? '+' : '') + fmtQ(tr.net)}
                    </td>
                    <td className="mono r" style={{ color: tr.margin >= 1 ? 'var(--good)' : tr.margin < 0 ? 'var(--bad)' : 'var(--warn)' }}>
                      {fmtPct(tr.margin)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
      {selectedDay && selData && selData.trades === 0 && (
        <div className="cal-detail">
          <div className="muted" style={{ fontSize: 11, padding: '8px 0' }}>
            {t('noTradesOnDay')} {mn[month]} {selectedDay}. <button className="rowBtn">{t('logATrade')}</button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useMemo, useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useTrackerState } from '@/lib/useTrackerState';
import {
  fmtQWithUnit, fmtU, fmtQ, fmtPct, fmtP,
  fmtTotal, fmtPrice,
  kpiFor, totalStock, stockCostQAR, getWACOP,
  rangeLabel, num, startOfDay, inRange,
  deriveCashQAR,
} from '@/lib/tracker-helpers';
import { useTheme } from '@/lib/theme-context';
import { useT } from '@/lib/i18n';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/auth-context';
import { useQuery } from '@tanstack/react-query';
import { CashBoxManager } from '@/features/dashboard/components/CashBoxManager';
import { buildDealRowModel } from '@/features/orders/utils/dealRowModel';
import {
  AreaChart, Area, XAxis, YAxis,
  Tooltip, ResponsiveContainer, CartesianGrid,
} from 'recharts';
import '@/styles/tracker.css';

interface DashboardPageProps {
  adminUserId?: string;
  adminMerchantId?: string;
  adminTrackerState?: any;
  isAdminView?: boolean;
}

export default function DashboardPage({ adminUserId, adminMerchantId, adminTrackerState, isAdminView }: DashboardPageProps = {}) {
  const { settings } = useTheme();
  const t = useT();
  const navigate = useNavigate();
  const { state, derived, applyState } = useTrackerState({
    lowStockThreshold: settings.lowStockThreshold,
    priceAlertThreshold: settings.priceAlertThreshold,
    range: settings.range,
    currency: settings.currency,
    preloadedState: adminTrackerState || undefined,
  });

  const dM = kpiFor(state, derived, 'this_month');
  const dL = kpiFor(state, derived, 'last_month');
  const d7  = kpiFor(state, derived, '7d');
  const d30 = kpiFor(state, derived, '30d');
  const dR = kpiFor(state, derived, settings.range);
  const stk = totalStock(derived);
  const stCost = stockCostQAR(derived);
  const wacop = getWACOP(derived);
  const rLabel = rangeLabel(settings.range);

  const allTrades = state.trades.filter(t => !t.voided);
  const getTradeMyPct = (tr: typeof allTrades[0]) => {
    const merchantPct = Number(tr.merchantPct);
    if (Number.isFinite(merchantPct) && merchantPct > 0 && merchantPct <= 100) return merchantPct;
    const partnerPct = Number(tr.partnerPct);
    if (Number.isFinite(partnerPct) && partnerPct >= 0 && partnerPct < 100) return 100 - partnerPct;
    return 100;
  };
  const allMargins = allTrades.map(tr => {
    const c = derived.tradeCalc.get(tr.id);
    if (!c?.ok) return null;
    if (tr.linkedDealId || tr.linkedRelId) {
      const myPct = getTradeMyPct(tr);
      const myNet = c.netQAR * myPct / 100;
      const rev = tr.amountUSDT * tr.sellPriceQAR;
      return rev > 0 ? (myNet / rev) * 100 : 0;
    }
    return c.margin;
  }).filter((x): x is number => x !== null);
  const avgM = allMargins.length ? allMargins.reduce((s, v) => s + v, 0) / allMargins.length : 0;

  const cycleHours = useMemo(() => {
    const tradesSorted = [...allTrades].sort((a, b) => a.ts - b.ts);
    const deltas: number[] = [];
    for (const tr of tradesSorted) {
      const c = derived.tradeCalc.get(tr.id);
      if (!c?.ok || !c.slices?.length) continue;
      for (const sl of c.slices) {
        const batch = state.batches.find(b => b.id === sl.batchId);
        if (batch) {
          const delta = (tr.ts - batch.ts) / (1000 * 60 * 60);
          if (delta > 0 && delta < 10000) deltas.push(delta);
        }
      }
    }
    return deltas.length ? deltas.reduce((s, v) => s + v, 0) / deltas.length : null;
  }, [allTrades, derived, state.batches]);

  const LOW = num(state.settings?.lowStockThreshold, 5000);
  const isLow = stk <= 0 || (LOW > 0 && stk < LOW);

  const [showCashBox, setShowCashBox] = useState(false);
  const [expandedNewKpi, setExpandedNewKpi] = useState<string | null>(null);
  const [roiPeriod, setRoiPeriod] = useState<'7d' | '30d'>('7d');
  const { user, merchantProfile } = useAuth();
  const userId = adminUserId || user?.id;
  const workspaceMerchantId = adminMerchantId || merchantProfile?.merchant_id;

  interface DealDetail {
    id: string;
    title: string;
    merchantName: string;
    net: number;
    myShare: number;
    partnerShare: number;
    vol: number;
    status: string;
    direction: 'outgoing' | 'incoming';
    dealType: string;
    ts: number;
  }

  const { data: merchantDealKpis } = useQuery({
    queryKey: ['dashboard-merchant-deals', userId, workspaceMerchantId],
    staleTime: 15_000,
    refetchInterval: 30_000,
    queryFn: async () => {
      if (!userId || !workspaceMerchantId) return null;
      const relsScopedRes = await supabase
        .from('merchant_relationships')
        .select('id, merchant_a_id, merchant_b_id')
        .eq('status', 'active')
        .or(`merchant_a_id.eq.${workspaceMerchantId},merchant_b_id.eq.${workspaceMerchantId}`);
      if (relsScopedRes.error) throw relsScopedRes.error;
      const relIds = (relsScopedRes.data || []).map(r => r.id);
      const { data: deals } = relIds.length > 0
        ? await supabase
            .from('merchant_deals')
            .select('id, amount, status, created_by, notes, deal_type, relationship_id, title, created_at')
            .in('relationship_id', relIds)
            .order('created_at', { ascending: false })
        : { data: [] as any[] };
      if (!deals || deals.length === 0) return null;

      const activeDeals = deals.filter(d => d.status !== 'cancelled' && d.status !== 'voided');
      const dealRelIds = [...new Set(activeDeals.map(d => d.relationship_id))];
      const { data: rels } = dealRelIds.length > 0
        ? await supabase.from('merchant_relationships').select('id, merchant_a_id, merchant_b_id').in('id', dealRelIds)
        : { data: [] as any[] };

      const allMerchantIds = new Set<string>();
      for (const r of (rels || [])) { allMerchantIds.add(r.merchant_a_id); allMerchantIds.add(r.merchant_b_id); }

      const { data: profiles } = allMerchantIds.size > 0
        ? await supabase.from('merchant_profiles').select('merchant_id, display_name, user_id').in('merchant_id', [...allMerchantIds])
        : { data: [] as any[] };

      const profileMap = new Map<string, { name: string; userId: string }>();
      for (const p of (profiles || [])) profileMap.set(p.merchant_id, { name: p.display_name, userId: p.user_id });

      const relMap = new Map<string, { merchant_a_id: string; merchant_b_id: string }>();
      for (const r of (rels || [])) relMap.set(r.id, r);

      let outCount = 0, outVol = 0, outNet = 0, outMyShare = 0;
      let inCount = 0, inVol = 0, inNet = 0, inMyShare = 0;
      let pendingCount = 0, approvedCount = 0;
      let totalMyShare = 0, totalPartnerShare = 0;
      const dealDetails: DealDetail[] = [];

      for (const d of activeDeals) {
        const direction = d.created_by === userId ? 'outgoing' as const : 'incoming' as const;
        const row = buildDealRowModel({
          deal: d,
          perspective: direction,
          locale: t.isRTL ? 'ar' : 'en',
        });
        const vol = row.volume;
        const dealNet = row.fullNet ?? 0;
        const myShare = direction === 'outgoing' ? (row.creatorNet ?? 0) : (row.partnerNet ?? 0);
        const partnerShare = direction === 'outgoing' ? (row.partnerNet ?? 0) : (row.creatorNet ?? 0);

        if (d.status === 'pending') pendingCount++;
        if (d.status === 'approved') approvedCount++;

        const rel = relMap.get(d.relationship_id);
        let merchantName = 'Unknown';
        if (rel) {
          const myProfile = [...profileMap.values()].find(p => p.userId === userId);
          const myMerchantId = myProfile ? [...profileMap.entries()].find(([, v]) => v.userId === userId)?.[0] : null;
          const counterId = myMerchantId === rel.merchant_a_id ? rel.merchant_b_id : rel.merchant_a_id;
          merchantName = profileMap.get(counterId)?.name || 'Unknown';
        }

        if (direction === 'outgoing') {
          outCount++; outVol += vol; outNet += dealNet; outMyShare += myShare;
        } else {
          inCount++; inVol += vol; inNet += dealNet; inMyShare += myShare;
        }

        totalMyShare += myShare;
        totalPartnerShare += partnerShare;

        dealDetails.push({
          id: d.id,
          title: d.title,
          merchantName,
          net: Math.round(dealNet * 100) / 100,
          myShare: Math.round(myShare * 100) / 100,
          partnerShare: Math.round(partnerShare * 100) / 100,
          vol: Math.round(vol * 100) / 100,
          status: d.status,
          direction,
          dealType: d.deal_type,
          ts: (() => {
            const tradeDateRaw = row.meta.trade_date;
            const fromMeta = tradeDateRaw ? new Date(tradeDateRaw).getTime() : NaN;
            const fromCreatedAt = d.created_at ? new Date(d.created_at).getTime() : NaN;
            return Number.isFinite(fromMeta) ? fromMeta : (Number.isFinite(fromCreatedAt) ? fromCreatedAt : Date.now());
          })(),
        });
      }

      return {
        totalDeals: activeDeals.length,
        outCount, outVol, outNet, outMyShare,
        inCount, inVol, inNet, inMyShare,
        pendingCount, approvedCount,
        totalVol: outVol + inVol,
        totalNet: outMyShare + inMyShare,
        totalMyShare, totalPartnerShare,
        dealDetails,
      };
    },
    enabled: !!userId && !!workspaceMerchantId,
  });

  const handleCashSave = useCallback((newCash: number, owner: string, history?: import('@/lib/tracker-helpers').CashTransaction[]) => {
    applyState({ ...state, cashQAR: newCash, cashOwner: owner, cashHistory: history ?? state.cashHistory ?? [] });
  }, [state, applyState]);

  const rangeMerchantKpis = useMemo(() => {
    if (!merchantDealKpis?.dealDetails) return null;
    const filtered = merchantDealKpis.dealDetails.filter(d => inRange(d.ts, settings.range));
    let inCount = 0, inNet = 0, inMyShare = 0;
    let outCount = 0, outNet = 0, outMyShare = 0;
    for (const d of filtered) {
      if (d.direction === 'incoming') {
        inCount++; inNet += d.net; inMyShare += d.myShare;
      } else {
        outCount++; outNet += d.net; outMyShare += d.myShare;
      }
    }
    return { inCount, inNet, inMyShare, outCount, outNet, outMyShare };
  }, [merchantDealKpis, settings.range]);

  const p2pAvgs = useMemo(() => {
    const sellTrades = allTrades.filter(t => t.usesStock && t.sellPriceQAR > 0);
    const avgSell = sellTrades.length ? sellTrades.reduce((s, t) => s + t.sellPriceQAR, 0) / sellTrades.length : null;
    const batches = state.batches.filter(b => b.buyPriceQAR > 0);
    const avgBuy = batches.length ? batches.reduce((s, b) => s + b.buyPriceQAR, 0) / batches.length : null;
    return { avgSell, avgBuy };
  }, [allTrades, state.batches]);

  const tradeNet = useCallback((tr: typeof allTrades[0]) => {
    const c = derived.tradeCalc.get(tr.id);
    let fullNet = 0;
    if (c?.ok) fullNet = c.netQAR;
    else if (tr.manualBuyPrice) fullNet = tr.amountUSDT * tr.sellPriceQAR - tr.amountUSDT * tr.manualBuyPrice - tr.feeQAR;
    if (tr.linkedDealId || tr.linkedRelId) {
      const myPct = getTradeMyPct(tr);
      return fullNet * myPct / 100;
    }
    return fullNet;
  }, [derived.tradeCalc]);

  const trendData = useMemo(() => {
    const sorted = [...allTrades].sort((a, b) => a.ts - b.ts).slice(-14);
    return sorted.map((tr, i) => {
      const rev = tr.amountUSDT * tr.sellPriceQAR;
      return {
        idx: i + 1,
        date: new Date(tr.ts).toLocaleDateString(undefined, { month: 'short', day: 'numeric' }),
        revenue: Math.round(rev),
        profit: Math.round(tradeNet(tr)),
      };
    });
  }, [allTrades, tradeNet]);

  const ChartTooltip = ({ active, payload, label }: any) => {
    if (!active || !payload?.length) return null;
    return (
      <div style={{
        background: 'var(--panel2)', border: '1px solid var(--line)',
        borderRadius: 6, padding: '6px 10px', fontSize: 10,
      }}>
        <div style={{ fontWeight: 700, marginBottom: 3 }}>{label}</div>
        {payload.map((p: any, i: number) => (
          <div key={i} style={{ color: p.color, display: 'flex', gap: 8, justifyContent: 'space-between' }}>
            <span>{p.name}</span>
            <span className="mono" style={{ fontWeight: 700 }}>{fmtTotal(Number(p.value))} QAR</span>
          </div>
        ))}
      </div>
    );
  };

  const badgeStyle = (condition: string) => {
    const color = condition === 'good' ? 'var(--good)' : condition === 'bad' ? 'var(--bad)' : 'var(--warn)';
    return {
      color,
      borderColor: `color-mix(in srgb, ${color} 30%, transparent)`,
      background: `color-mix(in srgb, ${color} 10%, transparent)`,
    };
  };

  const now = new Date();
  const monthKeys = ['january','february','march','april','may','june','july','august','september','october','november','december'];
  const curMo = t(monthKeys[now.getMonth()] as any);
  const prevDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  const prevMo = t(monthKeys[prevDate.getMonth()] as any);

  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'} style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: '100%' }}>
      <div className="kpi-band-grid">
        <div className="kpi-band">
          <div className="kpi-band-title">{t('tradingVolume')}</div>
          <div className="kpi-band-cols">
            <div>
              <div className="kpi-period">{curMo}</div>
              <div className="kpi-cell-val t1v">{fmtQWithUnit(dM.rev, settings.currency, wacop)}</div>
              <div className="kpi-cell-sub">{dM.count} {t('trades')} · {fmtU(dM.qty, 0)} USDT</div>
            </div>
            <div>
              <div className="kpi-period">{prevMo}</div>
              <div className="kpi-cell-val t1v">{fmtQWithUnit(dL.rev, settings.currency, wacop)}</div>
              <div className="kpi-cell-sub">{dL.count} {t('trades')} · {fmtU(dL.qty, 0)} USDT</div>
            </div>
          </div>
        </div>
        <div className="kpi-band">
          <div className="kpi-band-title">{t('netProfit')}</div>
          <div className="kpi-band-cols">
            <div>
              <div className="kpi-period">{curMo}</div>
              <div className={`kpi-cell-val ${dM.net >= 0 ? 'good' : 'bad'}`}>{fmtQWithUnit(dM.net, settings.currency, wacop)}</div>
              {dM.fee > 0 && <div className="kpi-cell-sub">{t('fees')} {fmtQWithUnit(dM.fee, settings.currency, wacop)}</div>}
              <div className="kpi-cell-sub" style={{ fontSize: 8, marginTop: 2 }}>📤 {t('myDealsLabel')}</div>
            </div>
            <div>
              <div className="kpi-period">{prevMo}</div>
              <div className={`kpi-cell-val ${dL.net >= 0 ? 'good' : 'bad'}`}>{fmtQWithUnit(dL.net, settings.currency, wacop)}</div>
              {dL.fee > 0 && <div className="kpi-cell-sub">{t('fees')} {fmtQWithUnit(dL.fee, settings.currency, wacop)}</div>}
              <div className="kpi-cell-sub" style={{ fontSize: 8, marginTop: 2 }}>📤 {t('myDealsLabel')}</div>
            </div>
          </div>
          {rangeMerchantKpis && rangeMerchantKpis.inCount > 0 && (
            <div style={{ marginTop: 6, padding: '5px 8px', borderRadius: 6, background: 'color-mix(in srgb, var(--good) 6%, transparent)', border: '1px solid color-mix(in srgb, var(--good) 15%, transparent)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 9, fontWeight: 700, color: 'var(--muted)' }}>
                  📥 {t('incomingDealsLabel')} ({rangeMerchantKpis.inCount}){isAdminView ? ` · ${t('myCutLabel')}` : ''}
                </span>
                <span className={`mono ${rangeMerchantKpis.inMyShare >= 0 ? 'good' : 'bad'}`} style={{ fontSize: 12, fontWeight: 800 }}>
                  {rangeMerchantKpis.inMyShare >= 0 ? '+' : ''}{fmtQWithUnit(rangeMerchantKpis.inMyShare)}
                </span>
              </div>
              <div style={{ fontSize: 8, color: 'var(--muted)', marginTop: 2 }}>
                {t('netProfitLabel')}: {fmtQWithUnit(rangeMerchantKpis.inNet)}
              </div>
            </div>
          )}
          {rangeMerchantKpis && rangeMerchantKpis.inCount > 0 && (
            <>
              <div style={{ marginTop: 4, display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '4px 8px', borderTop: '1px solid var(--line)' }}>
                <span style={{ fontSize: 9, fontWeight: 800, color: 'var(--text)', textTransform: 'uppercase', letterSpacing: '.5px' }}>📊 {t('combinedTotal')}</span>
                <span className={`mono ${(dR.net + rangeMerchantKpis.inMyShare) >= 0 ? 'good' : 'bad'}`} style={{ fontSize: 13, fontWeight: 800 }}>
                  {(dR.net + rangeMerchantKpis.inMyShare) >= 0 ? '+' : ''}{fmtQWithUnit(dR.net + rangeMerchantKpis.inMyShare)}
                </span>
              </div>
              <div className="kpi-cell-sub" style={{ marginTop: 2, fontSize: 8 }}>{rangeLabel(settings.range)} {t('total')}</div>
            </>
          )}
        </div>
      </div>

      <div className="kpis">
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={badgeStyle(dR.net >= 0 ? 'good' : 'bad')}>{rLabel}</span>
          </div>
          <div className="kpi-lbl">{t('netProfitLabel')}</div>
          <div className={`kpi-val ${dR.net >= 0 ? 'good' : 'bad'}`}>{fmtQWithUnit(dR.net, settings.currency, wacop)}</div>
          <div className="kpi-sub">{dR.count} {t('trades')} · {fmtQ(dR.rev)} {t('revSuffix')}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={badgeStyle(avgM >= 1 ? 'good' : avgM >= 0 ? 'warn' : 'bad')}>{allTrades.length} {t('trades')}</span>
          </div>
          <div className="kpi-lbl">{t('avgMargin')}</div>
          <div className={`kpi-val ${avgM >= 1 ? 'good' : avgM >= 0 ? 'warn' : 'bad'}`}>{fmtPct(avgM)}</div>
          <div className="kpi-sub">{dR.count} in range · avg {fmtPct(dR.avgMgn)}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={badgeStyle(isLow ? 'bad' : 'good')}>{isLow ? t('low') : t('ok')}</span>
          </div>
          <div className="kpi-lbl">{t('availableUsdt')}</div>
          <div className={`kpi-val ${isLow ? 'bad' : 'good'}`} style={isLow ? { animation: 'tracker-blink 1.5s infinite' } : undefined}>{fmtU(stk, 0)}</div>
          <div className="kpi-sub">{t('liquidUsdt')}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={{ color: 'var(--brand)', borderColor: 'color-mix(in srgb,var(--brand) 30%,transparent)', background: 'var(--brand3)' }}>{t('avPrice')}</span>
          </div>
          <div className="kpi-lbl">{t('avPriceSpread')}</div>
          <div className="kpi-val" style={{ fontSize: 16, color: 'var(--t2)' }}>{wacop ? fmtP(wacop) + ' QAR' : t('noStock')}</div>
          <div className="kpi-sub">
            {(() => {
              const sp = wacop && p2pAvgs.avgSell ? fmtPrice((p2pAvgs.avgSell - wacop) / wacop * 100) : null;
              return sp !== null
                ? <span className={Number(sp) >= 0 ? 'good' : 'bad'} style={{ fontWeight: 700 }}>{Number(sp) >= 0 ? '+' : ''}{sp}% vs P2P</span>
                : t('sellAboveAvPrice');
            })()}
          </div>
        </div>
      </div>

      <div className="kpis" style={{ marginTop: 0 }}>
        {(() => {
          const cashAccounts = state.cashAccounts || [];
          const cashLedger = state.cashLedger || [];
          const hasAccounts = cashAccounts.length > 0;
          const totalCash = hasAccounts ? deriveCashQAR(cashAccounts, cashLedger) : num(state.cashQAR, 0);

          return (
            <div className="kpi-card" style={{ cursor: !isAdminView ? 'pointer' : 'default' }} onClick={!isAdminView ? () => navigate('/trading/stock?tab=cash') : undefined}>
              <div className="kpi-head">
                <span className="kpi-badge" style={{ color: 'var(--warn)', borderColor: 'color-mix(in srgb,var(--warn) 30%,transparent)', background: 'color-mix(in srgb,var(--warn) 10%,transparent)' }}>
                  💰 {t('cash')}
                </span>
              </div>
              <div className="kpi-lbl">{t('cashAvailable')}</div>
              <div className="kpi-val" style={{ color: 'var(--warn)' }}>{fmtQWithUnit(totalCash, settings.currency, wacop)}</div>
              <div className="kpi-sub">
                {!isAdminView && <span style={{ fontSize: 9, color: 'var(--brand)', fontWeight: 600 }}>{t('openCashMgmt')}</span>}
              </div>
            </div>
          );
        })()}
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={{ color: 'var(--t5)', borderColor: 'color-mix(in srgb,var(--t5) 30%,transparent)', background: 'color-mix(in srgb,var(--t5) 10%,transparent)' }}>@{t('avPrice')}</span>
          </div>
          <div className="kpi-lbl">{t('buyingPower')}</div>
          {(() => {
            const cash = num(state.cashQAR, 0);
            const refPrice = wacop || p2pAvgs.avgBuy;
            const isFallback = !wacop && !!p2pAvgs.avgBuy;
            return (
              <>
                <div className="kpi-val" style={{ color: 'var(--t5)' }}>
                  {refPrice && cash > 0
                    ? fmtU(cash / refPrice, 0) + ' USDT'
                    : cash > 0
                      ? fmtQ(cash) + ' QAR'
                      : t('setCash')}
                </div>
                <div className="kpi-sub">
                  {refPrice
                    ? `@ ${fmtP(refPrice)} QAR${isFallback ? ` ${t('mktAvg')}` : ''}`
                    : cash > 0
                      ? t('addBatchesFirst')
                      : t('addBatchesFirst')}
                </div>
              </>
            );
          })()}
        </div>
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={{ color: 'var(--good)', borderColor: 'color-mix(in srgb,var(--good) 30%,transparent)', background: 'color-mix(in srgb,var(--good) 10%,transparent)' }}>{t('net')}</span>
          </div>
          <div className="kpi-lbl">{t('netPosition')}</div>
          <div className="kpi-val good">{fmtQWithUnit(stCost + num(state.cashQAR, 0), settings.currency, wacop)}</div>
          <div className="kpi-sub">{t('stock')} {fmtQWithUnit(stCost, settings.currency, wacop)} + {t('cash')} {fmtQWithUnit(num(state.cashQAR, 0), settings.currency, wacop)}</div>
        </div>
        <div className="kpi-card">
          <div className="kpi-head">
            <span className="kpi-badge" style={{ color: 'var(--muted)', borderColor: 'color-mix(in srgb,var(--muted) 30%,transparent)', background: 'color-mix(in srgb,var(--muted) 10%,transparent)' }}>{state.batches.length} {t('batchSuffix')}</span>
          </div>
          <div className="kpi-lbl">{t('stockCostEst')}</div>
          <div className="kpi-val" style={{ color: 'var(--text)' }}>{fmtQWithUnit(stCost, settings.currency, wacop)}</div>
          <div className="kpi-sub">{t('avPrice')} {wacop ? fmtP(wacop) + ' QAR' : '—'}</div>
        </div>
      </div>

      <div className="kpis" style={{ marginTop: 0 }}>
        {(() => {
          const roiData = roiPeriod === '7d' ? d7 : d30;
          const roiVal = stCost > 0 ? (roiData.net / stCost) * 100 : 0;
          const isExpanded = expandedNewKpi === 'roi';
          return (
            <div className="kpi-card" style={{ cursor: 'pointer', position: 'relative' }} onClick={() => setExpandedNewKpi(isExpanded ? null : 'roi')}>
              <div className="kpi-head" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span className="kpi-badge" style={{ color: 'var(--good)', borderColor: 'color-mix(in srgb,var(--good) 30%,transparent)', background: 'color-mix(in srgb,var(--good) 10%,transparent)' }}>
                  💹
                </span>
              </div>
              <div className="kpi-lbl">{t('roiLabel')}</div>
              <div className={`kpi-val ${roiVal >= 0 ? 'good' : 'bad'}`}>{fmtPrice(roiVal)}%</div>
              <div className="kpi-sub">{t('roiSub')}</div>
              <div style={{ display: 'flex', gap: 4, marginTop: 4, flexWrap: 'wrap', alignItems: 'center' }}>
                <span
                  className="kpi-badge"
                  style={{
                    fontSize: 9, padding: '1px 6px', cursor: 'pointer',
                    color: roiPeriod === '7d' ? 'var(--brand)' : 'var(--muted)',
                    borderColor: `color-mix(in srgb,${roiPeriod === '7d' ? 'var(--brand)' : 'var(--muted)'} 30%,transparent)`,
                    background: `color-mix(in srgb,${roiPeriod === '7d' ? 'var(--brand)' : 'var(--muted)'} 10%,transparent)`,
                    fontWeight: roiPeriod === '7d' ? 700 : 400,
                  }}
                  onClick={(e) => { e.stopPropagation(); setRoiPeriod('7d'); }}
                >7D</span>
                <span
                  className="kpi-badge"
                  style={{
                    fontSize: 9, padding: '1px 6px', cursor: 'pointer',
                    color: roiPeriod === '30d' ? 'var(--brand)' : 'var(--muted)',
                    borderColor: `color-mix(in srgb,${roiPeriod === '30d' ? 'var(--brand)' : 'var(--muted)'} 30%,transparent)`,
                    background: `color-mix(in srgb,${roiPeriod === '30d' ? 'var(--brand)' : 'var(--muted)'} 10%,transparent)`,
                    fontWeight: roiPeriod === '30d' ? 700 : 400,
                  }}
                  onClick={(e) => { e.stopPropagation(); setRoiPeriod('30d'); }}
                >30D</span>
                <span className="kpi-badge" style={{ fontSize: 9, padding: '1px 6px', color: 'var(--muted)', borderColor: 'color-mix(in srgb,var(--muted) 30%,transparent)', background: 'color-mix(in srgb,var(--muted) 10%,transparent)' }}>{t('orders')}</span>
                <span style={{ fontSize: 9, color: 'var(--warn)', marginLeft: 'auto' }}>💡 {isExpanded ? t('collapseLbl') : t('tapExpand')}</span>
              </div>
              {isExpanded && (
                <div style={{ marginTop: 8, padding: '8px 10px', borderTop: '1px solid var(--line)', fontSize: 11, lineHeight: 1.6, color: 'var(--t3)' }}>
                  <p>Return on invested capital for {roiPeriod === '7d' ? '7 days' : '30 days'} — normalizes profit vs full book.</p>
                  <p style={{ marginTop: 4 }}><strong style={{ color: 'var(--warn)' }}>Why:</strong> Raw QAR profit is misleading without context of how much capital is deployed.</p>
                  <div style={{ marginTop: 6, padding: '4px 8px', borderRadius: 4, background: 'var(--panel2)', fontFamily: 'monospace', fontSize: 10, color: 'var(--good)' }}>
                    = {roiPeriod}.netQAR ÷ stockCostQAR × 100
                  </div>
                </div>
              )}
            </div>
          );
        })()}

        {(() => {
          const isExpanded = expandedNewKpi === 'cycle';
          return (
            <div className="kpi-card" style={{ cursor: 'pointer', position: 'relative' }} onClick={() => setExpandedNewKpi(isExpanded ? null : 'cycle')}>
              <div className="kpi-head" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span className="kpi-badge" style={{ color: 'var(--warn)', borderColor: 'color-mix(in srgb,var(--warn) 30%,transparent)', background: 'color-mix(in srgb,var(--warn) 10%,transparent)' }}>
                  ⏱️
                </span>
              </div>
              <div className="kpi-lbl">{t('avgCycleTime')}</div>
              <div className="kpi-val" style={{ color: 'var(--warn)' }}>{cycleHours !== null ? `${fmtTotal(cycleHours)}h` : '—'}</div>
              <div className="kpi-sub">{t('avgCycleTimeSub')}</div>
              <div style={{ display: 'flex', gap: 4, marginTop: 4, flexWrap: 'wrap' }}>
                <span className="kpi-badge" style={{ fontSize: 9, padding: '1px 6px', color: 'var(--brand)', borderColor: 'color-mix(in srgb,var(--brand) 30%,transparent)', background: 'color-mix(in srgb,var(--brand) 10%,transparent)' }}>FIFO</span>
                <span className="kpi-badge" style={{ fontSize: 9, padding: '1px 6px', color: 'var(--muted)', borderColor: 'color-mix(in srgb,var(--muted) 30%,transparent)', background: 'color-mix(in srgb,var(--muted) 10%,transparent)' }}>Stock</span>
                <span style={{ fontSize: 9, color: 'var(--warn)', marginLeft: 'auto' }}>💡 {isExpanded ? t('collapseLbl') : t('tapExpand')}</span>
              </div>
              {isExpanded && (
                <div style={{ marginTop: 8, padding: '8px 10px', borderTop: '1px solid var(--line)', fontSize: 11, lineHeight: 1.6, color: 'var(--t3)' }}>
                  <p>Average hours from buying a batch to it being consumed in sales.</p>
                  <p style={{ marginTop: 4 }}><strong style={{ color: 'var(--warn)' }}>Why:</strong> Shorter cycle = faster capital rotation and less exposure to price moves.</p>
                  <div style={{ marginTop: 6, padding: '4px 8px', borderRadius: 4, background: 'var(--panel2)', fontFamily: 'monospace', fontSize: 10, color: 'var(--good)' }}>
                    = avg(trade.ts – slice.batchTs) per FIFO slice
                  </div>
                </div>
              )}
            </div>
          );
        })()}

        {rangeMerchantKpis && (
          <div className="kpi-card">
            <div className="kpi-head">
              <span className="kpi-badge" style={{ color: 'var(--brand)', borderColor: 'color-mix(in srgb,var(--brand) 30%,transparent)', background: 'color-mix(in srgb,var(--brand) 10%,transparent)' }}>
                📤 {rangeMerchantKpis.outCount} deals
              </span>
            </div>
            <div className="kpi-lbl">{isAdminView ? `${t('outgoingNet')} · ${t('myCutLabel')}` : t('outgoingNet')}</div>
            <div className={`kpi-val ${rangeMerchantKpis.outMyShare >= 0 ? 'good' : 'bad'}`}>
              {rangeMerchantKpis.outMyShare >= 0 ? '+' : ''}{fmtQWithUnit(rangeMerchantKpis.outMyShare)}
            </div>
            <div className="kpi-sub">{t('netProfitLabel')}: {fmtQWithUnit(rangeMerchantKpis.outNet)}</div>
          </div>
        )}

        {rangeMerchantKpis && (
          <div className="kpi-card">
            <div className="kpi-head">
              <span className="kpi-badge" style={{ color: 'var(--good)', borderColor: 'color-mix(in srgb,var(--good) 30%,transparent)', background: 'color-mix(in srgb,var(--good) 10%,transparent)' }}>
                📥 {rangeMerchantKpis.inCount} deals
              </span>
            </div>
            <div className="kpi-lbl">{isAdminView ? `${t('incomingNet')} · ${t('myCutLabel')}` : t('incomingNet')}</div>
            <div className={`kpi-val ${rangeMerchantKpis.inMyShare >= 0 ? 'good' : 'bad'}`}>
              {rangeMerchantKpis.inMyShare >= 0 ? '+' : ''}{fmtQWithUnit(rangeMerchantKpis.inMyShare)}
            </div>
            <div className="kpi-sub">{t('netProfitLabel')}: {fmtQWithUnit(rangeMerchantKpis.inNet)}</div>
          </div>
        )}
      </div>

      <div className="dash-bottom">
        <div className="panel">
          <div className="panel-head"><h2>{t('profitRevenueTrend')}</h2><span className="pill">{t('last14Trades')}</span></div>
          <div className="panel-body" style={{ height: 190, position: 'relative' }}>
            {trendData.length < 2 ? (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                <span className="muted" style={{ fontSize: 11 }}>{t('needAtLeast2Trades')}</span>
              </div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={trendData} margin={{ top: 8, right: 8, left: -16, bottom: 0 }}>
                  <defs>
                    <linearGradient id="gRevenue" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#6366f1" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="gProfit" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#22c55e" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#22c55e" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="var(--line)" strokeOpacity={0.3} />
                  <XAxis dataKey="date" tick={{ fontSize: 9, fill: 'var(--muted)' }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fontSize: 9, fill: 'var(--muted)' }} axisLine={false} tickLine={false} />
                  <Tooltip content={<ChartTooltip />} />
                  <Area type="monotone" dataKey="revenue" name={t('volume') || 'Revenue'} stroke="#6366f1" fill="url(#gRevenue)" strokeWidth={1.5} dot={false} />
                  <Area type="monotone" dataKey="profit" name={t('netProfitLabel') || 'Profit'} stroke="#22c55e" fill="url(#gProfit)" strokeWidth={2} dot={false} />
                </AreaChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>
        <div className="panel">
          <div className="panel-head"><h2>{t('periodStats')}</h2><span className="pill">{rLabel}</span></div>
          <div className="panel-body">
            <div className="prev-row"><span className="muted">{t('volume')}</span><strong className="mono t1v">{fmtQWithUnit(dR.rev, settings.currency, wacop)}</strong></div>
            <div className="prev-row"><span className="muted">{t('cost')}</span><strong className="mono">{fmtQWithUnit(dR.rev - dR.net - dR.fee, settings.currency, wacop)}</strong></div>
            {dR.fee > 0 && <div className="prev-row"><span className="muted">{t('fees')}</span><strong className="mono">{fmtQWithUnit(dR.fee, settings.currency, wacop)}</strong></div>}
            <div className="prev-row"><span className="muted">{t('netProfitLabel')}</span><strong className={`mono ${dR.net >= 0 ? 'good' : 'bad'}`}>{fmtQWithUnit(dR.net, settings.currency, wacop)}</strong></div>
            <div className="prev-row"><span className="muted">{t('avgMargin')}</span><strong className="mono" style={{ color: 'var(--t3)' }}>{fmtPct(avgM)}</strong></div>
            <div className="prev-row"><span className="muted">{t('trades')}</span><strong className="mono">{dR.count}</strong></div>
          </div>
        </div>
      </div>

      {showCashBox && !isAdminView && (
        <CashBoxManager
          currentCash={num(state.cashQAR, 0)}
          currentOwner={state.cashOwner || ''}
          cashHistory={state.cashHistory || []}
          onSave={handleCashSave}
          onClose={() => setShowCashBox(false)}
        />
      )}
    </div>
  );
}

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useTheme } from '@/lib/theme-context';
import { useAuth } from '@/features/auth/auth-context';
import { useT } from '@/lib/i18n';
import { supabase } from '@/integrations/supabase/client';
import { fmtU } from '@/lib/tracker-helpers';
import { DEAL_TYPE_CONFIGS } from '@/lib/deal-engine';
import { toast } from 'sonner';
import { UnifiedChatInbox } from '@/features/merchants/components/UnifiedChatInbox';
import { AgreementsGlobalTab } from '@/features/merchants/components/AgreementsGlobalTab';
import { LiquidityTab } from '@/features/merchants/liquidity/LiquidityTab';
import { useSettlementOverview } from '@/hooks/useSettlementOverview';
import { useProfitShareAgreements } from '@/hooks/useProfitShareAgreements';
import { isAgreementActive, getAgreementLabel } from '@/lib/deal-engine';
import { useIsMobile } from '@/hooks/use-mobile';
import '@/styles/tracker.css';
import { focusElementBySelectors } from '@/lib/focus-target';

type MerchantTab = 'relationships' | 'agreements' | 'settlements' | 'chat' | 'liquidity';

interface AgreementRow {
  id: string;
  relationship_id: string;
  title: string;
  deal_type: string;
  amount: number;
  currency: string;
  status: string;
  created_at: string;
  counterparty_name?: string;
  order_count?: number;
  settlement_cadence?: string;
}

interface MerchantsPageProps {
  adminUserId?: string;
  adminMerchantId?: string;
  isAdminView?: boolean;
}

export default function MerchantsPage({ adminUserId, adminMerchantId, isAdminView }: MerchantsPageProps = {}) {
  const { settings } = useTheme();
  const { userId: authUserId, merchantProfile: authMerchantProfile } = useAuth();
  const effectiveUserId = adminUserId || authUserId;
  const effectiveMerchantProfile = adminMerchantId
    ? { ...authMerchantProfile, merchant_id: adminMerchantId } as typeof authMerchantProfile
    : authMerchantProfile;
  // Alias for rest of file
  const userId = effectiveUserId;
  const merchantProfile = effectiveMerchantProfile;
  const t = useT();
  const navigate = useNavigate();
  const isMobile = useIsMobile();
  const [searchParams] = useSearchParams();

  const [tab, setTab] = useState<MerchantTab>(() => {
    const qTab = searchParams.get('tab');
    if (qTab === 'chat' || qTab === 'settlements' || qTab === 'relationships' || qTab === 'agreements' || qTab === 'liquidity') return qTab as MerchantTab;
    return 'relationships';
  });
  const [relationships, setRelationships] = useState<any[]>([]);
  const [agreements, setAgreements] = useState<AgreementRow[]>([]);
  const [invites, setInvites] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  // Find a Merchant state
  const [findQuery, setFindQuery] = useState('');
  const [findResult, setFindResult] = useState<any>(null);
  const [findStatus, setFindStatus] = useState<'idle' | 'searching' | 'found' | 'not_found' | 'already_connected'>('idle');
  const [sendingInvite, setSendingInvite] = useState(false);
  const [inviteMessage, setInviteMessage] = useState('');
  const { data: settlementOverview } = useSettlementOverview(adminMerchantId);
  const { data: allAgreements = [] } = useProfitShareAgreements(undefined, adminMerchantId);
  const [unreadChatCount, setUnreadChatCount] = useState(0);

  useEffect(() => { loadData(); }, [userId, merchantProfile?.merchant_id]);

  useEffect(() => {
    const focusInviteId = searchParams.get('focusInviteId');
    if (!focusInviteId) return;
    setTab('relationships');
    window.setTimeout(() => {
      focusElementBySelectors([
        `#invite-${focusInviteId}`,
        `[data-invite-id="${focusInviteId}"]`,
      ]);
    }, 200);
  }, [searchParams, invites.length]);


  // Fetch unread message count (scoped to this merchant's relationships only)
  useEffect(() => {
    if (!userId) return;
    const relationshipIds = relationships.map((r) => r.id).filter(Boolean);
    if (!relationshipIds.length) {
      setUnreadChatCount(0);
      return;
    }

    supabase
      .from('merchant_messages')
      .select('id', { count: 'exact', head: true })
      .in('relationship_id', relationshipIds)
      .neq('sender_id', userId)
      .is('read_at', null)
      .then(({ count }) => setUnreadChatCount(count || 0));
  }, [userId, relationships]);

  const handleOpenRelationship = useCallback((relationshipId: string) => {
    navigate(`/merchants/${relationshipId}`);
  }, [navigate]);

  const handleOpenOrders = useCallback((relationshipId: string) => {
    navigate(`/trading/orders?relationship=${relationshipId}`);
  }, [navigate]);

  const handleOpenRelationshipChat = useCallback((relationshipId: string) => {
    navigate(`/trading/merchants?tab=chat&relationship=${relationshipId}`);
  }, [navigate]);

  const loadData = async () => {
    if (!userId) return;
    setLoading(true);
    try {
      const myMerchantId = merchantProfile?.merchant_id;

      // ── CRITICAL: filter to only THIS merchant's data ──────────────────────
      // Without these filters every merchant sees ALL other merchants' relationships,
      // invites, and deals — causing ghost connections and data leakage.
      const [relsRes, invitesRes, profilesRes] = await Promise.all([
        supabase.from('merchant_relationships').select('*')
          .or(`merchant_a_id.eq.${myMerchantId},merchant_b_id.eq.${myMerchantId}`)
          .order('created_at', { ascending: false }),
        supabase.from('merchant_invites').select('*')
          .or(`from_merchant_id.eq.${myMerchantId},to_merchant_id.eq.${myMerchantId}`)
          .order('created_at', { ascending: false }),
        supabase.from('merchant_profiles').select('merchant_id, display_name, nickname, merchant_code'),
      ]);

      const profileMap = new Map(
        (profilesRes.data || []).map(p => [p.merchant_id, p])
      );

      const enrichedRels = (relsRes.data || []).map(r => {
        const cpId = r.merchant_a_id === myMerchantId ? r.merchant_b_id : r.merchant_a_id;
        const cp = profileMap.get(cpId);
        return {
          ...r,
          counterparty_name: cp?.display_name || cpId,
          counterparty_nickname: cp?.nickname || '',
          counterparty_code: (cp as any)?.merchant_code || '',
        };
      });

      const relationshipIds = enrichedRels.map((r) => r.id);
      const dealsRes = relationshipIds.length
        ? await supabase.from('merchant_deals').select('*').in('relationship_id', relationshipIds).order('created_at', { ascending: false })
        : { data: [], error: null };
      if (dealsRes.error) throw dealsRes.error;

      const enrichedDeals: AgreementRow[] = (dealsRes.data || []).map(d => {
        const rel = enrichedRels.find(r => r.id === d.relationship_id);
        return {
          id: d.id,
          relationship_id: d.relationship_id,
          title: d.title,
          deal_type: d.deal_type,
          amount: d.amount,
          currency: d.currency,
          status: d.status,
          created_at: d.created_at,
          counterparty_name: rel?.counterparty_name || '—',
          order_count: 0,
          settlement_cadence: (d as any).settlement_cadence || 'monthly',
        };
      });

      const enrichedInvites = (invitesRes.data || []).map(inv => {
        const fromP = profileMap.get(inv.from_merchant_id);
        const toP = profileMap.get(inv.to_merchant_id);
        const isIncoming = inv.to_merchant_id === myMerchantId;
        return {
          ...inv,
          from_name: fromP?.display_name || inv.from_merchant_id,
          to_name: toP?.display_name || inv.to_merchant_id,
          is_incoming: isIncoming,
        };
      });

      setRelationships(enrichedRels);
      setAgreements(enrichedDeals);
      setInvites(enrichedInvites);
    } catch (err) {
      console.error('Failed to load merchant data:', err);
    } finally {
      setLoading(false);
    }
  };

  // ─── Find a Merchant ───
  const handleFind = async () => {
    const q = findQuery.trim();
    if (!q) return;
    setFindStatus('searching');
    setFindResult(null);
    try {
      const myMerchantId = merchantProfile?.merchant_id;
      const { data, error } = await supabase
        .from('merchant_profiles')
        .select('merchant_id, display_name, nickname, region, bio, default_currency, merchant_code, created_at')
        .or(`merchant_code.eq.${q},nickname.ilike.%${q}%,merchant_id.ilike.%${q}%`)
        .neq('merchant_id', myMerchantId || '')
        .eq('status', 'active')
        .limit(1)
        .maybeSingle();

      if (error) throw error;
      if (!data) { setFindStatus('not_found'); return; }

      const existingMerchantIds = new Set([
        ...relationships.map(r => r.merchant_a_id === merchantProfile?.merchant_id ? r.merchant_b_id : r.merchant_a_id),
        ...invites.filter(i => i.status === 'pending').map(i =>
          i.from_merchant_id === merchantProfile?.merchant_id ? i.to_merchant_id : i.from_merchant_id
        ),
      ]);

      if (existingMerchantIds.has(data.merchant_id)) {
        setFindResult(data);
        setFindStatus('already_connected');
        return;
      }
      setFindResult(data);
      setFindStatus('found');
    } catch (err) {
      console.error('Find error:', err);
      setFindStatus('not_found');
    }
  };

  const handleSendInvite = async () => {
    if (!findResult || !merchantProfile) return;
    setSendingInvite(true);
    try {
      const { error } = await supabase.from('merchant_invites').insert({
        from_merchant_id: merchantProfile.merchant_id,
        to_merchant_id: findResult.merchant_id,
        status: 'pending',
        message: inviteMessage || null,
      });
      if (error) throw error;
      toast.success(`${t('inviteSentTo') || 'Invite sent to'} ${findResult.display_name}`);
      setFindQuery(''); setFindResult(null); setFindStatus('idle'); setInviteMessage('');
      loadData();
    } catch (err: any) { toast.error(err.message || 'Failed to send invite'); }
    finally { setSendingInvite(false); }
  };

  const handleAcceptInvite = async (invite: any) => {
    try {
      const { error: relError } = await supabase.from('merchant_relationships').insert({
        merchant_a_id: invite.from_merchant_id,
        merchant_b_id: invite.to_merchant_id,
        status: 'active',
      });
      if (relError) throw relError;
      const { error: invError } = await supabase.from('merchant_invites').update({ status: 'accepted' }).eq('id', invite.id);
      if (invError) throw invError;
      toast.success(t('inviteAccepted') || 'Invite accepted — relationship created!');
      loadData();
    } catch (err: any) { toast.error(err.message); }
  };

  const handleRejectInvite = async (id: string) => {
    try {
      const { error } = await supabase.from('merchant_invites').update({ status: 'rejected' }).eq('id', id);
      if (error) throw error;
      toast.success(t('inviteRejected') || 'Invite rejected');
      loadData();
    } catch (err: any) { toast.error(err.message); }
  };

  const handleWithdrawInvite = async (id: string) => {
    try {
      const { error } = await supabase.from('merchant_invites').update({ status: 'withdrawn' }).eq('id', id);
      if (error) throw error;
      toast.success(t('inviteWithdrawn') || 'Invite withdrawn');
      loadData();
    } catch (err: any) { toast.error(err.message); }
  };

  // Filtered lists
  const filteredRels = search
    ? relationships.filter(r =>
        r.counterparty_name?.toLowerCase().includes(search.toLowerCase()) ||
        r.counterparty_nickname?.toLowerCase().includes(search.toLowerCase())
      )
    : relationships;

  const cancelledDeals = useMemo(() => agreements.filter(a => a.status === 'cancelled'), [agreements]);

  const filteredLedger = useMemo(() => {
    if (!search) return cancelledDeals;
    return cancelledDeals.filter(a =>
      a.title.toLowerCase().includes(search.toLowerCase()) ||
      a.counterparty_name?.toLowerCase().includes(search.toLowerCase())
    );
  }, [cancelledDeals, search]);

  const statusPill = (status: string) => {
    const cls = status === 'active' || status === 'approved' || status === 'accepted' ? 'good'
      : status === 'pending' ? 'warn'
      : status === 'rejected' || status === 'cancelled' || status === 'terminated' || status === 'withdrawn' ? 'bad'
      : '';
    return <span className={`pill ${cls}`}>{status}</span>;
  };

  const dealTypeLabel = (dt: string) => {
    const cfg = DEAL_TYPE_CONFIGS[dt as keyof typeof DEAL_TYPE_CONFIGS];
    return cfg ? `${cfg.icon} ${cfg.label}` : dt;
  };

  const inboxCount = invites.filter(i => i.status === 'pending' && i.is_incoming).length;

  const overdueCount = settlementOverview?.overdueCount || 0;
  const activeAgreementCount = allAgreements.filter(a => isAgreementActive(a)).length;
  const tabs: { key: MerchantTab; label: string; icon: string; badge?: number }[] = [
    { key: 'relationships', label: t('relationships') || 'Relationships', icon: '👥' },
    { key: 'liquidity', label: t('liquidityTab') || 'Liquidity', icon: '💧' },
    { key: 'agreements', label: t('profitShareAgreements'), icon: '🤝' },
    { key: 'settlements', label: t('settlementTracker'), icon: '💰', badge: overdueCount > 0 ? overdueCount : undefined },
    { key: 'chat', label: t('chatTab') || 'Chat', icon: '💬', badge: unreadChatCount > 0 ? unreadChatCount : undefined },
  ];

  return (
    <div
      className="tracker-root"
      dir={t.isRTL ? 'rtl' : 'ltr'}
      style={{
        padding: isMobile ? 'max(12px, env(safe-area-inset-top, 0px)) 12px max(14px, env(safe-area-inset-bottom, 0px))' : 12,
        display: 'flex',
        flexDirection: 'column',
        gap: 10,
        minHeight: '100%',
      }}
    >

      {/* ─── HEADER ─── */}
      <div style={{ display: 'flex', alignItems: isMobile ? 'stretch' : 'center', justifyContent: 'space-between', gap: 10, flexWrap: 'wrap' }}>
        <div>
          <div style={{ fontSize: 13, fontWeight: 800 }}>🏪 {t('theMerchants') || 'The Merchants'}</div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('merchantOrchestratorDesc') || 'Relationship orchestration hub'}</div>
        </div>
        <div className="inputBox" style={{ maxWidth: isMobile ? '100%' : 240, width: isMobile ? '100%' : undefined, padding: '6px 10px' }}>
          <input
            placeholder={t('search') || 'Search...'}
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>
      </div>

      {/* ─── FIND A MERCHANT ─── */}
      <div style={{
        display: 'flex', gap: 8, alignItems: isMobile ? 'stretch' : 'center', flexWrap: isMobile ? 'wrap' : 'nowrap', padding: '8px 0',
        borderBottom: '1px solid var(--line)',
      }}>
        <div className="inputBox" style={{ flex: 1, maxWidth: isMobile ? '100%' : 320, width: isMobile ? '100%' : undefined, padding: '6px 10px' }}>
          <input
            placeholder={t('findMerchantPlaceholder') || 'Enter merchant code, nickname, or ID...'}
            value={findQuery}
            onChange={e => { setFindQuery(e.target.value); if (findStatus !== 'idle') { setFindStatus('idle'); setFindResult(null); } }}
            onKeyDown={e => { if (e.key === 'Enter') handleFind(); }}
          />
        </div>
        <button
          className="btn"
          onClick={handleFind}
          disabled={!findQuery.trim() || findStatus === 'searching'}
          style={{ whiteSpace: 'nowrap', minHeight: 44, width: isMobile ? '100%' : undefined }}
        >
          🔍 {findStatus === 'searching' ? (t('loading') || '...') : (t('findMerchant') || 'Find a Merchant')}
        </button>
      </div>

      {/* ─── FIND RESULT ─── */}
      {findStatus === 'not_found' && (
        <div style={{
          padding: '10px 14px', borderRadius: 8, border: '1px solid var(--line)',
          background: 'var(--cardBg)', fontSize: 11, color: 'var(--muted)',
        }}>
          ❌ {t('merchantNotFound') || 'No merchant found with that code or ID. Please check and try again.'}
        </div>
      )}

      {findStatus === 'already_connected' && findResult && (
        <div style={{
          padding: '10px 14px', borderRadius: 8, border: '1px solid var(--line)',
          background: 'var(--cardBg)', fontSize: 11,
        }}>
          <div style={{ fontWeight: 700, marginBottom: 4 }}>{findResult.display_name}</div>
          <div style={{ color: 'var(--muted)', fontSize: 10 }}>
            ✅ {t('alreadyConnected') || 'You are already connected or have a pending invite with this merchant.'}
          </div>
        </div>
      )}

      {findStatus === 'found' && findResult && (
        <div style={{
          padding: '12px 14px', borderRadius: 8, border: '1px solid var(--brand)',
          background: 'var(--cardBg)',
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 8 }}>
            <div>
              <div style={{ fontWeight: 800, fontSize: 13 }}>{findResult.display_name}</div>
              <div style={{ fontSize: 10, color: 'var(--muted)', marginTop: 2 }}>
                @{findResult.nickname} · {t('code') || 'Code'}: <span className="mono" style={{ fontWeight: 700 }}>{findResult.merchant_code || '—'}</span>
              </div>
              {findResult.region && <div style={{ fontSize: 10, color: 'var(--muted)', marginTop: 2 }}>📍 {findResult.region}</div>}
              {findResult.bio && <div style={{ fontSize: 10, color: 'var(--muted)', marginTop: 2 }}>{findResult.bio}</div>}
              <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 4 }}>
                {t('memberSince') || 'Member since'}: {new Date(findResult.created_at).toLocaleDateString()}
              </div>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6, alignItems: isMobile ? 'stretch' : 'flex-end', width: isMobile ? '100%' : undefined }}>
              <div className="inputBox" style={{ maxWidth: isMobile ? '100%' : 220, width: isMobile ? '100%' : undefined, padding: '4px 8px' }}>
                <input
                  placeholder={t('addANote') || 'Add a note (optional)...'}
                  value={inviteMessage}
                  onChange={e => setInviteMessage(e.target.value)}
                  style={{ fontSize: 10 }}
                />
              </div>
              <button className="btn" onClick={handleSendInvite} disabled={sendingInvite} style={{ fontSize: 11, minHeight: 42 }}>
                📨 {sendingInvite ? (t('loading') || '...') : (t('sendInvite') || 'Send Invite')}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── TAB BAR ─── */}
      <div style={{ display: 'flex', gap: 0, borderBottom: '1px solid var(--line)', marginBottom: 2, overflowX: 'auto', paddingBottom: 2 }}>
        {tabs.map(({ key, label, icon, badge }) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            style={{
              padding: isMobile ? '10px 14px' : '9px 18px', fontSize: 11, fontWeight: tab === key ? 700 : 500,
              color: tab === key ? 'var(--brand)' : 'var(--muted)',
              borderBottom: tab === key ? '2px solid var(--brand)' : '2px solid transparent',
              background: 'transparent', border: 'none', borderBottomStyle: 'solid', cursor: 'pointer',
              transition: 'all 0.15s', letterSpacing: '.2px',
              display: 'flex', alignItems: 'center', gap: 4,
              minHeight: 44,
              whiteSpace: 'nowrap',
            }}
          >
            {icon} {label}
            {badge != null && badge > 0 && (
              <span style={{
                fontSize: 9, fontWeight: 700, background: 'var(--bad)',
                color: '#fff', borderRadius: 10, padding: '1px 6px',
                minWidth: 16, textAlign: 'center',
              }}>
                {badge}
              </span>
            )}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="empty">
          <div className="empty-t">{t('loading') || 'Loading...'}</div>
        </div>
      ) : (
        <>
          {/* ═══ RELATIONSHIPS TAB ═══ */}
          {tab === 'relationships' && (
            <>
              {/* ── PENDING INVITES SECTION (INCOMING) ── */}
              {invites.filter(i => i.status === 'pending' && i.is_incoming).length > 0 && (
                <div style={{
                  padding: '10px 12px', borderRadius: 8, marginBottom: 10,
                  border: '2px solid var(--bad)',
                  background: 'color-mix(in srgb, var(--bad) 8%, var(--cardBg))',
                  animation: 'pulse 2s infinite',
                }}>
                  <div style={{ fontSize: 12, fontWeight: 800, marginBottom: 8, color: 'var(--bad)', display: 'flex', alignItems: 'center', gap: 6 }}>
                    🔔 {t('pendingInvitations')}
                    <span style={{
                      fontSize: 9, fontWeight: 700, background: 'var(--bad)',
                      color: '#fff', borderRadius: 10, padding: '1px 6px',
                    }}>
                      {invites.filter(i => i.status === 'pending' && i.is_incoming).length}
                    </span>
                  </div>
                  {invites.filter(i => i.status === 'pending' && i.is_incoming).map(inv => {
                    const elapsed = Date.now() - new Date(inv.created_at).getTime();
                    const days = Math.floor(elapsed / 86400000);
                    const hours = Math.floor((elapsed % 86400000) / 3600000);
                    const timeAgo = days > 0 ? `${days}d ${hours}h ago` : hours > 0 ? `${hours}h ago` : 'Just now';
                    return (
                      <div key={inv.id} style={{
                        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                        padding: '10px 12px', borderRadius: 6, marginBottom: 4,
                        background: 'var(--cardBg)', border: '1px solid var(--line)',
                        flexWrap: 'wrap', gap: 8,
                      }}>
                        <div style={{ flex: 1, minWidth: 180 }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
                            <span style={{ fontWeight: 800, fontSize: 12 }}>{inv.from_name}</span>
                            <span style={{ fontSize: 9, color: 'var(--muted)' }}>→</span>
                            <span style={{ fontSize: 11, color: 'var(--muted)', fontWeight: 600 }}>You</span>
                          </div>
                          {inv.message && (
                            <div style={{ fontSize: 10, color: 'var(--t2)', marginBottom: 3, fontStyle: 'italic' }}>
                              💬 "{inv.message}"
                            </div>
                          )}
                          <div style={{ display: 'flex', gap: 10, fontSize: 9, color: 'var(--muted)', flexWrap: 'wrap' }}>
                            <span>📅 {new Date(inv.created_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}</span>
                            <span>⏱ {timeAgo}</span>
                            <span className="pill warn" style={{ fontSize: 8, padding: '1px 6px' }}>{t('pendingStatus')}</span>
                          </div>
                        </div>
                        <div style={{ display: 'flex', gap: 6, width: isMobile ? '100%' : undefined }}>
                          <button
                            className="btn"
                            onClick={() => handleAcceptInvite(inv)}
                            style={{ fontSize: 11, background: 'var(--good)', color: '#fff', border: 'none', padding: '6px 14px', borderRadius: 6, fontWeight: 700, minHeight: 40, flex: isMobile ? 1 : undefined }}
                          >
                            ✓ {t('accept')}
                          </button>
                          <button
                            className="rowBtn"
                            onClick={() => handleRejectInvite(inv.id)}
                            style={{ fontSize: 11, color: 'var(--bad)', fontWeight: 700, minHeight: 40, flex: isMobile ? 1 : undefined }}
                          >
                            ✗ {t('reject')}
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}

              {/* ── SENT INVITES (OUTGOING PENDING) ── */}
              {invites.filter(i => i.status === 'pending' && !i.is_incoming).length > 0 && (
                <div style={{
                  padding: '10px 12px', borderRadius: 8, marginBottom: 10,
                  border: '1px solid var(--line)', background: 'var(--cardBg)',
                }}>
                  <div style={{ fontSize: 11, fontWeight: 700, marginBottom: 8, color: 'var(--muted)', display: 'flex', alignItems: 'center', gap: 6 }}>
                    📤 {t('sentInvites')}
                    <span style={{
                      fontSize: 9, fontWeight: 600, background: 'color-mix(in srgb, var(--warn) 15%, transparent)',
                      color: 'var(--warn)', borderRadius: 10, padding: '1px 6px',
                    }}>
                      {invites.filter(i => i.status === 'pending' && !i.is_incoming).length}
                    </span>
                  </div>
                  {invites.filter(i => i.status === 'pending' && !i.is_incoming).map(inv => {
                    const elapsed = Date.now() - new Date(inv.created_at).getTime();
                    const days = Math.floor(elapsed / 86400000);
                    const hours = Math.floor((elapsed % 86400000) / 3600000);
                    const timeAgo = days > 0 ? `${days}d ${hours}h ago` : hours > 0 ? `${hours}h ago` : 'Just now';
                    const expiresAt = inv.expires_at ? new Date(inv.expires_at) : null;
                    const isExpiringSoon = expiresAt && (expiresAt.getTime() - Date.now()) < 86400000 * 3;
                    return (
                      <div key={inv.id} style={{
                        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                        padding: '10px 12px', borderRadius: 6, marginBottom: 4,
                        border: '1px solid var(--line)', background: 'color-mix(in srgb, var(--warn) 3%, var(--cardBg))',
                        flexWrap: 'wrap', gap: 8,
                      }}>
                        <div style={{ flex: 1, minWidth: 180 }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
                            <span style={{ fontSize: 11, color: 'var(--muted)', fontWeight: 600 }}>You</span>
                            <span style={{ fontSize: 9, color: 'var(--muted)' }}>→</span>
                            <span style={{ fontWeight: 800, fontSize: 12 }}>{inv.to_name}</span>
                          </div>
                          {inv.message && (
                            <div style={{ fontSize: 10, color: 'var(--t2)', marginBottom: 3, fontStyle: 'italic' }}>
                              💬 "{inv.message}"
                            </div>
                          )}
                          <div style={{ display: 'flex', gap: 10, fontSize: 9, color: 'var(--muted)', flexWrap: 'wrap', alignItems: 'center' }}>
                            <span>📅 {new Date(inv.created_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}</span>
                            <span>⏱ {timeAgo}</span>
                            <span className="pill warn" style={{ fontSize: 8, padding: '1px 6px' }}>Awaiting response</span>
                            {expiresAt && (
                              <span style={{ color: isExpiringSoon ? 'var(--bad)' : 'var(--muted)', fontWeight: isExpiringSoon ? 700 : 400 }}>
                                ⏳ Expires {expiresAt.toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                              </span>
                            )}
                          </div>
                        </div>
                        <div style={{ display: 'flex', gap: 6, width: isMobile ? '100%' : undefined }}>
                          <button className="rowBtn" onClick={() => handleWithdrawInvite(inv.id)} style={{ fontSize: 10, color: 'var(--bad)', minHeight: 40, width: isMobile ? '100%' : undefined }}>
                            ↩ {t('withdraw')}
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}

              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                <div>
                  <div style={{ fontSize: 12, fontWeight: 700 }}>{t('activeRelationships')}</div>
                  <div style={{ fontSize: 10, color: 'var(--muted)' }}>{filteredRels.length} {t('merchants')}</div>
                </div>
              </div>

              {filteredRels.length === 0 ? (
                <div className="empty">
                  <div className="empty-t">{t('noRelationships')}</div>
                  <div className="empty-s">{t('sendInviteToStart')}</div>
                </div>
              ) : isMobile ? (
                <div style={{ display: 'grid', gap: 8 }}>
                  {filteredRels.map(r => {
                    const relDeals = agreements.filter(a => a.relationship_id === r.id && a.status !== 'cancelled');
                    return (
                      <div key={r.id} className="panel" style={{ padding: 10, borderRadius: 10 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                          <div style={{ minWidth: 0 }}>
                            <div style={{ fontWeight: 700, fontSize: 12, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{r.counterparty_name}</div>
                            <div style={{ fontSize: 10, color: 'var(--muted)' }}>@{r.counterparty_nickname || '—'}</div>
                            <div className="mono" style={{ fontSize: 10, color: 'var(--muted)', marginTop: 4 }}>
                              {(t('code') || 'Code')}: {r.counterparty_code || '—'}
                            </div>
                          </div>
                          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 4 }}>
                            {statusPill(r.status)}
                            <span style={{ fontSize: 10, color: 'var(--muted)' }}>{relDeals.length} {t('deals')}</span>
                          </div>
                        </div>
                        <div style={{ marginTop: 8, fontSize: 10, color: 'var(--muted)' }}>
                          {(t('since') || 'Since')}: {new Date(r.created_at).toLocaleDateString()}
                        </div>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, minmax(0, 1fr))', gap: 6, marginTop: 10 }}>
                          <button className="rowBtn" type="button" onClick={() => handleOpenRelationship(r.id)} style={{ minHeight: 40 }}>
                            {t('openWorkspaceLabel')}
                          </button>
                          <button className="rowBtn" type="button" onClick={() => handleOpenOrders(r.id)} style={{ minHeight: 40 }}>
                            {t('orders')}
                          </button>
                          <button
                            className="rowBtn"
                            type="button"
                            onClick={() => {
                              setTab('chat');
                            }}
                            style={{ minHeight: 40, gridColumn: '1 / -1' }}
                          >
                            {t('chatTab') || 'Chat'}
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="tableWrap">
                  <table>
                    <thead>
                      <tr>
                        <th>{t('merchant')}</th>
                        <th className="hide-mobile">{t('code')}</th>
                        <th>{t('status')}</th>
                        <th className="r hide-mobile">{t('deals')}</th>
                        <th className="hide-mobile">{t('since')}</th>
                        <th>{t('actions')}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredRels.map(r => {
                        const relDeals = agreements.filter(a => a.relationship_id === r.id && a.status !== 'cancelled');
                        return (
                          <tr key={r.id}>
                            <td>
                              <div style={{ fontWeight: 700, fontSize: 11 }}>{r.counterparty_name}</div>
                              <div style={{ fontSize: 9, color: 'var(--muted)' }}>@{r.counterparty_nickname}</div>
                            </td>
                            <td className="mono hide-mobile" style={{ fontSize: 10, fontWeight: 700 }}>{r.counterparty_code || '—'}</td>
                            <td>{statusPill(r.status)}</td>
                            <td className="mono r hide-mobile">{relDeals.length}</td>
                            <td className="mono hide-mobile">{new Date(r.created_at).toLocaleDateString()}</td>
                            <td>
                              <div style={{ display: 'flex', gap: 4 }}>
                                <button className="rowBtn" type="button" onClick={() => handleOpenRelationship(r.id)}>
                                  {t('openWorkspaceLabel')}
                                </button>
                                <button className="rowBtn" type="button" onClick={() => handleOpenOrders(r.id)}>
                                  {t('orders')}
                                </button>
                              </div>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              )}
            </>
          )}

          {tab === 'liquidity' && (
            <LiquidityTab
              onOpenRelationship={handleOpenRelationship}
              onOpenChat={handleOpenRelationshipChat}
              onOpenDeal={handleOpenOrders}
            />
          )}


          {/* ═══ AGREEMENTS TAB ═══ */}
          {tab === 'agreements' && (
            <AgreementsGlobalTab
              relationships={relationships}
              allAgreements={allAgreements}
              activeAgreementCount={activeAgreementCount}
              onOpenRelationship={handleOpenRelationship}
            />
          )}

          {/* ═══ SETTLEMENTS TAB ═══ */}
          {tab === 'settlements' && (
            <>
              {/* KPI row */}
              {settlementOverview && (
                isMobile ? (
                  <div className="panel" style={{ padding: 10, marginBottom: 10 }}>
                    <div style={{ fontSize: 12, fontWeight: 800, marginBottom: 8 }}>{t('settlementTracker')}</div>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, minmax(0, 1fr))', gap: 8 }}>
                      <div className="panel" style={{ padding: 8 }}>
                        <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('dueNow')}</div>
                        <div className="mono" style={{ fontSize: 14, fontWeight: 800, color: settlementOverview.dueCount > 0 ? 'orange' : 'var(--muted)' }}>{settlementOverview.dueCount}</div>
                      </div>
                      <div className="panel" style={{ padding: 8 }}>
                        <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('overdueSettlement')}</div>
                        <div className="mono" style={{ fontSize: 14, fontWeight: 800, color: settlementOverview.overdueCount > 0 ? 'var(--bad)' : 'var(--muted)' }}>{settlementOverview.overdueCount}</div>
                      </div>
                      <div className="panel" style={{ padding: 8 }}>
                        <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('settledThisMonth')}</div>
                        <div className="mono" style={{ fontSize: 14, fontWeight: 800, color: 'var(--good)' }}>{settlementOverview.settledThisMonth}</div>
                      </div>
                      <div className="panel" style={{ padding: 8 }}>
                        <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('totalOutstandingLabel')}</div>
                        <div className="mono" style={{ fontSize: 13, fontWeight: 800 }}>{fmtU(settlementOverview.totalOutstanding)}</div>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="kpi-band" style={{ marginBottom: 10 }}>
                    <div className="kpi-band-title">{t('settlementTracker')}</div>
                    <div className="kpi-band-cols">
                      <div>
                        <div className="kpi-period">{t('dueNow')}</div>
                        <div className="kpi-cell-val" style={{ color: settlementOverview.dueCount > 0 ? 'orange' : 'var(--muted)' }}>
                          {settlementOverview.dueCount}
                        </div>
                      </div>
                      <div>
                        <div className="kpi-period">{t('overdueSettlement')}</div>
                        <div className="kpi-cell-val" style={{ color: settlementOverview.overdueCount > 0 ? 'var(--bad)' : 'var(--muted)' }}>
                          {settlementOverview.overdueCount}
                        </div>
                      </div>
                      <div>
                        <div className="kpi-period">{t('settledThisMonth')}</div>
                        <div className="kpi-cell-val" style={{ color: 'var(--good)' }}>{settlementOverview.settledThisMonth}</div>
                      </div>
                      <div>
                        <div className="kpi-period">{t('totalOutstandingLabel')}</div>
                        <div className="kpi-cell-val">{fmtU(settlementOverview.totalOutstanding)}</div>
                      </div>
                    </div>
                  </div>
                )
              )}

              {/* Grouped by relationship */}
              {!settlementOverview || settlementOverview.items.length === 0 ? (
                <div className="empty">
                  <div className="empty-t">{t('noDeals')}</div>
                  <div className="empty-s">{t('createDealsFromWorkspace')}</div>
                </div>
              ) : (
                Array.from(settlementOverview.byRelationship.entries()).map(([relId, group]) => (
                  <div key={relId} className="panel" style={{ padding: 10, marginBottom: 8 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: isMobile ? 'stretch' : 'center', marginBottom: 6, gap: 8, flexWrap: isMobile ? 'wrap' : 'nowrap' }}>
                      <div style={{ fontSize: 12, fontWeight: 700, minWidth: 0 }}>{group.name}</div>
                      <button className="rowBtn" onClick={() => handleOpenRelationship(relId)} style={{ fontSize: 10, minHeight: isMobile ? 40 : undefined, width: isMobile ? '100%' : undefined }}>
                        {t('openWorkspace')} →
                      </button>
                    </div>
                    {isMobile ? (
                      <div style={{ display: 'grid', gap: 8, paddingBottom: 'max(8px, env(safe-area-inset-bottom, 0px))' }}>
                        {group.items.map(item => {
                          const statusCls = item.status === 'overdue' ? 'bad' : item.status === 'due' ? 'warn' : '';
                          const cadenceLabel = item.cadence === 'per_order' ? '⚡ ' + t('perTrade') : item.cadence === 'weekly' ? '📆 ' + t('weekly') : '📅 ' + t('monthly');
                          return (
                            <div key={item.period_id} className="previewBox" style={{ padding: 10 }}>
                              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8, marginBottom: 6 }}>
                                <div style={{ fontWeight: 700, fontSize: 12, minWidth: 0 }}>{item.deal_title}</div>
                                <span className={`pill ${statusCls}`} style={{ fontSize: 10 }}>{item.status === 'overdue' ? '⚠️ ' : ''}{item.status}</span>
                              </div>
                              <div style={{ display: 'grid', gap: 4 }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                                  <span className="muted">{t('period') || 'Period'}</span>
                                  <span className="mono" style={{ fontSize: 11 }}>{item.period_key}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                                  <span className="muted">{t('settlementCadence')}</span>
                                  <span style={{ fontSize: 11 }}>{cadenceLabel}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                                  <span className="muted">{t('partnerShare')}</span>
                                  <span className="mono" style={{ fontSize: 12, fontWeight: 700 }}>{fmtU(item.partner_amount)}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                                  <span className="muted">{t('dueDate') || 'Due'}</span>
                                  <span className="mono" style={{ fontSize: 11 }}>{item.due_at ? new Date(item.due_at).toLocaleDateString() : '—'}</span>
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    ) : (
                      <div className="tableWrap">
                        <table>
                          <thead>
                            <tr>
                              <th>{t('title') || 'Deal'}</th>
                              <th>{t('period') || 'Period'}</th>
                              <th>{t('settlementCadence')}</th>
                              <th className="r">{t('partnerShare')}</th>
                              <th>{t('status')}</th>
                              <th>{t('dueDate') || 'Due'}</th>
                            </tr>
                          </thead>
                          <tbody>
                            {group.items.map(item => {
                              const statusCls = item.status === 'overdue' ? 'bad' : item.status === 'due' ? 'warn' : '';
                              return (
                                <tr key={item.period_id}>
                                  <td style={{ fontWeight: 700, fontSize: 11 }}>{item.deal_title}</td>
                                  <td className="mono" style={{ fontSize: 10 }}>{item.period_key}</td>
                                  <td style={{ fontSize: 10 }}>
                                    {item.cadence === 'per_order' ? '⚡ ' + t('perTrade') : item.cadence === 'weekly' ? '📆 ' + t('weekly') : '📅 ' + t('monthly')}
                                  </td>
                                  <td className="mono r">{fmtU(item.partner_amount)}</td>
                                  <td><span className={`pill ${statusCls}`}>{item.status === 'overdue' ? '⚠️ ' : ''}{item.status}</span></td>
                                  <td className="mono" style={{ fontSize: 10 }}>{item.due_at ? new Date(item.due_at).toLocaleDateString() : '—'}</td>
                                </tr>
                              );
                            })}
                          </tbody>
                        </table>
                      </div>
                    )}
                  </div>
                ))
              )}
            </>
          )}

          {/* ═══ CHAT TAB ═══ */}
          {tab === 'chat' && (
            <UnifiedChatInbox relationships={relationships} />
          )}

        </>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useTheme } from '@/lib/theme-context';
import { useAuth } from '@/features/auth/auth-context';
import { useT } from '@/lib/i18n';
import { supabase } from '@/integrations/supabase/client';
import { fmtU } from '@/lib/tracker-helpers';
import { DEAL_TYPE_CONFIGS } from '@/lib/deal-engine';
import { toast } from 'sonner';
import '@/styles/tracker.css';

type NetworkTab = 'network' | 'deals' | 'inbox';

export default function NetworkPage() {
  const { settings } = useTheme();
  const { userId, merchantProfile } = useAuth();
  const t = useT();
  const [searchParams, setSearchParams] = useSearchParams();

  const initialTab = (searchParams.get('tab') as NetworkTab) || 'network';
  const [tab, setTab] = useState<NetworkTab>(initialTab);
  const [search, setSearch] = useState('');

  // Data
  const [relationships, setRelationships] = useState<any[]>([]);
  const [deals, setDeals] = useState<any[]>([]);
  const [invites, setInvites] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Find a Merchant state
  const [findQuery, setFindQuery] = useState('');
  const [findResult, setFindResult] = useState<any>(null);
  const [findStatus, setFindStatus] = useState<'idle' | 'searching' | 'found' | 'not_found' | 'already_connected'>('idle');
  const [sendingInvite, setSendingInvite] = useState(false);
  const [inviteMessage, setInviteMessage] = useState('');

  useEffect(() => {
    loadData();
  }, [userId]);

  useEffect(() => {
    setSearchParams({ tab }, { replace: true });
  }, [tab]);

  const loadData = async () => {
    if (!userId) return;
    setLoading(true);
    try {
      const myMerchantId = merchantProfile?.merchant_id;

      const [relsRes, dealsRes, invitesRes, profilesRes] = await Promise.all([
        supabase.from('merchant_relationships').select('*').order('created_at', { ascending: false }),
        supabase.from('merchant_deals').select('*').order('created_at', { ascending: false }),
        supabase.from('merchant_invites').select('*').order('created_at', { ascending: false }),
        supabase.from('merchant_profiles').select('merchant_id, display_name, nickname, merchant_code'),
      ]);

      const profileMap = new Map(
        (profilesRes.data || []).map(p => [p.merchant_id, p])
      );

      const enrichedRels = (relsRes.data || []).map(r => {
        const cpId = r.merchant_a_id === myMerchantId ? r.merchant_b_id : r.merchant_a_id;
        const cp = profileMap.get(cpId);
        return {
          ...r,
          counterparty_name: cp?.display_name || cpId,
          counterparty_nickname: cp?.nickname || '',
          counterparty_code: (cp as any)?.merchant_code || '',
        };
      });

      const enrichedDeals = (dealsRes.data || []).map(d => {
        const rel = enrichedRels.find(r => r.id === d.relationship_id);
        return { ...d, counterparty_name: rel?.counterparty_name || '—' };
      });

      const enrichedInvites = (invitesRes.data || []).map(inv => {
        const fromP = profileMap.get(inv.from_merchant_id);
        const toP = profileMap.get(inv.to_merchant_id);
        const isIncoming = inv.to_merchant_id === myMerchantId;
        return {
          ...inv,
          from_name: fromP?.display_name || inv.from_merchant_id,
          to_name: toP?.display_name || inv.to_merchant_id,
          is_incoming: isIncoming,
        };
      });

      setRelationships(enrichedRels);
      setDeals(enrichedDeals);
      setInvites(enrichedInvites);
    } catch (err) {
      console.error('Network load error:', err);
    } finally {
      setLoading(false);
    }
  };

  const statusPill = (status: string) => {
    const cls = status === 'active' || status === 'approved' || status === 'accepted' ? 'good'
      : status === 'pending' ? 'warn'
      : status === 'rejected' || status === 'cancelled' || status === 'terminated' || status === 'withdrawn' ? 'bad'
      : '';
    return <span className={`pill ${cls}`}>{status}</span>;
  };

  const dealTypeLabel = (dt: string) => {
    const cfg = DEAL_TYPE_CONFIGS[dt as keyof typeof DEAL_TYPE_CONFIGS];
    return cfg ? `${cfg.icon} ${cfg.label}` : dt;
  };

  // ─── Find a Merchant ───
  const handleFind = async () => {
    const q = findQuery.trim();
    if (!q) return;
    setFindStatus('searching');
    setFindResult(null);
    try {
      const myMerchantId = merchantProfile?.merchant_id;

      // Search by merchant_code, nickname, or merchant_id
      const { data, error } = await supabase
        .from('merchant_profiles')
        .select('merchant_id, display_name, nickname, region, bio, default_currency, merchant_code, created_at')
        .or(`merchant_code.eq.${q},nickname.ilike.%${q}%,merchant_id.ilike.%${q}%`)
        .neq('merchant_id', myMerchantId || '')
        .eq('status', 'active')
        .limit(1)
        .maybeSingle();

      if (error) throw error;

      if (!data) {
        setFindStatus('not_found');
        return;
      }

      // Check if already connected or has pending invite
      const existingMerchantIds = new Set([
        ...relationships.map(r => r.merchant_a_id === myMerchantId ? r.merchant_b_id : r.merchant_a_id),
        ...invites.filter(i => i.status === 'pending').map(i =>
          i.from_merchant_id === myMerchantId ? i.to_merchant_id : i.from_merchant_id
        ),
      ]);

      if (existingMerchantIds.has(data.merchant_id)) {
        setFindResult(data);
        setFindStatus('already_connected');
        return;
      }

      setFindResult(data);
      setFindStatus('found');
    } catch (err) {
      console.error('Find error:', err);
      setFindStatus('not_found');
    }
  };

  // ─── Send Invite ───
  const handleSendInvite = async () => {
    if (!findResult || !merchantProfile) return;
    setSendingInvite(true);
    try {
      const { error } = await supabase.from('merchant_invites').insert({
        from_merchant_id: merchantProfile.merchant_id,
        to_merchant_id: findResult.merchant_id,
        status: 'pending',
        message: inviteMessage || null,
      });
      if (error) throw error;
      toast.success(`${t('inviteSentTo') || 'Invite sent to'} ${findResult.display_name}`);
      setFindQuery('');
      setFindResult(null);
      setFindStatus('idle');
      setInviteMessage('');
      loadData();
    } catch (err: any) {
      toast.error(err.message || 'Failed to send invite');
    } finally {
      setSendingInvite(false);
    }
  };

  // ─── Accept Invite ───
  const handleAcceptInvite = async (invite: any) => {
    try {
      const { error: relError } = await supabase.from('merchant_relationships').insert({
        merchant_a_id: invite.from_merchant_id,
        merchant_b_id: invite.to_merchant_id,
        status: 'active',
      });
      if (relError) throw relError;

      const { error: invError } = await supabase
        .from('merchant_invites')
        .update({ status: 'accepted' })
        .eq('id', invite.id);
      if (invError) throw invError;

      toast.success(t('inviteAccepted') || 'Invite accepted — relationship created!');
      loadData();
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleRejectInvite = async (id: string) => {
    try {
      const { error } = await supabase
        .from('merchant_invites')
        .update({ status: 'rejected' })
        .eq('id', id);
      if (error) throw error;
      toast.success(t('inviteRejected') || 'Invite rejected');
      loadData();
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleWithdrawInvite = async (id: string) => {
    try {
      const { error } = await supabase
        .from('merchant_invites')
        .update({ status: 'withdrawn' })
        .eq('id', id);
      if (error) throw error;
      toast.success(t('inviteWithdrawn') || 'Invite withdrawn');
      loadData();
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const filteredRels = search
    ? relationships.filter(r => r.counterparty_name?.toLowerCase().includes(search.toLowerCase()))
    : relationships;

  const filteredDeals = search
    ? deals.filter(d => d.title?.toLowerCase().includes(search.toLowerCase()) || d.counterparty_name?.toLowerCase().includes(search.toLowerCase()))
    : deals;

  const inboxCount = invites.filter(i => i.status === 'pending' && i.is_incoming).length;

  const tabs: { key: NetworkTab; label: string; icon: string; badge?: number }[] = [
    { key: 'network', label: t('myNetwork') || 'My Network', icon: '👥' },
    { key: 'deals', label: t('deals'), icon: '🤝' },
    { key: 'inbox', label: t('inbox') || 'Inbox', icon: '📥', badge: inboxCount },
  ];

  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'} style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: '100%' }}>

      {/* ─── HEADER ─── */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 10, flexWrap: 'wrap' }}>
        <div>
          <div style={{ fontSize: 13, fontWeight: 800 }}>🌐 {t('network')}</div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('networkDesc') || 'Relationships, deals & invitations'}</div>
        </div>
        <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
          <div className="inputBox" style={{ maxWidth: 200, padding: '6px 10px' }}>
            <input
              placeholder={t('search') || 'Search...'}
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
          </div>
        </div>
      </div>

      {/* ─── FIND A MERCHANT SECTION ─── */}
      <div style={{
        display: 'flex', gap: 8, alignItems: 'center', padding: '8px 0',
        borderBottom: '1px solid var(--line)',
      }}>
        <div className="inputBox" style={{ flex: 1, maxWidth: 320, padding: '6px 10px' }}>
          <input
            placeholder={t('findMerchantPlaceholder') || 'Enter merchant code, nickname, or ID...'}
            value={findQuery}
            onChange={e => { setFindQuery(e.target.value); if (findStatus !== 'idle') { setFindStatus('idle'); setFindResult(null); } }}
            onKeyDown={e => { if (e.key === 'Enter') handleFind(); }}
          />
        </div>
        <button
          className="btn"
          onClick={handleFind}
          disabled={!findQuery.trim() || findStatus === 'searching'}
          style={{ whiteSpace: 'nowrap' }}
        >
          🔍 {findStatus === 'searching' ? (t('loading') || '...') : (t('findMerchant') || 'Find a Merchant')}
        </button>
      </div>

      {/* ─── FIND RESULT ─── */}
      {findStatus === 'not_found' && (
        <div style={{
          padding: '10px 14px', borderRadius: 8, border: '1px solid var(--line)',
          background: 'var(--cardBg)', fontSize: 11, color: 'var(--muted)',
        }}>
          ❌ {t('merchantNotFound') || 'No merchant found with that code or ID. Please check and try again.'}
        </div>
      )}

      {findStatus === 'already_connected' && findResult && (
        <div style={{
          padding: '10px 14px', borderRadius: 8, border: '1px solid var(--line)',
          background: 'var(--cardBg)', fontSize: 11,
        }}>
          <div style={{ fontWeight: 700, marginBottom: 4 }}>{findResult.display_name}</div>
          <div style={{ color: 'var(--muted)', fontSize: 10 }}>
            ✅ {t('alreadyConnected') || 'You are already connected or have a pending invite with this merchant.'}
          </div>
        </div>
      )}

      {findStatus === 'found' && findResult && (
        <div style={{
          padding: '12px 14px', borderRadius: 8, border: '1px solid var(--brand)',
          background: 'var(--cardBg)',
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 8 }}>
            <div>
              <div style={{ fontWeight: 800, fontSize: 13 }}>{findResult.display_name}</div>
              <div style={{ fontSize: 10, color: 'var(--muted)', marginTop: 2 }}>
                @{findResult.nickname} · {t('code') || 'Code'}: <span className="mono" style={{ fontWeight: 700 }}>{(findResult as any).merchant_code || '—'}</span>
              </div>
              {findResult.region && (
                <div style={{ fontSize: 10, color: 'var(--muted)', marginTop: 2 }}>📍 {findResult.region}</div>
              )}
              {findResult.bio && (
                <div style={{ fontSize: 10, color: 'var(--muted)', marginTop: 2 }}>{findResult.bio}</div>
              )}
              <div style={{ fontSize: 9, color: 'var(--muted)', marginTop: 4 }}>
                {t('memberSince') || 'Member since'}: {new Date(findResult.created_at).toLocaleDateString()}
              </div>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6, alignItems: 'flex-end' }}>
              <div className="inputBox" style={{ maxWidth: 220, padding: '4px 8px' }}>
                <input
                  placeholder={t('addANote') || 'Add a note (optional)...'}
                  value={inviteMessage}
                  onChange={e => setInviteMessage(e.target.value)}
                  style={{ fontSize: 10 }}
                />
              </div>
              <button
                className="btn"
                onClick={handleSendInvite}
                disabled={sendingInvite}
                style={{ fontSize: 11 }}
              >
                📨 {sendingInvite ? (t('loading') || '...') : (t('sendInvite') || 'Send Invite')}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── TAB BAR ─── */}
      <div style={{ display: 'flex', gap: 0, borderBottom: '1px solid var(--line)', marginBottom: 2 }}>
        {tabs.map(({ key, label, icon, badge }) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            style={{
              padding: '9px 18px', fontSize: 11, fontWeight: tab === key ? 700 : 500,
              color: tab === key ? 'var(--brand)' : 'var(--muted)',
              borderBottom: tab === key ? '2px solid var(--brand)' : '2px solid transparent',
              background: 'transparent', border: 'none', borderBottomStyle: 'solid', cursor: 'pointer',
              transition: 'all 0.15s', letterSpacing: '.2px',
              display: 'flex', alignItems: 'center', gap: 4,
            }}
          >
            {icon} {label}
            {badge != null && badge > 0 && (
              <span style={{
                fontSize: 9, fontWeight: 700, background: 'var(--bad)',
                color: '#fff', borderRadius: 10, padding: '1px 6px',
                minWidth: 16, textAlign: 'center',
              }}>
                {badge}
              </span>
            )}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="empty">
          <div className="empty-t">{t('loading') || 'Loading...'}</div>
        </div>
      ) : (
        <>
          {/* ═══ MY NETWORK TAB ═══ */}
          {tab === 'network' && (
            <>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                <div>
                  <div style={{ fontSize: 12, fontWeight: 700 }}>{t('myNetwork') || 'My Network'}</div>
                  <div style={{ fontSize: 10, color: 'var(--muted)' }}>{filteredRels.length} {t('connections') || 'connections'}</div>
                </div>
              </div>

              {filteredRels.length === 0 ? (
                <div className="empty">
                  <div className="empty-t">{t('noConnections') || 'No connections yet'}</div>
                  <div className="empty-s">{t('sendInviteToConnect') || 'Find a merchant above to connect'}</div>
                </div>
              ) : (
                <div className="tableWrap">
                  <table>
                    <thead>
                      <tr>
                        <th>{t('merchant') || 'Merchant'}</th>
                        <th>{t('code') || 'Code'}</th>
                        <th>{t('status')}</th>
                        <th className="r">{t('deals')}</th>
                        <th className="r">{t('exposure') || 'Exposure'}</th>
                        <th>{t('since') || 'Since'}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredRels.map(r => {
                        const relDeals = deals.filter(d => d.relationship_id === r.id);
                        const activeExp = relDeals.filter(d => d.status === 'active').reduce((s: number, d: any) => s + d.amount, 0);
                        return (
                          <tr key={r.id}>
                            <td>
                              <div style={{ fontWeight: 700, fontSize: 11 }}>{r.counterparty_name}</div>
                              <div style={{ fontSize: 9, color: 'var(--muted)' }}>@{r.counterparty_nickname}</div>
                            </td>
                            <td className="mono" style={{ fontSize: 10, fontWeight: 700 }}>{r.counterparty_code || '—'}</td>
                            <td>{statusPill(r.status)}</td>
                            <td className="mono r">{relDeals.length}</td>
                            <td className="mono r">{fmtU(activeExp)} USDT</td>
                            <td className="mono" style={{ fontSize: 10 }}>{new Date(r.created_at).toLocaleDateString()}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              )}
            </>
          )}

          {/* ═══ DEALS TAB ═══ */}
          {tab === 'deals' && (
            <>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                <div>
                  <div style={{ fontSize: 12, fontWeight: 700 }}>{t('deals')}</div>
                  <div style={{ fontSize: 10, color: 'var(--muted)' }}>{filteredDeals.length} {t('total') || 'total'}</div>
                </div>
              </div>

              {filteredDeals.length === 0 ? (
                <div className="empty">
                  <div className="empty-t">{t('noDeals') || 'No deals yet'}</div>
                  <div className="empty-s">{t('createDealFromMerchants') || 'Create deals from The Merchants page'}</div>
                </div>
              ) : (
                <div className="tableWrap">
                  <table>
                    <thead>
                      <tr>
                        <th>{t('title') || 'Title'}</th>
                        <th>{t('merchant') || 'Merchant'}</th>
                        <th>{t('type') || 'Type'}</th>
                        <th className="r">{t('amount')}</th>
                        <th>{t('status')}</th>
                        <th>{t('date')}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredDeals.map((d: any) => (
                        <tr key={d.id}>
                          <td style={{ fontWeight: 700, fontSize: 11 }}>{d.title}</td>
                          <td style={{ fontSize: 10 }}>{d.counterparty_name}</td>
                          <td style={{ fontSize: 10 }}>{dealTypeLabel(d.deal_type)}</td>
                          <td className="mono r">{fmtU(d.amount)} {d.currency}</td>
                          <td>{statusPill(d.status)}</td>
                          <td className="mono" style={{ fontSize: 10 }}>{new Date(d.created_at).toLocaleDateString()}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </>
          )}

          {/* ═══ INBOX TAB ═══ */}
          {tab === 'inbox' && (
            <>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                <div>
                  <div style={{ fontSize: 12, fontWeight: 700 }}>{t('inbox') || 'Inbox'}</div>
                  <div style={{ fontSize: 10, color: 'var(--muted)' }}>{t('pendingActions') || 'Pending invitations & actions'}</div>
                </div>
              </div>

              {/* Incoming invites */}
              {invites.filter(i => i.is_incoming).length === 0 ? (
                <div className="empty">
                  <div className="empty-t">{t('noInboxItems') || 'No pending items'}</div>
                  <div className="empty-s">{t('inboxEmpty') || 'Your inbox is empty'}</div>
                </div>
              ) : (
                <div className="tableWrap">
                  <table>
                    <thead>
                      <tr>
                        <th>{t('fromLabel') || 'From'}</th>
                        <th>{t('message') || 'Message'}</th>
                        <th>{t('status')}</th>
                        <th>{t('date')}</th>
                        <th>{t('actions')}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {invites.filter(i => i.is_incoming).map(inv => (
                        <tr key={inv.id}>
                          <td style={{ fontWeight: 700, fontSize: 11 }}>{inv.from_name}</td>
                          <td style={{ fontSize: 10, color: 'var(--muted)', maxWidth: 200, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            {inv.message || '—'}
                          </td>
                          <td>{statusPill(inv.status)}</td>
                          <td className="mono" style={{ fontSize: 10 }}>{new Date(inv.created_at).toLocaleDateString()}</td>
                          <td>
                            {inv.status === 'pending' && (
                              <div style={{ display: 'flex', gap: 4 }}>
                                <button className="rowBtn" onClick={() => handleAcceptInvite(inv)}>
                                  ✓ {t('accept') || 'Accept'}
                                </button>
                                <button className="rowBtn" onClick={() => handleRejectInvite(inv.id)}>
                                  ✗ {t('reject') || 'Reject'}
                                </button>
                              </div>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}

              {/* Sent invites */}
              {invites.filter(i => !i.is_incoming).length > 0 && (
                <>
                  <div style={{ fontSize: 11, fontWeight: 700, marginTop: 12, marginBottom: 4 }}>
                    📤 {t('sentInvites') || 'Sent Invitations'}
                  </div>
                  <div className="tableWrap">
                    <table>
                      <thead>
                        <tr>
                          <th>{t('toLabel') || 'To'}</th>
                          <th>{t('message') || 'Message'}</th>
                          <th>{t('status')}</th>
                          <th>{t('date')}</th>
                          <th>{t('actions')}</th>
                        </tr>
                      </thead>
                      <tbody>
                        {invites.filter(i => !i.is_incoming).map(inv => (
                          <tr key={inv.id}>
                            <td style={{ fontWeight: 700, fontSize: 11 }}>{inv.to_name}</td>
                            <td style={{ fontSize: 10, color: 'var(--muted)' }}>{inv.message || '—'}</td>
                            <td>{statusPill(inv.status)}</td>
                            <td className="mono" style={{ fontSize: 10 }}>{new Date(inv.created_at).toLocaleDateString()}</td>
                            <td>
                              {inv.status === 'pending' && (
                                <button className="rowBtn" onClick={() => handleWithdrawInvite(inv.id)}>
                                  ↩ {t('withdraw') || 'Withdraw'}
                                </button>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </>
              )}
            </>
          )}
        </>
      )}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Bell, CheckCheck, Handshake, Mail, ShieldCheck, Package,
  Zap, Clock, ArrowRight, Sparkles, Search, Trash2, Filter,
  ChevronDown, X,
} from 'lucide-react';
import { formatDistanceToNow, isToday, isYesterday, format } from 'date-fns';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import {
  useNotifications,
  useMarkNotificationRead,
  useMarkAllRead,
  type Notification,
} from '@/hooks/useNotifications';
import { handleNotificationClick } from '@/lib/notification-router';
import { normalizeNotificationCategory } from '@/types/notifications';
import { smartGroupNotifications, type SmartNotification } from '@/lib/notification-grouping';
import { useT } from '@/lib/i18n';

// ─── Category Config ────────────────────────────────────────────────
type CategoryKey = 'all' | 'deal' | 'order' | 'invite' | 'approval' | 'system';

const CATEGORY_KEYS: { key: CategoryKey; labelKey: string; icon: React.ComponentType<{ className?: string }>; color: string; bg: string }[] = [
  { key: 'all', labelKey: 'notifAllActivity', icon: Sparkles, color: 'text-primary', bg: 'bg-primary/10' },
  { key: 'deal', labelKey: 'notifDeals', icon: Handshake, color: 'text-accent', bg: 'bg-accent/10' },
  { key: 'order', labelKey: 'orders', icon: Package, color: 'text-warning', bg: 'bg-warning/10' },
  { key: 'invite', labelKey: 'notifInvites', icon: Mail, color: 'text-primary', bg: 'bg-primary/10' },
  { key: 'approval', labelKey: 'notifApprovals', icon: ShieldCheck, color: 'text-success', bg: 'bg-success/10' },
  { key: 'system', labelKey: 'notifSystem', icon: Zap, color: 'text-muted-foreground', bg: 'bg-muted' },
];

const categoryMeta: Record<string, { icon: React.ComponentType<{ className?: string }>; color: string; bg: string; gradient: string }> = {
  deal: { icon: Handshake, color: 'text-accent', bg: 'bg-accent/10', gradient: 'from-accent/20 to-transparent' },
  order: { icon: Package, color: 'text-warning', bg: 'bg-warning/10', gradient: 'from-warning/20 to-transparent' },
  invite: { icon: Mail, color: 'text-primary', bg: 'bg-primary/10', gradient: 'from-primary/20 to-transparent' },
  network: { icon: Mail, color: 'text-primary', bg: 'bg-primary/10', gradient: 'from-primary/20 to-transparent' },
  approval: { icon: ShieldCheck, color: 'text-success', bg: 'bg-success/10', gradient: 'from-success/20 to-transparent' },
  merchant: { icon: Handshake, color: 'text-accent', bg: 'bg-accent/10', gradient: 'from-accent/20 to-transparent' },
  system: { icon: Zap, color: 'text-muted-foreground', bg: 'bg-muted', gradient: 'from-muted to-transparent' },
};

// ─── Group by day ───────────────────────────────────────────────────
function groupByDay(items: Notification[], t: any): { label: string; items: Notification[] }[] {
  const groups = new Map<string, Notification[]>();
  for (const n of items) {
    const d = new Date(n.created_at);
    let label: string;
    if (isToday(d)) label = t('notifToday');
    else if (isYesterday(d)) label = t('notifYesterday');
    else label = format(d, 'EEEE, MMM d');
    const existing = groups.get(label) || [];
    existing.push(n);
    groups.set(label, existing);
  }
  return Array.from(groups.entries()).map(([label, items]) => ({ label, items }));
}


// ─── Notification Card ──────────────────────────────────────────────
function NotificationCard({
  n,
  onNavigate,
  onMarkRead,
  t,
}: {
  n: SmartNotification;
  onNavigate: (n: Notification) => void;
  onMarkRead: (id: string) => void;
  t: (key: string) => string;
}) {
  const meta = categoryMeta[n.category] ?? categoryMeta.system;
  const Icon = meta.icon;
  const isUnread = !n.read_at;
  const isAdminPriority = n.category === 'system' || n.category === 'approval' || n.category === 'invite';

  return (
    <div
      className={cn(
        'group relative flex items-start gap-4 p-4 rounded-xl transition-all cursor-pointer border',
        isAdminPriority && isUnread
          ? 'bg-destructive/[0.04] border-destructive/20 shadow-sm shadow-destructive/5 hover:shadow-md hover:border-destructive/30'
          : isUnread
          ? 'bg-card border-primary/15 shadow-sm hover:shadow-md hover:border-primary/25'
          : 'bg-card/50 border-border/50 hover:bg-card hover:border-border'
      )}
      onClick={() => onNavigate(n)}
    >
      {/* Timeline connector dot */}
      {isUnread && (
        <div className="absolute -left-[29px] top-5 hidden lg:flex">
          <span className="relative flex h-3 w-3">
            <span className={cn('animate-ping absolute inline-flex h-full w-full rounded-full opacity-40', isAdminPriority ? 'bg-destructive' : 'bg-primary')} />
            <span className={cn('relative inline-flex rounded-full h-3 w-3 border-2 border-background', isAdminPriority ? 'bg-destructive' : 'bg-primary')} />
          </span>
        </div>
      )}
      {!isUnread && (
        <div className="absolute -left-[27px] top-6 hidden lg:flex h-2 w-2 rounded-full bg-border" />
      )}

      {/* Category icon */}
      <div className={cn(
        'flex h-10 w-10 shrink-0 items-center justify-center rounded-xl transition-transform group-hover:scale-110',
        isAdminPriority ? 'bg-destructive/10' : meta.bg
      )}>
        <Icon className={cn('h-5 w-5', isAdminPriority ? 'text-destructive' : meta.color)} />
      </div>

      {/* Content */}
      <div className="flex-1 min-w-0">
        <div className="flex items-start justify-between gap-3">
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
              {isUnread && <span className={cn('h-2 w-2 rounded-full shrink-0', isAdminPriority ? 'bg-destructive' : 'bg-primary')} />}
              {isAdminPriority && isUnread && (
                <span className="shrink-0 text-[8px] font-black uppercase tracking-wider bg-destructive text-destructive-foreground px-1.5 py-0.5 rounded">
                  ⚡ {t('priority') || 'PRIORITY'}
                </span>
              )}
              {n.groupCount && n.groupCount > 1 && (
                <span className="shrink-0 text-[8px] font-black bg-primary/15 text-primary px-1.5 py-0.5 rounded">
                  ×{n.groupCount} {t('messages') || 'messages'}
                </span>
              )}
              <h4 className={cn(
                'text-sm leading-tight truncate',
                isUnread ? 'font-bold text-foreground' : 'font-medium text-muted-foreground'
              )}>
                {n.title}
              </h4>
            </div>
            {n.body && (
              <p className="text-[12px] text-muted-foreground/70 leading-relaxed mt-1 line-clamp-2">
                {n.body}
              </p>
            )}
          </div>
          <ArrowRight className="h-4 w-4 text-muted-foreground/30 mt-0.5 opacity-0 group-hover:opacity-100 transition-all group-hover:translate-x-0.5 shrink-0" />
        </div>

        <div className="flex items-center gap-3 mt-2">
          <div className="flex items-center gap-1">
            <Clock className="h-3 w-3 text-muted-foreground/40" />
            <span className="text-[10px] text-muted-foreground/50 font-medium">
              {formatDistanceToNow(new Date(n.created_at), { addSuffix: true })}
            </span>
          </div>
          <span className={cn(
            'text-[9px] font-bold uppercase tracking-wider px-2 py-0.5 rounded-md',
            isAdminPriority ? 'bg-destructive/10 text-destructive' : cn(meta.bg, meta.color)
          )}>
            {n.category}
          </span>
          {isUnread && (
            <button
              onClick={(e) => { e.stopPropagation(); onMarkRead(n.id); }}
              className="ml-auto text-[10px] text-muted-foreground/50 hover:text-foreground font-medium transition-colors"
            >
              {t('markRead')}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── Main Page ──────────────────────────────────────────────────────
export default function NotificationsPage() {
  const navigate = useNavigate();
  const t = useT();
  const { data: notifications, isLoading, unreadCount } = useNotifications();
  const markRead = useMarkNotificationRead();
  const markAllRead = useMarkAllRead();

  const [activeCategory, setActiveCategory] = useState<CategoryKey>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [showUnreadOnly, setShowUnreadOnly] = useState(false);

  const filtered = useMemo(() => {
    let items = notifications ?? [];

    if (activeCategory !== 'all') {
      items = items.filter(n => normalizeNotificationCategory(n.category) === activeCategory);
    }

    if (showUnreadOnly) {
      items = items.filter(n => !n.read_at);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      items = items.filter(n =>
        n.title.toLowerCase().includes(q) ||
        (n.body ?? '').toLowerCase().includes(q)
      );
    }

    return items;
  }, [notifications, activeCategory, showUnreadOnly, searchQuery]);

  const smartFiltered = useMemo(() => smartGroupNotifications(filtered), [filtered]);
  const grouped = useMemo(() => groupByDay(smartFiltered, t), [smartFiltered, t]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    for (const n of (notifications ?? [])) {
      if (!n.read_at) {
        const cat = normalizeNotificationCategory(n.category);
        counts[cat] = (counts[cat] || 0) + 1;
      }
    }
    return counts;
  }, [notifications]);

  const handleNavigate = (n: Notification) => {
    if (!n.read_at) markRead.mutate(n.id);
    handleNotificationClick(n, navigate);
  };

  return (
    <div className="min-h-full bg-background">
      {/* ── Hero Header ── */}
      <div className="relative overflow-hidden border-b border-border/50">
        <div className="absolute inset-0 bg-gradient-to-br from-primary/[0.03] via-transparent to-accent/[0.03]" />
        <div className="relative px-4 sm:px-6 py-6">
          <div className="flex items-start justify-between gap-4">
            <div className="flex items-center gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-primary/10 shadow-sm">
                <Sparkles className="h-6 w-6 text-primary" />
              </div>
              <div>
                <h1 className="text-xl font-black text-foreground tracking-tight">{t('activityCenter')}</h1>
                <p className="text-[12px] text-muted-foreground mt-0.5 flex items-center gap-2">
                  <span className="relative flex h-2 w-2">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-success opacity-60" />
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-success" />
                  </span>
                  {t('realTimeUpdates')} · {(notifications ?? []).length} {t('totalAlerts')}
                </p>
              </div>
            </div>
            {unreadCount > 0 && (
              <Button
                variant="outline"
                size="sm"
                className="gap-1.5 text-[11px] h-8 rounded-lg"
                onClick={() => markAllRead.mutate()}
                disabled={markAllRead.isPending}
              >
                <CheckCheck className="h-3.5 w-3.5" />
                {t('notifMarkAllRead')} ({unreadCount})
              </Button>
            )}
          </div>

          {/* ── Stats bar ── */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mt-5">
            {[
              { label: t('notifTotal'), value: (notifications ?? []).length, icon: Bell, color: 'text-foreground' },
              { label: t('notifUnread'), value: unreadCount, icon: Sparkles, color: unreadCount > 0 ? 'text-destructive' : 'text-muted-foreground' },
              { label: t('notifDeals'), value: (notifications ?? []).filter(n => normalizeNotificationCategory(n.category) === 'deal').length, icon: Handshake, color: 'text-accent' },
              { label: t('notifThisWeek'), value: (notifications ?? []).filter(n => Date.now() - new Date(n.created_at).getTime() < 7 * 86400000).length, icon: Clock, color: 'text-primary' },
            ].map(stat => (
              <div key={stat.label} className="flex items-center gap-2.5 p-3 rounded-xl bg-card/80 border border-border/50">
                <stat.icon className={cn('h-4 w-4', stat.color)} />
                <div>
                  <div className={cn('text-lg font-black leading-none', stat.color)}>{stat.value}</div>
                  <div className="text-[9px] font-semibold text-muted-foreground uppercase tracking-wider mt-0.5">{stat.label}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── Controls ── */}
      <div className="px-4 sm:px-6 py-4">
        <div className="flex flex-col sm:flex-row gap-3">
          {/* Search */}
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground/50" />
            <input
              type="text"
              placeholder={t('searchNotifications')}
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-9 py-2 rounded-lg border border-border/50 bg-card text-sm text-foreground placeholder:text-muted-foreground/40 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/30 transition-all"
            />
            {searchQuery && (
              <button
                onClick={() => setSearchQuery('')}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground/50 hover:text-foreground"
              >
                <X className="h-3.5 w-3.5" />
              </button>
            )}
          </div>

          {/* Unread toggle */}
          <button
            onClick={() => setShowUnreadOnly(!showUnreadOnly)}
            className={cn(
              'flex items-center gap-1.5 px-3 py-2 rounded-lg border text-[11px] font-semibold transition-all whitespace-nowrap',
              showUnreadOnly
                ? 'bg-primary text-primary-foreground border-primary'
                : 'bg-card border-border/50 text-muted-foreground hover:text-foreground hover:border-border'
            )}
          >
            <Filter className="h-3.5 w-3.5" />
            {t('unreadOnly')}
          </button>
        </div>

        {/* Category tabs */}
        <div className="flex gap-2 mt-3 overflow-x-auto scrollbar-hide pb-1">
          {CATEGORY_KEYS.map(cat => {
            const count = cat.key === 'all' ? unreadCount : (categoryCounts[cat.key] || 0);
            const isActive = activeCategory === cat.key;
            const CatIcon = cat.icon;
            return (
              <button
                key={cat.key}
                onClick={() => setActiveCategory(cat.key)}
                className={cn(
                  'flex items-center gap-1.5 px-3.5 py-2 rounded-xl text-[11px] font-semibold transition-all whitespace-nowrap shrink-0 border',
                  isActive
                    ? 'bg-primary text-primary-foreground border-primary shadow-sm shadow-primary/20'
                    : 'bg-card border-border/50 text-muted-foreground hover:text-foreground hover:border-border'
                )}
              >
                <CatIcon className="h-3.5 w-3.5" />
                {t(cat.labelKey as any)}
                {count > 0 && (
                  <span className={cn(
                    'flex h-[18px] min-w-[18px] items-center justify-center rounded-full px-1 text-[9px] font-black',
                    isActive
                      ? 'bg-primary-foreground/20 text-primary-foreground'
                      : 'bg-destructive/10 text-destructive'
                  )}>
                    {count}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* ── Timeline ── */}
      <div className="px-4 sm:px-6 pb-10">
        {isLoading ? (
          <div className="flex flex-col items-center py-20 gap-4">
            <div className="h-12 w-12 rounded-full border-2 border-primary/20 border-t-primary animate-spin" />
            <p className="text-sm text-muted-foreground font-medium">{t('loadingActivityFeed')}</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex flex-col items-center py-20 gap-4">
            <div className="flex h-20 w-20 items-center justify-center rounded-3xl bg-muted/50">
              {activeCategory === 'all' ? (
                <Bell className="h-8 w-8 text-muted-foreground/30" />
              ) : (
                (() => {
                  const CatIcon = CATEGORY_KEYS.find(c => c.key === activeCategory)?.icon ?? Bell;
                  return <CatIcon className="h-8 w-8 text-muted-foreground/30" />;
                })()
              )}
            </div>
            <div className="text-center">
              <h3 className="text-sm font-bold text-muted-foreground">
                {searchQuery ? t('noResultsFound') : showUnreadOnly ? t('noUnreadNotifications') : t('notifNoActivityYet')}
              </h3>
              <p className="text-[12px] text-muted-foreground/60 mt-1 max-w-[260px]">
                {searchQuery
                  ? `${t('noNotificationsMatch')} "${searchQuery}"`
                  : showUnreadOnly
                  ? t('allCaughtUp')
                  : t('createDealOrInvite')}
              </p>
            </div>
          </div>
        ) : (
          <div className="relative">
            {/* Timeline line */}
            <div className="absolute left-0 top-0 bottom-0 w-px bg-border/50 hidden lg:block" style={{ left: '15px' }} />

            <div className="space-y-6 lg:pl-10">
              {grouped.map(group => (
                <div key={group.label}>
                  {/* Day header */}
                  <div className="flex items-center gap-3 mb-3 relative">
                    <div className="absolute -left-10 hidden lg:flex h-7 w-7 items-center justify-center rounded-full bg-card border-2 border-border">
                      <span className="text-[9px] font-black text-muted-foreground">
                        {group.label === t('notifToday') ? '🔥' : group.label === t('notifYesterday') ? '📅' : '📆'}
                      </span>
                    </div>
                    <h3 className="text-[11px] font-black uppercase tracking-widest text-muted-foreground/60">
                      {group.label}
                    </h3>
                    <div className="h-px flex-1 bg-border/30" />
                    <span className="text-[10px] font-semibold text-muted-foreground/40">
                      {group.items.length} {t('notifItems')}
                    </span>
                  </div>

                  {/* Cards */}
                  <div className="space-y-2">
                    {(group.items as SmartNotification[]).map(n => (
                      <NotificationCard
                        key={n.id}
                        n={n}
                        t={t as any}
                        onNavigate={handleNavigate}
                        onMarkRead={(id) => markRead.mutate(id)}
                      />
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';
import { useAuth } from '@/features/auth/auth-context';
import { supabase } from '@/integrations/supabase/client';
import { MerchantNetworkSelector } from '@/components/orders/import/MerchantNetworkSelector';
import { ImportPreviewTable } from '@/components/orders/import/ImportPreviewTable';
import { ImportSourceTabs } from '@/components/orders/import/ImportSourceTabs';
import type { LedgerNetworkMerchant, LedgerParseRow, LedgerSourceType } from '@/types/ledgerImport';
import { parseLedgerText } from '@/services/ledgerImport/parser';
import { readTextFile, validateTextFile } from '@/services/ledgerImport/fileReaders/textFileReader';
import { readSpreadsheet, validateSpreadsheetFile } from '@/services/ledgerImport/fileReaders/spreadsheetReader';
import { assessOcrTextQuality, extractTextFromImage, type OcrExtractionResult, validateImageFile } from '@/services/ledgerImport/fileReaders/imageReader';
import { buildNetworkMerchants } from '@/services/ledgerImport/network';
import { canSaveImportedRows } from '@/services/ledgerImport/guards';

interface ParseInput {
  text: string;
  sourceType: LedgerSourceType;
  sourceFileName?: string | null;
  confidencePenalty?: number;
}

export default function OrdersImportLedgerPage() {
  const navigate = useNavigate();
  const { userId, merchantProfile } = useAuth();

  const [sourceType, setSourceType] = useState<LedgerSourceType>('pasted_text');
  const [rawText, setRawText] = useState('');
  const [files, setFiles] = useState<File[]>([]);
  const [sheetName, setSheetName] = useState('');
  const [sheetNames, setSheetNames] = useState<string[]>([]);
  const [imagePreviewUrls, setImagePreviewUrls] = useState<string[]>([]);
  const [ocrStatus, setOcrStatus] = useState('Idle');
  const [ocrWarning, setOcrWarning] = useState<string | null>(null);
  const [ocrMetadata, setOcrMetadata] = useState<Record<string, unknown>[]>([]);
  const [extractedImageText, setExtractedImageText] = useState('');
  const [merchants, setMerchants] = useState<LedgerNetworkMerchant[]>([]);
  const [selectedRelationshipId, setSelectedRelationshipId] = useState('');
  const [rows, setRows] = useState<LedgerParseRow[]>([]);
  const [batchId, setBatchId] = useState('');
  const [isParsing, setIsParsing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const selectedMerchant = merchants.find((m) => m.relationshipId === selectedRelationshipId) || null;

  useEffect(() => {
    const loadNetworkMerchants = async () => {
      if (!merchantProfile?.merchant_id) return;
      const myMerchantId = merchantProfile.merchant_id;
      const [relRes, profileRes] = await Promise.all([
        supabase
          .from('merchant_relationships')
          .select('id, merchant_a_id, merchant_b_id')
          .eq('status', 'active')
          .or(`merchant_a_id.eq.${myMerchantId},merchant_b_id.eq.${myMerchantId}`),
        supabase.from('merchant_profiles').select('merchant_id, display_name, nickname, merchant_code'),
      ]);

      if (relRes.error || profileRes.error) {
        toast.error('Failed to load network merchants.');
        return;
      }

      const networkMerchants = buildNetworkMerchants(myMerchantId, relRes.data || [], profileRes.data || []);
      setMerchants(networkMerchants);
      if (networkMerchants.length === 1) setSelectedRelationshipId(networkMerchants[0].relationshipId);
    };

    loadNetworkMerchants();
  }, [merchantProfile?.merchant_id]);

  useEffect(() => {
    if (!selectedMerchant) {
      setRows([]);
      return;
    }
    setRows((prev) => prev.map((row) => ({
      ...row,
      selectedMerchantId: selectedMerchant.merchantId,
      selectedMerchantName: selectedMerchant.merchantName,
      saveEnabled: row.status === 'parsed' && row.parsedType === 'merchant_deal',
    })));
  }, [selectedMerchant]);

  useEffect(() => {
    if (sourceType !== 'image') {
      setImagePreviewUrls([]);
      setExtractedImageText('');
      setOcrWarning(null);
      setOcrMetadata([]);
      setOcrStatus('Idle');
    }
  }, [sourceType]);

  const saveableRows = useMemo(() => rows.filter((row) => row.status === 'parsed' && row.parsedType === 'merchant_deal' && row.saveEnabled), [rows]);
  const saveAllowed = canSaveImportedRows(userId, selectedRelationshipId, rows) && !(sourceType === 'image' && !!ocrWarning);

  const validateFile = (nextFile: File): string | null => {
    if (sourceType === 'text_file') return validateTextFile(nextFile);
    if (sourceType === 'spreadsheet') return validateSpreadsheetFile(nextFile);
    if (sourceType === 'image') return validateImageFile(nextFile);
    return null;
  };

  const parseInputs = (inputs: ParseInput[]) => {
    if (!userId || !selectedMerchant) {
      toast.error('Select a network merchant before parsing.');
      return;
    }

    const seen = new Set<string>();
    const merged: LedgerParseRow[] = [];

    inputs.forEach((input, idx) => {
      console.debug('[ledger-import:parse] source', input.sourceType, input.sourceFileName || 'manual');
      const parsed = parseLedgerText(input.text, {
        uploaderUserId: userId,
        selectedMerchantId: selectedMerchant.merchantId,
        selectedMerchantName: selectedMerchant.merchantName,
        sourceType: input.sourceType,
        sourceFileName: input.sourceFileName,
        lineOffset: idx * 100000,
        confidencePenalty: input.confidencePenalty ?? 0,
      });

      parsed.rows.forEach((row) => {
        if (seen.has(row.normalizedHash)) {
          merged.push({ ...row, status: 'skipped', parseResult: 'Skipped', skipReason: 'Duplicate line in batch', saveEnabled: false });
          return;
        }
        seen.add(row.normalizedHash);
        merged.push(row);
      });
    });

    setBatchId(crypto.randomUUID());
    setRows(merged);
    toast.success(`Parsed ${merged.filter((r) => r.status === 'parsed').length} supported rows. ${merged.filter((r) => r.status === 'skipped').length} skipped.`);
  };

  const runImageOcr = async () => {
    if (files.length === 0) {
      toast.error('Please select photos first.');
      return;
    }

    setOcrStatus('Running OCR...');
    setOcrWarning(null);
    const ocrLines: string[] = [];
    const meta: Record<string, unknown>[] = [];

    try {
      for (const file of files) {
        const ocr: OcrExtractionResult = await extractTextFromImage(file);
        if (ocr.text.trim()) ocrLines.push(ocr.text.trim());
        if (ocr.warning) setOcrWarning(ocr.warning);
        meta.push({ file: file.name, ...(ocr.metadata || {}), engine: ocr.engine });
      }
      setExtractedImageText(ocrLines.join('\n'));
      setOcrMetadata(meta);
      setOcrStatus(`OCR complete for ${files.length} image(s)`);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : 'OCR failed.';
      setOcrWarning(message);
      setOcrStatus('OCR failed');
      toast.error(message);
    }
  };

  const handleParse = async () => {
    if (!selectedMerchant) {
      toast.error('Counterparty merchant must be selected from your network.');
      return;
    }

    setIsParsing(true);
    try {
      if (sourceType === 'pasted_text') {
        parseInputs([{ text: rawText, sourceType: 'pasted_text' }]);
        return;
      }

      if (files.length === 0) {
        toast.error('Please select file(s) first.');
        return;
      }

      for (const file of files) {
        const fileValidation = validateFile(file);
        if (fileValidation) {
          toast.error(`${file.name}: ${fileValidation}`);
          return;
        }
      }

      if (sourceType === 'text_file') {
        const inputs: ParseInput[] = [];
        for (const file of files) {
          const text = await readTextFile(file);
          inputs.push({ text, sourceType: 'text_file', sourceFileName: file.name });
        }
        parseInputs(inputs);
        return;
      }

      if (sourceType === 'spreadsheet') {
        const inputs: ParseInput[] = [];
        const sheetSet = new Set<string>();
        for (const file of files) {
          const workbook = await readSpreadsheet(file);
          workbook.sheets.forEach((s) => sheetSet.add(s));
          inputs.push({ text: workbook.lines.join('\n'), sourceType: 'spreadsheet', sourceFileName: file.name });
        }
        setSheetNames(Array.from(sheetSet));
        if (!sheetName && sheetSet.size > 0) setSheetName(Array.from(sheetSet)[0]);
        parseInputs(inputs);
        return;
      }

      if (sourceType === 'image') {
        const quality = assessOcrTextQuality(extractedImageText);
        if (!extractedImageText.trim()) {
          toast.error('No OCR text found. Run OCR first or enter text manually.');
          return;
        }
        if (!quality.isValid) {
          setOcrWarning(quality.reason || 'Low quality OCR output');
          toast.error('OCR output quality is low. Please correct extracted text before parsing.');
          return;
        }
        parseInputs([{ text: extractedImageText, sourceType: 'image', sourceFileName: files.map((f) => f.name).join(','), confidencePenalty: 0.15 }]);
      }
    } catch (error: unknown) {
      toast.error(error instanceof Error ? error.message : 'Failed to parse import source.');
    } finally {
      setIsParsing(false);
    }
  };

  const handleSave = async () => {
    if (!userId || !selectedMerchant) {
      toast.error('User and merchant context are required before saving.');
      return;
    }
    if (saveableRows.length === 0) {
      toast.error('No supported merchant_deal rows to save.');
      return;
    }

    setIsSaving(true);
    try {
      const { data: existingImports } = await supabase
        .from('merchant_deals')
        .select('metadata')
        .eq('relationship_id', selectedMerchant.relationshipId)
        .eq('created_by', userId)
        .eq('metadata->>import_source', 'manual_ledger_import')
        .limit(1000);

      const existingHashes = new Set((existingImports || []).map((deal: any) => deal.metadata?.normalized_hash).filter(Boolean));

      const payload = saveableRows
        .filter((row) => !existingHashes.has(row.normalizedHash))
        .map((row) => ({
          relationship_id: selectedMerchant.relationshipId,
          deal_type: 'arbitrage',
          title: `Ledger Import · USDT ${row.usdtAmount} @ ${row.rate}`,
          amount: row.computedQarAmount || 0,
          currency: 'USDT',
          status: 'pending',
          created_by: userId,
          notes: [
            'template: ledger_import_phase_1',
            `quantity: ${row.usdtAmount}`,
            `sell_price: ${row.rate}`,
            `direction: ${row.direction}`,
            `import_source: manual_ledger_import`,
            `source_file_name: ${row.sourceFileName || ''}`,
            `import_batch_id: ${batchId}`,
            `raw_line: ${row.rawLine}`,
            `intermediary: ${row.intermediary || ''}`,
            `parse_confidence: ${row.confidence}`,
          ].join(' | '),
          metadata: {
            import_source: 'manual_ledger_import',
            source_file_name: row.sourceFileName,
            import_batch_id: batchId,
            normalized_hash: row.normalizedHash,
            raw_line: row.rawLine,
            intermediary: row.intermediary,
            parse_confidence: row.confidence,
            direction: row.direction,
            uploader_user_id: row.uploaderUserId,
            counterparty_merchant_id: row.selectedMerchantId,
            counterparty_merchant_name: row.selectedMerchantName,
            source_type: row.sourceType,
          },
        }));

      if (payload.length === 0) {
        toast.error('All supported rows appear to be duplicates.');
        return;
      }

      const { error } = await supabase.from('merchant_deals').insert(payload);
      if (error) throw error;
      toast.success(`Saved ${payload.length} row(s).`);
      navigate('/trading/orders');
    } catch (error: unknown) {
      toast.error(error instanceof Error ? error.message : 'Save failed.');
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="tracker-root" style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ fontSize: 14, fontWeight: 800 }}>Import Merchant Ledger</div>
        <button className="btn secondary" onClick={() => navigate('/trading/orders')}>Back to Orders</button>
      </div>

      <ImportSourceTabs value={sourceType} onChange={setSourceType} />

      <div className="card" style={{ padding: 10, display: 'grid', gap: 8 }}>
        <MerchantNetworkSelector merchants={merchants} selectedRelationshipId={selectedRelationshipId} onSelect={setSelectedRelationshipId} />

        {sourceType === 'pasted_text' && (
          <textarea value={rawText} onChange={(e) => setRawText(e.target.value)} rows={8} className="inp" placeholder="الصق النص هنا" />
        )}

        {sourceType !== 'pasted_text' && (
          <>
            <input
              className="inp"
              type="file"
              multiple
              accept={sourceType === 'image' ? '.png,.jpg,.jpeg,.webp' : sourceType === 'spreadsheet' ? '.xlsx,.xls,.csv' : '.txt,.md,.csv'}
              onChange={(e) => {
                const selected = Array.from(e.target.files || []);
                if (selected.length === 0) return;
                for (const file of selected) {
                  const validation = validateFile(file);
                  if (validation) {
                    toast.error(`${file.name}: ${validation}`);
                    return;
                  }
                }
                setFiles(selected);
                setRows([]);
                if (sourceType === 'image') {
                  setImagePreviewUrls(selected.map((file) => URL.createObjectURL(file)));
                  setExtractedImageText('');
                  setOcrWarning(null);
                  setOcrMetadata([]);
                  setOcrStatus(`${selected.length} image(s) selected`);
                }
              }}
            />
            {files.length > 0 && <div className="pill">Selected: {files.length} file(s)</div>}
          </>
        )}

        {sourceType === 'spreadsheet' && sheetNames.length > 1 && (
          <select className="inp" value={sheetName} onChange={(e) => setSheetName(e.target.value)}>
            {sheetNames.map((name) => <option key={name} value={name}>{name}</option>)}
          </select>
        )}

        {sourceType === 'image' && (
          <div style={{ display: 'grid', gap: 8 }}>
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
              {imagePreviewUrls.map((url) => <img key={url} src={url} alt="Selected upload" style={{ maxWidth: 140, borderRadius: 8, border: '1px solid var(--line)' }} />)}
            </div>
            <div className="pill">OCR status: {ocrStatus}</div>
            {ocrWarning && <div className="pill bad">{ocrWarning}</div>}
            {ocrMetadata.length > 0 && <div className="pill">OCR meta: {JSON.stringify(ocrMetadata)}</div>}
            <label style={{ fontSize: 11, color: 'var(--muted)' }}>Extracted text from image(s)</label>
            <textarea className="inp" rows={8} value={extractedImageText} onChange={(e) => setExtractedImageText(e.target.value)} placeholder="OCR output appears here. You can edit before parse." />
            <div style={{ display: 'flex', gap: 8 }}>
              <button className="btn secondary" onClick={runImageOcr} disabled={files.length === 0}>Run OCR</button>
              <button className="btn" onClick={handleParse} disabled={isParsing || !extractedImageText.trim()}>Parse extracted text</button>
            </div>
          </div>
        )}

        {sourceType !== 'image' && <button className="btn" onClick={handleParse} disabled={isParsing || merchants.length === 0}>{isParsing ? 'Parsing...' : 'Parse'}</button>}

        <button className="btn" onClick={handleSave} disabled={isSaving || !saveAllowed || !selectedMerchant}>{isSaving ? 'Saving...' : `Confirm & Save (${saveableRows.length})`}</button>
      </div>

      <ImportPreviewTable rows={rows} />
    </div>
  );
}

