        return { ...d, counterparty_name: (rel as any)?.counterparty_name || '—' } as any as MerchantDeal;
      });
      setAllMerchantDeals(enrichedDeals);

      // Fetch capital transfers across all relationships
      const transferResults = await Promise.all(
