                  </label>

                  <div className="field2" style={{ marginBottom: 10 }}>
                    <div className="lbl" style={{ color: 'var(--brand)', fontWeight: 700 }}>{t('selectPartner')} <span style={{ color: 'var(--bad)' }}>*</span></div>
