import { useState, useMemo } from 'react';
import { useT } from '@/lib/i18n';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { RefreshCw } from 'lucide-react';
import { format } from 'date-fns';

import { MarketId, MARKETS } from '@/features/p2p/types';
import { useP2PMarketData } from '@/features/p2p/hooks/useP2PMarketData';
import { computeFIFO, totalStock, getWACOP, stockCostQAR } from '@/lib/tracker-helpers';
import { getCurrentTrackerState } from '@/lib/tracker-backup';
import type { TrackerState } from '@/lib/tracker-helpers';
import { MarketKpiGrid } from '@/features/p2p/components/MarketKpiGrid';
import { PriceHistorySparklines } from '@/features/p2p/components/PriceHistorySparklines';
import { MerchantDepthStats } from '@/features/p2p/components/MerchantDepthStats';
import { P2POfferTable } from '@/features/p2p/components/P2POfferTable';

export default function P2PTrackerPage() {
  const t = useT();
  const [market, setMarket] = useState<MarketId>('qatar');
  const { snapshot, history, merchantStats, loading, latestFetchedAt, qatarRates, refresh } = useP2PMarketData(market);
  const currentMarket = MARKETS.find(m => m.id === market)!;

  const todaySummary = useMemo(() => {
    const todayStr = format(new Date(), 'yyyy-MM-dd');
    const todayPts = history.filter(h => format(new Date(h.ts), 'yyyy-MM-dd') === todayStr);
    if (!todayPts.length) return null;
    const sellPresent = todayPts.filter(p => p.sellAvg != null);
    const buyPresent = todayPts.filter(p => p.buyAvg != null);
    return {
      highSell: sellPresent.length ? Math.max(...sellPresent.map(p => p.sellAvg!)) : null,
      lowSell: sellPresent.length ? Math.min(...sellPresent.map(p => p.sellAvg!)) : null,
      highBuy: buyPresent.length ? Math.max(...buyPresent.map(p => p.buyAvg!)) : null,
      lowBuy: buyPresent.length ? Math.min(...buyPresent.map(p => p.buyAvg!)) : null,
    };
  }, [history]);

  const dataAgeLabel = useMemo(() => {
    if (!latestFetchedAt) return null;
    const ageMin = Math.floor((Date.now() - new Date(latestFetchedAt).getTime()) / 60000);
    if (ageMin < 1) return 'just now';
    if (ageMin < 60) return `${ageMin} min ago`;
    return `${Math.floor(ageMin / 60)}h ago`;
  }, [latestFetchedAt]);

  // ── Derive mid-rate helper ──────────────────────────────────────────────────
  const deriveMid = (s: number | null, b: number | null): number | null => {
    if (s != null && b != null && s > 0 && b > 0) return (s + b) / 2;
    return s ?? b ?? null;
  };

  const sellAvg = snapshot?.sellAvg ?? null;
  const buyAvg  = snapshot?.buyAvg  ?? null;

  // ── Profit if sold now in this market ──────────────────────────────────────
  const profitIfSold = useMemo(() => {
    try {
      const stateRaw = getCurrentTrackerState(localStorage);
      if (!stateRaw || !Array.isArray((stateRaw as any).batches) || !(stateRaw as any).batches.length) return null;
      const st = stateRaw as unknown as TrackerState;
      const derived = computeFIFO(st.batches, st.trades || []);
      const stock = totalStock(derived);
      if (stock <= 0) return null;
      const wacop = getWACOP(derived);
      const costBasis = stockCostQAR(derived);
      if (!wacop || wacop <= 0) return null;

      const localMid = deriveMid(sellAvg, buyAvg);
      const qatarMid = market === 'qatar'
        ? localMid
        : qatarRates ? deriveMid(qatarRates.sellAvg, qatarRates.buyAvg) : null;
      if (!localMid || localMid <= 0 || !qatarMid || qatarMid <= 0 || !sellAvg || sellAvg <= 0) return null;

      const localToUsd  = 1 / localMid;
      const qarToUsd    = 1 / qatarMid;
      const qarToLocal  = localMid / qatarMid;

      const costQAR        = costBasis;
      const costLocal      = costQAR * qarToLocal;
      const sellValueLocal = stock * sellAvg;
      const profitLocal    = sellValueLocal - costLocal;
      const profit         = profitLocal * localToUsd;

      return {
        stock, wacop, costQAR, costLocal,
        costBasisUSD: costQAR * qarToUsd,
        sellValueLocal, sellValueUSD: sellValueLocal * localToUsd,
        profitLocal, profit,
        fx: { localToUsd, qarToUsd, qarToLocal },
      };
    } catch { return null; }
  }, [sellAvg, buyAvg, market, qatarRates]);

  // ── Round-trip spread simulation ───────────────────────────────────────────
  const roundTripSim = useMemo(() => {
    if (!profitIfSold || !sellAvg || !buyAvg || sellAvg <= 0 || buyAvg <= 0) return null;
    const { qarToLocal, localToUsd } = profitIfSold.fx;
    if (!qarToLocal || !localToUsd || qarToLocal <= 0 || localToUsd <= 0) return null;

    const startingCapitalLocal = profitIfSold.costQAR * qarToLocal;
    if (startingCapitalLocal <= 0) return null;

    const boughtUSDT         = startingCapitalLocal / buyAvg;
    const finalLocal         = boughtUSDT * sellAvg;
    const roundTripProfitLocal = finalLocal - startingCapitalLocal;
    const profit             = roundTripProfitLocal * localToUsd;
    const pct                = (roundTripProfitLocal / startingCapitalLocal) * 100;

    return {
      startingCapitalLocal,
      startingCapitalUSD: startingCapitalLocal * localToUsd,
      finalLocal, finalUSD: finalLocal * localToUsd,
      boughtUSDT, profit,
      spreadRatio: sellAvg / buyAvg,
      pct,
    };
  }, [profitIfSold, sellAvg, buyAvg]);

  if (loading && (!snapshot || snapshot.sellAvg === null)) {
    return <div className="p-8 text-center text-muted-foreground">Loading market data...</div>;
  }

  // Handle "No data yet" state for new markets
  const hasNoData = !snapshot || (snapshot.sellAvg === null && snapshot.buyAvg === null && !history.length);

  return (
    <div className="space-y-2 p-2 md:p-3">
      <div className="flex flex-wrap items-center gap-2">
        <Tabs value={market} onValueChange={(v) => setMarket(v as MarketId)}>
          <TabsList>
            {MARKETS.map(m => (
              <TabsTrigger key={m.id} value={m.id} className="text-[11px] px-3">{m.label}</TabsTrigger>
            ))}
          </TabsList>
        </Tabs>

        <Button variant="outline" size="sm" onClick={refresh} disabled={loading} className="gap-1.5 h-8 text-[11px]">
          <RefreshCw className={`h-3.5 w-3.5 ${loading ? 'animate-spin' : ''}`} />
          {t('p2pRefresh')}
        </Button>

        <span className="flex items-center gap-1.5 text-[11px] text-muted-foreground">
          <span className="h-2 w-2 rounded-full bg-green-400 animate-pulse" />
          {hasNoData ? 'Waiting for first sync…' : 'Sync · 5 min'}
        </span>

        <Badge variant="outline" className="font-mono text-[11px]">{currentMarket.pair}</Badge>
      </div>

      {hasNoData ? (
        <div className="flex flex-col items-center justify-center py-20 gap-3 text-center">
          <span className="h-3 w-3 rounded-full bg-amber-400 animate-pulse" />
          <p className="text-sm font-semibold text-muted-foreground">Collecting data for {currentMarket.label}…</p>
          <p className="text-xs text-muted-foreground/60 max-w-xs">
            The backend sync runs every 5 minutes. First data point will appear automatically — no refresh needed.
          </p>
        </div>
      ) : snapshot && (
        <>
          <MarketKpiGrid
            snapshot={snapshot}
            market={market}
            todaySummary={todaySummary}
            profitIfSold={profitIfSold}
            roundTripSim={roundTripSim}
            t={t}
          />

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-2">
            <PriceHistorySparklines history={history} dataAgeLabel={dataAgeLabel} t={t} />
            <MerchantDepthStats merchantStats={merchantStats} />
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-2">
            <P2POfferTable offers={snapshot.sellOffers} type="sell" t={t} />
            <P2POfferTable offers={snapshot.buyOffers} type="buy" t={t} />
          </div>
        </>
      )}
    </div>
  );
}

import { useState, useMemo, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '@/features/auth/auth-context';
import { useT } from '@/lib/i18n';
import { supabase } from '@/integrations/supabase/client';
import { AgreementsTab } from '@/features/merchants/components/AgreementsTab';
import { SettlementTab } from '@/features/merchants/components/SettlementTab';
import { ChatTab } from '@/features/merchants/components/ChatTab';
import { useTrackerState } from '@/lib/useTrackerState';
import { fmtTotal } from '@/lib/tracker-helpers';
import '@/styles/tracker.css';

type WorkspaceTab = 'agreements' | 'settlements' | 'chat';

interface LegacyDealRow {
  id: string;
  relationship_id: string;
  title: string;
  deal_type: string;
  amount: number;
  currency: string;
  status: string;
  created_at: string;
  settlement_cadence?: string;
}

export default function RelationshipPage() {
  const { relationshipId } = useParams<{ relationshipId: string }>();
  const navigate = useNavigate();
  const { userId, merchantProfile } = useAuth();
  const t = useT();
  const [activeTab, setActiveTab] = useState<WorkspaceTab>('agreements');
  const [relationship, setRelationship] = useState<any>(null);
  const [legacyDeals, setLegacyDeals] = useState<LegacyDealRow[]>([]);
  const [loading, setLoading] = useState(true);

  const { state: trackerState, derived: trackerDerived } = useTrackerState({});

  useEffect(() => {
    if (!relationshipId || !userId) return;
    loadData();
  }, [relationshipId, userId, merchantProfile?.merchant_id]);

  const loadData = async () => {
    if (!relationshipId || !userId) return;
    setLoading(true);
    try {
      const myMerchantId = merchantProfile?.merchant_id;

      const [relRes, dealsRes, profilesRes] = await Promise.all([
        supabase.from('merchant_relationships').select('*').eq('id', relationshipId).single(),
        supabase.from('merchant_deals').select('*').eq('relationship_id', relationshipId).order('created_at', { ascending: false }),
        supabase.from('merchant_profiles').select('merchant_id, display_name, nickname, merchant_code'),
      ]);

      if (relRes.error || !relRes.data) {
        navigate('/merchants');
        return;
      }

      const profileMap = new Map((profilesRes.data || []).map(p => [p.merchant_id, p]));
      const r = relRes.data;
      const cpId = r.merchant_a_id === myMerchantId ? r.merchant_b_id : r.merchant_a_id;
      const cp = profileMap.get(cpId);

      setRelationship({
        ...r,
        counterparty_name: cp?.display_name || cpId,
        counterparty_nickname: cp?.nickname || '',
        counterparty_code: (cp as any)?.merchant_code || '',
      });

      setLegacyDeals((dealsRes.data || []).map(d => ({
        id: d.id,
        relationship_id: d.relationship_id,
        title: d.title,
        deal_type: d.deal_type,
        amount: d.amount,
        currency: d.currency,
        status: d.status,
        created_at: d.created_at,
        settlement_cadence: (d as any).settlement_cadence || 'monthly',
      })));
    } catch (err) {
      console.error('Failed to load relationship:', err);
      navigate('/merchants');
    } finally {
      setLoading(false);
    }
  };

  const relDeals = useMemo(() =>
    legacyDeals
      .filter(a => a.relationship_id === relationshipId && a.status !== 'cancelled')
      .map(d => ({
        id: d.id,
        title: d.title,
        deal_type: d.deal_type,
        settlement_cadence: d.settlement_cadence || 'monthly',
        amount: d.amount,
        created_at: d.created_at,
      })),
    [legacyDeals, relationshipId]
  );

  const isPartner = relationship
    ? merchantProfile?.merchant_id !== relationship.merchant_a_id
    : false;

  const tabs: { key: WorkspaceTab; label: string; icon: string }[] = [
    { key: 'agreements', label: t('profitShareAgreements'), icon: '🤝' },
    { key: 'settlements', label: t('settlements'), icon: '💰' },
    { key: 'chat', label: t('chatTab'), icon: '💬' },
  ];

  if (loading) {
    return (
      <div className="tracker-root" style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: '100%' }}>
        <div className="empty">
          <div className="empty-t">{t('loading') || 'Loading...'}</div>
        </div>
      </div>
    );
  }

  if (!relationship) return null;

  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'} style={{ padding: 12, display: 'flex', flexDirection: 'column', gap: 0, minHeight: '100%' }}>

      {/* ─── HEADER ─── */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}>
        <button className="rowBtn" onClick={() => navigate('/merchants')} style={{ fontSize: 14, flexShrink: 0 }}>←</button>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 14, fontWeight: 800, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {relationship.counterparty_name}
          </div>
          <div style={{ fontSize: 10, color: 'var(--muted)' }}>
            @{relationship.counterparty_nickname} · {t('code') || 'Code'}:{' '}
            <span className="mono" style={{ fontWeight: 700 }}>{relationship.counterparty_code || '—'}</span>
          </div>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 2, flexShrink: 0 }}>
          <span className={`pill ${relationship.status === 'active' ? 'good' : 'warn'}`}>{relationship.status}</span>
          <span style={{ fontSize: 9, color: 'var(--muted)' }}>
            {t('since') || 'Since'}: {new Date(relationship.created_at).toLocaleDateString()}
          </span>
        </div>
      </div>

      {/* ─── MERCHANT TREASURY PANEL ─── */}
      {(() => {
        const linkedAccounts = (trackerState.cashAccounts || []).filter(a => a.relationshipId === relationshipId);
        if (linkedAccounts.length === 0) return null;

        const ledger = trackerState.cashLedger || [];
        const totals = new Map<string, number>();
        let lastRecon = 0;

        linkedAccounts.forEach(acc => {
          const bal = (ledger || [])
            .filter(e => e.accountId === acc.id)
            .reduce((sum, e) => sum + (e.direction === 'in' ? e.amount : -e.amount), 0);
          totals.set(acc.currency, (totals.get(acc.currency) || 0) + bal);
          if (acc.lastReconciled && acc.lastReconciled > lastRecon) lastRecon = acc.lastReconciled;
        });

        return (
          <div className="panel" style={{ marginBottom: 12, border: '1px solid color-mix(in srgb, var(--brand) 30%, transparent)', background: 'color-mix(in srgb, var(--brand) 4%, transparent)' }}>
            <div style={{ padding: '10px 14px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontSize: 10, color: 'var(--brand)', fontWeight: 800, textTransform: 'uppercase', marginBottom: 2, letterSpacing: '0.05em' }}>
                  {t('merchantTreasury' as any) || 'Merchant Treasury'}
                </div>
                <div style={{ display: 'flex', gap: 14 }}>
                  {Array.from(totals.entries()).map(([curr, amt]) => (
                    <div key={curr} className="mono" style={{ fontSize: 18, fontWeight: 900 }}>
                      {fmtTotal(amt)} <span style={{ fontSize: 10, fontWeight: 600, color: 'var(--muted)' }}>{curr}</span>
                    </div>
                  ))}
                </div>
              </div>
              <div style={{ textAlign: 'right' }}>
                <div style={{ fontSize: 9, color: 'var(--muted)', marginBottom: 2 }}>{t('lastReconciled' as any) || 'Last Reconciled'}</div>
                <div style={{ fontSize: 10, fontWeight: 600, color: lastRecon ? 'var(--text)' : 'var(--warn)' }}>
                  {lastRecon ? new Date(lastRecon).toLocaleDateString() : 'Never'}
                </div>
              </div>
            </div>
          </div>
        );
      })()}

      {/* ─── TAB BAR ─── */}
      <div style={{ display: 'flex', gap: 0, borderBottom: '1px solid var(--line)', marginBottom: 12, overflowX: 'auto' }}>
        {tabs.map(({ key, label, icon }) => (
          <button
            key={key}
            onClick={() => setActiveTab(key)}
            style={{
              padding: '8px 12px', fontSize: 10, fontWeight: activeTab === key ? 700 : 500,
              color: activeTab === key ? 'var(--brand)' : 'var(--muted)',
              borderBottom: activeTab === key ? '2px solid var(--brand)' : '2px solid transparent',
              background: 'transparent', border: 'none', borderBottomStyle: 'solid', cursor: 'pointer',
              transition: 'all 0.15s',
              display: 'flex', alignItems: 'center', gap: 4, whiteSpace: 'nowrap',
            }}
          >
            {icon} {label}
          </button>
        ))}
      </div>

      {/* ─── TAB CONTENT ─── */}
      <div style={{ flex: 1 }}>
        {activeTab === 'agreements' && (
          <AgreementsTab
            relationshipId={relationship.id}
            counterpartyName={relationship.counterparty_name}
          />
        )}
        {activeTab === 'settlements' && (
          <SettlementTab
            relationshipId={relationship.id}
            deals={relDeals}
            isPartner={isPartner}
            trades={trackerState.trades || []}
            tradeCalc={trackerDerived.tradeCalc || new Map()}
          />
        )}
        {activeTab === 'chat' && (
          <ChatTab relationshipId={relationship.id} />
        )}
      </div>
    </div>
  );
}

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useTrackerState } from '@/lib/useTrackerState';
import {
  fmtU,
  fmtP,
  fmtQ, fmtQWithUnit,
  fmtDate,
  fmtDur,
  fmtTotal,
  num,
  getWACOP,
  rangeLabel,
  batchCycleTime,
  computeFIFO,
  uid,
  getAccountBalance,
  getAllAccountBalances,
  deriveCashQAR,
  type TrackerState,
  type CashLedgerEntry,
} from '@/lib/tracker-helpers';
import { useTheme } from '@/lib/theme-context';
import { useT } from '@/lib/i18n';
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { CashManagement } from '@/features/stock/components/CashManagement';
import { useIsMobile } from '@/hooks/use-mobile';
import '@/styles/tracker.css';
import { focusElementBySelectors } from '@/lib/focus-target';

const nowInput = () => new Date().toISOString().slice(0, 16);
const norm = (v: string) => v.trim().toLowerCase();

function inputFromTs(ts: number) {
  return new Date(ts).toISOString().slice(0, 16);
}

export default function StockPage() {
  const { settings, update } = useTheme();
  const t = useT();
  const isMobile = useIsMobile();

  const { state, derived, applyState } = useTrackerState({
    lowStockThreshold: settings.lowStockThreshold,
    priceAlertThreshold: settings.priceAlertThreshold,
    range: settings.range,
    currency: settings.currency,
  });

  const [batchDate, setBatchDate] = useState(nowInput());
  const [batchMode, setBatchMode] = useState<'QAR' | 'USDT'>('QAR');
  const [batchEntryMode, setBatchEntryMode] = useState<'price_vol' | 'qty_total' | 'qty_price'>('price_vol');
  const [batchUsdtQty, setBatchUsdtQty] = useState('');
  const [detailsOpen, setDetailsOpen] = useState<Record<string, boolean>>({});
  const [batchPrice, setBatchPrice] = useState('');
  const [batchAmount, setBatchAmount] = useState('');
  const [batchSupplier, setBatchSupplier] = useState('');
  const [batchNote, setBatchNote] = useState('');
  const [batchMsg, setBatchMsg] = useState('');
  const [selectedMonth, setSelectedMonth] = useState<string>(new Date().toISOString().slice(0, 7));

  const [supplierMenuOpen, setSupplierMenuOpen] = useState(false);
  const [supplierAddOpen, setSupplierAddOpen] = useState(false);
  const [newSupplierName, setNewSupplierName] = useState('');
  const [newSupplierPhone, setNewSupplierPhone] = useState('');

  const [editingBatchId, setEditingBatchId] = useState<string | null>(null);
  const [editDate, setEditDate] = useState('');
  const [editSource, setEditSource] = useState('');
  const [editSupplierCustom, setEditSupplierCustom] = useState('');
  const [editQty, setEditQty] = useState('');
  const [editPrice, setEditPrice] = useState('');
  const [editNote, setEditNote] = useState('');

  const [manualSuppliers, setManualSuppliers] = useState<Array<{ name: string; phone?: string }>>([]);

  // ── Cash Management tab ──────────────────────────────────────────
  const [searchParams] = useSearchParams();
  const [stockTab, setStockTab] = useState<'batches' | 'cash'>(
    searchParams.get('tab') === 'cash' ? 'cash' : 'batches'
  );
  const [fundingAccountId, setFundingAccountId] = useState<string>('');

  // Clear shared search query on mount to prevent cross-page filter leak
  useEffect(() => {
    if (settings.searchQuery) update({ searchQuery: '' });
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Derive account balances for funding source selector
  const cashAccounts = state.cashAccounts || [];
  const cashLedger = state.cashLedger || [];
  const accountBalances = useMemo(() => getAllAccountBalances(cashAccounts, cashLedger), [cashAccounts, cashLedger]);
  const activeAccounts = useMemo(() => cashAccounts.filter(a => a.status === 'active'), [cashAccounts]);


  useEffect(() => {
    const focusStockId = searchParams.get('focusStockId');
    if (!focusStockId) return;
    window.setTimeout(() => {
      focusElementBySelectors([
        `#stock-${focusStockId}`,
        `[data-stock-id="${focusStockId}"]`,
      ]);
    }, 180);
  }, [searchParams, state.batches.length]);

  // Auto-select first account if none selected and accounts exist
  useEffect(() => {
    if (!fundingAccountId && activeAccounts.length > 0) {
      // Prefer the account with highest balance
      const best = [...activeAccounts].sort((a, b) => (accountBalances.get(b.id) || 0) - (accountBalances.get(a.id) || 0));
      setFundingAccountId(best[0]?.id || 'none');
    }
  }, [activeAccounts, fundingAccountId, accountBalances]);

  useEffect(() => {
    const next: TrackerState = {
      ...state,
      range: settings.range,
      currency: settings.currency,
      settings: {
        ...state.settings,
        lowStockThreshold: settings.lowStockThreshold,
        priceAlertThreshold: settings.priceAlertThreshold,
      },
    };
    applyState(next);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [settings.range, settings.currency, settings.lowStockThreshold, settings.priceAlertThreshold]);

  const wacop = getWACOP(derived);
  /** Currency-aware formatter: respects the global QAR/USDT toggle using FIFO WACOP */
  const fmtC = useCallback((v: number) => fmtQWithUnit(v, settings.currency, wacop), [settings.currency, wacop]);
  const rLabel = rangeLabel(state.range);

  const query = (settings.searchQuery || '').trim().toLowerCase();
  const supplierLookup = useMemo(() => {
    const names = [
      ...manualSuppliers.map((s) => s.name),
      ...state.batches.map((b) => b.source),
    ].filter(Boolean);
    const unique = [...new Set(names.map((n) => n.trim()).filter(Boolean))].sort((a, b) => a.localeCompare(b));
    if (!query) return unique;
    return unique.filter((n) => n.toLowerCase().includes(query));
  }, [manualSuppliers, query, state.batches]);

  const availableMonths = useMemo(() => {
    const months = new Set<string>();
    const curMonthKey = new Date().toISOString().slice(0, 7);
    months.add(curMonthKey);
    state.batches.forEach(b => {
      const d = new Date(b.ts);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      months.add(key);
    });
    return Array.from(months).sort().reverse();
  }, [state.batches]);

  const perf = useMemo(() => state.batches
    .map((b) => {
      const db = derived.batches.find((x) => x.id === b.id);
      const rem = db ? Math.max(0, db.remainingUSDT) : b.initialUSDT;
      const used = b.initialUSDT - rem;
      let profit = 0;
      for (const [, c] of derived.tradeCalc) {
        if (!c.ok) continue;
        const s = c.slices.find((sl) => sl.batchId === b.id);
        if (s) profit += s.qty * c.ppu;
      }
      return { ...b, remaining: rem, used, profit };
    })
    .filter((b) => {
      if (selectedMonth !== 'all') {
        const d = new Date(b.ts);
        const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        if (key !== selectedMonth) return false;
      }
      if (!query) return true;
      return [fmtDate(b.ts), b.source, b.note].join(' ').toLowerCase().includes(query);
    })
    .sort((a, b) => b.ts - a.ts), [derived, query, state.batches, selectedMonth]);

  const suppliersForPanel = useMemo(() => [
    ...new Set(state.batches.map((b) => b.source.trim()).filter(Boolean)),
  ], [state.batches]);

  const addSupplier = () => {
    if (!newSupplierName.trim()) return;
    setManualSuppliers((prev) => {
      if (prev.some((s) => norm(s.name) === norm(newSupplierName))) return prev;
      return [...prev, { name: newSupplierName.trim(), phone: newSupplierPhone.trim() }];
    });
    setBatchSupplier(newSupplierName.trim());
    setSupplierAddOpen(false);
    setSupplierMenuOpen(false);
    setNewSupplierName('');
    setNewSupplierPhone('');
  };

  const addBatch = () => {
    const ts = new Date(batchDate).getTime();
    const source = batchSupplier.trim();

    let px = 0;
    let totalUSDT = 0;
    let volumeQAR = 0;

    if (batchEntryMode === 'price_vol') {
      px = Number(batchPrice);
      const rawAmt = Number(batchAmount);
      const errs: string[] = [];
      if (!Number.isFinite(ts)) errs.push(t('date'));
      if (!(px > 0)) errs.push(t('price'));
      if (!(rawAmt > 0)) errs.push(t('volume'));
      if (!source) errs.push(t('supplier'));
      if (errs.length) { setBatchMsg(`${t('fixFields')} ${errs.join(', ')}`); return; }
      volumeQAR = batchMode === 'USDT' ? rawAmt * px : rawAmt;
      totalUSDT = volumeQAR / px;
    } else if (batchEntryMode === 'qty_total') {
      totalUSDT = Number(batchUsdtQty);
      volumeQAR = Number(batchAmount);
      const errs: string[] = [];
      if (!Number.isFinite(ts)) errs.push(t('date'));
       if (!(totalUSDT > 0)) errs.push(t('usdtQtyValidation'));
       if (!(volumeQAR > 0)) errs.push(t('totalQarValidation'));
      if (!source) errs.push(t('supplier'));
      if (errs.length) { setBatchMsg(`${t('fixFields')} ${errs.join(', ')}`); return; }
      px = volumeQAR / totalUSDT;
    } else {
      totalUSDT = Number(batchUsdtQty);
      px = Number(batchPrice);
      const errs: string[] = [];
      if (!Number.isFinite(ts)) errs.push(t('date'));
      if (!(totalUSDT > 0)) errs.push(t('usdtQtyValidation'));
      if (!(px > 0)) errs.push(t('price'));
      if (!source) errs.push(t('supplier'));
      if (errs.length) { setBatchMsg(`${t('fixFields')} ${errs.join(', ')}`); return; }
      volumeQAR = totalUSDT * px;
    }

    const batchCostQAR = volumeQAR;
    const batchId = uid();

    // ── Multi-account cash deduction (new system) ──────────────────
    let nextCashLedger = [...(state.cashLedger || [])];
    let fundingLedgerEntryId: string | undefined;
    let selectedFundingAccountId: string | undefined;

    if (activeAccounts.length > 0 && fundingAccountId && fundingAccountId !== 'none') {
      const selectedAcc = activeAccounts.find(a => a.id === fundingAccountId);
      if (!selectedAcc) { setBatchMsg(t('fundingAccNotFound')); return; }
      const availBal = accountBalances.get(fundingAccountId) || 0;
      if (availBal < batchCostQAR) {
        setBatchMsg(`⚠ ${t('insufficientInAcc')} "${selectedAcc.name}". ${t('availableLbl')}: ${fmtTotal(availBal)} QAR, ${t('requiredLbl')}: ${fmtTotal(batchCostQAR)} QAR`);
        return;
      }
      const entryId = uid();
      const purchaseEntry: CashLedgerEntry = {
        id: entryId,
        ts: Date.now(),
        type: 'stock_purchase',
        accountId: fundingAccountId,
        direction: 'out',
        amount: batchCostQAR,
        currency: 'QAR',
        linkedEntityType: 'batch',
        linkedEntityId: batchId,
        note: `Stock purchase: ${fmtU(totalUSDT)} USDT @ ${fmtP(px)} from ${source}`,
      };
      nextCashLedger = [...nextCashLedger, purchaseEntry];
      fundingLedgerEntryId = entryId;
      selectedFundingAccountId = fundingAccountId;
    }

    // ── Legacy cashQAR backward-compat deduction ────────────────────
    const currentCash = num(state.cashQAR, 0);
    const newCashFromLedger = activeAccounts.length > 0
      ? deriveCashQAR(cashAccounts, nextCashLedger)
      : Math.max(0, currentCash - batchCostQAR);
    const cashTx: import('@/lib/tracker-helpers').CashTransaction = {
      id: uid(),
      ts: Date.now(),
      type: 'batch_purchase',
      amount: Math.min(batchCostQAR, currentCash),
      balanceAfter: newCashFromLedger,
      owner: state.cashOwner || '',
      bankAccount: activeAccounts.find(a => a.id === fundingAccountId)?.name || '',
      note: `Stock purchase: ${fmtU(totalUSDT)} USDT @ ${fmtP(px)} from ${source}`,
    };

    const next: TrackerState = {
      ...state,
      cashQAR: newCashFromLedger,
      cashHistory: [...(state.cashHistory || []), cashTx],
      cashLedger: nextCashLedger,
      batches: [
        ...state.batches,
        {
          id: batchId,
          ts,
          source,
          note: batchNote.trim(),
          buyPriceQAR: px,
          initialUSDT: totalUSDT,
          revisions: [],
          fundingAccountId: selectedFundingAccountId,
          fundingLedgerEntryId,
        },
      ],
    };

    applyState(next);
    setBatchAmount('');
    setBatchPrice('');
    setBatchUsdtQty('');
    setBatchSupplier('');
    setBatchNote('');
    const fundingAccName = activeAccounts.find(a => a.id === fundingAccountId)?.name;
    const deductMsg = fundingAccName
       ? ` · ${fmtTotal(batchCostQAR)} QAR ${t('deductedFromAccount')} "${fundingAccName}"`
       : currentCash > 0 ? ` · ${fmtTotal(Math.min(batchCostQAR, currentCash))} QAR ${t('deductedFromCash')}` : '';
    setBatchMsg(t('batchAdded') + deductMsg);
  };

  const openEdit = (id: string) => {
    const b = state.batches.find((x) => x.id === id);
    if (!b) return;
    setEditingBatchId(id);
    setEditDate(inputFromTs(b.ts));
    setEditSource(b.source);
    setEditSupplierCustom('');
    setEditQty(String(b.initialUSDT));
    setEditPrice(String(b.buyPriceQAR));
    setEditNote(b.note || '');
  };

  const saveBatchEdit = () => {
    if (!editingBatchId) return;
    const ts = new Date(editDate).getTime();
    const qty = Number(editQty);
    const px = Number(editPrice);
    const src = editSource.trim();
    if (!Number.isFinite(ts) || !(qty > 0) || !(px > 0) || !src) {
      return;
    }

    const existingBatch = state.batches.find(b => b.id === editingBatchId);
    const oldCost = existingBatch ? existingBatch.initialUSDT * existingBatch.buyPriceQAR : 0;
    const newCost = qty * px;
    const delta = newCost - oldCost; // positive = extra spend, negative = refund

    // ── Ledger adjustment if multi-account is active ─────────────
    let nextCashLedger = [...(state.cashLedger || [])];
    if (Math.abs(delta) > 0.01 && existingBatch?.fundingAccountId) {
      const adjustEntry: CashLedgerEntry = {
        id: uid(),
        ts: Date.now(),
        type: 'stock_edit_adjust',
        accountId: existingBatch.fundingAccountId,
        direction: delta > 0 ? 'out' : 'in',
        amount: Math.abs(delta),
        currency: 'QAR',
        linkedEntityType: 'batch',
        linkedEntityId: editingBatchId,
        note: `Batch edit: cost ${delta > 0 ? 'increased' : 'reduced'} by ${fmtTotal(Math.abs(delta))} QAR`,
      };
      nextCashLedger = [...nextCashLedger, adjustEntry];
    }

    const nextBatches = state.batches.map((b) => {
      if (b.id !== editingBatchId) return b;
      return {
        ...b,
        ts,
        source: src,
        note: editNote.trim(),
        initialUSDT: qty,
        buyPriceQAR: px,
        revisions: [
          { at: Date.now(), before: { ts: b.ts, source: b.source, note: b.note, initialUSDT: b.initialUSDT, buyPriceQAR: b.buyPriceQAR } },
          ...b.revisions,
        ].slice(0, 20),
      };
    });

    const newCashQAR = (state.cashAccounts || []).length > 0
      ? deriveCashQAR(state.cashAccounts, nextCashLedger)
      : Math.max(0, num(state.cashQAR, 0) - delta);

    applyState({ ...state, batches: nextBatches, cashLedger: nextCashLedger, cashQAR: newCashQAR });
    setEditingBatchId(null);
  };

  const deleteBatch = () => {
    if (!editingBatchId) return;
    const batch = state.batches.find(b => b.id === editingBatchId);
    if (!batch) return;

    const batchCostQAR = batch.initialUSDT * batch.buyPriceQAR;

    // ── Double-refund guard ───────────────────────────────────────
    const alreadyRefunded = (state.cashLedger || []).some(
      e => e.type === 'stock_refund' && e.linkedEntityId === editingBatchId
    );
    if (alreadyRefunded) {
      // Batch already refunded — just remove from list
      applyState({ ...state, batches: state.batches.filter(b => b.id !== editingBatchId) });
      setEditingBatchId(null);
      return;
    }

    // ── Multi-account refund (new system) ─────────────────────────
    let nextCashLedger = [...(state.cashLedger || [])];
    if (batch.fundingAccountId && (state.cashAccounts || []).length > 0) {
      const refundEntry: CashLedgerEntry = {
        id: uid(),
        ts: Date.now(),
        type: 'stock_refund',
        accountId: batch.fundingAccountId,
        direction: 'in',
        amount: batchCostQAR,
        currency: 'QAR',
        linkedEntityType: 'batch',
        linkedEntityId: editingBatchId,
        note: `Batch refund: ${fmtU(batch.initialUSDT)} USDT @ ${fmtP(batch.buyPriceQAR)} from ${batch.source || 'unknown'}`,
      };
      nextCashLedger = [...nextCashLedger, refundEntry];
    }

    // ── Legacy cashQAR refund ─────────────────────────────────────
    const currentCash = num(state.cashQAR, 0);
    const newCashQAR = (state.cashAccounts || []).length > 0
      ? deriveCashQAR(state.cashAccounts, nextCashLedger)
      : currentCash + batchCostQAR;
    const cashTx: import('@/lib/tracker-helpers').CashTransaction = {
      id: uid(),
      ts: Date.now(),
      type: 'batch_refund' as any,
      amount: batchCostQAR,
      balanceAfter: newCashQAR,
      owner: state.cashOwner || '',
      bankAccount: state.cashAccounts?.find(a => a.id === batch.fundingAccountId)?.name || '',
      note: `Batch deleted: ${fmtU(batch.initialUSDT)} USDT @ ${fmtP(batch.buyPriceQAR)} from ${batch.source || 'unknown'}`,
    };

    applyState({
      ...state,
      batches: state.batches.filter(b => b.id !== editingBatchId),
      cashQAR: newCashQAR,
      cashHistory: [...(state.cashHistory || []), cashTx],
      cashLedger: nextCashLedger,
    });
    setEditingBatchId(null);
  };

  return (
    <div className="tracker-root" dir={t.isRTL ? 'rtl' : 'ltr'} style={{ padding: isMobile ? '10px max(10px, env(safe-area-inset-right)) max(10px, env(safe-area-inset-bottom)) max(10px, env(safe-area-inset-left))' : 12, display: 'flex', flexDirection: 'column', gap: 10, minHeight: isMobile ? 'calc(100dvh - env(safe-area-inset-top))' : '100%' }}>

      {/* ── Stock Page Tab Switcher ─────────────────────────────── */}
      <div style={{ display: 'flex', gap: 2, background: 'var(--panel)', borderRadius: 8, padding: 3, alignSelf: isMobile ? 'stretch' : 'flex-start', width: isMobile ? '100%' : undefined }}>
        <button
          onClick={() => setStockTab('batches')}
          style={{ padding: isMobile ? '8px 12px' : '6px 16px', minHeight: isMobile ? 36 : undefined, flex: isMobile ? 1 : undefined, fontSize: 12, fontWeight: 700, border: 'none', cursor: 'pointer', borderRadius: 6, background: stockTab === 'batches' ? 'var(--brand)' : 'transparent', color: stockTab === 'batches' ? '#fff' : 'var(--muted)', transition: 'all 0.12s' }}>
          📦 {t('batches')}
        </button>
        <button
          onClick={() => setStockTab('cash')}
