/* ── IDB Vault (Ring 1) ── */
interface Snapshot {
  id: string;
  ts: number;
  label: string;
  sizeKB: number;
  checksum: string;
  tradeCount: number;
  batchCount: number;
  state: Record<string, unknown>;
}

function fnv1a(str: string): string {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h = (h ^ str.charCodeAt(i)) >>> 0;
    h = Math.imul(h, 16777619) >>> 0;
  }
  return h.toString(16).toUpperCase();
}

function openIDB(): Promise<IDBDatabase> {
  return new Promise((res, rej) => {
    const req = indexedDB.open('p2p_tracker_vault', 1);
    req.onupgradeneeded = (e) => {
      const db = (e.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains('snapshots')) db.createObjectStore('snapshots', { keyPath: 'id' });
      if (!db.objectStoreNames.contains('metadata')) db.createObjectStore('metadata', { keyPath: 'key' });
    };
    req.onsuccess = (e) => res((e.target as IDBOpenDBRequest).result);
    req.onerror = () => rej(new Error('IndexedDB not available'));
  });
}

async function idbList(): Promise<Snapshot[]> {
  const db = await openIDB();
  return new Promise((res) => {
    const tx = db.transaction('snapshots', 'readonly');
    const req = tx.objectStore('snapshots').getAll();
    req.onsuccess = () => {
      const snaps = (req.result || []).sort((a: Snapshot, b: Snapshot) => b.ts - a.ts);
      res(snaps);
    };
    req.onerror = () => res([]);
  });
}

async function idbSave(state: Record<string, unknown>, label: string): Promise<void> {
  const db = await openIDB();
  const str = JSON.stringify(state || {});
  const snap: Snapshot = {
    id: 'snap_' + Date.now(),
    ts: Date.now(),
    label: label || 'Manual',
    sizeKB: Math.max(1, Math.ceil(str.length / 1024)),
    checksum: fnv1a(str),
    tradeCount: Array.isArray((state as any)?.trades) ? (state as any).trades.length : 0,
    batchCount: Array.isArray((state as any)?.batches) ? (state as any).batches.length : 0,
    state,
  };
  return new Promise((res, rej) => {
    const tx = db.transaction('snapshots', 'readwrite');
    tx.objectStore('snapshots').put(snap);
    tx.oncomplete = () => res();
    tx.onerror = () => rej(new Error('Failed to save'));
  });
}

async function idbGet(id: string): Promise<Snapshot | null> {
  const db = await openIDB();
  return new Promise((res) => {
    const tx = db.transaction('snapshots', 'readonly');
    const req = tx.objectStore('snapshots').get(id);
    req.onsuccess = () => res(req.result || null);
    req.onerror = () => res(null);
  });
}

async function idbDelete(id: string): Promise<void> {
  const db = await openIDB();
  return new Promise((res, rej) => {
    const tx = db.transaction('snapshots', 'readwrite');
    tx.objectStore('snapshots').delete(id);
    tx.oncomplete = () => res();
    tx.onerror = () => rej();
  });
}

function downloadBlob(content: string, filename: string, mime = 'application/json') {
  const blob = new Blob([content], { type: mime });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(a.href);
}

function getCurrentState(): Record<string, unknown> {
  return getCurrentTrackerState(localStorage);
}

async function clearTrackerVaultDb(): Promise<void> {
  await new Promise<void>((resolve) => {
    const req = indexedDB.deleteDatabase('p2p_tracker_vault');
    req.onsuccess = () => resolve();
    req.onerror = () => resolve();
    req.onblocked = () => resolve();
  });
}

export default function VaultPage() {
  const t = useT();
  const navigate = useNavigate();
  const { email, userId, merchantProfile } = useAuth();

  const [snaps, setSnaps] = useState<Snapshot[]>([]);
  const [snapDesc, setSnapDesc] = useState('');
  const [loading, setLoading] = useState(false);
  const [autoBackup, setAutoBackup] = useState(() => loadAutoBackupFromStorage(localStorage));
  const importInputRef = useRef<HTMLInputElement>(null);
  const [importStatus, setImportStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [importMsg, setImportMsg] = useState('');
  const [exportStatus, setExportStatus] = useState<'idle' | 'success'>('idle');

  // ── Ring 2 Cloud Vault State ──
  const [cloudLoggedIn, setCloudLoggedIn] = useState(false);
  const [cloudAuthState, setCloudAuthState] = useState<'idle' | 'authenticating' | 'failed' | 'ready'>('idle');
  const [cloudAuthError, setCloudAuthError] = useState('');
  const [cloudVersions, setCloudVersions] = useState<CloudVersion[]>([]);
  const [cloudLoading, setCloudLoading] = useState(false);
  const [cloudLabel, setCloudLabel] = useState('');
  const [selectedVersion, setSelectedVersion] = useState('');

  const authenticateCloud = useCallback(async () => {
    gasLoadConfig();
    if (isCloudLoggedIn()) {
      setCloudLoggedIn(true);
      setCloudAuthState('ready');
      setCloudAuthError('');
      return true;
    }

    if (!email || !userId) {
      setCloudLoggedIn(false);
      setCloudAuthState('failed');
      setCloudAuthError('Missing account identity (email/user id).');
      return false;
    }

    setCloudAuthState('authenticating');
    setCloudAuthError('');
    const res = await autoAuthenticateCloudWithDetails(email, userId, merchantProfile?.display_name || undefined);
    setCloudLoggedIn(res.ok);
    setCloudAuthState(res.ok ? 'ready' : 'failed');
    setCloudAuthError(res.reason || '');
    return res.ok;
  }, [email, userId, merchantProfile?.display_name]);

  // Auto-authenticate with GAS using Google session
  useEffect(() => {
    void authenticateCloud();
  }, [authenticateCloud]);

  const loadSnaps = useCallback(async () => {
    try {
      const list = await idbList();
      setSnaps(list);
    } catch {
      setSnaps([]);
    }
  }, []);

  useEffect(() => { loadSnaps(); }, [loadSnaps]);

  const takeSnapshot = async () => {
    if (!snapDesc.trim()) {
      toast.error(t.lang === 'ar' ? 'أضف وصفاً للنسخة الاحتياطية' : 'Add a description for the snapshot');
      return;
    }
    setLoading(true);
    try {
      const state = getCurrentState();
      await idbSave(state, snapDesc.trim());
      setSnapDesc('');
      toast.success(t.lang === 'ar' ? '📸 تم حفظ النسخة' : '📸 Snapshot saved');
      await loadSnaps();
    } catch (e: any) {
      toast.error((t.lang === 'ar' ? 'فشل: ' : 'Failed: ') + (e.message || 'error'));
    } finally {
      setLoading(false);
    }
  };

  const restoreSnap = async (id: string) => {
    if (!confirm(t.lang === 'ar' ? 'استعادة هذه النسخة؟ سيتم استبدال البيانات الحالية.' : 'Restore this local snapshot? Current data will be overwritten.')) return;
    const snap = await idbGet(id);
    if (!snap?.state) { toast.error(t.lang === 'ar' ? 'النسخة غير موجودة' : 'Snapshot not found'); return; }
    try {
      const sk = findTrackerStorageKey(localStorage);
      localStorage.removeItem('tracker_data_cleared');
      localStorage.setItem(sk, JSON.stringify(snap.state));
      await saveTrackerStateNow(snap.state as unknown as TrackerState);
      toast.success(t.lang === 'ar' ? '✓ تمت الاستعادة' : '✓ Restored from local snapshot');
      window.location.reload();
    } catch (e: any) {
      toast.error((t.lang === 'ar' ? 'فشلت الاستعادة: ' : 'Restore failed: ') + e.message);
    }
  };

  const exportSnap = async (id: string) => {
    const snap = await idbGet(id);
    if (!snap?.state) { toast.error(t.lang === 'ar' ? 'النسخة غير موجودة' : 'Snapshot not found'); return; }
    const label = (snap.label || 'snapshot').replace(/[^a-zA-Z0-9_-]+/g, '_').slice(0, 40);
    const d = new Date(snap.ts);
    const fname = `snapshot-${d.toISOString().slice(0, 19).replace(/[:T]/g, '-')}-${label}.json`;
    downloadBlob(JSON.stringify(snap.state, null, 2), fname);
    toast.success(t.lang === 'ar' ? 'تم تصدير النسخة' : 'Exported snapshot');
  };

  const deleteSnap = async (id: string) => {
    if (!confirm(t.lang === 'ar' ? 'حذف هذه النسخة؟' : 'Delete this snapshot?')) return;
    await idbDelete(id);
    toast(t.lang === 'ar' ? 'تم حذف النسخة' : 'Snapshot deleted');
    await loadSnaps();
  };

  const handleAutoBackupToggle = (v: boolean) => {
    setAutoBackup(v);
    saveAutoBackupToStorage(localStorage, v);
    toast(v ? (t.lang === 'ar' ? 'النسخ التلقائي مفعّل' : 'Auto-backup ON') : (t.lang === 'ar' ? 'النسخ التلقائي معطّل' : 'Auto-backup OFF'));
  };

  // Cloud auth is automatic — no manual login needed

  const handleCloudLogout = () => {
    clearCloudSession();
    setCloudLoggedIn(false);
    setCloudAuthState('failed');
    setCloudAuthError('Signed out from Cloud session.');
    setCloudVersions([]);
    toast('Logged out from Cloud');
  };

  const cloudBackupNow = async () => {
    if (!getGasUrl()) { toast.error('Cloud URL is missing'); return; }
    setCloudLoading(true);
    try {
      const state = getCurrentState();
      const res = await gasPost({
        action: 'backup',
        exportedAt: new Date().toISOString(),
        state,
        label: cloudLabel || 'Manual backup',
      });
      if (res && res.ok === false) throw new Error(res.error || 'Backup rejected');
      setGasLastSync(Date.now());
      gasSaveConfig();
      setCloudLabel('');
      toast.success('☁ Backed up · ' + new Date().toLocaleTimeString());
    } catch (e: any) {
      toast.error('Backup failed: ' + e.message);
    } finally {
      setCloudLoading(false);
    }
  };

  const loadCloudVersions = async () => {
    if (!getGasUrl()) { toast.error('Cloud URL is missing'); return; }
    setCloudLoading(true);
    try {
      const res = await gasPost({ action: 'meta' });
      if (!res || res.ok === false) throw new Error(res?.error || 'Meta rejected');
      setCloudVersions(Array.isArray(res.versions) ? res.versions : []);
    } catch (e: any) {
      toast.error('Failed to load versions: ' + e.message);
    } finally {
      setCloudLoading(false);
    }
  };

  const restoreCloudVersion = async (versionId: string) => {
    if (!confirm('Restore this cloud backup? This will overwrite ALL local data.')) return;
    setCloudLoading(true);
    try {
      const res = await gasPost({ action: 'restoreVersion', versionId });
      if (!res || res.ok === false) throw new Error(res?.error || 'Restore rejected');
      if (!res.state) { toast.error('No backup content'); return; }
      const sk = findTrackerStorageKey(localStorage);
      localStorage.removeItem('tracker_data_cleared');
      localStorage.setItem(sk, JSON.stringify(res.state));
      await saveTrackerStateNow(res.state as unknown as TrackerState);
      toast.success('✓ Restored version ' + String(versionId).slice(0, 8));
      window.location.reload();
    } catch (e: any) {
      toast.error('Restore failed: ' + e.message);
    } finally {
      setCloudLoading(false);
    }
  };

  const scanCloudFiles = async () => {
    if (!getGasUrl()) { toast.error('Cloud URL is missing'); return; }
    setCloudLoading(true);
    try {
      const res = await gasPost({ action: 'scanFiles' });
      if (res && res.files) {
        toast.success(`Found ${res.files.length} backup files`);
      } else {
        toast.info('Scan complete');
      }
    } catch (e: any) {
      toast.error('Scan failed: ' + e.message);
    } finally {
      setCloudLoading(false);
    }
  };

  const handleCloudImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const data = JSON.parse(reader.result as string);
        const normalized = normalizeImportedTrackerState(data);
        const tradeCount = Array.isArray(normalized.trades) ? (normalized.trades as any[]).length : 0;
        const batchCount = Array.isArray(normalized.batches) ? (normalized.batches as any[]).length : 0;
        if (!confirm(`Import this file? (${tradeCount} trades, ${batchCount} batches)\nThis will replace your current state.`)) return;
        const sk = findTrackerStorageKey(localStorage);
        localStorage.removeItem('tracker_data_cleared');
        localStorage.setItem(sk, JSON.stringify(normalized));
        void saveTrackerStateNow(normalized as unknown as TrackerState);
        toast.success('Data imported — reloading…');
        setTimeout(() => window.location.reload(), 1000);
      } catch {
        toast.error('Invalid JSON file');
      }
    };
    reader.readAsText(f);
    e.target.value = '';
  };

  // Cloud setup actions use built-in URL

  const setupRestore = async () => {
    if (!getGasUrl()) { toast.error('Cloud URL is missing'); return; }
    setCloudLoading(true);
    try {
      const res = await gasPost({ action: 'restore' });
      if (!res || res.ok === false) throw new Error(res?.error || 'Restore rejected');
      if (!res.state) { toast.info('No backup found'); return; }
      const dt = res.exportedAt ? new Date(res.exportedAt).toLocaleString() : 'unknown date';
      if (!confirm(`Restore from cloud backup?\nBackup saved: ${dt}\n\nThis will overwrite ALL local data.`)) return;
      const sk = findTrackerStorageKey(localStorage);
      localStorage.removeItem('tracker_data_cleared');
      localStorage.setItem(sk, JSON.stringify(res.state));
      await saveTrackerStateNow(res.state as unknown as TrackerState);
      setGasLastSync(Date.now());
      gasSaveConfig();
      toast.success('✓ Restored from Cloud');
      window.location.reload();
    } catch (e: any) {
      toast.error('Restore failed: ' + e.message);
    } finally {
      setCloudLoading(false);
    }
  };




  // Data export helpers
  const exportJSON = () => {
    const state = getCurrentState();
    const fname = `p2p-tracker-${new Date().toISOString().slice(0, 10)}.json`;
    downloadBlob(JSON.stringify(state, null, 2), fname);
    setExportStatus('success');
    toast.success(t.lang === 'ar' ? 'تم تصدير JSON' : 'JSON exported');
    setTimeout(() => setExportStatus('idle'), 3000);
  };

  const exportCSV = () => {
    const state = getCurrentState() as any;
    const trades = state.trades || [];
    if (!trades.length) { toast.error(t.lang === 'ar' ? 'لا توجد صفقات للتصدير' : 'No trades to export'); return; }
    const headers = ['id', 'ts', 'amountUSDT', 'sellPriceQAR', 'feeQAR', 'note', 'voided'];
    const rows = trades.map((t: any) => headers.map(h => JSON.stringify(t[h] ?? '')).join(','));
    downloadBlob([headers.join(','), ...rows].join('\n'), `trades-${new Date().toISOString().slice(0, 10)}.csv`, 'text/csv');
    setExportStatus('success');
    toast.success(t.lang === 'ar' ? 'تم تصدير CSV' : 'CSV exported');
    setTimeout(() => setExportStatus('idle'), 3000);
  };

  const exportExcel = () => {
    const state = getCurrentState() as any;
    const trades = state.trades || [];
    const batches = state.batches || [];
    if (!trades.length && !batches.length) {
      toast.error(t.lang === 'ar' ? 'لا توجد بيانات للتصدير' : 'No data to export');
      return;
    }
    const tradeHeaders = ['ID', 'Date', 'Amount USDT', 'Sell Price QAR', 'Fee QAR', 'Note', 'Voided'];
    const tradeRows = trades.map((tr: any) => [
      tr.id || '', new Date(tr.ts || tr.created_at || 0).toLocaleString(),
      tr.amountUSDT ?? tr.quantity ?? '', tr.sellPriceQAR ?? tr.unit_price ?? '',
      tr.feeQAR ?? tr.fee ?? '', tr.note ?? tr.notes ?? '', tr.voided ?? tr.status ?? ''
    ].join('\t'));
    const batchHeaders = ['ID', 'Date', 'Quantity', 'Price', 'Source', 'Note'];
    const batchRows = batches.map((b: any) => [
      b.id || '', new Date(b.ts || b.acquired_at || b.created_at || 0).toLocaleString(),
      b.qty ?? b.quantity ?? '', b.priceQAR ?? b.unit_cost ?? '',
      b.source ?? b.notes ?? '', b.note ?? ''
    ].join('\t'));
    const content = `TRADES\n${tradeHeaders.join('\t')}\n${tradeRows.join('\n')}\n\nBATCHES\n${batchHeaders.join('\t')}\n${batchRows.join('\n')}`;
    downloadBlob(content, `p2p-tracker-${new Date().toISOString().slice(0, 10)}.tsv`, 'text/tab-separated-values');
    setExportStatus('success');
    toast.success(t.lang === 'ar' ? 'تم تصدير Excel (TSV)' : 'Excel (TSV) exported');
    setTimeout(() => setExportStatus('idle'), 3000);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setImportStatus('loading');
    setImportMsg('');
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const data = JSON.parse(reader.result as string);
        const normalized = normalizeImportedTrackerState(data);
        const tradeCount = Array.isArray(normalized.trades) ? (normalized.trades as any[]).length : 0;
        const batchCount = Array.isArray(normalized.batches) ? (normalized.batches as any[]).length : 0;
        
        if (!confirm(
          t.lang === 'ar' 
            ? `استيراد هذه البيانات؟ (${tradeCount} صفقة، ${batchCount} دفعة)\nسيتم استبدال البيانات الحالية.`
            : `Import this data? (${tradeCount} trades, ${batchCount} batches)\nThis will replace your current state.`
        )) {
          setImportStatus('idle');
          return;
        }
        const sk = findTrackerStorageKey(localStorage);
        localStorage.removeItem('tracker_data_cleared');
        localStorage.setItem(sk, JSON.stringify(normalized));
        void saveTrackerStateNow(normalized as unknown as TrackerState);
        setImportStatus('success');
        setImportMsg(t.lang === 'ar' 
          ? `✓ تم الاستيراد: ${tradeCount} صفقة، ${batchCount} دفعة` 
          : `✓ Imported: ${tradeCount} trades, ${batchCount} batches`);
        toast.success(t.lang === 'ar' ? 'تم استيراد البيانات — جاري إعادة التحميل…' : 'Data imported — reloading…');
        setTimeout(() => window.location.reload(), 1000);
      } catch (err: any) {
        setImportStatus('error');
        setImportMsg(t.lang === 'ar' ? 'ملف JSON غير صالح أو تنسيق غير مدعوم' : 'Invalid JSON file or unsupported format');
        toast.error(t.lang === 'ar' ? 'ملف JSON غير صالح' : 'Invalid JSON file');
      }
    };
    reader.onerror = () => {
      setImportStatus('error');
      setImportMsg(t.lang === 'ar' ? 'فشل قراءة الملف' : 'Failed to read file');
    };
    reader.readAsText(f);
    e.target.value = '';
  };

  const clearAll = async () => {
    if (!confirm(t.lang === 'ar' ? '⚠ مسح جميع البيانات؟ لا يمكن التراجع إلا إذا كان لديك نسخة احتياطية.' : '⚠ Clear ALL data? This cannot be undone unless you have a backup.')) return;
    clearTrackerStorage(localStorage);
    localStorage.setItem('tracker_data_cleared', 'true');
    await clearTrackerVaultDb();
    const emptyState = { batches: [], trades: [], customers: [], cashQAR: 0, cashOwner: '', currency: 'QAR', range: '7d', settings: { lowStockThreshold: 5000, priceAlertThreshold: 2 }, cal: { year: new Date().getFullYear(), month: new Date().getMonth(), selectedDay: null } };
    void saveTrackerStateNow(emptyState as unknown as TrackerState);
    toast.success(t.lang === 'ar' ? 'تم مسح البيانات — جاري إعادة التحميل…' : 'Data cleared — reloading…');
    setTimeout(() => window.location.reload(), 500);
  };

  const fmtDate = (ts: number) => {
    const d = new Date(ts);
    return d.toLocaleDateString() + ' ' + d.toLocaleTimeString();
  };

  const lastSyncTime = getGasLastSync();

  return (
    <div className="tracker-page" dir={t.isRTL ? 'rtl' : 'ltr'}>
      <PageHeader 
        title={t('vaultTitle')} 
        description={t('vaultSub')} 
      />

      <div className="p-6 space-y-4">
        {/* ── Row 1: Ring 1 + Ring 2 ── */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">

          {/* ── 💾 Ring 1 — Local Snapshots ── */}
          <Card className="glass">
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle className="text-sm font-display">
                  {t.lang === 'ar' ? '💾 الحلقة 1 — نسخ محلية' : '💾 Ring 1 — Local Snapshots'}
                </CardTitle>
                <Badge variant="outline" className="text-[10px]">IndexedDB</Badge>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <p className="text-[11px] text-muted-foreground leading-relaxed">
                {t.lang === 'ar' 
                  ? 'نسخ احتياطية محلية تلقائية كل 10 عمليات حفظ. تبقى حتى بعد مسح ذاكرة المتصفح.'
                  : 'Automatic local snapshots every 10 saves. Survives browser cache clears. No internet required.'}
              </p>

              <div className="space-y-2">
                <Label className="text-xs">{t.lang === 'ar' ? 'الوصف *' : 'Description *'}</Label>
                <Input
                  value={snapDesc}
                  onChange={e => setSnapDesc(e.target.value)}
                  placeholder={t.lang === 'ar' ? 'لماذا تأخذ هذه النسخة؟' : 'Why are you taking this snapshot?'}
                />
              </div>

              <Button onClick={takeSnapshot} disabled={loading} size="sm">
                <Camera className="w-3 h-3 mr-1" /> {t.lang === 'ar' ? 'أخذ نسخة الآن' : 'Take Snapshot Now'}
              </Button>

              {/* Snapshot list */}
              <div className="space-y-0 border-t pt-3">
                {snaps.length === 0 ? (
                  <p className="text-[10px] text-muted-foreground">
                    {t.lang === 'ar' ? 'لا توجد نسخ محلية بعد.' : 'No local snapshots yet. They are created every 10 saves automatically.'}
                  </p>
                ) : (
                  snaps.slice(0, 8).map(s => (
                    <div key={s.id} className="flex justify-between items-start gap-2 py-2 border-b border-border/50">
                      <div className="min-w-0">
                        <div className="flex gap-2 items-baseline">
                          <span className="text-[11px] font-bold whitespace-nowrap">{fmtDate(s.ts)}</span>
                          <span className="text-[10px] text-muted-foreground truncate">{s.label || '—'}</span>
                        </div>
                        <div className="text-[9px] text-muted-foreground">
                          {s.tradeCount} {t.lang === 'ar' ? 'صفقة' : 'trades'} · {s.batchCount} {t.lang === 'ar' ? 'دفعة' : 'batches'} · {s.sizeKB} KB · ✓ {(s.checksum || '—').slice(0, 8)}
                        </div>
                      </div>
                      <div className="flex gap-1 shrink-0">
                        <Button variant="ghost" size="sm" className="h-6 text-[9px] px-2" onClick={() => restoreSnap(s.id)}>
                          {t.lang === 'ar' ? 'استعادة' : 'Restore'}
                        </Button>
                        <Button variant="ghost" size="sm" className="h-6 text-[9px] px-2" onClick={() => exportSnap(s.id)}>
                          {t.lang === 'ar' ? 'تصدير' : 'Export'}
                        </Button>
                        <Button variant="ghost" size="sm" className="h-6 text-[9px] px-2 text-destructive" onClick={() => deleteSnap(s.id)}>
                          {t.lang === 'ar' ? 'حذف' : 'Del'}
                        </Button>
                      </div>
                    </div>
                  ))
                )}
                {snaps.length > 8 && (
                  <p className="text-[10px] text-muted-foreground pt-2">+{snaps.length - 8} {t.lang === 'ar' ? 'نسخ أقدم' : 'more older snapshots'}</p>
                )}
              </div>

              {/* Recovery */}
              <div className="border-t pt-3">
                <Label className="text-xs mb-2 block">{t.lang === 'ar' ? 'وضع الاسترداد' : 'Recovery Mode'}</Label>
                <p className="text-[10px] text-muted-foreground">
                  {snaps.length} {t.lang === 'ar' ? 'نسخة' : 'snapshots'}{snaps.length > 0 ? ` · ${t.lang === 'ar' ? 'الأحدث' : 'Latest'}: ${new Date(snaps[0].ts).toLocaleTimeString()}` : ''}
                </p>
                <Button variant="outline" size="sm" className="mt-2 text-[10px]" onClick={loadSnaps}>
                  <RefreshCw className="w-3 h-3 mr-1" /> {t.lang === 'ar' ? 'تحديث' : 'Refresh'}
                </Button>
              </div>

              {/* Auto-backup toggle */}
              <div className="flex items-center justify-between pt-2 border-t">
                <Label className="text-xs">{t.lang === 'ar' ? 'نسخ تلقائي بعد كل تغيير' : 'Auto-backup after every change'}</Label>
                <Switch checked={autoBackup} onCheckedChange={handleAutoBackupToggle} />
              </div>
            </CardContent>
          </Card>

          {/* ── ☁ Ring 2 — Cloud Vault ── */}
          <Card className="glass">
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle className="text-sm font-display">
                  {t.lang === 'ar' ? '☁ الحلقة 2 — الخزنة السحابية' : '☁ Ring 2 — Cloud Vault'}
                </CardTitle>
                {cloudLoggedIn ? (
                  <Badge variant="outline" className="text-[10px] text-green-500 border-green-500/30">✓ {getGasSession()?.email}</Badge>
                ) : (
                  <Badge variant="outline" className="text-[10px] text-yellow-500 border-yellow-500/30">⚠ Not signed in</Badge>
                )}
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              {!cloudLoggedIn ? (
                <>
                  <p className="text-[11px] text-muted-foreground leading-relaxed">
                    {t.lang === 'ar' ? 'جاري الاتصال بالسحابة تلقائياً...' : 'Connecting to cloud automatically...'}
                  </p>
                  {cloudAuthState === 'authenticating' ? (
                    <div className="flex items-center gap-2">
                      <Loader2 className="w-3 h-3 animate-spin text-muted-foreground" />
                      <span className="text-[10px] text-muted-foreground">
                        {t.lang === 'ar' ? 'يتم تسجيل الدخول باستخدام حسابك' : 'Signing in with your account...'}
                      </span>
                    </div>
                  ) : (
                    <div className="space-y-2">
                      <p className="text-[10px] text-amber-500">
                        {t.lang === 'ar' ? 'تعذر تسجيل الدخول السحابي تلقائياً.' : 'Cloud auto sign-in failed.'}
                      </p>
                      <p className="text-[10px] text-muted-foreground">
                        {cloudAuthError || (t.lang === 'ar' ? 'حاول مرة أخرى بعد لحظات.' : 'Try again in a few seconds.')}
                      </p>
                      <Button variant="outline" size="sm" className="h-7 text-[10px]" onClick={() => void authenticateCloud()}>
                        {t.lang === 'ar' ? 'إعادة المحاولة' : 'Retry cloud sign-in'}
                      </Button>
                    </div>
                  )}
                </>
              ) : (
                <>
                  <p className="text-[11px] text-muted-foreground leading-relaxed">
                    {t.lang === 'ar'
                      ? 'نسخ سحابية عبر Google Drive. حتى 30 نسخة + نسخ دائمة مثبتة.'
                      : 'Versioned cloud backups via Google Drive. Up to 30 versions + pinned permanent backups.'}
                  </p>

                  {/* Manual backup with label */}
                  <div className="flex gap-2">
                    <Input
                      value={cloudLabel}
                      onChange={e => setCloudLabel(e.target.value)}
                      placeholder={t.lang === 'ar' ? 'وصف النسخة (اختياري)' : 'Backup label (optional)'}
                      className="flex-1 text-[11px]"
                    />
                    <Button size="sm" onClick={cloudBackupNow} disabled={cloudLoading}>
                      {cloudLoading ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Cloud className="w-3 h-3 mr-1" />}
                      {t.lang === 'ar' ? 'نسخ الآن' : 'Backup Now'}
                    </Button>
                  </div>

                  {/* Version browser */}
                  <div className="max-h-[240px] overflow-y-auto text-[11px] border rounded-md p-2 bg-muted/20">
                    {cloudVersions.length === 0 ? (
                      <p className="text-[10px] text-muted-foreground p-2">
                        {t.lang === 'ar' ? 'لا توجد نسخ سحابية بعد. انقر "نسخ الآن" أولاً.' : 'No cloud backups yet. Click Backup Now first.'}
                      </p>
                    ) : (
                  cloudVersions.map((v, idx) => {
                    const dt = v.exportedAt ? new Date(v.exportedAt).toLocaleString() : 'unknown';
                    const bytes = v.bytes != null ? ` · ${fmtBytes(v.bytes)}` : '';
                    const vidShort = String(v.versionId || '').slice(0, 8);
                    const isSel = selectedVersion === v.versionId;
                    return (
                      <div
                        key={v.versionId}
                        className={`flex justify-between items-center gap-2 p-2 rounded-md cursor-pointer border mb-1 ${isSel ? 'border-primary bg-primary/5' : 'border-border/50'}`}
                        onClick={() => setSelectedVersion(v.versionId)}
                      >
                        <div className="min-w-0">
                          <div className="font-bold text-[11px] whitespace-nowrap">
                            {dt} <Badge variant="outline" className="text-[9px] ml-1">{vidShort}</Badge>
                          </div>
                          <div className="text-[10px] text-muted-foreground">
                            {idx === 0 ? 'LATEST' : ''}{bytes}{v.fileId ? ` · file ${String(v.fileId).slice(0, 8)}…` : ''}
                          </div>
                        </div>
                        <div className="flex gap-1 shrink-0">
                          <Button variant="ghost" size="sm" className="h-6 text-[9px] px-2" onClick={(e) => { e.stopPropagation(); /* preview could go here */ }}>
                            Preview
                          </Button>
                          <Button variant="ghost" size="sm" className="h-6 text-[9px] px-2 text-destructive" onClick={(e) => { e.stopPropagation(); restoreCloudVersion(v.versionId); }}>
                            Restore
                          </Button>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>

              {/* Actions */}
              <div className="flex gap-2 flex-wrap">
                <Button variant="secondary" size="sm" onClick={loadCloudVersions} disabled={cloudLoading}>
                  <RefreshCw className={`w-3 h-3 mr-1 ${cloudLoading ? 'animate-spin' : ''}`} /> Refresh
                </Button>
                <Button variant="secondary" size="sm" onClick={scanCloudFiles} disabled={cloudLoading}>
                  <Search className="w-3 h-3 mr-1" /> Scan Files
                </Button>
                <label className="cursor-pointer">
                  <Button variant="secondary" size="sm" asChild>
                    <span><Upload className="w-3 h-3 mr-1" /> Import File</span>
                  </Button>
                  <input type="file" accept=".json" className="hidden" onChange={handleCloudImportFile} />
                </label>
              </div>

                  {/* Logout */}
                  <div className="flex items-center justify-between pt-2 border-t">
                    <span className="text-[10px] text-muted-foreground">{getGasSession()?.email}</span>
                    <Button variant="ghost" size="sm" className="h-6 text-[9px] px-2" onClick={handleCloudLogout}>
                      <LogOut className="w-3 h-3 mr-1" /> Sign Out
                    </Button>
                  </div>
                </>
              )}
            </CardContent>
          </Card>
        </div>

        {/* ── Row 2: Cloud Backup Setup + Data Export/Import ── */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">

          {/* ── ☁ Cloud Backup Setup ── */}
          <Card className="glass">
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle className="text-sm font-display">
                  {t.lang === 'ar' ? '☁ إعداد النسخ السحابي' : '☁ Cloud Backup Setup'}
                </CardTitle>
                <Badge variant="outline" className="text-[10px] text-green-500 border-green-500/30">✓ Connected</Badge>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <p className="text-[11px] text-muted-foreground leading-relaxed">
                {t.lang === 'ar'
                  ? 'النسخ السحابي مُفعّل ومتصل تلقائياً. تُدار النسخ من الخزنة السحابية أعلاه.'
                  : 'Cloud backup is pre-configured and connected. Manage versions from the Cloud Vault above.'}
              </p>

              {/* Action buttons */}
              <div className="flex gap-2 flex-wrap">
                <Button variant="secondary" size="sm" onClick={cloudBackupNow} disabled={cloudLoading} className="flex-1 min-w-[140px]">
                  {cloudLoading ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Cloud className="w-3 h-3 mr-1" />}
                  Backup Now
                </Button>
                <Button variant="secondary" size="sm" onClick={loadCloudVersions} disabled={cloudLoading} className="flex-1 min-w-[140px]">
                  🧾 Backups
                </Button>
                <Button variant="secondary" size="sm" onClick={setupRestore} disabled={cloudLoading} className="flex-1 min-w-[140px]">
                  <Download className="w-3 h-3 mr-1" /> Restore
                </Button>
              </div>

              {/* Auto-backup toggle */}
              <div className="flex items-center justify-between pt-2 border-t">
                <Label className="text-xs">{t.lang === 'ar' ? 'نسخ تلقائي بعد كل تغيير' : 'Auto-backup after every change'}</Label>
                <Switch checked={autoBackup} onCheckedChange={handleAutoBackupToggle} />
              </div>

              {lastSyncTime > 0 && (
                <p className="text-[9px] text-muted-foreground">
                  Last sync: {new Date(lastSyncTime).toLocaleString()}
                </p>
              )}
            </CardContent>
          </Card>

          {/* ── 📦 Data Export & Import ── */}
          <Card className="glass">
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle className="text-sm font-display">
                  {t.lang === 'ar' ? '📦 تصدير واستيراد البيانات' : '📦 Data Export & Import'}
                </CardTitle>
                <Badge variant="outline" className="text-[10px]">JSON · Excel · CSV</Badge>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <p className="text-[11px] text-muted-foreground leading-relaxed">
                {t.lang === 'ar' 
                  ? 'صدّر بياناتك للنسخ الاحتياطي، تحليل Excel، أو النقل بين الأجهزة.'
                  : 'Export your data for offline backup, Excel analysis, or transfer between devices.'}
              </p>

              <div className="flex gap-2 flex-wrap">
                <Button variant="outline" size="sm" onClick={exportExcel}>
                  <FileSpreadsheet className="w-3 h-3 mr-1" /> Excel
                </Button>
                <Button variant="outline" size="sm" onClick={exportJSON}>
                  <FileJson className="w-3 h-3 mr-1" /> JSON
                </Button>
                <Button variant="outline" size="sm" onClick={exportCSV}>
                  <FileText className="w-3 h-3 mr-1" /> CSV
                </Button>
                {exportStatus === 'success' && (
                  <span className="flex items-center gap-1 text-[10px] text-green-500">
                    <CheckCircle2 className="w-3 h-3" /> {t.lang === 'ar' ? 'تم التصدير' : 'Exported'}
                  </span>
                )}
              </div>

              <div className="space-y-2">
                <label className="block">
                  <Button variant="outline" size="sm" className="cursor-pointer" asChild>
                    <span><Upload className="w-3 h-3 mr-1" /> {t.lang === 'ar' ? 'استيراد JSON' : 'Import JSON'}</span>
                  </Button>
                  <input ref={importInputRef} type="file" accept="application/json,.json" className="hidden" onChange={handleImport} />
                </label>
                {importStatus === 'loading' && (
                  <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                    <Loader2 className="w-3 h-3 animate-spin" /> {t.lang === 'ar' ? 'جاري المعالجة...' : 'Processing...'}
                  </div>
                )}
                {importStatus === 'success' && (
                  <div className="flex items-center gap-2 text-[10px] text-green-500">
                    <CheckCircle2 className="w-3 h-3" /> {importMsg}
                  </div>
                )}
                {importStatus === 'error' && (
                  <div className="flex items-center gap-2 text-[10px] text-destructive">
                    <XCircle className="w-3 h-3" /> {importMsg}
                  </div>
                )}
              </div>

              <div className="border-t pt-3 space-y-2">
                <Label className="text-[10px] uppercase tracking-wider text-muted-foreground opacity-70">
                  {t.lang === 'ar' ? 'أدوات متقدمة' : 'Advanced Tools'}
                </Label>
                <div className="flex gap-2">
                  <Button variant="secondary" size="sm" onClick={() => navigate('/trading/orders/import-ledger')}>
                     <RefreshCw className="w-3 h-3 mr-1" /> {t('importLedger')}
                  </Button>
                </div>
                <p className="text-[10px] text-muted-foreground">
                  {t.lang === 'ar' 
                    ? 'استيراد سجلات PDF أو نصية من الوسطاء تلقائياً.' 
                    : 'Bulk-import merchant ledgers from pasted text or screenshots.'}
                </p>
              </div>

              <div className="border-t pt-3">
                <Button variant="destructive" size="sm" onClick={clearAll}>
                  <AlertTriangle className="w-3 h-3 mr-1" /> {t.lang === 'ar' ? 'مسح جميع البيانات' : 'Clear All Data'}
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { focusElementBySelectors } from '@/lib/focus-target';
import { format } from 'date-fns';
import { Check, X, Shield, Loader2, Users } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { Textarea } from '@/components/ui/textarea';
import { useToast } from '@/hooks/use-toast';
import {
  useAdminProfiles,
  useApproveProfile,
  useRejectProfile,
  useIsAdmin,
  type PendingProfile,
} from '@/features/admin/hooks/useAdminProfiles';

function StatusBadge({ status }: { status: string }) {
  const map: Record<string, { variant: 'default' | 'secondary' | 'destructive' | 'outline'; label: string }> = {
    pending: { variant: 'outline', label: 'Pending' },
    approved: { variant: 'default', label: 'Approved' },
    rejected: { variant: 'destructive', label: 'Rejected' },
  };
  const cfg = map[status] ?? { variant: 'secondary' as const, label: status };
  return <Badge variant={cfg.variant}>{cfg.label}</Badge>;
}

function RejectDialog({ profile, onReject }: { profile: PendingProfile; onReject: (reason: string) => void }) {
  const [reason, setReason] = useState('');
  return (
    <AlertDialog>
      <AlertDialogTrigger asChild>
        <Button variant="destructive" size="sm">
          <X className="mr-1 h-3.5 w-3.5" /> Reject
        </Button>
      </AlertDialogTrigger>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Reject {profile.email}?</AlertDialogTitle>
          <AlertDialogDescription>
            This user will be denied access. Provide a reason.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          placeholder="Reason for rejection…"
          value={reason}
          onChange={(e) => setReason(e.target.value)}
          className="min-h-[80px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction
            disabled={!reason.trim()}
            onClick={() => onReject(reason.trim())}
            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
          >
            Confirm Rejection
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

export default function AdminApprovalsPage() {
  const { toast } = useToast();
  const [searchParams] = useSearchParams();
  const { data: isAdmin, isLoading: roleLoading } = useIsAdmin();
  const { data: profiles, isLoading } = useAdminProfiles();
  const approve = useApproveProfile();
  const reject = useRejectProfile();

  if (roleLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  if (!isAdmin) {
    return (
      <div className="flex items-center justify-center py-20">
        <Card className="w-full max-w-sm text-center">
          <CardHeader>
            <Shield className="mx-auto h-10 w-10 text-destructive" />
            <CardTitle>Access Denied</CardTitle>
            <CardDescription>You do not have admin privileges.</CardDescription>
          </CardHeader>
        </Card>
      </div>
    );
  }

  const pending = profiles?.filter((p) => p.status === 'pending') ?? [];
  const others = profiles?.filter((p) => p.status !== 'pending') ?? [];


  useEffect(() => {
    const focusApprovalId = searchParams.get('focusApprovalId');
    if (!focusApprovalId) return;
    window.setTimeout(() => {
      focusElementBySelectors([
        `#approval-${focusApprovalId}`,
        `[data-approval-id="${focusApprovalId}"]`,
      ]);
    }, 150);
  }, [searchParams, profiles]);

  const handleApprove = async (p: PendingProfile) => {
    try {
      await approve.mutateAsync(p.user_id);
      toast({ title: 'Approved', description: `${p.email} has been approved.` });
    } catch {
      toast({ title: 'Error', description: 'Failed to approve user.', variant: 'destructive' });
    }
  };

  const handleReject = async (p: PendingProfile, reason: string) => {
    try {
      await reject.mutateAsync({ profileUserId: p.user_id, reason });
      toast({ title: 'Rejected', description: `${p.email} has been rejected.` });
    } catch {
      toast({ title: 'Error', description: 'Failed to reject user.', variant: 'destructive' });
    }
  };

  return (
    <div className="space-y-6">
      {/* Pending */}
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Users className="h-5 w-5 text-primary" />
            <CardTitle className="text-lg">Pending Approvals</CardTitle>
            {pending.length > 0 && (
              <Badge variant="secondary" className="ml-auto">{pending.length}</Badge>
            )}
          </div>
          <CardDescription>Review and approve new user registrations.</CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
            </div>
          ) : pending.length === 0 ? (
            <p className="py-6 text-center text-sm text-muted-foreground">
              No pending accounts to review.
            </p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Email</TableHead>
                  <TableHead>Registered</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {pending.map((p) => (
                  <TableRow key={p.id} id={`approval-${p.id}`} data-approval-id={p.id}>
                    <TableCell className="font-medium">{p.email}</TableCell>
                    <TableCell className="text-muted-foreground text-sm">
                      {format(new Date(p.created_at), 'MMM d, yyyy HH:mm')}
                    </TableCell>
                    <TableCell><StatusBadge status={p.status} /></TableCell>
                    <TableCell className="text-right space-x-2">
                      <Button
                        size="sm"
                        onClick={() => handleApprove(p)}
                        disabled={approve.isPending}
                      >
                        <Check className="mr-1 h-3.5 w-3.5" /> Approve
                      </Button>
                      <RejectDialog profile={p} onReject={(reason) => handleReject(p, reason)} />
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* History */}
      {others.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Account History</CardTitle>
          </CardHeader>
          <CardContent>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Email</TableHead>
                  <TableHead>Registered</TableHead>
                  <TableHead>Status</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {others.map((p) => (
                  <TableRow key={p.id} id={`approval-${p.id}`} data-approval-id={p.id}>
                    <TableCell className="font-medium">{p.email}</TableCell>
                    <TableCell className="text-muted-foreground text-sm">
                      {format(new Date(p.created_at), 'MMM d, yyyy HH:mm')}
                    </TableCell>
                    <TableCell><StatusBadge status={p.status} /></TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '@/features/auth/auth-context';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Loader2, CheckCircle2, XCircle } from 'lucide-react';
import { toast } from 'sonner';
import { useT } from '@/lib/i18n';

export default function OnboardingPage() {
  const { refreshProfile, userId, merchantProfile, isLoading } = useAuth();
  const navigate = useNavigate();
  const t = useT();
  const [loading, setLoading] = useState(false);
  const [nicknameStatus, setNicknameStatus] = useState<'idle' | 'checking' | 'available' | 'taken'>('idle');

  const [form, setForm] = useState({
    display_name: '',
    nickname: '',
    region: '',
    default_currency: 'USDT',
    bio: '',
  });

  useEffect(() => {
    if (!isLoading && merchantProfile) {
      navigate('/dashboard', { replace: true });
    }
  }, [isLoading, merchantProfile, navigate]);

  const checkNickname = async (nick: string) => {
    if (nick.length < 3) { setNicknameStatus('idle'); return; }
    setNicknameStatus('checking');
    try {
      const { data } = await supabase
        .from('merchant_profiles')
        .select('id')
        .eq('merchant_id', nick)
        .maybeSingle();
      setNicknameStatus(data ? 'taken' : 'available');
    } catch {
      setNicknameStatus('idle');
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (nicknameStatus === 'taken') {
      toast.error(t('onboardNickTaken'));
      return;
    }
    if (!userId) {
      toast.error('Not authenticated');
      return;
    }
    setLoading(true);
    try {
      // Generate a unique 4-digit merchant code
      let merchantCode = '';
      let codeUnique = false;
      while (!codeUnique) {
        merchantCode = String(Math.floor(1000 + Math.random() * 9000));
        const { data: existing } = await (supabase
          .from('merchant_profiles') as any)
          .select('id')
          .eq('merchant_code', merchantCode)
          .maybeSingle();
        codeUnique = !existing;
      }

      const insertPayload: any = {
        user_id: userId,
        merchant_id: form.nickname,
        nickname: form.nickname,
        display_name: form.display_name,
        region: form.region || null,
        default_currency: form.default_currency || 'USDT',
        bio: form.bio || null,
        merchant_code: merchantCode,
      };
      const { error } = await supabase.from('merchant_profiles').insert(insertPayload);
      if (error) throw error;
      await refreshProfile();
      toast.success(t('onboardSuccess'));
      navigate('/dashboard');
    } catch (err: unknown) {
      await refreshProfile();
      const message = err instanceof Error ? err.message : 'Failed to create profile';

      if (message.toLowerCase().includes('duplicate') || message.includes('409')) {
        toast.info(t('onboardDuplicate'));
        navigate('/dashboard', { replace: true });
        return;
      }

      toast.error(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-background p-4" dir={t.isRTL ? 'rtl' : 'ltr'}>
      <Card className="w-full max-w-lg">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl">{t('onboardTitle')}</CardTitle>
          <CardDescription>{t('onboardDesc')}</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="display_name">{t('onboardDisplayName')}</Label>
              <Input
                id="display_name"
                placeholder={t('onboardDisplayNamePh')}
                value={form.display_name}
                onChange={(e) => setForm(f => ({ ...f, display_name: e.target.value }))}
                required
                minLength={2}
                maxLength={80}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="nickname">{t('onboardNickname')}</Label>
              <div className="relative">
                <Input
                  id="nickname"
                  placeholder={t('onboardNicknamePh')}
                  value={form.nickname}
                  onChange={(e) => {
                    const v = e.target.value.toLowerCase().replace(/[^a-z0-9_.-]/g, '');
                    setForm(f => ({ ...f, nickname: v }));
                    checkNickname(v);
                  }}
                  required
                  minLength={3}
                  maxLength={32}
                  className="pr-8"
                  dir="ltr"
                />
                <div className="absolute right-2 top-1/2 -translate-y-1/2">
                  {nicknameStatus === 'available' && <CheckCircle2 className="h-4 w-4 text-success" />}
                  {nicknameStatus === 'taken' && <XCircle className="h-4 w-4 text-destructive" />}
                </div>
              </div>
              <p className="text-xs text-muted-foreground">{t('onboardNicknameHint')}</p>
            </div>

            <div className="space-y-2">
              <Label htmlFor="region">{t('onboardRegion')}</Label>
              <Input
                id="region"
                placeholder={t('onboardRegionPh')}
                value={form.region}
                onChange={(e) => setForm(f => ({ ...f, region: e.target.value }))}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="default_currency">{t('onboardCurrency')}</Label>
              <Input
                id="default_currency"
                placeholder="USDT"
                value={form.default_currency}
                onChange={(e) => setForm(f => ({ ...f, default_currency: e.target.value.toUpperCase() }))}
                dir="ltr"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="bio">{t('onboardBio')}</Label>
              <Textarea
                id="bio"
                placeholder={t('onboardBioPh')}
                value={form.bio}
                onChange={(e) => setForm(f => ({ ...f, bio: e.target.value }))}
                rows={3}
              />
            </div>

            <Button type="submit" className="w-full" disabled={loading || nicknameStatus === 'taken'}>
              {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {t('onboardSubmit')}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

import { describe, it, expect } from 'vitest';
import { buildOrderFromDraft, createId, economicTermsChanged, getMerchantAgreementDeleteMode, createMerchantAgreementSnapshot } from '@/lib/trading/utils';
import { calculateNetProfit } from '@/lib/trading/profit-service';
import type { MerchantAgreement, OrderDraft, AgreementTemplate } from '@/lib/trading/types';

describe('trading/profit-service — calculateNetProfit', () => {
  const base = { templateId: 'T1', agreementId: 'A1', version: 1 };

  it('profit_share: round(total * profitSharePercent / 100)', () => {
    const result = calculateNetProfit({
      quantity: 100, unitPrice: 10,
      snapshot: { ...base, agreementType: 'profit_share', profitSharePercent: 20 },
    });
    expect(result).toBe(200);
  });

  it('fixed_margin: round(quantity * fixedMarginAmount)', () => {
    const result = calculateNetProfit({
      quantity: 100, unitPrice: 10,
      snapshot: { ...base, agreementType: 'fixed_margin', fixedMarginAmount: 2 },
    });
    expect(result).toBe(200);
  });

  it('spread: round(total * spreadPercent / 100)', () => {
    const result = calculateNetProfit({
      quantity: 100, unitPrice: 10,
      snapshot: { ...base, agreementType: 'spread', spreadPercent: 1.5 },
    });
    expect(result).toBe(15);
  });

  it('commission: round(total * commissionPercent / 100)', () => {
    const result = calculateNetProfit({
      quantity: 100, unitPrice: 10,
      snapshot: { ...base, agreementType: 'commission', commissionPercent: 5 },
    });
    expect(result).toBe(50);
  });

  it('custom: round(sum(fixedValues) + total * sum(percentages) / 100)', () => {
    const result = calculateNetProfit({
      quantity: 100, unitPrice: 10,
      snapshot: {
        ...base, agreementType: 'custom',
        fixedValues: { base: 10 },
        percentages: { fee: 2 },
      },
    });
    expect(result).toBe(30);
  });

  it('unknown type returns 0', () => {
    const result = calculateNetProfit({
      quantity: 100, unitPrice: 10,
      snapshot: { ...base, agreementType: 'unknown' as any },
    });
    expect(result).toBe(0);
  });
});

describe('trading/utils', () => {
  describe('createId', () => {
    it('returns prefixed ID', () => {
      const id = createId('ORD');
      expect(id).toMatch(/^ORD-[a-z0-9]+$/);
    });
  });

  describe('economicTermsChanged', () => {
    it('returns false for identical configs', () => {
      const cfg = { profitSharePercent: 20 };
      expect(economicTermsChanged(cfg, { ...cfg })).toBe(false);
    });

    it('returns true for different configs', () => {
      expect(economicTermsChanged({ profitSharePercent: 20 }, { profitSharePercent: 30 })).toBe(true);
    });
  });

  describe('getMerchantAgreementDeleteMode', () => {
    const agreement = { id: 'agr-1' } as MerchantAgreement;

    it('returns "archive" if agreement is used in orders', () => {
      expect(getMerchantAgreementDeleteMode(agreement, new Set(['agr-1']))).toBe('archive');
    });

    it('returns "delete" if agreement is unused', () => {
      expect(getMerchantAgreementDeleteMode(agreement, new Set())).toBe('delete');
    });
  });

  describe('buildOrderFromDraft', () => {
    const mockAgreement: MerchantAgreement = {
      id: 'agr-1',
      templateId: 'tpl-1',
      merchantId: 'MRC-001',
      merchantName: 'Test Merchant',
      agreementType: 'profit_share',
      title: 'Test Agreement',
      status: 'approved',
      approvedByUserId: 'user-1',
      approvedAt: '2026-01-01T00:00:00Z',
      resolvedTermsSnapshot: {
        templateId: 'tpl-1',
        agreementId: 'agr-1',
        version: 1,
        agreementType: 'profit_share',
        profitSharePercent: 20,
      },
      version: 1,
      isActive: true,
      createdAt: '2026-01-01T00:00:00Z',
      updatedAt: '2026-01-01T00:00:00Z',
    };

    const mockDraft: OrderDraft = {
      direction: 'outgoing',
      merchantId: 'MRC-001',
      merchantName: 'Test Merchant',
      buyerId: 'BUY-001',
      buyerName: 'Test Buyer',
      merchantAgreementId: 'agr-1',
      quantity: 100,
      unitPrice: 10,
      currency: 'USDT',
    };

    it('creates order with correct computedNetProfit for profit_share', () => {
      const order = buildOrderFromDraft(mockDraft, mockAgreement, 'user-1');
      expect(order.computedNetProfit).toBe(200); // 1000 * 20%
      expect(order.totalAmount).toBe(1000);
      expect(order.status).toBe('confirmed');
      expect(order.agreementSnapshot.profitSharePercent).toBe(20);
    });

    it('throws when agreement is not approved', () => {
      const pendingAgreement = { ...mockAgreement, status: 'pending' as const };
      expect(() => buildOrderFromDraft(mockDraft, pendingAgreement, 'user-1'))
        .toThrow('Agreement must be approved and active');
    });

    it('throws when agreement is not active', () => {
      const inactiveAgreement = { ...mockAgreement, isActive: false };
      expect(() => buildOrderFromDraft(mockDraft, inactiveAgreement, 'user-1'))
        .toThrow('Agreement must be approved and active');
    });

    it('throws when merchantId does not match', () => {
      const mismatchDraft = { ...mockDraft, merchantId: 'MRC-999' };
      expect(() => buildOrderFromDraft(mismatchDraft, mockAgreement, 'user-1'))
        .toThrow('agreement.merchantId must equal draft.merchantId');
    });

    it('preserves immutable agreementSnapshot', () => {
      const order = buildOrderFromDraft(mockDraft, mockAgreement, 'user-1');
      // Snapshot should be a copy, not a reference
      expect(order.agreementSnapshot).not.toBe(mockAgreement.resolvedTermsSnapshot);
      expect(order.agreementSnapshot).toEqual(mockAgreement.resolvedTermsSnapshot);
    });
  });
});

import { describe, it, expect } from 'vitest';
import { mergeTrackerStatesForMerchant } from '@/lib/tracker-sync';

describe('mergeTrackerStatesForMerchant', () => {
  it('merges batches/trades/customers across merchant user snapshots without duplicates', () => {
    const merged = mergeTrackerStatesForMerchant([
      {
        updated_at: '2026-04-01T00:00:00.000Z',
        state: {
          batches: [{ id: 'b1', ts: 1, source: 'A', initialUSDT: 10, buyPriceQAR: 3.5, note: '' } as any],
          trades: [{ id: 't1', ts: 2, inputMode: 'USDT', amountUSDT: 1, sellPriceQAR: 4, feeQAR: 0, note: '', voided: false, usesStock: true, revisions: [], customerId: '' } as any],
          customers: [{ id: 'c1', name: 'Foo', phone: '' } as any],
        },
      },
      {
        updated_at: '2026-04-02T00:00:00.000Z',
        state: {
          batches: [{ id: 'b2', ts: 3, source: 'B', initialUSDT: 20, buyPriceQAR: 3.6, note: '' } as any],
          trades: [{ id: 't2', ts: 4, inputMode: 'USDT', amountUSDT: 2, sellPriceQAR: 4.1, feeQAR: 0, note: '', voided: false, usesStock: true, revisions: [], customerId: '' } as any],
          customers: [{ id: 'c2', name: 'Bar', phone: '' } as any],
        },
      },
      {
        updated_at: '2026-04-03T00:00:00.000Z',
        state: {
          trades: [{ id: 't2', ts: 5, inputMode: 'USDT', amountUSDT: 2, sellPriceQAR: 4.2, feeQAR: 0, note: 'updated', voided: false, usesStock: true, revisions: [], customerId: '' } as any],
        },
      },
    ]);

    expect(merged?.batches).toHaveLength(2);
    expect(merged?.trades).toHaveLength(2);
    expect(merged?.customers).toHaveLength(2);
    const t2 = (merged?.trades as any[]).find((t) => t.id === 't2');
    expect(t2?.sellPriceQAR).toBe(4.2);
    expect(t2?.note).toBe('updated');
  });
});
